const nexusLocalMusicPlayback = {
  context: null,
  gain: null,
  nodes: [],
  timers: [],
  state: "idle",
  volume: 0.12,
  muted: false,
  track: null
};

function clearNexusLocalMusicTimers() {
  nexusLocalMusicPlayback.timers.forEach(timer => clearTimeout(timer));
  nexusLocalMusicPlayback.timers = [];
}

function setNexusLocalMusicGain(value = nexusLocalMusicPlayback.volume) {
  const gain = nexusLocalMusicPlayback.gain;
  if (!gain) return;
  const target = nexusLocalMusicPlayback.muted ? 0.0001 : Math.max(0.0001, Math.min(0.3, value));
  try {
    gain.gain.cancelScheduledValues(gain.context.currentTime);
    gain.gain.setTargetAtTime(target, gain.context.currentTime, 0.03);
  } catch (error) {
    gain.gain.value = target;
  }
}

function resetNexusLocalMusicPlayback(state = "idle") {
  clearNexusLocalMusicTimers();
  nexusLocalMusicPlayback.context = null;
  nexusLocalMusicPlayback.gain = null;
  nexusLocalMusicPlayback.nodes = [];
  nexusLocalMusicPlayback.state = state;
  nexusLocalMusicPlayback.track = null;
}

function stopNexusLocalMusicPlayback(options = {}) {
  const context = nexusLocalMusicPlayback.context;
  const wasActive = Boolean(context && nexusLocalMusicPlayback.state !== "idle");
  clearNexusLocalMusicTimers();
  nexusLocalMusicPlayback.nodes.forEach(node => {
    try {
      node.stop?.(0);
    } catch (error) {
      // The oscillator may already have stopped.
    }
    try {
      node.disconnect?.();
    } catch (error) {
      // The node may already be disconnected.
    }
  });
  nexusLocalMusicPlayback.nodes = [];
  if (context) {
    try {
      context.close?.().catch?.(() => {});
    } catch (error) {
      // Some browsers throw if the context is already closing.
    }
  }
  resetNexusLocalMusicPlayback(options.state || "stopped");
  if (options.toast && wasActive) toast("Local music demo stopped");
  return wasActive;
}

function scheduleNexusLocalMusicCleanup(context) {
  const timer = setTimeout(() => {
    if (nexusLocalMusicPlayback.context !== context) return;
    stopNexusLocalMusicPlayback({ state: "idle" });
  }, 7000);
  nexusLocalMusicPlayback.timers.push(timer);
}

async function playNexusMusicTestAudio(query = "music") {
  const AudioContextClass = window.AudioContext || window.webkitAudioContext;
  if (!AudioContextClass) {
    toast("This browser cannot play the local Nexus music demo.");
    return false;
  }
  stopNexusLocalMusicPlayback({ state: "stopped" });
  const track = nexusMusicTestCatalog(query);
  const context = new AudioContextClass();
  try {
    await context.resume();
  } catch (error) {
    resetNexusLocalMusicPlayback("idle");
    toast("Tap a music command again to allow browser audio playback.");
    return false;
  }
  const gain = context.createGain();
  gain.gain.setValueAtTime(0.0001, context.currentTime);
  gain.gain.exponentialRampToValueAtTime(nexusLocalMusicPlayback.muted ? 0.0001 : nexusLocalMusicPlayback.volume, context.currentTime + 0.08);
  gain.gain.exponentialRampToValueAtTime(0.0001, context.currentTime + 6.2);
  gain.connect(context.destination);
  nexusLocalMusicPlayback.context = context;
  nexusLocalMusicPlayback.gain = gain;
  nexusLocalMusicPlayback.nodes = [];
  nexusLocalMusicPlayback.state = "playing";
  nexusLocalMusicPlayback.track = track;
  track.notes.forEach((frequency, index) => {
    const start = context.currentTime + index * track.tempo;
    const osc = context.createOscillator();
    const noteGain = context.createGain();
    osc.type = index % 2 ? track.wave : "sine";
    osc.frequency.setValueAtTime(frequency, start);
    noteGain.gain.setValueAtTime(0.0001, start);
    noteGain.gain.exponentialRampToValueAtTime(0.32, start + 0.04);
    noteGain.gain.exponentialRampToValueAtTime(0.0001, start + Math.max(0.18, track.tempo - 0.05));
    osc.connect(noteGain);
    noteGain.connect(gain);
    osc.start(start);
    osc.stop(start + Math.max(0.22, track.tempo - 0.02));
    nexusLocalMusicPlayback.nodes.push(osc);
  });
  const bass = context.createOscillator();
  bass.type = "sine";
  bass.frequency.setValueAtTime(track.bass, context.currentTime);
  bass.connect(gain);
  bass.start(context.currentTime);
  bass.stop(context.currentTime + 6.1);
  nexusLocalMusicPlayback.nodes.push(bass);
  scheduleNexusLocalMusicCleanup(context);
  toast(`Playing ${track.label}`);
  return true;
}

function localMusicControlIntent(command = "") {
  const lower = normalizeToolText(command);
  if (!/\bmusic\b|\bsong\b|\bsongs\b|\bplaylist\b/.test(lower)) return null;
  if (/\b(stop|cancel|end|turn off|shut off)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\b(stop|cancel|end)\b/.test(lower)) return "stop";
  if (/\b(pause|hold)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\bpause\b/.test(lower)) return "pause";
  if (/\b(resume|continue|restart)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\b(resume|continue|restart)\b/.test(lower)) return "resume";
  if (/\b(mute|silence)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\bmute\b/.test(lower)) return "mute";
  if (/\b(unmute|unsilence)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\bunmute\b/.test(lower)) return "unmute";
  if (/\b(volume|turn)\b.*\b(up|louder|higher)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\b(volume up|turn up|louder|higher)\b/.test(lower)) return "volume-up";
  if (/\b(volume|turn)\b.*\b(down|lower|quieter|softer)\b.*\b(music|song|songs|playlist)\b|\b(music|song|songs|playlist)\b.*\b(volume down|turn down|lower|quieter|softer)\b/.test(lower)) return "volume-down";
  return null;
}

function handleLocalMusicControlCommand(command = "") {
  const action = localMusicControlIntent(command);
  if (!action) return false;
  const playback = nexusLocalMusicPlayback;
  const active = Boolean(playback.context && playback.state !== "idle" && playback.state !== "stopped");
  let message = "";
  if (action === "stop") {
    const stopped = stopNexusLocalMusicPlayback({ toast: true, state: "stopped" });
    message = stopped ? "Local music demo stopped. Nexus is still listening when you call it again." : "No local music demo is playing right now.";
  } else if (action === "pause") {
    if (playback.context && playback.state === "playing") {
      playback.context.suspend?.().catch?.(() => {});
      clearNexusLocalMusicTimers();
      playback.state = "paused";
      message = "Local music demo paused. Say resume music to continue it.";
    } else {
      message = playback.state === "paused" ? "Local music demo is already paused." : "No local music demo is playing right now.";
    }
  } else if (action === "resume") {
    if (playback.context && playback.state === "paused") {
      playback.context.resume?.().catch?.(() => {});
      playback.state = "playing";
      scheduleNexusLocalMusicCleanup(playback.context);
      message = "Local music demo resumed.";
    } else {
      message = active ? "Local music demo is already playing." : "Nothing is paused in the local music demo.";
    }
  } else if (action === "mute") {
    playback.muted = true;
    setNexusLocalMusicGain();
    message = active ? "Local music demo muted." : "Local music demo will start muted next time.";
  } else if (action === "unmute") {
    playback.muted = false;
    setNexusLocalMusicGain();
    message = active ? "Local music demo unmuted." : "Local music demo will use sound next time.";
  } else if (action === "volume-up" || action === "volume-down") {
    const delta = action === "volume-up" ? 0.03 : -0.03;
    playback.volume = Math.max(0.03, Math.min(0.24, Number((playback.volume + delta).toFixed(2))));
    if (action === "volume-up") playback.muted = false;
    setNexusLocalMusicGain(playback.volume);
    message = `Local music demo volume is ${Math.round((playback.muted ? 0 : playback.volume) / 0.24 * 100)}%.`;
  }
  updateNexusBehaviorLayer("answering", "Nexus adjusted the local browser music demo playback.");
  renderLiveVoiceSuggestions(["play relaxing music", "pause music", "resume music", "stop music"]);
  if (message) setVoiceResponse(message, true);
  return true;
}

async function runMusicAssistantCommand(command = "", options = {}) {
  const turnToken = options.turnToken || null;
  if (handleLocalMusicControlCommand(command)) return true;
  const intent = musicAssistantIntent(command);
  if (!intent) return false;
  updateNexusBehaviorLayer("answering", "Nexus understood this as an everyday music request and is checking the connected music provider.");
  renderLiveVoiceSuggestions(["what time is it", "weather in Nairobi", "open learning", "Nexus stop"]);
  const result = await runUtilityAgentCommand(command, intent.response, null, { turnToken });
  if (ignoreStaleNexusTurn(turnToken, "music answer")) return true;
  const music = result?.metadata?.music;
  if (music && music.status !== "playback-started") {
    const played = await playNexusMusicTestAudio(intent.query);
    if (!played) setVoiceResponse("I understood the music request, but the browser did not allow local demo playback yet. Try again from a button or typed command.", true);
  }
  return true;
}

function nextStepAssistantAnswer() {
  const course = activeCourse();
  const role = firstEligibleRole();
  const product = firstProduct();
  if (!(data.profile.enrollments || []).length && course) return `Next best step: start ${translatedCourse(course).title}. This creates learning evidence.`;
  if (!(data.profile.applications || []).length && role) return `Next best step: apply for ${role.title}. This creates workforce evidence.`;
  if (!(data.profile.healthIntakes || []).length) return "Next best step: start telehealth intake so Nexus can guide care access and safety support.";
  if (!(data.profile.orders || []).length && product) return `Next best step: create a crop order for ${product.name}. This connects buyer, route, payment, and delivery tracking.`;
  return "Next best step: ask Nexus to run route intelligence, field alert, buyer message, or health safety reminder.";
}

function nexusUtilityAssistantResponse(command = "") {
  const lower = normalizeToolText(command);
  const raw = String(command || "").toLowerCase();
  const haystack = `${lower} ${raw}`;
  if (!lower && !raw.trim()) return "";
  if (/\b(what time is it|current time|time now|tell me the time|hora es|quelle heure|saa ngapi)\b/.test(lower) || /(الوقت|الساعة)/.test(raw)) {
    return localTimeAnswer();
  }
  if (/\b(weather|temperature|too hot|heat|outside|walk|walking|rain|forecast|clima|meteo|météo|hali ya hewa)\b/.test(haystack) || /(الطقس|الحرارة)/.test(raw)) {
    return weatherAssistantAnswer(command);
  }
  if (/\b(shipment|delivery|deliver|arrive|arrival|eta|track my sale|track my order|track my product|where is my crop|where is my shipment|route status)\b/.test(lower)) {
    if (canOpenSection("map")) goSection(experienceMode === "user" ? "map" : "map");
    return shipmentEtaAnswer();
  }
  if (/\b(appointment|schedule|calendar|visit|call with provider|doctor time|provider time|shift time|what time is my)\b/.test(lower)) {
    return appointmentAnswer();
  }
  if (/\b(what is next today|what do i have today|today's plan|daily plan|my day|what should i do today)\b/.test(lower)) {
    return `${localTimeAnswer()} ${appointmentAnswer()} ${shipmentEtaAnswer()}`;
  }
  return "";
}

function nexusUtilityAssistantResponseV2(command = "") {
  const lower = normalizeToolText(command);
  const raw = String(command || "").toLowerCase();
  const haystack = `${lower} ${raw}`;
  if (!lower && !raw.trim()) return "";
  if (/\b(what time is it|current time|time now|tell me the time|hora es|quelle heure|saa ngapi)\b/.test(lower) || /(\u0627\u0644\u0648\u0642\u062a|\u0627\u0644\u0633\u0627\u0639\u0629)/.test(raw)) {
    return localTimeAnswer();
  }
  if (/\b(weather|temperature|too hot|heat|outside|walk|walking|rain|forecast|clima|meteo|météo|hali ya hewa)\b/.test(haystack) || /(\u0627\u0644\u0637\u0642\u0633|\u0627\u0644\u062d\u0631\u0627\u0631\u0629)/.test(raw)) {
    return weatherAssistantAnswer(command);
  }
  const musicIntent = musicAssistantIntent(command);
  if (musicIntent) return musicIntent.response;
  if (/\b(crop timing|planting time|when should i plant|when to plant|best time to plant|harvest time|when should i harvest|when to harvest|crop calendar|plant today|harvest today)\b/.test(lower)) return cropTimingAssistantAnswer();
  if (/\b(route delay|route delays|delay|delays|delayed|traffic|road blocked|roadblock|late delivery|delivery delay|delivery delays|shipment delay|shipment delays|route problem)\b/.test(lower)) return routeDelayAssistantAnswer();
  if (/\b(buyer message|message buyer|contact buyer|buyer update|text buyer|whatsapp buyer|send buyer|talk to buyer|speak to buyer)\b/.test(lower)) return buyerMessageAssistantAnswer();
  if (/\b(field alert|field warning|crop alert|farm alert|pest alert|drone alert|field problem|crop problem|crop stress|field risk|bad crop|crops going bad)\b/.test(lower)) return fieldAlertAssistantAnswer();
  if (/\b(health safety|safety reminder|health reminder|is it safe|too hot for grandma|patient safety|care reminder|outbreak safety|heat safety)\b/.test(lower)) return healthSafetyAssistantAnswer();
  if (/\b(situation agent|manage this situation|handle this situation|what is the situation|situation plan|help me with this situation)\b/.test(lower)) return `${nextStepAssistantAnswer()} Nexus Situation Agent is using memory, situation detection, one-question intake, planning, safety, follow-up, role tone, and provider truthfulness.`;
  if (/\b(new mission brain|mission brain|nexus mission brain|activate mission brain|build mission brain|all 10 mission brain|all ten mission brain|goal brain|mission intelligence)\b/.test(lower)) return "Nexus Mission Brain is active. I will read the goal, use context and memory, check providers and maps, score the decision, create a mission plan, watch safety, adapt by role, and recommend the next best step.";
  if (/\b(trusted operating system|trusted os|people can rely on|actually rely on|can we trust|trust review|dependable platform|reliable operating system|production trust|trust score)\b/.test(lower)) return "Trusted Operating System review is active. Nexus checks reliable workflows, provider truth, safety, role permissions, memory, multilingual voice, map intelligence, auditability, failure recovery, and production hardening.";
  if (/\b(pre provider|pre-provider|before providers|until providers|providerless|no vendor|without vendors|without providers|provider readiness|provider hardening|real providers arrive|live providers arrive|what works without providers)\b/.test(lower)) return "Pre-provider hardening is active. Nexus can run guided learning, workforce, telehealth, trade, drone, map, voice, memory, confirmation, and audit workflows with platform records and local context. I will say what is live, what is local, and what needs credentials.";
  if (/\b(shipment|delivery|deliver|arrive|arrival|eta|track my sale|track my order|track my product|where is my crop|where is my shipment|route status)\b/.test(lower)) {
    if (canOpenSection("map")) goSection("map");
    return shipmentEtaAnswer();
  }
  if (/\b(appointment|schedule|calendar|visit|call with provider|doctor time|provider time|shift time|what time is my)\b/.test(lower)) {
    return appointmentAnswer();
  }
  if (/\b(what is next today|what do i have today|today's plan|daily plan|my day|what should i do today)\b/.test(lower)) {
    return `${localTimeAnswer()} ${appointmentAnswer()} ${shipmentEtaAnswer()} ${nextStepAssistantAnswer()}`;
  }
  if (/\b(what should i do next|what next|next best action|next best step|recommend next|guide my next step|what do you recommend)\b/.test(lower)) return nextStepAssistantAnswer();
  return "";
}

function speechSafetyRisk(command = "", source = "voice") {
  const heardText = String(command || "").replace(/\s+/g, " ").trim();
  const lower = normalizeToolText(heardText);
  const language = languageCode();
  const wordCount = lower ? lower.split(/\s+/).filter(Boolean).length : 0;
  const mixedLanguageTerms = /\b(english|french|francais|spanish|espanol|arabic|kiswahili|swahili|nigeria|drc|kenya|egypt)\b/.test(lower);
  const categories = [];
  const has = pattern => pattern.test(lower);
  if (has(/\b(doctor|nurse|clinic|hospital|injury|hurt|pain|bleeding|emergency|medicine|telehealth|provider|sick|care)\b/)) categories.push("health");
  if (has(/\b(sell|buy|buyer|seller|price|payment|wallet|order|crop|delivery|shipment|market|transaction)\b/)) categories.push("trade");
  if (has(/\b(job|work|apply|role|shift|interview|worker|employment|pay)\b/)) categories.push("workforce");
  if (has(/\b(route|track|location|where|map|facility|road|gps|delivery|shipment)\b/)) categories.push("map");
  if (has(/\b(drone|scan|footage|field|pest|irrigation|harvest|plant)\b/)) categories.push("drone");
  const sensitive = categories.length > 0;
  const fastLanguage = ["fr", "sw", "ar", "es"].includes(language);
  const longVoice = source === "voice" && wordCount >= 9;
  const unclear = source === "voice" && (wordCount <= 2 || /\b(thing|stuff|that|this|there|it)\b/.test(lower));
  const needsConfirmation = Boolean(source === "voice" && (sensitive || (fastLanguage && longVoice) || mixedLanguageTerms || unclear));
  const riskLevel = categories.includes("health") && /\b(emergency|bleeding|severe|danger|unconscious|breathing)\b/.test(lower)
    ? "high"
    : needsConfirmation
      ? "medium"
      : "low";
  const reason = needsConfirmation
    ? `Voice safety is active for ${categories.join(", ") || voiceLanguageName()} because spoken or translated commands can be misheard.`
    : `Voice safety is monitoring ${voiceLanguageName()} commands.`;
  const confirmationPrompt = needsConfirmation
    ? `I heard: ${heardText}. If that is right, say yes. If not, say stop or repeat it slowly.`
    : "";
  const safety = {
    language,
    languageName: voiceLanguageName(),
    locale: voiceLocale(),
    rate: speechRateForLanguage(language),
    pitch: speechPitchForLanguage(language),
    source,
    wordCount,
    categories,
    sensitive,
    needsConfirmation,
    riskLevel,
    reason,
    confirmationPrompt,
    heardText,
    suggestions: needsConfirmation
      ? ["say yes", "say stop", "repeat slowly", "change language"]
      : ["keep speaking naturally", "say slow down", "change language"]
  };
  localStorage.setItem("agrinexusSpeechSafety", JSON.stringify(safety));
  return safety;
}

function speechSafetyPrefix(command = "") {
  const safety = speechSafetyRisk(command, "voice");
  return safety.needsConfirmation ? `${safety.confirmationPrompt} ` : "";
}

function shouldConfirmSpeechSafety(command, source = "voice") {
  return speechSafetyRisk(command, source).needsConfirmation;
}

function multilingualSpeechSafetySummary() {
  const safety = JSON.parse(localStorage.getItem("agrinexusSpeechSafety") || "null") || speechSafetyRisk(agentPerformanceState.lastCommand || "", "voice");
  const mode = localStorage.getItem("agrinexusSlowSpeech") === "on" ? "slow speech is on" : "normal speech pacing";
  return `Multilingual speech safety is active in User, Admin, and Investor mode. Current language is ${safety.languageName}, locale ${safety.locale}, voice rate ${safety.rate}, and ${mode}. Nexus confirms risky health, trade, workforce, map, money, route, emergency, and drone commands before taking action.`;
}

function applySpeechSafetyToDecision(decision, command = "", source = "voice") {
  if (!decision) return null;
  const safety = speechSafetyRisk(command, source);
  const response = safety.needsConfirmation && decision.type !== "listen"
    ? `${decision.response} ${safety.confirmationPrompt}`
    : decision.response;
  return {
    ...decision,
    speechSafety: safety,
    response,
    reason: `${decision.reason} Speech safety: ${safety.reason}`,
    suggestions: Array.from(new Set([...(decision.suggestions || []), ...(safety.suggestions || [])])).slice(0, 7)
  };
}

function normalizeRuralSpeechAliases(command = "") {
  let text = normalizeToolText(command);
  const replacements = [
    [/\b(nexas|nexis|nextus|next\s+us|neck\s+sus|neck\s+is|nexus's|nexuses)\b/g, "nexus"],
    [/\b(agri\s*next|agree\s*nexus|angry\s*nexus)\b/g, "agrinexus"],
    [/\b(docta|dokita|doktor|likita|hakim|tabib)\b/g, "doctor"],
    [/\b(kliniki|clinic\s+near|hospitali|dispensary|health\s+post)\b/g, "clinic"],
    [/\b(dawa|oogun|magani|ogwu|medhanit|remedio|medicina)\b/g, "medicine"],
    [/\b(shamba|gona|oko|ugbo|ersha|fazenda|campo)\b/g, "farm"],
    [/\b(mazao|harvest|produce|cosecha|colheita)\b/g, "crop"],
    [/\b(soko|kasuwa|oja|ahia|gebeya|mercado|marche)\b/g, "market"],
    [/\b(kazi|aiki|ise|oru|sera|emploi|trabajo|trabalho)\b/g, "work"],
    [/\b(mnunuzi|comprador|acheteur)\b/g, "buyer"],
    [/\b(uza|vender|vendre)\b/g, "sell"],
    [/\b(nunua|comprar|acheter)\b/g, "buy"],
    [/\b(ramani|mapa|carte)\b/g, "map"],
    [/\b(njia|rota|ruta|itineraire)\b/g, "route"],
    [/\b(somo|curso|cours|aula|lesson\s+hard)\b/g, "course"],
    [/\b(mwalimu|teacher|teach\s+me)\b/g, "teach me"],
    [/\b(pikin|mtoto|child|kid)\b/g, "child"],
    [/\b(mama|mother|mom|mum)\b/g, "mother"]
  ];
  replacements.forEach(([pattern, value]) => {
    text = text.replace(pattern, value);
  });
  return text.replace(/\s+/g, " ").trim();
}

function ruralSpeechProfile(command = "") {
  const original = String(command || "").replace(/\s+/g, " ").trim();
  const lower = normalizeRuralSpeechAliases(original);
  const normalized = normalizeMultilingualBehaviorCommand(lower);
  const words = normalized.split(/\s+/).filter(Boolean);
  const has = patterns => patterns.some(pattern => pattern.test(normalized) || pattern.test(lower));
  const imperfectEnglish = has([
    /\b(i no|me no|we no|no sabi|no understand|no get|no fit|i dey|we dey|dey|wan|wanna|abeg|pikin|mama|wahala|small small|make you|how i go|where .* dey)\b/,
    /\b(i need|i want|need|want)\s+(doctor|job|work|medicine|market|buyer|sell|buy|learn|course|map)\b/,
    /\b(body pain|body dey pain|head pain|stomach pain|crop no good|farm no good|plant no good|road no good)\b/
  ]);
  const languageGroups = [
    /\b(ayuda|necesito|quiero|trabajo|salud|medicina|clinica|comprador|vender|comprar|ruta|mapa)\b/.test(lower),
    /\b(aide|besoin|travail|sante|medecin|clinique|acheteur|vendre|acheter|route|carte)\b/.test(lower),
    /\b(nahitaji|nataka|nisaidie|kazi|afya|daktari|kliniki|mnunuzi|uza|nunua|ramani|njia)\b/.test(lower),
    /\b(preciso|quero|ajuda|trabalho|saude|medico|clinica|comprador|vender|comprar|rota|mapa)\b/.test(lower),
    /\b(biko|abeg|wahala|sabi|dey|pikin|mama|likita|magani|kasuwa|gona|dokita|dawa|shamba|mazao|soko|kazi|ramani|njia)\b/.test(normalizeToolText(original)),
    /[\u0621-\u064a]/.test(original)
  ].filter(Boolean).length;
  const mixedLanguage = languageGroups >= 1 && /\b(nexus|help|doctor|job|work|crop|farm|sell|buyer|map|route|medicine|clinic|market)\b/.test(lower);
  const lowLiteracy = has([
    /\b(no read|cannot read|can't read|cant read|no understand|i no understand|too many words|speak simple|talk simple|slow|grandma|elder|old person)\b/,
    /\b(read for me|explain simple|say simple|small words|not school|no school)\b/
  ]);
  const urgent = has([
    /\b(cannot breathe|cant breathe|can't breathe|bleeding|unconscious|emergency|urgent|baby sick|pikin sick|child sick|very hot|high fever|danger)\b/
  ]);
  const scores = {
    health: [
      /\b(doctor|nurse|clinic|hospital|medicine|pharmacy|sick|pain|hurt|injury|bleeding|fever|body pain|pikin sick|child sick|mama sick|health|care|afya|daktari|clinica|medecin|medico)\b/,
      /\b(no doctor|no clinic|need medicine|medicine no dey|body dey pain|child sick|mother sick)\b/
    ].reduce((score, pattern) => score + (pattern.test(normalized) || pattern.test(lower) ? 1 : 0), 0),
    trade: [
      /\b(crop|farm|maize|cassava|rice|beans|yam|buyer|seller|sell|buy|market|price|harvest|plant|field|crop no good|farm no good|where market dey|mazao|shamba|comprador|acheteur)\b/,
      /\b(i wan sell|want sell|sell my|buy crop|buyer far|road not safe|market price|farm problem)\b/
    ].reduce((score, pattern) => score + (pattern.test(normalized) || pattern.test(lower) ? 1 : 0), 0),
    workforce: [
      /\b(job|work|work dey|find work|need work|need job|apply|employment|money|role|shift|interview|kazi|trabajo|travail|trabalho)\b/,
      /\b(i wan work|job for|work for|i no get work)\b/
    ].reduce((score, pattern) => score + (pattern.test(normalized) || pattern.test(lower) ? 1 : 0), 0),
    learning: [
      /\b(learn|course|lesson|school|training|certificate|teach|study|class|no understand lesson|read for me|explain simple|mafunzo|curso|cours)\b/,
      /\b(i wan learn|want learn|teach me|lesson hard)\b/
    ].reduce((score, pattern) => score + (pattern.test(normalized) || pattern.test(lower) ? 1 : 0), 0),
    map: [
      /\b(map|route|road|where|location|near|nearest|driver lost|lost driver|gps|track|shipment|delivery|where .* dey|ramani|ruta|route|rota)\b/,
      /\b(where road|road no good|where clinic|where market|where my product)\b/
    ].reduce((score, pattern) => score + (pattern.test(normalized) || pattern.test(lower) ? 1 : 0), 0)
  };
  const ranked = Object.entries(scores).sort((a, b) => b[1] - a[1]);
  const [intent, score] = ranked[0] || ["general", 0];
  const rewriteMap = {
    health: urgent ? "open telehealth emergency help" : "open telehealth and start intake",
    trade: "sell my crop",
    workforce: "show me jobs",
    learning: "start a course",
    map: "open map and check route risk"
  };
  const confidence = Math.min(0.94, Math.max(0.35, (score * 0.22) + (imperfectEnglish ? 0.16 : 0) + (mixedLanguage ? 0.1 : 0) + (lowLiteracy ? 0.08 : 0) + (words.length >= 4 ? 0.08 : 0)));
  const nextQuestions = {
    health: urgent ? "Where is the person, and are they safe right now?" : "Where are you, and do you need clinic, medicine, or phone/video help?",
    trade: "What crop is it, and are you trying to save it, sell it, or move it?",
    workforce: "What country do you want to work in, and what kind of work can you do?",
    learning: "What do you want to learn, and should I explain it slowly?",
    map: "Where are you starting from, and where do you need to go?",
    general: "Is this about health, crops, work, learning, or the map?"
  };
  return {
    original,
    normalized,
    intent: score ? intent : "general",
    confidence: Number(confidence.toFixed(2)),
    rewriteCommand: score ? rewriteMap[intent] : "",
    imperfectEnglish,
    mixedLanguage,
    lowLiteracy,
    urgent,
    nextQuestion: nextQuestions[score ? intent : "general"],
    style: lowLiteracy || imperfectEnglish || mixedLanguage ? "simple-human-one-question" : "standard"
  };
}

function ruralSpeechProfileSummary(command = "") {
  const profile = ruralSpeechProfile(command);
  return `Rural speech profile: ${profile.intent}, confidence ${Math.round(profile.confidence * 100)} percent, style ${profile.style}. Next question: ${profile.nextQuestion}`;
}

function ruralCommunicationBridge(command = "") {
  const heard = String(command || "").replace(/\s+/g, " ").trim();
  const normalized = normalizeRuralSpeechAliases(heard);
  const profile = ruralSpeechProfile(normalized || heard);
  const africaStyle = ruralAfricaConversationStyle(heard || normalized, profile);
  const kenyaStyle = ruralKenyaCommunicationStyle(heard || normalized);
  const tokens = normalized.split(/\s+/).filter(Boolean);
  const suspectedWakeMishear = /\b(texas|nexas|nexis|nextus|next\s+us|neck\s+sus|neck\s+is|agree\s+nexus|angry\s+nexus)\b/.test(normalizeToolText(heard));
  const shortButUseful = profile.intent !== "general" && tokens.length <= 5;
  const needsOneQuestion = profile.intent !== "general" && profile.confidence >= 0.46 && profile.confidence < 0.7;
  const intentLabels = {
    health: "health help",
    trade: "crop or market help",
    workforce: "work help",
    learning: "learning help",
    map: "map or route help",
    general: "general help"
  };
  return {
    heard,
    normalized,
    profile,
    suspectedWakeMishear,
    shortButUseful,
    needsOneQuestion,
    africaStyle,
    kenyaStyle,
    intentLabel: intentLabels[profile.intent] || intentLabels.general,
    response: africaStyle.active
      ? ruralAfricaPlainResponse(profile)
      : kenyaStyle.active
      ? ruralKenyaPlainResponse(profile, intentLabels)
      : profile.intent === "general"
      ? "I may have heard that wrong. Say it again slowly, or say health, crops, work, learning, map, or medicine."
      : `I think you mean ${intentLabels[profile.intent]}. ${profile.nextQuestion}`
  };
}

function ruralAfricaConversationStyle(command = "", profile = ruralSpeechProfile(command)) {
  const lower = normalizeToolText(command);
  const fragments = lower.split(/\s+/).filter(Boolean);
  const incompleteSentence = fragments.length <= 7
    || /\b(no|need|want|help|sick|pain|hot|bleed|medicine|doctor|clinic|crop|bad|rain|job|work|learn|map|lost)\b/.test(lower)
    || !/[.?!]$/.test(String(command || "").trim());
  const active = profile.lowLiteracy
    || profile.imperfectEnglish
    || profile.mixedLanguage
    || incompleteSentence && /\b(africa|rural|village|farm|farmer|grandma|elder|mother|mama|child|baby|doctor|clinic|medicine|pharmacy|crop|market|buyer|job|course|map|road|route|nigeria|ghana|kenya|tanzania|rwanda|uganda|ethiopia|egypt|drc|congo|senegal|mali|zambia|south africa|hausa|yoruba|igbo|swahili|kiswahili|amharic|oromo|lingala|french|arabic|portuguese)\b/.test(lower);
  return {
    active,
    style: active ? "pan-african-rural-plain-language" : "standard",
    promise: "Understand incomplete rural speech across Africa: short fragments, mixed language, one question at a time, no shame, no diagnosis.",
    medicalRules: [
      "Do not diagnose.",
      "Check danger signs first.",
      "Ask where the person is.",
      "Route urgent symptoms to emergency or nearest human care.",
      "Prepare clinic, mobile clinic, pharmacy, or provider handoff."
    ],
    examples: [
      "Baby hot... no doctor.",
      "Medicine finished... village far.",
      "Crop bad... rain no come.",
      "Job please... no certificate.",
      "Map clinic... near me."
    ]
  };
}

function ruralAfricaPlainResponse(profile = {}) {
  const openers = {
    health: profile.urgent
      ? "I hear health danger. Is the person breathing, awake, and safe right now? Where are they?"
      : "I hear health help. Where are you, and do you need clinic, medicine, or phone help?",
    trade: "I hear farm or market help. What crop is it, and where is the farm?",
    workforce: "I hear work help. What country are you in, and what work can you do?",
    learning: "I hear learning help. What do you want to learn first?",
    map: "I hear map help. Where are you starting, and where do you need to go?",
    general: "I may have heard only part of that. Say one word: health, crop, work, learning, map, or medicine."
  };
  return openers[profile.intent] || openers.general;
}

function ruralKenyaCommunicationStyle(command = "") {
  const lower = normalizeToolText(command);
  const active = /\b(kenya|kenyan|kiswahili|swahili|shamba|mazao|soko|dawa|kliniki|daktari|mama|nyanya|bibi|mtoto|tafadhali|pole|habari|niko|nataka|nahitaji|nisaidie|msaada|bei|mahindi|ngombe|maziwa|matatu|m-pesa|mpesa)\b/.test(lower)
    || /\b(rural farmer|village farmer|grandma|elder|plain village|speak simple|talk simple|farmer language)\b/.test(lower);
  return {
    active,
    style: active ? "rural-kenya-plain-kiswahili" : "standard",
    promise: "Respectful plain language for rural Kenya: short sentences, one question at a time, light Kiswahili words with clear meaning, no fake accent.",
    principles: [
      "Respect the person first.",
      "Use short sentences.",
      "Ask one question at a time.",
      "Use familiar Kiswahili words only when useful.",
      "Explain the meaning clearly.",
      "Do not fake tribal dialects or caricature rural speech."
    ],
    phrases: [
      "Pole. Nimekusikia. Sorry, I hear you.",
      "Twende hatua moja. Let us go one step.",
      "Unahitaji nini kwanza? What do you need first?",
      "Ni shamba, afya, kazi, masomo, au ramani? Is it farm, health, work, learning, or map?",
      "Nitasema kwa maneno rahisi. I will use simple words."
    ]
  };
}

function ruralKenyaPlainResponse(profile = {}, intentLabels = {}) {
  const openers = {
    health: "Pole. Afya kwanza. Health first. Where are you, and do you need clinic, medicine, or phone help?",
    trade: "Sawa. Tuanze na shamba. Let us start with the farm. What crop is it, and do you want to sell it, move it, or check a problem?",
    workforce: "Sawa. Let us look for work. What country do you want to work in, and what work can you do?",
    learning: "Sawa. We will learn slowly. What lesson do you want, and should I read it aloud?",
    map: "Sawa. Open the route. Where are you starting from, and where do you need to go?",
    general: "Pole. Nimekusikia. Say it again slowly, or say shamba, afya, kazi, masomo, ramani, or dawa."
  };
  if (profile.intent && openers[profile.intent]) return openers[profile.intent];
  return `Twende hatua moja. I think you mean ${intentLabels[profile.intent] || "help"}. ${profile.nextQuestion || "What do you need first?"}`;
}

function normalizeImperfectSpeech(command = "") {
  const original = String(command || "").replace(/\s+/g, " ").trim();
  const lower = normalizeMultilingualBehaviorCommand(normalizeRuralSpeechAliases(original));
  const replacements = [
    [/\bagri\s*trade\b/g, "agritrade"],
    [/\bagri\s*nexus\b/g, "agrinexus"],
    [/\btele\s*health\b/g, "telehealth"],
    [/\bdoctor help\b/g, "open telehealth and start intake"],
    [/\bhealth help\b/g, "open telehealth and start intake"],
    [/\bjob please\b/g, "show me jobs"],
    [/\bwork please\b/g, "show me jobs"],
    [/\bsell crop\b/g, "sell my crop"],
    [/\bbuy crop\b/g, "buy a crop"],
    [/\bwhere product\b/g, "track my product route"],
    [/\bwhere my product\b/g, "track my product route"],
    [/\btrack sale\b/g, "track my sale route"],
    [/\bmap route\b/g, "open map and check route risk"],
    [/\bdrone farm\b/g, "run drone scan on my farm"],
    [/\bteach me\b/g, "start a course"],
    [/\bi want learn\b/g, "start a course"],
    [/\bi need job\b/g, "show me jobs"],
    [/\bi need doctor\b/g, "open telehealth and start intake"],
    [/\bcrop bad\b/g, "my crop looks bad what should I do"],
    [/\bplant sick\b/g, "my plant looks sick what should I do"],
    [/\bmaize bad\b/g, "my maize crop looks bad what should I do"],
    [/\bcassava bad\b/g, "my cassava crop looks bad what should I do"],
    [/\bchild sick\b/g, "my child is sick what should I do"],
    [/\bbaby sick\b/g, "my baby is sick what should I do"],
    [/\bneed medicine\b/g, "I need medicine and pharmacy help"],
    [/\bmedicine no dey\b/g, "I need medicine and pharmacy help"],
    [/\bbody pain\b/g, "I am sick and need health help"],
    [/\bbody dey pain\b/g, "I am sick and need health help"],
    [/\bpikin sick\b/g, "my child is sick what should I do"],
    [/\bmama sick\b/g, "my mother is sick what should I do"],
    [/\bmedicine help\b/g, "I need medicine and pharmacy help"],
    [/\bclinic near\b/g, "find a clinic near me"],
    [/\bwhere clinic\b/g, "find a clinic near me"],
    [/\bwhere clinic dey\b/g, "find a clinic near me"],
    [/\bjob kenya\b/g, "help me find work in Kenya"],
    [/\bjob south africa\b/g, "help me find work in South Africa"],
    [/\bwork dey\b/g, "show me jobs"],
    [/\bi wan work\b/g, "show me jobs"],
    [/\bi wan learn\b/g, "start a course"],
    [/\bi wan sell\b/g, "sell my crop"],
    [/\bi wan buy\b/g, "buy a crop"],
    [/\bno understand\b/g, "I do not understand please explain simply"],
    [/\bi no understand\b/g, "I do not understand please explain simply"],
    [/\bno sabi\b/g, "I do not understand please explain simply"],
    [/\bi no sabi\b/g, "I do not understand please explain simply"],
    [/\bno fit read\b/g, "please read this slowly and explain simply"],
    [/\bspeak simple\b/g, "please explain simply"],
    [/\bhelp farm\b/g, "help me with my farm problem"],
    [/\bcrop no good\b/g, "my crop looks bad what should I do"],
    [/\bfarm no good\b/g, "my farm has a problem what should I do"],
    [/\bwhere market dey\b/g, "show me the market and buyer route"],
    [/\bmarket how much\b/g, "what is the market price"]
  ];
  let rewritten = lower;
  replacements.forEach(([pattern, value]) => {
    rewritten = rewritten.replace(pattern, value);
  });
  const profile = ruralSpeechProfile(rewritten);
  const hasAction = /\b(open|start|show|apply|sell|buy|contact|call|message|run|create|track|find|explain|change|switch|translate|confirm|cancel|stop)\b/.test(rewritten);
  if (profile.rewriteCommand && profile.confidence >= 0.58 && !hasAction) rewritten = profile.rewriteCommand;
  return rewritten.replace(/\s+/g, " ").trim() || original;
}

function behaviorTextVariants(command = "") {
  const raw = String(command || "").replace(/\s+/g, " ").trim();
  const latin = raw.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const compact = latin.replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();
  return { raw, latin, compact };
}

function normalizeMultilingualBehaviorCommand(command = "") {
  const { raw, compact } = behaviorTextVariants(command);
  if (!raw) return raw;
  const patterns = [
    {
      command: "change language to english",
      match: [
        /\b(cambia|cambiar|cambie|pon|poner|usa|usar|habla|hablar|responde|responder).*\b(ingles|english)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(ingles|english)\b/,
        /\b(change|switch|set|use|speak|respond).*\b(english|ingles|anglais|kiingereza)\b/,
        /\b(change|switch|set|use|speak|respond).*\b(nigeria|nigerian)\b/
      ]
    },
    {
      command: "change language to spanish",
      match: [
        /\b(cambia|cambiar|cambie|pon|poner|usa|usar|habla|hablar|responde|responder).*\b(espanol|spanish)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(espanhol|spanish|espanol)\b/,
        /\b(change|switch|set|use|speak|respond).*\b(spanish|espanol|kihispania)\b/
      ]
    },
    {
      command: "change language to portuguese",
      match: [
        /\b(change|switch|set|use|speak|respond|cambiar|hablar).*\b(portuguese|portugues|portuguesa|brazil|brasil|brasileiro)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(portugues|portuguese|brasil|brazil|brasileiro)\b/
      ]
    },
    {
      command: "change language to french",
      match: [
        /\b(change|switch|set|use|speak|respond|cambiar|hablar).*\b(french|francais|frances|kifaransa|drc|congo)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(frances|french|francais)\b/,
        /\b(change|switch|set|use|speak|respond).*\b(french|francais|frances)\b/
      ]
    },
    {
      command: "change language to kiswahili",
      match: [
        /\b(change|switch|set|use|speak|respond|cambiar|hablar).*\b(kiswahili|swahili|suajili|kenya|kenyan)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(swahili|kiswahili|quenia|kenya)\b/,
        /\b(badilisha|tumia|ongea|zungumza|jibu).*\b(kiswahili|swahili)\b/
      ]
    },
    {
      command: "change language to arabic",
      match: [
        /\b(change|switch|set|use|speak|respond|cambiar|hablar).*\b(arabic|arabe|kiarabu|egypt|egyptian)\b/,
        /\b(mudar|mude|trocar|troque|usar|use|falar|fale|responder|responda).*\b(arabe|arabic|egito|egypt)\b/,
        /(?:\u063a\u064a\u0631|\u0628\u062f\u0644|\u062a\u0643\u0644\u0645|\u0627\u0633\u062a\u062e\u062f\u0645).*(?:\u0639\u0631\u0628\u064a|\u0627\u0644\u0639\u0631\u0628\u064a\u0629|\u0645\u0635\u0631)/
      ]
    },
    {
      command: "open telehealth and start intake",
      match: [
        /\b(abre|abrir|necesito|quiero|ayuda).*\b(salud|doctor|medico|clinica|telemedicina|enfermera|dolor|enfermo)\b/,
        /\b(abrir|abre|preciso|quero|ajuda|me ajuda).*\b(saude|medico|doutor|clinica|telemedicina|enfermeira|dor|doente|remedio)\b/,
        /\b(ouvre|ouvrir|besoin|aide).*\b(sante|medecin|docteur|clinique|telemedecine|hopital|douleur|malade)\b/,
        /\b(fungua|hitaji|nahitaji|nisaidie).*\b(afya|daktari|kliniki|hospitali|mgonjwa|maumivu)\b/,
        /(?:\u0635\u062d\u0629|\u0637\u0628\u064a\u0628|\u0639\u064a\u0627\u062f\u0629|\u0645\u0631\u064a\u0636|\u0623\u0644\u0645|\u0645\u0633\u062a\u0634\u0641\u0649)/
      ]
    },
    {
      command: "show me jobs",
      match: [
        /\b(abre|buscar|busca|quiero|necesito|aplicar|solicitar).*\b(trabajo|empleo|puesto|rol)\b/,
        /\b(abrir|abre|buscar|procura|procurar|quero|preciso|candidatar|aplicar).*\b(trabalho|emprego|vaga|cargo|servico)\b/,
        /\b(ouvre|chercher|cherche|besoin|postuler).*\b(travail|emploi|poste|role)\b/,
        /\b(fungua|tafuta|nahitaji|omba).*\b(kazi|ajira)\b/,
        /(?:\u0639\u0645\u0644|\u0648\u0638\u064a\u0641\u0629|\u062a\u0642\u062f\u0645)/
      ]
    },
    {
      command: "start a course",
      match: [
        /\b(abre|abrir|empezar|iniciar|quiero|necesito).*\b(aprendizaje|curso|leccion|clase|capacitacion|certificado)\b/,
        /\b(abrir|abre|comecar|iniciar|quero|preciso).*\b(aprendizado|curso|aula|licao|treinamento|certificado)\b/,
        /\b(ouvre|commencer|demarrer|besoin).*\b(apprentissage|cours|lecon|formation|certificat)\b/,
        /\b(fungua|anza|nahitaji|nataka).*\b(mafunzo|kozi|somo|cheti)\b/,
        /(?:\u062a\u0639\u0644\u0645|\u062f\u0631\u0633|\u062f\u0648\u0631\u0629|\u0634\u0647\u0627\u062f\u0629)/
      ]
    },
    {
      command: "sell my crop",
      match: [
        /\b(vender|vendo|vende|quiero vender|comprador|mercado).*\b(cosecha|cultivo|maiz|arroz|yuca|producto)\b/,
        /\b(vender|vendo|comprador|mercado|negociar).*\b(colheita|plantacao|milho|arroz|mandioca|produto|safra)\b/,
        /\b(vendre|acheteur|marche|marchand).*\b(recolte|culture|mais|riz|manioc|produit)\b/,
        /\b(uza|kuuza|mnunuzi|soko).*\b(mazao|mahindi|mchele|muhogo|bidhaa)\b/,
        /(?:\u0628\u064a\u0639|\u0645\u062d\u0635\u0648\u0644|\u0645\u0634\u062a\u0631\u064a|\u0633\u0648\u0642)/
      ]
    },
    {
      command: "buy a crop",
      match: [
        /\b(comprar|quiero comprar|busco).*\b(cosecha|cultivo|maiz|arroz|yuca|producto)\b/,
        /\b(comprar|quero comprar|procuro|buscar).*\b(colheita|plantacao|milho|arroz|mandioca|produto|safra)\b/,
        /\b(acheter|je veux acheter|cherche).*\b(recolte|culture|mais|riz|manioc|produit)\b/,
        /\b(nunua|kununua|natafuta).*\b(mazao|mahindi|mchele|muhogo|bidhaa)\b/,
        /(?:\u0627\u0634\u062a\u0631\u064a|\u0634\u0631\u0627\u0621|\u0645\u062d\u0635\u0648\u0644)/
      ]
    },
    {
      command: "open map and check route risk",
      match: [
        /\b(abre|abrir|mostrar|rastrea|seguir|ubicar).*\b(mapa|ruta|envio|entrega|ubicacion|camino)\b/,
        /\b(abrir|abre|mostrar|rastrear|seguir|localizar).*\b(mapa|rota|envio|entrega|localizacao|caminho)\b/,
        /\b(ouvre|ouvrir|montre|suivre|localiser).*\b(carte|itineraire|livraison|position|route)\b/,
        /\b(fungua|onyesha|fuatilia|tafuta).*\b(ramani|njia|usafirishaji|mahali)\b/,
        /(?:\u062e\u0631\u064a\u0637\u0629|\u0645\u0633\u0627\u0631|\u0645\u0648\u0642\u0639|\u062a\u0648\u0635\u064a\u0644)/
      ]
    },
    {
      command: "run drone scan on my farm",
      match: [
        /\b(drone|dron|escanea|revisar).*\b(finca|campo|granja|cultivo)\b/,
        /\b(drone|escanear|verificar|analisar).*\b(fazenda|campo|plantacao|roca|lavoura)\b/,
        /\b(drone|scanner|analyser).*\b(champ|ferme|culture)\b/,
        /\b(drone|kagua|chunguza).*\b(shamba|mazao)\b/,
        /(?:\u0637\u0627\u0626\u0631\u0629 \u0628\u062f\u0648\u0646 \u0637\u064a\u0627\u0631|\u062f\u0631\u0648\u0646|\u0645\u0632\u0631\u0639\u0629|\u062d\u0642\u0644)/
      ]
    }
  ];
  const hit = patterns.find(item => item.match.some(pattern => pattern.test(compact) || pattern.test(raw)));
  return hit ? hit.command : compact || raw;
}

function adaptiveCommandUnderstanding(command = "") {
  const original = String(command || "").replace(/\s+/g, " ").trim();
  const learnedRule = findNexusAdaptiveRule(original);
  if (learnedRule) {
    const context = nexusContextMemoryModel(original, "adaptive");
    return {
      original,
      normalized: learnedRule.target,
      rewrittenCommand: learnedRule.target,
      intent: "adaptive",
      confidence: Number(Math.max(0.86, learnedRule.confidence || 0.86).toFixed(2)),
      needsHumanCheck: false,
      context,
      ruralProfile: ruralSpeechProfile(learnedRule.target),
      nextQuestion: nexusNextBestQuestion("adaptive", original, context),
      learnedRule
    };
  }
  const ruralProfile = ruralSpeechProfile(original);
  const normalized = normalizeImperfectSpeech(original);
  const lower = normalizeToolText(normalized);
  const words = lower.split(/\s+/).filter(Boolean);
  const families = [
    { intent: "health", command: "open telehealth and start intake", terms: ["doctor", "nurse", "clinic", "hospital", "pain", "hurt", "injury", "sick", "medicine", "health", "care", "provider", "telehealth", "medico", "salud", "sante", "hopital", "afya", "saude", "doutor", "clinica", "dor", "doente", "remedio"] },
    { intent: "workforce", command: "show me jobs", terms: ["job", "work", "role", "apply", "worker", "shift", "interview", "employment", "skills", "trabajo", "emploi", "kazi", "trabalho", "emprego", "vaga", "cargo", "servico"] },
    { intent: "trade", command: "sell my crop", terms: ["crop", "buyer", "seller", "sell", "buy", "market", "price", "payment", "wallet", "order", "farm", "harvest", "maize", "rice", "cassava", "producto", "vendre", "acheter", "soko", "mazao", "colheita", "plantacao", "milho", "mandioca", "comprador", "mercado", "safra"] },
    { intent: "map", command: "open map and check route risk", terms: ["map", "route", "road", "location", "track", "where", "facility", "delivery", "shipment", "gps", "ruta", "carte", "ramani", "njia", "mapa", "rota", "localizacao", "entrega", "envio", "caminho"] },
    { intent: "learning", command: "start a course", terms: ["learn", "course", "lesson", "training", "certificate", "student", "quiz", "school", "study", "aprender", "cours", "kujifunza", "somo", "curso", "aula", "licao", "treinamento", "certificado", "aluno"] },
    { intent: "drone", command: "run drone scan on my farm", terms: ["drone", "scan", "footage", "field", "pest", "irrigation", "aerial", "farm video", "fazenda", "roca", "lavoura", "plantacao"] }
  ];
  const scored = families.map(family => {
    const hits = family.terms.filter(term => lower.includes(term)).length;
    return { ...family, hits, score: hits / Math.max(2, Math.min(8, words.length)) };
  }).sort((a, b) => b.score - a.score);
  const best = scored[0];
  const hasAction = /\b(open|start|show|apply|sell|buy|contact|call|message|run|create|track|find|explain|change|switch|translate|confirm|cancel|stop)\b/.test(lower);
  const rewrittenCommand = best?.hits && !hasAction
    ? best.command
    : normalized;
  const confidence = Math.min(.96, Math.max(.45, (best?.score || 0) + (hasAction ? .42 : .28) + (words.length >= 4 ? .12 : 0) + (ruralProfile.intent !== "general" ? .08 : 0) + (ruralProfile.lowLiteracy ? .04 : 0)));
  const context = nexusContextMemoryModel(original, best?.hits ? best.intent : "general");
  const needsHumanCheck = confidence < .72 || (best?.hits > 0 && !hasAction && ruralProfile.confidence < .72);
  const understanding = {
    original,
    normalized,
    rewrittenCommand,
    intent: best?.hits ? best.intent : "general",
    confidence: Number(confidence.toFixed(2)),
    needsHumanCheck,
    context,
    ruralProfile,
    nextQuestion: ruralProfile.intent !== "general"
      ? ruralProfile.nextQuestion
      : nexusNextBestQuestion(best?.hits ? best.intent : "general", original, context),
    reason: ruralProfile.intent !== "general"
      ? `Rural speech profile matched ${ruralProfile.intent} at ${Math.round(ruralProfile.confidence * 100)} percent.`
      : best?.hits
        ? `Matched ${best.intent} from ${best.hits} speech clue(s).`
        : "No strong workflow clue found yet.",
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusAdaptiveUnderstanding", JSON.stringify(understanding));
  return understanding;
}

function nexusContextMemoryModel(command = "", intent = "general") {
  const mode = conversationPlatformMode();
  const modeMemory = conversationMemoryForMode(mode);
  const profile = data?.profile || {};
  const activeOrder = (profile.orders || [])[0] || (profile.tradeOrders || [])[0] || null;
  const activeIntake = (profile.healthIntakes || [])[0] || null;
  const activeApplication = (profile.applications || [])[0] || null;
  const activeCourse = (profile.enrollments || [])[0] || null;
  const activeScan = (profile.droneScans || [])[0] || null;
  const section = currentSectionId();
  const memory = {
    mode,
    modeLabel: conversationPlatformLabel(mode),
    userName: userFirstName(),
    language: voiceLanguageName(),
    section,
    intent,
    command,
    lastTopic: modeMemory.lastTopic || "",
    lastQuestion: modeMemory.lastQuestion || "",
    lastAnswer: modeMemory.lastAnswer || "",
    activeOrder: activeOrder ? `${activeOrder.orderNumber || activeOrder.id || "order"} ${activeOrder.stage || ""}`.trim() : "",
    activeIntake: activeIntake ? `${activeIntake.patientRef || "intake"} ${activeIntake.riskLevel || ""}`.trim() : "",
    activeApplication: activeApplication ? `${activeApplication.roleTitle || activeApplication.roleId || "application"} ${activeApplication.status || ""}`.trim() : "",
    activeCourse: activeCourse ? `${activeCourse.courseTitle || activeCourse.courseId || "course"} ${activeCourse.progress || 0}%` : "",
    activeScan: activeScan ? `${activeScan.scanRef || "drone scan"} ${activeScan.cropHealthScore || ""}`.trim() : "",
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusContextMemory", JSON.stringify(memory));
  return memory;
}

function nexusNextBestQuestion(intent = "general", command = "", context = nexusContextMemoryModel(command, intent)) {
  const lower = normalizeToolText(command);
  const questions = {
    health: context.activeIntake
      ? `Do you want me to continue the current health intake ${context.activeIntake}, contact the provider, or explain the next care step?`
      : "Is this urgent, or should I start a normal telehealth intake first?",
    trade: context.activeOrder
      ? `Do you want me to track ${context.activeOrder}, contact the buyer, or update the delivery route?`
      : "Are you trying to sell crops, buy crops, contact a buyer, or track a delivery?",
    workforce: context.activeApplication
      ? `Do you want me to continue ${context.activeApplication}, find another job, or prepare for interview?`
      : "Do you want to find jobs, apply for a role, or check what skills you still need?",
    learning: context.activeCourse
      ? `Do you want to continue ${context.activeCourse}, build captions, or complete the lesson?`
      : "Do you want to start a course, hear the lesson, get captions, or work toward a certificate?",
    map: context.activeOrder
      ? `Should I show the route for ${context.activeOrder}, check risk, or find the nearest facility?`
      : "Do you want the route, the nearest facility, the risk layer, or live tracking?",
    drone: context.activeScan
      ? `Should I explain ${context.activeScan} in simple terms or create the next field task?`
      : "Do you want a drone scan, a simple crop health explanation, or a field task recommendation?",
    general: "Do you want health, work, learning, trade, map, or help deciding?"
  };
  if (/\b(urgent|emergency|bleeding|danger|severe)\b/.test(lower)) return "Is anyone in immediate danger right now?";
  return questions[intent] || questions.general;
}

function nexusContextMemorySummary() {
  const memory = JSON.parse(localStorage.getItem("agrinexusContextMemory") || "null") || nexusContextMemoryModel(agentPerformanceState.lastCommand || "", "general");
  const active = [
    memory.activeOrder ? `order ${memory.activeOrder}` : "",
    memory.activeIntake ? `health intake ${memory.activeIntake}` : "",
    memory.activeApplication ? `application ${memory.activeApplication}` : "",
    memory.activeCourse ? `course ${memory.activeCourse}` : "",
    memory.activeScan ? `drone scan ${memory.activeScan}` : ""
  ].filter(Boolean).join("; ") || "no active workflow record yet";
  return `Context memory is active for ${memory.modeLabel}. I know the user is in ${memory.section}, speaking ${memory.language}, with intent ${memory.intent}. Active context: ${active}. My next best question is: ${nexusNextBestQuestion(memory.intent, memory.command || "", memory)}`;
}

function nexusAdvisorProfile(intent = "general") {
  const mode = conversationPlatformMode();
  const section = currentSectionId();
  const role = mode === "admin" ? "operator"
    : mode === "investor" ? "investor reviewer"
      : intent === "health" ? "patient or caregiver"
        : intent === "trade" || intent === "drone" ? "farmer or market user"
          : intent === "workforce" ? "worker"
            : intent === "learning" ? "learner"
              : "everyday user";
  const style = mode === "user"
    ? "plain language, one question at a time, large-action guidance"
    : mode === "admin"
      ? "risk-first, evidence-first, operational"
      : "impact-first, proof-first, non-technical";
  const goals = {
    health: "get the user to safe telehealth support without giving medical diagnosis",
    trade: "help move crops from seller to buyer with route, payment, and communication evidence",
    drone: "turn field evidence into simple crop guidance and the next safe field task",
    workforce: "help the user find work, apply, and understand the next readiness gap",
    learning: "help the learner choose, complete, understand, and prove training progress",
    map: "explain route, facility, risk, and location context clearly",
    general: "understand the need and route to the safest useful workflow"
  };
  return {
    mode,
    section,
    role,
    style,
    goal: goals[intent] || goals.general,
    guardrail: intent === "health"
      ? "resource guidance only; urgent danger should use local emergency services"
      : intent === "trade"
        ? "confirm before money, buyer, seller, or route actions"
        : "confirm before important workflow changes",
    updatedAt: new Date().toISOString()
  };
}

function nexusDecisionScoringModel(command = agentPerformanceState.lastCommand || "") {
  const understanding = adaptiveCommandUnderstanding(command);
  const context = nexusContextMemoryModel(command, understanding.intent);
  const advisor = nexusAdvisorProfile(understanding.intent);
  const providerDepth = providerActionDepthStatus();
  const providerGroup = understanding.intent === "health" ? providerDepth.telehealth
    : understanding.intent === "trade" || understanding.intent === "drone" || understanding.intent === "map" ? providerDepth.trade
      : understanding.intent === "workforce" ? providerDepth.workforce
        : understanding.intent === "learning" ? providerDepth.learning
          : providerDepth.voice;
  const liveReadiness = providerGroup?.total ? Math.round((providerGroup.ready / providerGroup.total) * 100) : 50;
  const safety = understanding.intent === "health" ? 92
    : understanding.intent === "trade" ? 84
      : understanding.intent === "map" ? 82
        : 88;
  const usefulness = Math.min(98, Math.round((understanding.confidence * 55) + (context.lastTopic ? 10 : 0) + (liveReadiness * .25) + 18));
  const confidence = Math.min(99, Math.round((understanding.confidence * 70) + (liveReadiness * .18) + (safety * .12)));
  const score = Math.round((confidence * .36) + (usefulness * .34) + (safety * .2) + (liveReadiness * .1));
  const recommendation = understanding.rewrittenCommand || nexusNextBestQuestion(understanding.intent, command, context);
  const model = {
    command,
    intent: understanding.intent,
    advisor,
    context,
    confidence,
    usefulness,
    safety,
    liveReadiness,
    score,
    recommendation,
    why: `I matched ${understanding.intent}, used ${advisor.role} behavior, checked live readiness ${liveReadiness}%, and weighted safety ${safety}%.`,
    nextQuestion: understanding.nextQuestion || nexusNextBestQuestion(understanding.intent, command, context),
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusDecisionScoring", JSON.stringify(model));
  return model;
}

function nexusLiveKnowledgeFeedReadiness() {
  const providers = data?.providers || [];
  const providerReady = id => ["connected", "ready"].includes(providers.find(provider => provider.id === id)?.status);
  const feeds = [
    { id: "weather", title: "Weather and heat", ready: providerReady("weather") || providerReady("map-tiles"), value: "walking, planting, harvest, and field-risk guidance" },
    { id: "health", title: "Health/outbreak alerts", ready: providerReady("health-telehealth") || providerReady("health-ehr"), value: "regional telehealth safety and referral context" },
    { id: "market", title: "Crop prices and buyers", ready: providerReady("trade-market"), value: "buyer matching, price comparison, and sale timing" },
    { id: "jobs", title: "Job listings", ready: providerReady("workforce-jobs"), value: "live role search and application support" },
    { id: "courses", title: "Course catalog", ready: providerReady("learning-courses"), value: "real course selection and completion paths" },
    { id: "drone", title: "Drone/satellite evidence", ready: providerReady("field-drones"), value: "field condition interpretation and intervention planning" },
    { id: "logistics", title: "Logistics and routing", ready: providerReady("trade-logistics") || providerReady("map-tiles"), value: "delivery tracking, route risk, and facility routing" },
    { id: "communications", title: "SMS/WhatsApp/phone", ready: providerReady("sms-delivery") || providerReady("whatsapp-delivery") || providerReady("phone-voice"), value: "two-way buyer, provider, and learner communication" }
  ];
  const ready = feeds.filter(feed => feed.ready).length;
  const model = { ready, total: feeds.length, feeds, updatedAt: new Date().toISOString() };
  localStorage.setItem("agrinexusLiveKnowledgeFeeds", JSON.stringify(model));
  return model;
}

function nexusPredictiveAdvisorModel(command = agentPerformanceState.lastCommand || "") {
  const scoring = nexusDecisionScoringModel(command);
  const feeds = nexusLiveKnowledgeFeedReadiness();
  const profile = data?.profile || {};
  const predictions = [];
  const add = (module, priority, message, commandText) => predictions.push({ module, priority, message, command: commandText });
  if ((profile.healthIntakes || []).length && !(profile.telehealthFollowUps || []).length) add("Health", "high", "Health intake exists but follow-up is not scheduled.", "schedule telehealth follow up");
  if ((profile.orders || profile.tradeOrders || []).length && !(profile.tradeMessageThreads || []).length) add("Trade", "high", "A trade order needs buyer-seller communication evidence.", "contact buyer");
  if ((profile.orders || profile.tradeOrders || []).length && !(profile.mapInsights || []).length) add("Map", "medium", "A sale route exists without route-risk intelligence.", "track my sale route");
  if ((profile.enrollments || []).length && !(profile.certificates || []).length) add("Learning", "medium", "A learner has course progress but no certificate evidence yet.", "issue my certificate");
  if ((profile.applications || []).length && !(profile.interviews || 0)) add("Workforce", "medium", "A job application exists but interview support is not scheduled.", "prepare interview");
  if ((profile.droneScans || []).length && !(profile.fieldInterventions || []).length) add("Drone", "medium", "Drone evidence exists but no field task has been created.", "create field task");
  if (feeds.ready < feeds.total) add("Live feeds", "setup", `${feeds.ready}/${feeds.total} live knowledge feeds are ready.`, "explain live intelligence feeds");
  if (!predictions.length) add("Nexus", "ready", "No immediate gap detected. The smartest next move is to keep guiding the active request.", scoring.recommendation);
  const model = {
    score: scoring.score,
    intent: scoring.intent,
    nextBestAction: predictions[0].command,
    nextBestQuestion: scoring.nextQuestion,
    predictions: predictions.slice(0, 6),
    feeds,
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusPredictiveAdvisor", JSON.stringify(model));
  return model;
}

function nexusPredictiveAdvisorSummary(command = agentPerformanceState.lastCommand || "") {
  const model = nexusPredictiveAdvisorModel(command);
  const top = model.predictions[0];
  return `Predictive advisor is active. Intelligence score ${model.score}/100. Top prediction: ${top.module} ${top.priority}: ${top.message} Next best action: ${top.command}. Live feeds ready: ${model.feeds.ready}/${model.feeds.total}. Next question: ${model.nextBestQuestion}`;
}

function nexusLiveKnowledgeFeedSummary() {
  const model = nexusLiveKnowledgeFeedReadiness();
  const feedText = model.feeds.map(feed => `${feed.title}: ${feed.ready ? "ready" : "needs provider"} for ${feed.value}`).join(". ");
  return `Live intelligence feed readiness is ${model.ready}/${model.total}. ${feedText}.`;
}

function nexusAdaptiveUnderstandingSummary() {
  const stored = JSON.parse(localStorage.getItem("agrinexusAdaptiveUnderstanding") || "null") || adaptiveCommandUnderstanding(agentPerformanceState.lastCommand || "");
  return `Adaptive understanding is active. Nexus heard: ${stored.original || "nothing yet"}. It normalized that to: ${stored.rewrittenCommand || stored.normalized || "no command yet"}. Intent: ${stored.intent}. Confidence: ${Math.round((stored.confidence || 0) * 100)} percent. Next best question: ${stored.nextQuestion || "What do you need next?"} ${stored.needsHumanCheck ? "For unclear or risky speech, Nexus will confirm before acting." : "Nexus can route this without extra friction."}`;
}

function languageFromVoiceCommand(command) {
  const lower = String(command || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  if (/[\u0627-\u064a]/.test(command)) {
    if (/\u0627\u0646\u062c\u0644\u064a\u0632\u064a|\u0627\u0646\u0643\u0644\u064a\u0632\u064a|\u0627\u0644\u0627\u0646\u062c\u0644\u064a\u0632\u064a\u0629/.test(command)) return "en";
    if (/\u0641\u0631\u0646\u0633\u064a|\u0627\u0644\u0641\u0631\u0646\u0633\u064a\u0629/.test(command)) return "fr";
    if (/\u0633\u0648\u0627\u062d\u064a\u0644\u064a|\u0643\u0633\u0648\u0627\u062d\u064a\u0644\u064a/.test(command)) return "sw";
    if (/\u0639\u0631\u0628\u064a|\u0627\u0644\u0639\u0631\u0628\u064a\u0629|\u0645\u0635\u0631/.test(command)) return "ar";
    if (/\u0627\u0633\u0628\u0627\u0646\u064a|\u0627\u0644\u0627\u0633\u0628\u0627\u0646\u064a\u0629/.test(command)) return "es";
  }
  const languages = {
    english: "en",
    eng: "en",
    englsh: "en",
    englisch: "en",
    inglish: "en",
    anglais: "en",
    ingles: "en",
    kiingereza: "en",
    nigeria: "en",
    nigerian: "en",
    french: "fr",
    francais: "fr",
    frances: "fr",
    kifaransa: "fr",
    drc: "fr",
    congo: "fr",
    swahili: "sw",
    kiswahili: "sw",
    suajili: "sw",
    kenya: "sw",
    kenyan: "sw",
    arabic: "ar",
    arabe: "ar",
    kiarabu: "ar",
    egypt: "ar",
    egyptian: "ar",
    spanish: "es",
    espanol: "es",
    espanhol: "es",
    kihispania: "es",
    portuguese: "pt",
    portugues: "pt",
    portuguesa: "pt",
    brazil: "pt",
    brasil: "pt",
    brasileiro: "pt"
  };
  const match = lower.match(/\b(?:to|into|in|as|use|speak|talk|respond|reply|change|switch|set|translate|mudar|trocar|usar|falar|responder)\s+(english|eng|englsh|englisch|inglish|anglais|ingles|kiingereza|nigeria|nigerian|french|francais|frances|kifaransa|drc|congo|swahili|kiswahili|suajili|kenya|kenyan|arabic|arabe|kiarabu|egypt|egyptian|spanish|espanol|espanhol|kihispania|portuguese|portugues|portuguesa|brazil|brasil|brasileiro)\b/);
  if (match?.[1]) return languages[match[1]] || "";
  return Object.entries(languages).find(([name]) => lower.includes(name))?.[1] || "";
}

function appAutoLanguageChoice(command = "") {
  const raw = String(command || "");
  const lower = raw.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  if (!lower.trim() && !/[\u0627-\u064a]/.test(raw)) return null;
  if (isUniversalLanguageCommand(raw)) return null;
  if (/[\u0627-\u064a]/.test(raw)) return { language: "ar", label: "Arabic", evidence: "Arabic script" };
  const choices = [
    { language: "es", label: "Spanish", tests: [/\bhola\b/, /\bbuenos dias\b/, /\bbuenas tardes\b/, /\bbuenas noches\b/, /\bme llamo\b/, /\bmi nombre es\b/, /\byo necesito\b/, /\bnecesito ayuda\b/, /\bquiero\b/, /\bespanol\b/] },
    { language: "fr", label: "French", tests: [/\bbonjour\b/, /\bbonsoir\b/, /\bsalut\b/, /\bje m appelle\b/, /\bje suis\b/, /\bmon nom est\b/, /\bj ai besoin\b/, /\bfrancais\b/, /\baidez[-\s]?moi\b/] },
    { language: "sw", label: "Kiswahili", tests: [/\bjambo\b/, /\bhabari\b/, /\bmambo\b/, /\bnaitwa\b/, /\bjina langu\b/, /\bninahitaji\b/, /\btafadhali\b/, /\bkiswahili\b/, /\bswahili\b/] },
    { language: "pt", label: "Portuguese", tests: [/\bola\b/, /\bbom dia\b/, /\bboa tarde\b/, /\bboa noite\b/, /\bme chamo\b/, /\bmeu nome e\b/, /\bpreciso\b/, /\bportugues\b/] },
    { language: "en", label: "English", tests: [/\benglish\b/, /\bspeak english\b/, /\buse english\b/, /\bback to english\b/, /\bhello\b/, /\bgood morning\b/, /\bgood afternoon\b/, /\bmy name is\b/, /\bi need help\b/] }
  ];
  return choices.find(choice => choice.tests.some(pattern => pattern.test(lower))) || null;
}

async function applyAutoLanguageFromSpeech(rawCommand, options = {}) {
  if (options.skipLanguageAutoDetect || !data?.user) return null;
  const choice = appAutoLanguageChoice(rawCommand);
  if (!choice || choice.language === languageCode()) return null;
  if (partialAppLanguageCodes.has(choice.language)) {
    localStorage.setItem("agrinexusAutoLanguage", JSON.stringify({
      language: choice.language,
      label: choice.label,
      partial: true,
      evidence: choice.evidence || "spoken phrase",
      mode: experienceMode || data?.user?.role || "platform",
      createdAt: new Date().toISOString()
    }));
    return null;
  }
  try {
    const previousLanguage = languageCode();
    data = await request("/api/user/language", { method: "POST", body: { language: choice.language } });
    localStorage.setItem("agrinexusAutoLanguage", JSON.stringify({
      language: choice.language,
      label: choice.label,
      evidence: choice.evidence || "spoken phrase",
      mode: experienceMode || data?.user?.role || "platform",
      createdAt: new Date().toISOString()
    }));
    render();
    refreshLanguageEverywhere();
    if (previousLanguage !== languageCode()) refreshVoiceForLanguageChange();
    updateNexusBehaviorLayer("listening", `Nexus detected ${choice.label} and changed language for ${experienceModeLabel()}.`);
    const status = $("#globalAssistantStatus");
    if (status) status.textContent = translateText(`Detected ${choice.label}. Keep speaking naturally.`);
    return choice;
  } catch (error) {
    console.warn("Auto language detection failed", error);
    return null;
  }
}

