    cropSpoilage: has(["bad", "going bad", "spoil", "spoiling", "rot", "disease", "pest", "yellow", "dry", "stress", "weak", "dying", "not growing"]) && has(["crop", "crops", "field", "farm", "plant", "maize", "rice", "cassava", "yam", "beans"]),
