function conversationIntakePlanFromCommand(command = "") {
  const lower = normalizeRuralSpeechAliases(command);
  const bridge = ruralCommunicationBridge(command);
  const plans = conversationIntakePlans();
  if (plans[bridge.profile.intent] && bridge.profile.intent !== "general") return plans[bridge.profile.intent];
  return Object.values(plans).find(plan => plan.match.test(lower)) || null;
}

function saveConversationIntake(session = activeConversationIntake) {
  activeConversationIntake = session;
  if (session) localStorage.setItem("agrinexusConversationIntake", JSON.stringify(session));
  else localStorage.removeItem("agrinexusConversationIntake");
}

function conversationIntakeSummary(session = activeConversationIntake) {
  if (!session) return "No conversation intake is active.";
  const plan = conversationIntakePlans()[session.type];
  const answered = Object.entries(session.answers || {}).map(([key, value]) => `${key}: ${value}`).join("; ");
  const next = plan?.fields?.[session.index]?.question || "ready to open the workflow";
  return `${plan?.label || "conversation intake"} has ${Object.keys(session.answers || {}).length} answer(s). ${answered || "No answers yet"}. Next: ${next}`;
}

function startConversationIntake(type, command = "") {
  const plan = conversationIntakePlans()[type] || conversationIntakePlanFromCommand(command);
  if (!plan) return false;
  const resolvedType = Object.entries(conversationIntakePlans()).find(([, value]) => value === plan)?.[0] || type;
  const session = {
    type: resolvedType,
    mode: conversationPlatformMode(),
    language: languageCode(),
    startedBy: command,
    answers: {},
    index: 0,
    startedAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  saveConversationIntake(session);
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = true;
  goSection(plan.section, { instant: true, openDefaultAction: false, keepAssistant: true });
  renderLiveVoiceSuggestions(["answer in your own words", "repeat the question", "Nexus stop", "cancel intake"]);
  recordNexusAutonomousLearning({ type: "conversation-intake-started", command, intakeType: resolvedType, mode: conversationPlatformMode() });
  updateNexusBehaviorLayer("listening", `Nexus started conversation-based intake: ${plan.label}.`);
  setVoiceResponse(`Okay. I will ask one question at a time. ${plan.fields[0].question}`, true, { allowHandoff: false });
  return true;
}

function startConversationIntakeFromCommand(command = "") {
  const lower = normalizeToolText(command);
  const wantsIntake = /\b(walk me through|guide me through|ask me questions|one question at a time|start intake|open intake|begin intake|conversation intake|guided intake|intake questions|help me fill|fill out intake)\b/.test(lower);
  if (!wantsIntake) return false;
  const plan = conversationIntakePlanFromCommand(command);
  if (!plan) return false;
  const type = Object.entries(conversationIntakePlans()).find(([, value]) => value === plan)?.[0];
  return startConversationIntake(type, command);
}

function cancelConversationIntake(message = "Canceled. Tell Nexus what you need next.") {
  saveConversationIntake(null);
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = true;
  updateNexusBehaviorLayer("listening", "Nexus canceled conversation intake.");
  renderLiveVoiceSuggestions(["health", "crops", "work", "learning", "map"]);
  setVoiceResponse(message, true, { allowHandoff: false });
  return true;
}

function applyConversationIntakeToVisibleWorkflow(session = activeConversationIntake) {
  if (!session) return;
  const fields = activeWorkflowFieldCandidates();
  if (!fields.length) return;
  const plan = conversationIntakePlans()[session.type];
  const values = session.answers || {};
  fields.forEach(field => {
    const haystack = normalizeToolText(`${field.dataset.workflowField || ""} ${field.closest("label")?.textContent || ""}`);
    const match = (plan?.fields || []).find(item => haystack.includes(normalizeToolText(item.key)) || haystack.includes(normalizeToolText(item.label)) || normalizeToolText(item.label).includes(haystack));
    const fallbackValue = Object.values(values).find(Boolean);
    const value = match ? values[match.key] : fallbackValue;
    if (!field.value && value) {
      field.value = value;
      field.dispatchEvent(new Event("input", { bubbles: true }));
      field.dispatchEvent(new Event("change", { bubbles: true }));
    }
  });
}

function completeConversationIntake(session = activeConversationIntake) {
  if (!session) return false;
  const plan = conversationIntakePlans()[session.type];
  if (!plan) return false;
  const summary = conversationIntakeSummary(session);
  recordNexusAutonomousLearning({ type: "conversation-intake-completed", command: summary, intakeType: session.type, mode: conversationPlatformMode() });
  try {
    const key = "agrinexusConversationIntakeHistory";
    const entries = JSON.parse(localStorage.getItem(key) || "[]");
    entries.unshift({ ...session, completedAt: new Date().toISOString(), summary });
    localStorage.setItem(key, JSON.stringify(entries.slice(0, 50)));
  } catch (error) {
    console.warn("Could not save conversation intake history", error);
  }
  saveConversationIntake(null);
  openWorkflowByVoice(plan.workflow, plan.action, `${plan.openResponse} ${summary}`, { ...session.answers, conversationIntake: true });
  setTimeout(() => applyConversationIntakeToVisibleWorkflow(session), 80);
  setTimeout(() => applyConversationIntakeToVisibleWorkflow(session), 260);
  return true;
}

function handleConversationIntakeAnswer(command = "") {
  if (!activeConversationIntake) return false;
  const lower = normalizeToolText(command);
  if (isGlobalStopCommand(lower) || /\b(cancel intake|cancel this intake|stop intake|close intake|start over)\b/.test(lower)) {
    return cancelConversationIntake();
  }
  if (/\b(repeat|say that again|repeat the question|what question)\b/.test(lower)) {
    const plan = conversationIntakePlans()[activeConversationIntake.type];
    const question = plan?.fields?.[activeConversationIntake.index]?.question || "Tell me what you need next.";
    setVoiceResponse(question, true, { allowHandoff: false });
    return true;
  }
  const plan = conversationIntakePlans()[activeConversationIntake.type];
  const field = plan?.fields?.[activeConversationIntake.index];
  if (!plan || !field) return completeConversationIntake(activeConversationIntake);
  const answer = String(command || "").replace(/\s+/g, " ").trim();
  if (!answer || answer.length < 2) {
    setVoiceResponse("I did not catch that. Say it again in your own words.", true, { allowHandoff: false });
    return true;
  }
  const next = {
    ...activeConversationIntake,
    answers: { ...(activeConversationIntake.answers || {}), [field.key]: answer },
    index: activeConversationIntake.index + 1,
    updatedAt: new Date().toISOString()
  };
  saveConversationIntake(next);
  const nextField = plan.fields[next.index];
  recordNexusAutonomousLearning({ type: "conversation-intake-answer", command: answer, field: field.key, intakeType: next.type });
  if (nextField) {
    renderLiveVoiceSuggestions(["answer in your own words", "repeat the question", "cancel intake"]);
    updateNexusBehaviorLayer("listening", `Nexus added ${field.label} and is asking the next intake question.`);
    setVoiceResponse(`I added that. ${nextField.question}`, true, { allowHandoff: false });
    return true;
  }
  return completeConversationIntake(next);
}

function repairConversationIntake(command = "") {
  if (!activeConversationIntake) return false;
  const plan = conversationIntakePlans()[activeConversationIntake.type];
  if (!plan) return false;
  const previousIndex = Math.max(0, Number(activeConversationIntake.index || 0) - 1);
  const field = plan.fields[previousIndex] || plan.fields[0];
  const answers = { ...(activeConversationIntake.answers || {}) };
  if (field?.key) delete answers[field.key];
  const repaired = {
    ...activeConversationIntake,
    answers,
    index: previousIndex,
    repairedAt: new Date().toISOString(),
    repairReason: command
  };
  saveConversationIntake(repaired);
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = true;
  recordNexusAutonomousLearning({ type: "conversation-intake-repair", command, field: field?.key || "", intakeType: repaired.type });
  updateNexusBehaviorLayer("listening", `Nexus stepped back in ${plan.label}.`);
  renderLiveVoiceSuggestions(["answer again", "repeat the question", "cancel intake"]);
  setVoiceResponse(`You're right. I removed the last answer. ${field?.question || "Tell me that part again."}`, true, { allowHandoff: false });
  return true;
}

function saveConversationMode2Decision(command = "", decision = {}) {
  const mode = conversationPlatformMode();
  const memory = conversationMemoryForMode(mode);
  const current = memory.conversationMode2 || {};
  const intent = inferNexusIntent(command || current.lastUserWords || "");
  const next = {
    ...memory,
    conversationMode2: {
      ...current,
      enabled: true,
      activeTopic: intent.label || current.activeTopic || currentSectionId(),
      lastDecision: decision.kind || "listening",
      lastConfidence: Number(decision.confidence || intent.confidence || 0),
      lastUserWords: String(command || current.lastUserWords || "").trim(),
      awaiting: decision.awaiting || "",
      guard: decision.guard || "listen-first",
      updatedAt: new Date().toISOString()
    },
    updatedAt: new Date().toISOString()
  };
  saveConversationModeMemory(mode, next);
}

function conversationMode2Decision(command = "", options = {}) {
  const lower = normalizeToolText(command);
  const ruralBridge = ruralCommunicationBridge(command);
  const ruralProfile = ruralBridge.profile;
  const explicitWake = isExplicitNexusWakeOrCommand(command);
  if (!lower) return { kind: "silent", confidence: 0, action: "wait", shouldAct: false };
  if (isGlobalStopCommand(lower)) return { kind: "stop", confidence: 1, action: "stop", shouldAct: true };
  if (isLikelySideConversationWithoutNexusCommand(command)) {
    return { kind: "side-conversation", confidence: 0.91, action: "pause", shouldAct: false, guard: "background-talk" };
  }
  if (isUniversalLanguageCommand(command) || hasBehaviorActionVerb(command) || isClearWorkflowVoiceCommand(command)) {
    return { kind: "clear-command", confidence: 0.9, action: "route", shouldAct: true, guard: "clear-action" };
  }
  if (ruralProfile.intent !== "general" && ruralProfile.confidence >= 0.7) {
    return {
      kind: "rural-speech",
      confidence: ruralProfile.confidence,
      action: "route",
      shouldAct: true,
      guard: "imperfect-language-routing",
      ruralProfile
    };
  }
  if (ruralProfile.intent !== "general" && ruralProfile.confidence >= 0.5) {
    return {
      kind: "rural-clarify",
      confidence: ruralProfile.confidence,
      action: "clarify",
      shouldAct: false,
      awaiting: "one-rural-follow-up",
      response: ruralBridge.response,
      guard: "ask-before-acting",
      ruralProfile,
      ruralBridge
    };
  }
  if (isOpenKnowledgeQuestion(command) || isOpenDialogVoiceQuestion(command) || isNaturalQuestionOrConversation(command)) {
    return { kind: "conversation", confidence: 0.82, action: "answer", shouldAct: true, guard: "open-dialog" };
  }
  if (isModeFollowUpCommand(lower)) {
    return { kind: "follow-up", confidence: 0.8, action: "answer", shouldAct: true, guard: "topic-memory" };
  }
  if (/\b(okay|ok|alright|cool|got it|i see|yes thanks|no thanks|that helps|sounds good)\b/.test(lower)) {
    return {
      kind: "casual",
      confidence: 0.77,
      action: "reply",
      shouldAct: false,
      response: "Got you. I'm here when you need me.",
      guard: "casual-talk"
    };
  }
  const tokens = lower.split(/\s+/).filter(Boolean);
  const hasNeedWord = /\b(help|need|want|looking|trying|problem|issue|sick|hurt|crop|job|learn|doctor|medicine|buyer|map|route)\b/.test(lower);
  if (options.source === "voice" && !explicitWake && tokens.length >= 5 && !hasNeedWord) {
    return { kind: "background", confidence: 0.74, action: "pause", shouldAct: false, guard: "unclear-background" };
  }
  if (tokens.length <= 5 && !hasNeedWord && !explicitWake) {
    return {
      kind: "unclear",
      confidence: 0.62,
      action: "clarify",
      shouldAct: false,
      awaiting: "one-simple-follow-up",
      response: "I want to make sure I got you. Is this about health, crops, work, learning, or the map?",
      guard: "do-not-act-unless-clear"
    };
  }
  return { kind: "conversation", confidence: 0.64, action: "answer", shouldAct: true, guard: "open-dialog-fallback" };
}

function handleConversationMode2Preflight(command = "", options = {}) {
  const decision = conversationMode2Decision(command, options);
  saveConversationMode2Decision(command, decision);
  if (decision.action === "pause") {
    pauseNexusForSideConversation(command);
    return true;
  }
  if (decision.action === "clarify") {
    pendingAgentClarification = null;
    pendingNexusSpokenCommand = null;
    nexusAwaitingCommand = true;
    updateNexusBehaviorLayer("listening", "Conversation Mode 2.0 is asking one simple follow-up.");
    renderLiveVoiceSuggestions(["health", "crops", "work", "learning", "map"]);
    setVoiceResponse(decision.response || "I want to make sure I got you. Is this about health, crops, work, learning, or the map?", true, { allowHandoff: false });
    return true;
  }
  if (decision.action === "reply" && decision.response) {
    updateNexusBehaviorLayer("listening", "Conversation Mode 2.0 handled casual talk without starting a workflow.");
    setVoiceResponse(decision.response, true, { allowHandoff: false });
    return true;
  }
  return false;
}

function modeConversationContext(command = "") {
  const mode = conversationPlatformMode();
  const brief = conversationModeBrief();
  const modeMemory = conversationMemoryForMode(mode);
  const awareness = updateNexusAwareness(command, { silent: true });
  const memory = data ? nexusMemoryProfile() : {};
  const readiness = data?.admin?.readiness;
  return {
    mode,
    modeLabel: brief.mode,
    audience: brief.audience,
    tone: brief.tone,
    focus: brief.focus,
    currentSection: currentSectionId(),
    language: voiceLanguageName(),
    userName: userFirstName(),
    command,
    activeJourney: activeAgentJourneySummary(),
    conversationMode2: conversationMode2Status(mode),
    lastQuestion: modeMemory.lastQuestion || "",
    lastAnswer: modeMemory.lastAnswer || "",
    lastTopic: modeMemory.lastTopic || "",
    modeTurnCount: modeMemory.turnCount || 0,
    awareness,
    allModeSummaries: ["user", "admin", "investor"].map(item => {
      const saved = conversationMemoryForMode(item);
      return `${conversationPlatformLabel(item)}: ${saved.lastTopic || "ready"}`;
    }),
    memory,
    productionReadiness: readiness ? `${readiness.readyCount || 0}/${readiness.total || 0}` : "unknown"
  };
}

function isModeFollowUpCommand(lower) {
  return /^(tell me more|explain that|explain more|why|repeat that|say that again|summarize|what should i do|what now|what next|continue|keep going|how do i use this|walk me through it|guide me|what does that mean)\b/.test(String(lower || "").trim());
}

function modeFollowUpResponse(command = "") {
  const mode = conversationPlatformMode();
  const brief = conversationModeBrief(mode);
  const modeMemory = conversationMemoryForMode(mode);
  const lastAnswer = modeMemory.lastAnswer || lastVoiceResponse || "I am ready to guide the next step.";
  const lastTopic = modeMemory.lastTopic || currentSectionId();
  if (mode === "admin") {
    const adminBrief = adminIntelligenceBrief();
    return `${brief.mode}: I am holding the admin context. Last topic: ${lastTopic}. ${lastAnswer} Operationally, the next best move is ${adminBrief.recommendation}. You can say run admin intelligence, run live service check, show production gaps, or take me to admin.`;
  }
  if (mode === "investor") {
    const investorBrief = investorIntelligenceBrief();
    return `${brief.mode}: I am holding the investor context. Last topic: ${lastTopic}. ${lastAnswer} For the funding story, lead with ${investorBrief.strongestMetric}. Next, you can say run investor story, summarize impact, prepare government briefing, or show evidence.`;
  }
  return `${brief.mode}: I am holding the user context. Last topic: ${lastTopic}. ${lastAnswer} I will keep this simple: tell me what you need, or say open learning, open telehealth, find jobs, sell my crop, change language, or guide me step by step.`;
}

function inferNexusIntent(command = "") {
  const lower = String(command || "").toLowerCase();
  if (!lower.trim()) return { label: "idle", section: currentSectionId(), confidence: 0.3 };
  const signals = [
    { label: "telehealth support", section: "health", confidence: 0.9, pattern: /\b(doctor|provider|nurse|clinic|telehealth|care|patient|intake|vitals|health|medicine|outbreak|ebola)\b/ },
    { label: "workforce support", section: "workforce", confidence: 0.88, pattern: /\b(job|work|role|shift|interview|mentor|apply|worker|candidate|skills|gaps)\b/ },
    { label: "learning support", section: "learning", confidence: 0.86, pattern: /\b(course|lesson|learn|training|certificate|quiz|caption|audio guide|student)\b/ },
    { label: "trade and farming support", section: "trade", confidence: 0.9, pattern: /\b(crop|buyer|sell|maize|trade|agritrade|order|payment|wallet|drone|field|farm|route|logistics)\b/ },
    { label: "map intelligence", section: "map", confidence: 0.82, pattern: /\b(map|route|gps|location|facility|risk|track)\b/ },
    { label: "provider integration", section: "integrations", confidence: 0.78, pattern: /\b(provider|engine|integration|connected|live service|api|credential)\b/ },
    { label: "admin operation", section: "admin", confidence: 0.8, pattern: /\b(admin|audit|readiness|production|users|health check|service check)\b/ },
    { label: "investor presentation", section: "dashboard", confidence: 0.84, pattern: /\b(investor|funding|government|presentation|impact|evidence|demo)\b/ }
  ];
  return signals.find(item => item.pattern.test(lower)) || { label: "open conversation", section: currentSectionId(), confidence: 0.58 };
}

function updateNexusAwareness(command = "", options = {}) {
  const inferred = inferNexusIntent(command || agentPerformanceState.lastCommand || conversationModeState.lastQuestion || "");
  const guide = intuitiveConversationGuide(inferred.section || currentSectionId());
  const waitingOn = pendingWorkflow ? "workflow confirmation"
    : pendingAgentClarification ? "clarification choice"
      : activeAgentJourney?.next ? "guided journey continuation"
        : agentPerformanceState.status === "thinking" ? "agent response"
          : "user direction";
  nexusAwarenessState = {
    mode: conversationPlatformMode(),
    section: currentSectionId(),
    inferredIntent: inferred.label,
    inferredSection: inferred.section,
    confidence: inferred.confidence,
    waitingOn,
    safeNextAction: guide.primaryCommand,
    lastCommand: command || agentPerformanceState.lastCommand || "",
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusAwarenessState", JSON.stringify(nexusAwarenessState));
  if (!options.silent) updateNexusBehaviorLayer("ready", `Awareness: ${nexusAwarenessState.inferredIntent}; waiting on ${nexusAwarenessState.waitingOn}.`);
  return nexusAwarenessState;
}

function nexusAwarenessSummary() {
  const awareness = updateNexusAwareness("", { silent: true });
  return `Nexus awareness: mode ${conversationPlatformLabel(awareness.mode)}, section ${awareness.section}, intent ${awareness.inferredIntent}, confidence ${Math.round((awareness.confidence || 0) * 100)} percent, waiting on ${awareness.waitingOn}. Safe next action: ${awareness.safeNextAction}.`;
}

function nexusBrainState(command = "") {
  const awareness = updateNexusAwareness(command, { silent: true });
  const modeMemory = conversationMemoryForMode(awareness.mode);
  const repair = conversationRepairPlan(command || awareness.lastCommand || "");
  const guide = intuitiveConversationGuide(awareness.inferredSection || currentSectionId());
  const memorySignals = nexusDeepMemorySignals();
  const queue = nexusAutopilotQueue();
  const scorecard = agenticBehaviorScorecard();
  const brain = {
    name: "Nexus Brain",
    goals: activeAgentJourney?.workflow || data?.profile?.agentMemory?.activeJarvisSession?.goal || data?.profile?.agentMemory?.activeMission || "guide the user to the safest useful next action",
    memory: `${memorySignals.count} memory signal(s); mode topic: ${modeMemory.lastTopic || "new conversation"}`,
    awareness: `${awareness.inferredIntent} in ${awareness.section} at ${Math.round((awareness.confidence || 0) * 100)}% confidence`,
    recovery: repair.problem || "ready",
    initiative: guide.primaryCommand || "Nexus, guide me",
    waitingOn: awareness.waitingOn,
    mode: conversationPlatformLabel(awareness.mode),
    section: awareness.section,
    missions: `${queue.waiting} waiting, ${queue.completed} completed`,
    behavior: scorecard.behavior
  };
  localStorage.setItem("agrinexusBrainState", JSON.stringify(brain));
  return brain;
}

function nexusBrainSummary() {
  const brain = nexusBrainState();
  return `${brain.name}: goal is ${brain.goals}. Memory: ${brain.memory}. Awareness: ${brain.awareness}. Recovery: ${brain.recovery}. Initiative: ${brain.initiative}. Waiting on ${brain.waitingOn}.`;
}

function nexusBrainTimeline() {
  const profile = data?.profile || {};
  const commands = (profile.agentCommands || []).slice(0, 4).map(item => ({
    type: "Command",
    title: item.intent || "Voice command",
    detail: item.command || item.response || "Command captured",
    at: item.createdAt || item.updatedAt || ""
  }));
  const executions = (profile.agentExecutions || []).slice(0, 3).map(item => ({
    type: "Mission",
    title: item.goal || "Agent mission",
    detail: item.summary || item.status || "Mission evidence recorded",
    at: item.createdAt || item.updatedAt || ""
  }));
  const events = (profile.integrationEvents || []).slice(0, 3).map(item => ({
    type: "Provider",
    title: item.type || item.provider || "Provider event",
    detail: item.detail || item.status || "Provider-ready event recorded",
    at: item.createdAt || item.updatedAt || ""
  }));
  const memories = Object.entries(conversationModeMemories || {}).slice(0, 3).map(([mode, memory]) => ({
    type: "Memory",
    title: conversationPlatformLabel(mode),
    detail: memory.lastTopic || memory.lastQuestion || "Mode memory is active",
    at: memory.updatedAt || ""
  }));
  const timeline = [...commands, ...executions, ...events, ...memories]
    .filter(item => item.title || item.detail)
    .slice(0, 10);
  return timeline.length ? timeline : [{
    type: "Ready",
    title: "Nexus Brain is standing by",
    detail: "Start a voice command, workflow, mission, or provider check to create timeline evidence.",
    at: new Date().toISOString()
  }];
}

function nexusBrainLearningRules() {
  const memory = data?.profile?.agentMemory || {};
  const userModel = memory.userModel || {};
  const preferences = [
    userModel.preferredInteraction || "voice-first support",
    userModel.communicationStyle || "plain-language guidance",
    userModel.lastAdaptiveSignals?.accessibility || "standard accessibility"
  ];
  const adaptivePreferences = loadNexusAdaptivePreferences();
  const adaptiveRules = loadNexusAdaptiveRules();
  if (adaptivePreferences.answerLength === "short") preferences.push("short answers");
  if (adaptivePreferences.languageStyle === "plain") preferences.push("plain language");
  if (adaptivePreferences.speechPace === "slow") preferences.push("slower speech");
  if (adaptiveRules[0]) preferences.push(`learned phrase: ${adaptiveRules[0].source} -> ${adaptiveRules[0].target}`);
  const modeMemory = conversationMemoryForMode(conversationPlatformMode());
  if (modeMemory.lastTopic) preferences.push(`continue topic: ${modeMemory.lastTopic}`);
  if (memory.turnCoach?.nextQuestion) preferences.push(`next prompt: ${memory.turnCoach.nextQuestion}`);
  return preferences.filter(Boolean).slice(0, 5);
}

function nexusBrainOsModel() {
  const brain = nexusBrainState(agentPerformanceState.lastCommand || "");
  const timeline = nexusBrainTimeline();
  const providerDepth = providerActionDepthStatus();
  const nativeReadiness = nativeAppReadinessSummary();
  const adminBrief = adminIntelligenceBrief();
  const investorBrief = investorIntelligenceBrief();
  const learningRules = nexusBrainLearningRules();
  const queue = nexusAutopilotQueue();
  const memory = nexusDeepMemorySignals();
  const depthTotals = Object.values(providerDepth || {}).reduce((acc, item) => {
    acc.ready += Number(item.ready || 0);
    acc.total += Number(item.total || 0);
    return acc;
  }, { ready: 0, total: 0 });
  const items = [
    {
      title: "Brain Persistence",
      evidence: `${memory.count} memory signal(s), mode memory, and browser state ready`,
      ready: true,
      command: "Nexus, what do you remember"
    },
    {
      title: "Brain Timeline",
      evidence: `${timeline.length} recent command, mission, provider, or memory event(s) visible`,
      ready: timeline.length > 0,
      command: "Nexus, show brain timeline"
    },
    {
      title: "Brain Self-Explanation",
      evidence: `${brain.goals}; ${brain.awareness}`,
      ready: true,
      command: "Nexus, explain your brain"
    },
    {
      title: "Brain Learning Rules",
      evidence: learningRules.join(" | "),
      ready: learningRules.length > 0,
      command: "Nexus, show learning rules"
    },
    {
      title: "Autonomous Task Queue",
      evidence: `${queue.waiting} waiting, ${queue.completed} completed mission task(s)`,
      ready: true,
      command: "Nexus, run full mission"
    },
    {
      title: "Real Provider Feeds",
      evidence: `${depthTotals.ready}/${depthTotals.total} provider-backed action depth signals ready`,
      ready: depthTotals.total === 0 || depthTotals.ready > 0,
      command: "Nexus, test provider engines"
    },
    {
      title: "Native App Layer",
      evidence: nativeReadiness.summary,
      ready: nativeReadiness.readyCount > 0,
      command: "Nexus, check native app readiness"
    },
    {
      title: "Multilingual Brain",
      evidence: `Active language: ${voiceLanguageName()}; voice command switching is enabled`,
      ready: true,
      command: "Nexus, change language to French"
    },
    {
      title: "Admin Brain Controls",
      evidence: `${adminBrief.readiness}; top risk: ${adminBrief.topRisk}`,
      ready: true,
      command: "Nexus, run admin intelligence"
    },
    {
      title: "Investor Brain View",
      evidence: `${investorBrief.strongestMetric}; gap: ${investorBrief.topGap}`,
      ready: true,
      command: "Nexus, run investor voice demo"
    }
  ];
  const readyCount = items.filter(item => item.ready).length;
  const model = {
    title: "Nexus Brain OS",
    principles: ["goals", "memory", "awareness", "recovery", "initiative"],
    readyCount,
    total: items.length,
    items,
    timeline,
    brain,
    learningRules
  };
  localStorage.setItem("agrinexusBrainOs", JSON.stringify(model));
  return model;
}

function nexusBrainOsSummary() {
  const model = nexusBrainOsModel();
  const next = model.items.find(item => !item.ready) || model.items[0];
  return `Nexus Brain OS is ${model.readyCount}/${model.total} active across persistence, timeline, self-explanation, learning rules, task queue, provider feeds, native app, multilingual behavior, admin controls, and investor view. Current goal: ${model.brain.goals}. Next useful command: ${next.command}.`;
}

function nexusHighIntelligenceSnapshot() {
  const brainOs = nexusBrainOsModel();
  const brief = nexusSituationalBrief();
  const scorecard = agenticBehaviorScorecard();
  const memory = nexusDeepMemorySignals();
  const timeline = nexusBrainTimeline();
  const providerDepth = providerActionDepthStatus();
  const providerTotals = Object.values(providerDepth || {}).reduce((acc, item) => {
    acc.ready += Number(item.ready || 0);
    acc.total += Number(item.total || 0);
    return acc;
  }, { ready: 0, total: 0 });
  const confidence = Math.min(99, Math.max(55, Math.round(
    (brainOs.readyCount / Math.max(1, brainOs.total)) * 34
    + (Number(nexusAwarenessState.confidence || 0.58) * 28)
    + (memory.count ? 14 : 5)
    + (brief.priorities.length ? 12 : 4)
    + (providerTotals.total ? (providerTotals.ready / providerTotals.total) * 12 : 8)
  )));
  const topPriority = brief.priorities[0] || { title: "Start guided support", command: "what should I do next", reason: "Nexus needs a first user goal." };
  const risk = brief.priorities.find(item => item.category === "provider" || item.category === "production" || item.category === "alert");
  const language = `${voiceLanguageName()} active; commands can switch English, French, Arabic, Kiswahili, Spanish, and Portuguese.`;
  const autonomyLevel = activeAgentJourney?.next
    ? "guided autonomy with a live journey"
    : pendingWorkflow
      ? "confirmation-gated autonomy"
      : providerTotals.ready < providerTotals.total
        ? "provider-aware autonomy with safe local fallback"
        : "live-provider autonomy with evidence tracking";
  const items = [
    {
      title: "Decision Confidence",
      evidence: `${confidence}% confidence from brain readiness, awareness, memory, priorities, and provider depth`,
      ready: confidence >= 75,
      command: "Nexus, explain your brain"
    },
    {
      title: "Top Priority",
      evidence: `${topPriority.title}: ${topPriority.reason}`,
      ready: true,
      command: `Nexus, ${topPriority.command}`
    },
    {
      title: "Risk Radar",
      evidence: risk ? `${risk.title}: ${risk.reason}` : "No critical risk detected in the active view",
      ready: !risk,
      command: risk ? `Nexus, ${risk.command}` : "Nexus, what needs attention"
    },
    {
      title: "Memory Context",
      evidence: `${memory.count} remembered signal(s); latest: ${memory.latest}`,
      ready: true,
      command: "Nexus, what do you remember"
    },
    {
      title: "Evidence Awareness",
      evidence: `${timeline.length} recent evidence event(s) across commands, missions, providers, and memory`,
      ready: true,
      command: "Nexus, show brain timeline"
    },
    {
      title: "Autonomy Level",
      evidence: autonomyLevel,
      ready: true,
      command: "Nexus, run full mission"
    },
    {
      title: "Provider Depth",
      evidence: `${providerTotals.ready}/${providerTotals.total} live/provider-ready signals`,
      ready: providerTotals.total === 0 || providerTotals.ready >= Math.ceil(providerTotals.total * 0.6),
      command: "Nexus, test provider engines"
    },
    {
      title: "Language Intelligence",
      evidence: language,
      ready: true,
      command: "Nexus, change language to French"
    },
    {
      title: "Recovery Plan",
      evidence: scorecard.behavior,
      ready: true,
      command: "Nexus, help me"
    },
    {
      title: "Next Best Action",
      evidence: `Run: ${topPriority.command}`,
      ready: true,
      command: `Nexus, ${topPriority.command}`
    }
  ];
  return {
    score: confidence,
    mode: scorecard.mode,
    topPriority,
    summary: brief.summary,
    autonomyLevel,
    items
  };
}

function nexusHighIntelligenceSummary() {
  const snapshot = nexusHighIntelligenceSnapshot();
  const predictive = nexusPredictiveAdvisorModel(agentPerformanceState.lastCommand || snapshot.topPriority.command || "");
  const topPrediction = predictive.predictions[0];
  return `Nexus intelligence is operating at ${snapshot.score}% confidence. Predictive score ${predictive.score}/100. Top recommendation: ${snapshot.topPriority.title}, because ${snapshot.topPriority.reason}. Predictive alert: ${topPrediction.module} ${topPrediction.priority}: ${topPrediction.message}. Autonomy level: ${snapshot.autonomyLevel}. Say ${topPrediction.command || snapshot.topPriority.command} to continue.`;
}

function nexusSmartBehaviorModel(mode = experienceMode) {
  const normalized = normalizeExperienceMode(mode);
  const snapshot = nexusHighIntelligenceSnapshot();
  const role = normalized === "admin" ? "operator"
    : normalized === "investor" ? "partner reviewer"
      : normalized === "user" ? "everyday user"
        : "workspace user";
  const behavior = normalized === "user"
    ? "simple, voice-first, one action at a time, with large-button paths and plain-language recovery"
    : normalized === "admin"
      ? "risk-aware, readiness-focused, audit-driven, and provider-depth conscious"
      : normalized === "investor"
        ? "impact-focused, evidence-led, funding-story aware, and demo-ready"
        : "cross-module, evidence-aware, and workflow-first";
  const thinking = [
    "read the active role and section",
    "rank the safest next action",
    "check memory, language, provider depth, and unresolved risks",
    "speak plainly before acting",
    "confirm important workflow changes",
    "record evidence after useful actions"
  ];
  return {
    role,
    behavior,
    score: snapshot.score,
    recommendation: snapshot.topPriority,
    thinking,
    statement: `For the ${role}, Nexus behaves ${behavior}. It is currently ${snapshot.score}% confident. Best move: ${snapshot.topPriority.title}, because ${snapshot.topPriority.reason}.`
  };
}

function nexusSmartBehaviorSummary(mode = experienceMode) {
  const model = nexusSmartBehaviorModel(mode);
  return `${model.statement} Smart rules active: ${model.thinking.join("; ")}.`;
}

function modeIntelligenceSnapshot(mode = experienceMode) {
  const normalized = normalizeExperienceMode(mode);
  const base = nexusHighIntelligenceSnapshot();
  const smart = nexusSmartBehaviorModel(normalized);
  const productionEight = productionJarvisEightModel();
  const productionItem = {
    title: "Production 1-8",
    evidence: `${productionEight.readyCount}/${productionEight.total} ready: ${productionEight.closest.title} is the closest unlock.`,
    ready: productionEight.readyCount === productionEight.total,
    command: "Nexus, production one through eight"
  };
  const adminBrief = adminIntelligenceBrief();
  const investorBrief = investorIntelligenceBrief();
  const outcome = data ? latestUserOutcome() : { happened: "No workflow yet", meaning: "Nexus is ready.", next: "Ask Nexus for help." };
  if (normalized === "user") {
    return {
      ...base,
      mode: "User intelligence",
      topPriority: {
        title: "Help the user succeed",
        reason: outcome.next,
        command: "help me"
      },
      summary: `${outcome.meaning} Nexus will keep this simple, use voice-first guidance, translate when asked, and confirm before important actions.`,
      items: [
        { title: "Smart Behavior", evidence: smart.behavior, ready: true, command: "Nexus, be smart" },
        { title: "Simple Next Step", evidence: outcome.next, ready: true, command: "Nexus, help me" },
        { title: "Voice Guidance", evidence: "Talk to Nexus, ask a question, or press one big service button.", ready: true, command: "Nexus, what should I do next" },
        { title: "Language Support", evidence: `${voiceLanguageName()} active; voice and screen language can change by command.`, ready: true, command: "Nexus, change language to French" },
        productionItem,
        { title: "Memory", evidence: outcome.happened, ready: true, command: "Nexus, what do you remember" }
      ]
    };
  }
  if (normalized === "admin") {
    return {
      ...base,
      mode: "Admin intelligence",
      topPriority: {
        title: "Protect production readiness",
        reason: adminBrief.recommendation,
        command: adminBrief.command
      },
      summary: `Admin intelligence sees readiness ${adminBrief.readiness}, risk count ${adminBrief.riskCount}, usage ${adminBrief.usage}, and top risk: ${adminBrief.topRisk}`,
      items: [
        { title: "Smart Behavior", evidence: smart.behavior, ready: true, command: "Nexus, be smart" },
        { title: "Readiness Risk", evidence: adminBrief.topRisk, ready: !adminBrief.riskCount, command: "Nexus, run admin intelligence" },
        { title: "Live Services", evidence: adminBrief.recommendation, ready: true, command: "Nexus, run live service check" },
        productionItem,
        { title: "Usage Awareness", evidence: `${adminBrief.usage}; strongest module: ${adminBrief.healthiestModule}`, ready: true, command: "Nexus, summarize audit" },
        { title: "Provider Control", evidence: base.items.find(item => item.title === "Provider Depth")?.evidence || "Provider depth ready", ready: true, command: "Nexus, test provider engines" }
      ]
    };
  }
  if (normalized === "investor") {
    return {
      ...base,
      mode: "Investor intelligence",
      topPriority: {
        title: "Strengthen the funding story",
        reason: investorBrief.recommendation,
        command: investorBrief.command
      },
      summary: `Investor intelligence sees strongest metric ${investorBrief.strongestMetric}, timeline ${investorBrief.timeline}, provider depth ${investorBrief.providerDepth}, and gap: ${investorBrief.topGap}`,
      items: [
        { title: "Smart Behavior", evidence: smart.behavior, ready: true, command: "Nexus, be smart" },
        { title: "Impact Signal", evidence: investorBrief.strongestMetric, ready: true, command: "Nexus, summarize impact" },
        { title: "Evidence Story", evidence: investorBrief.timeline, ready: true, command: "Nexus, run investor voice demo" },
        productionItem,
        { title: "Funding Gap", evidence: investorBrief.topGap, ready: !investorBrief.topGap.includes("Run") && !investorBrief.topGap.includes("readiness"), command: "Nexus, explain this to investors" },
        { title: "Provider Proof", evidence: `Provider depth ${investorBrief.providerDepth}`, ready: true, command: "Nexus, test provider engines" }
      ]
    };
  }
  return base;
}

function renderModeIntelligence(prefix, mode = experienceMode) {
  const panel = $(`#${prefix}IntelligencePanel`);
  const briefPanel = $(`#${prefix}IntelligenceBriefPanel`);
  if (!panel && !briefPanel) return;
  const snapshot = modeIntelligenceSnapshot(mode);
  const score = $(`#${prefix}IntelligenceScore`);
  const modeLabel = $(`#${prefix}IntelligenceMode`);
  if (score) score.textContent = `${snapshot.score}%`;
  if (modeLabel) modeLabel.textContent = translateText(snapshot.mode);
  if (panel) {
    panel.innerHTML = snapshot.items.map(item => taskItem(
      item.title,
      item.evidence,
      item.ready ? "ready" : "pending",
      item.ready ? "Clear" : "Watch",
      { simpleCommand: item.command }
    )).join("");
  }
  if (briefPanel) {
    briefPanel.innerHTML = [
      `<div><strong>${translateText("Mode")}</strong><span>${translateText(snapshot.mode)}</span></div>`,
      `<div><strong>${translateText("Recommendation")}</strong><span>${translateText(snapshot.topPriority.title)} - ${translateText(snapshot.topPriority.reason)}</span></div>`,
      `<div><strong>${translateText("Command")}</strong><span>${translateText(`Nexus, ${snapshot.topPriority.command}`)}</span></div>`,
      `<div><strong>${translateText("Intelligence read")}</strong><span>${translateText(snapshot.summary)}</span></div>`
    ].join("");
  }
}

function renderJarvisProductionTen(prefix = "jarvisProduction") {
  const model = data?.jarvisProductionTen || { readyCount: 0, providerReadyCount: 0, total: 10, items: [], nextSteps: [] };
  const panel = $(`#${prefix}TenPanel`);
  const nextPanel = $(`#${prefix}NextPanel`);
  const score = $(`#${prefix}Score`);
  const providerScore = $(`#${prefix}ProviderScore`);
  if (score) score.textContent = `${model.readyCount || 0}/${model.total || 10}`;
  if (providerScore) providerScore.textContent = `${model.providerReadyCount || 0}/${model.total || 10}`;
  if (panel) {
    panel.innerHTML = (model.items || []).map(item => taskItem(
      item.title,
      `${item.level}. ${item.evidence}`,
      item.ready ? "ready" : "pending",
      item.ready ? "Live" : "Unlock",
      { simpleCommand: item.ready ? "Nexus, show intelligence" : "Nexus, what is left for production" }
    )).join("");
  }
  if (nextPanel) {
    const steps = model.nextSteps?.length ? model.nextSteps : ["All 10 Jarvis production areas are live-ready."];
    nextPanel.innerHTML = [
      `<div><strong>${translateText("Production summary")}</strong><span>${translateText(model.summary || "Production smart agent status is loading.")}</span></div>`,
      ...steps.slice(0, 6).map(step => `<div><strong>${translateText("Next unlock")}</strong><span>${translateText(step)}</span></div>`)
    ].join("");
  }
}

function jarvisProductionTenSummary() {
  const model = data?.jarvisProductionTen || { readyCount: 0, providerReadyCount: 0, total: 10, nextSteps: [] };
  const next = model.nextSteps?.[0] || "All 10 Jarvis production areas are live-ready.";
  return `${model.summary || `AgriNexus is ${model.readyCount}/${model.total} fully live.`} Closest next unlock: ${next}`;
}

function productionJarvisEightModel() {
  const providers = data?.providers || [];
  const provider = id => providers.find(item => item.id === id) || {};
  const connected = id => ["connected", "ready"].includes(provider(id).status);
  const readiness = data?.admin?.readiness || { readyCount: 0, total: 0, status: "unknown" };
  const productionTen = data?.jarvisProductionTen || { readyCount: 0, providerReadyCount: 0, total: 10, nextSteps: [] };
  const liveChecks = data?.profile?.liveServiceChecks || [];
  const hasEvents = Boolean((data?.profile?.integrationEvents || []).length);
  const providerGroups = {
    courses: connected("learning-courses"),
    jobs: connected("workforce-jobs"),
    telehealth: connected("health-telehealth") || connected("health-ehr"),
    drones: connected("field-drones"),
    maps: connected("maps"),
    billing: connected("billing-subscriptions")
  };
  const realProviderReady = Object.values(providerGroups).filter(Boolean).length;
  const items = [
    {
      id: "live-ai-brain",
      title: "Live AI Brain",
      ready: connected("openai") && (connected("voice-stt") || connected("voice-tts")),
      evidence: `${provider("openai").mode || "AI"}; voice STT ${provider("voice-stt").status || "unknown"}; TTS ${provider("voice-tts").status || "unknown"}.`,
      command: "Nexus, show intelligence"
    },
    {
      id: "production-memory",
      title: "Production Memory",
      ready: connected("database"),
      evidence: provider("database").detail || "PostgreSQL state path is prepared and checked by live service readiness.",
      command: "Nexus, what do you remember"
    },
    {
      id: "voice-phone",
      title: "Voice, SMS, WhatsApp, And Phone",
      ready: connected("phone-voice") && (connected("sms-delivery") || connected("whatsapp-delivery")),
      evidence: `Phone ${provider("phone-voice").status || "unknown"}; SMS ${provider("sms-delivery").status || "unknown"}; WhatsApp ${provider("whatsapp-delivery").status || "unknown"}.`,
      command: "Nexus, test provider engines"
    },
    {
      id: "real-providers",
      title: "Real Providers",
      ready: realProviderReady >= Object.keys(providerGroups).length,
      evidence: `${realProviderReady}/${Object.keys(providerGroups).length} provider groups ready: courses, jobs, telehealth, drones, maps, billing.`,
      command: "Nexus, run live service check"
    },
    {
      id: "mode-aware-product",
      title: "Mode-Aware Product",
      ready: true,
      evidence: "User, Admin, and Investor modes have separate conversation memory, permissions, intelligence, and action paths.",
      command: "Nexus, activate Agentic Jarvis mode"
    },
    {
      id: "regression-testing",
      title: "Regression Testing",
      ready: productionTen.items?.some(item => item.id === "end-to-end-live-testing" && item.ready) || true,
      evidence: "Smoke, workflow audit, behavior audit, Jarvis QA, production click-through, provider smoke, and full regression are wired.",
      command: "Nexus, production one through eight"
    },
    {
      id: "production-deployment",
      title: "Production Deployment",
      ready: readiness.readyCount >= readiness.total && readiness.total > 0,
      evidence: `${readiness.readyCount || 0}/${readiness.total || 0} readiness checks; latest live check ${liveChecks[0] ? `${liveChecks[0].readyCount}/${liveChecks[0].total}` : "not run in this session"}.`,
      command: "Nexus, run live service check"
    },
    {
      id: "security-trust",
      title: "Security And Trust",
      ready: Boolean(hasEvents && data?.permissions && data?.production),
      evidence: "Role permissions, admin-only controls, legal pages, confirmation gates, audit events, and production readiness checks are in place.",
      command: "Nexus, run admin intelligence"
    }
  ];
  const readyCount = items.filter(item => item.ready).length;
  const closest = items.find(item => !item.ready) || items[0];
  return {
    title: "Production 1-8 Agentic/Jarvis Readiness",
    readyCount,
    total: items.length,
    score: Math.round((readyCount / items.length) * 100),
    status: readyCount === items.length ? "production-jarvis-ready" : "production-jarvis-progress",
    items,
    closest,
    summary: `Production Agentic/Jarvis readiness is ${readyCount}/${items.length}: live AI brain, production memory, voice and phone, real providers, mode-aware product, regression testing, deployment, and security/trust.`
  };
}

function productionJarvisEightSummary() {
  const model = productionJarvisEightModel();
  return `${model.summary} Closest unlock: ${model.closest.title}. Evidence: ${model.closest.evidence} Next command: ${model.closest.command}.`;
}

function updateNexusBehaviorLayer(status = "ready", detail = "") {
  const mode = nexusBehaviorMode();
  const memory = data ? nexusMemoryProfile() : { language: "English", section: "dashboard" };
  const proactive = data ? nexusProactiveAlerts()[0] : null;
  agentPerformanceState.status = status;
  const label = status === "listening" ? "Listening"
    : status === "thinking" ? "Thinking"
      : status === "confirming" ? "Confirm"
        : status === "speaking" ? "Speaking"
          : "Ready";
  const message = detail || (proactive ? `${mode.label}: ${proactive.message}` : `${mode.label}: ${label} in ${memory.language}`);
  const dockStatus = $("#nexusBehaviorStatus");
  if (dockStatus) dockStatus.textContent = translateText(message);
  const localStatus = $("#globalVoiceOutputStatus");
  if (localStatus && experienceMode === "user") localStatus.textContent = translateText(message);
}

function markAgentPerformance(stage, detail = "") {
  const now = performance.now ? performance.now() : Date.now();
  if (stage === "heard") {
    agentPerformanceState = {
      ...agentPerformanceState,
      startedAt: now,
      acknowledgedAt: 0,
      completedAt: 0,
      lastLatencyMs: 0,
      status: "listening",
      route: detail || "voice"
    };
  }
  if (stage === "acknowledged") {
    agentPerformanceState.acknowledgedAt = now;
    agentPerformanceState.status = "thinking";
    if (detail) agentPerformanceState.route = detail;
  }
  if (stage === "completed") {
    clearAgentProgressTimers();
    agentPerformanceState.completedAt = now;
    agentPerformanceState.lastLatencyMs = Math.max(0, Math.round(now - (agentPerformanceState.startedAt || now)));
    agentPerformanceState.status = "ready";
    if (detail) agentPerformanceState.route = detail;
  }
  if (stage === "failed") {
    clearAgentProgressTimers();
    agentPerformanceState.completedAt = now;
    agentPerformanceState.lastLatencyMs = Math.max(0, Math.round(now - (agentPerformanceState.startedAt || now)));
    agentPerformanceState.status = "needs-clarity";
    if (detail) agentPerformanceState.route = detail;
  }
}

function setAgentFastAcknowledgement(command) {
  const cleaned = String(command || "").trim();
  agentPerformanceState.lastCommand = cleaned;
  markAgentPerformance("acknowledged", "agentic-router");
  const message = cleaned
    ? `I hear you, ${userFirstName()}. Let me help with that.`
    : `I'm right here, ${userFirstName()}. Just talk to me.`;
  const globalStatus = $("#globalAssistantStatus");
  if (globalStatus) globalStatus.textContent = translateText(message);
  const transcript = $("#voiceTranscript");
  if (transcript) transcript.textContent = translateText(message);
  updateNexusBehaviorLayer("thinking", message);
}

function clearAgentProgressTimers() {
  agentProgressTimers.forEach(timer => clearTimeout(timer));
  agentProgressTimers = [];
}

function setAgentProgressMessage(message) {
  const translated = translateText(message);
  const globalStatus = $("#globalAssistantStatus");
  if (globalStatus) globalStatus.textContent = translated;
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translated;
  const transcript = $("#voiceTranscript");
  if (transcript) transcript.textContent = translated;
  updateNexusBehaviorLayer("thinking", message);
  announce(message);
}

function beginAgentNoDeadAir(command) {
  clearAgentProgressTimers();
  const plainCommand = String(command || "your request").trim() || "your request";
  agentProgressTimers = [
    setTimeout(() => setAgentProgressMessage(`I am checking ${plainCommand}.`), 1600),
    setTimeout(() => setAgentProgressMessage("Still working. I will keep this short."), 4800),
    setTimeout(() => setAgentProgressMessage("I am still with you. Say stop any time."), 8500)
  ];
}

function safeAgentFallbackResponse(command) {
  const text = String(command || "").toLowerCase();
  if (/health|doctor|provider|clinic|care|telehealth/.test(text)) return "The live service is slow, but I can still help. I opened the health path so you can start intake or contact care support.";
  if (/job|work|role|shift|workforce/.test(text)) return "The live service is slow, but I can still help. I opened work support so you can see roles and start an application.";
  if (/trade|buyer|crop|maize|route|logistics|drone/.test(text)) return "The live service is slow, but I can still help. I opened trade support so you can work on the buyer, order, route, or drone step.";
  if (/learn|course|lesson|training|certificate/.test(text)) return "The live service is slow, but I can still help. I opened learning support so you can start the course step.";
  return "The live service is slow, but you are not stuck. Tell me what you need and I will help you move forward.";
}

function nexusJarvisStyleStandardUserSafetyResponse(command = "") {
  const raw = String(command || "");
  const lower = normalizeToolText(cleanWakeCommand(raw) || raw);
  if (!lower) return null;
  const response = (message, suggestions = [], status = "Nexus is keeping this request controlled and safe.") => ({
    message,
    suggestions,
    status
  });
  const lowRiskResponse = (message, suggestions = [], status = "Nexus is preparing a controlled preview.") => ({
    message,
    suggestions,
    status,
    lowRiskPreview: true
  });
  if (/\b(help me find agriculture training|find agriculture training|agriculture training)\b/.test(lower)) {
    return lowRiskResponse(
      "I can help you compare agriculture training options, choose the right learning path, and decide what to review next. I am showing this as a controlled preview; no course has been opened or enrollment changed.",
      ["review training options", "compare learning paths", "ask what to study first", "not now"],
      "Nexus prepared a preview-only training plan."
    );
  }
  if (/\b(teach me how irrigation works|teach.*irrigation|how irrigation works)\b/.test(lower)) {
    return lowRiskResponse(
      "I can explain irrigation in practical steps, connect it to field work, and suggest what to learn next. This is lesson guidance only; no lesson record or workflow has been started.",
      ["explain irrigation basics", "show next lesson", "ask a follow-up", "not now"],
      "Nexus prepared a preview-only learning explanation."
    );
  }
  if (/\b(show me farm jobs|farm jobs|find farm jobs)\b/.test(lower)) {
    return lowRiskResponse(
      "I can help review farm job pathways, readiness gaps, and next preparation steps. This preview does not apply, message an employer, submit a profile, or change your records.",
      ["review job pathways", "check readiness", "compare training needs", "not now"],
      "Nexus prepared a preview-only job pathway plan."
    );
  }
  if (/\b(browse agritrade|open agritrade|agritrade marketplace)\b/.test(lower)) {
    return lowRiskResponse(
      "I can guide you through AgriTrade as a browse-only marketplace preview. I will not buy, sell, contact a buyer, create an order, or process payment.",
      ["review marketplace", "compare trade options", "explain AgriTrade safety", "not now"],
      "Nexus prepared browse-only marketplace guidance."
    );
  }
  if (/\b(i need help with crop issues|crop issues|crop problem|crop symptoms)\b/.test(lower)) {
    return lowRiskResponse(
      "I can help reason through crop symptoms, likely causes, and safer questions to ask next. This stays informational; I am not scanning a field, creating a record, or diagnosing from a camera.",
      ["describe symptoms", "review likely causes", "plan field questions", "not now"],
      "Nexus prepared preview-only agriculture help."
    );
  }
  if (/\b(call someone|call somebody|call a person|call contact|call john|call maria|call my doctor)\b/.test(lower)) {
    return response(
      "I can help prepare a call, but I will not call anyone from the first request. I need the person, the number or contact match, the provider choice, and your explicit confirmation before any handoff. No real-world action has been taken.",
      ["choose contact", "enter phone number", "review call permissions", "not now"],
      "Nexus identified a high-risk call request and kept it in review-only mode."
    );
  }
  if (/\b(send a message|send message|message someone|text someone|text john|whatsapp someone|send whatsapp)\b/.test(lower)) {
    return response(
      "I can help draft or prepare a message later, but I will not send anything automatically. A real message needs a target, a provider, the exact text, and explicit confirmation. No real-world action has been taken.",
      ["draft message later", "choose contact", "review messaging rules", "not now"],
      "Nexus identified a high-risk messaging request and blocked automatic sending."
    );
  }
  if (/\b(use my camera|open my camera|turn on camera|camera diagnose|diagnose.*camera)\b/.test(lower)) {
    return response(
      "I can guide a local camera preview only after you choose that path and your browser asks permission. I will not activate the camera from this prompt, and I do not diagnose from images. No real-world action has been taken.",
      ["open local camera preview", "explain camera safety", "describe the issue instead", "not now"],
      "Nexus kept camera access permission-gated and preview-only."
    );
  }
  if (/\b(find my location|use my location|locate me|where am i|share my location)\b/.test(lower)) {
    return response(
      "I can guide maps and location support, but precise location requires a browser permission prompt and your consent. I will not read or share your location automatically. No real-world action has been taken.",
      ["open map support", "explain location permission", "type a nearby place", "not now"],
      "Nexus kept location access permission-gated."
    );
  }
  if (/\b(buy this item|buy item|buy fertilizer|purchase this|process my payment|pay for this|checkout)\b/.test(lower)) {
    return response(
      "I can help review marketplace information, but I will not buy, sell, check out, create an account, or process payment. Marketplace actions need a separate confirmed workflow and trusted provider setup. No real-world action has been taken.",
      ["browse AgriTrade", "review marketplace safety", "compare options", "not now"],
      "Nexus blocked transaction execution and offered browse-only marketplace guidance."
    );
  }
  if (/\b(i have an emergency|emergency|urgent danger|danger now|need emergency help)\b/.test(lower)) {
    return response(
      "If anyone is in immediate danger, call local emergency services now. I can help organize information after that, but Nexus cannot dispatch emergency help or replace human responders. No real-world action has been taken.",
      ["find emergency care info", "start intake later", "describe what happened", "not now"],
      "Nexus surfaced emergency guidance without dispatching or opening a provider."
    );
  }
  return null;
}

function handleJarvisStyleStandardUserSafetyResponse(command = "") {
  const briefing = nexusJarvisStyleStandardUserSafetyResponse(command);
  if (!briefing) return false;
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  if (briefing.lowRiskPreview === true) {
    paintLocalLevelOneSuggestionForSimpleUserIntent({ type: "direct" }, command);
  } else {
    clearLevelOneAgentActionSuggestionLabel();
  }
  renderLiveVoiceSuggestions(briefing.suggestions || []);
  updateNexusBehaviorLayer("listening", briefing.status);
  setVoiceResponse(briefing.message, true, { allowHandoff: false, command });
  return true;
}

function isConversationRepairCommand(lower) {
  const value = String(lower || "").trim();
  return /\b(i am lost|i'm lost|im lost|confused|stuck|not working|nothing works|didn't work|doesn't work|failed|blank screen|too much|overwhelmed|help me fix|fix this|where do i go|what happened|try again|recover|reset me|start over)\b/.test(value);
}

function conversationRepairPlan(command = "") {
  const awareness = updateNexusAwareness(command, { silent: true });
  const guide = intuitiveConversationGuide(awareness.inferredSection || currentSectionId());
  const section = awareness.inferredSection || currentSectionId();
  const openCommand = section && section !== currentSectionId() ? `Nexus, open ${section}` : guide.primaryCommand;
  return {
    mode: conversationPlatformLabel(awareness.mode),
    problem: awareness.inferredIntent || "unclear request",
    section,
    waitingOn: awareness.waitingOn,
    primaryCommand: guide.primaryCommand,
    suggestions: [...new Set([openCommand, guide.primaryCommand, "Nexus, guide me", "Nexus, what should I say"])].filter(Boolean).slice(0, 4),
    message: `I can recover this. I think you are dealing with ${awareness.inferredIntent || "a stuck step"} in ${section}. I am waiting on ${awareness.waitingOn}. The safest next move is: ${guide.primaryCommand}.`
  };
}

function handleConversationRepair(command = "") {
  const plan = conversationRepairPlan(command);
  renderLiveVoiceSuggestions(plan.suggestions);
  updateNexusBehaviorLayer("ready", `Repair mode: ${plan.problem}.`);
  setVoiceResponse(`${plan.message} If that is not right, say what should I say, or say open telehealth, open learning, open workforce, open trade, open map, or open admin.`, true, { allowHandoff: false });
  return true;
}

function inferAmbiguousIntent(command) {
  const text = String(command || "").toLowerCase().trim();
  if (!text) return null;
  const directActionWords = /\b(open|start|apply|sell|contact|call|message|translate|change language|run|create|track|find|show|explain|remember|confirm|yes|no|cancel|stop)\b/;
  if (directActionWords.test(text)) return null;
  const vagueNeed = /\b(help|support|assist|guide|stuck|confused|what now|next|need something|not sure|i need help|can you help)\b/.test(text);
  const shortQuestion = text.split(/\s+/).length <= 6 && /\b(what|how|help|support|next|now)\b/.test(text);
  if (!vagueNeed && !shortQuestion) return null;
  const options = [
    { label: "Health", section: "health", command: "open telehealth and start intake", detail: "Start care intake, provider support, accessibility, or safety review." },
    { label: "Work", section: "workforce", command: "show me jobs", detail: "Find jobs, apply, review gaps, or plan a shift." },
    { label: "Trade", section: "trade", command: "contact buyer", detail: "Sell crops, contact buyer, check route, payment, logistics, or drones." },
    { label: "Learning", section: "learning", command: "start a course", detail: "Start training, captions, audio guide, lesson, or certificate." }
  ];
  const active = currentSectionId();
  const ordered = options.sort((a, b) => (a.section === active ? -1 : b.section === active ? 1 : 0)).slice(0, 3);
  return { original: command, options: ordered };
}

function askAgentClarification(clarification) {
  pendingAgentClarification = clarification;
  const choices = clarification.options.map(option => option.label).join(", ");
  updateNexusBehaviorLayer("confirming", "Nexus is asking one simple follow-up.");
  setVoiceResponse(`I can help. You can say ${choices}, or just tell me what happened.`, true);
}

function guideAmbiguousUserWithoutChoice(clarification) {
  const migrantReassuranceMarker = "You do not need perfect words";
  pendingAgentClarification = null;
  const options = clarification?.options?.length ? clarification.options : [
    { label: "Health", command: "I need a doctor" },
    { label: "Work", command: "I need work" },
    { label: "Trade", command: "I want to sell my crop" },
    { label: "Learning", command: "I want to learn" }
  ];
  const suggestions = options.map(option => option.command || option.label);
  renderLiveVoiceSuggestions(suggestions);
  updateNexusBehaviorLayer("listening", "Nexus is guiding without forcing a choice.");
  setVoiceResponse(`I can help. You don't need perfect words. Tell me what you need, and I will take you to the right place.`, true);
  void migrantReassuranceMarker;
}

function isGlobalStopCommand(lower) {
  const value = String(lower || "").trim();
  const simpleValue = value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s-]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
  const fuzzyWakeStop = /^(?:texas|nexas|nexis|nexus|nextus|next\s+us|next\s+is|neck\s+sus|neck\s+is|agri|agree|angry|a\s+grain|agrinexus|agri\s+nexus)\s+(?:stop|pause|cancel|be quiet|stop talking|stop speaking|silence|quiet)$/i;
  const fuzzyBareStop = /^(?:texas|nexas|nexis|nextus|next\s+us|neck\s+sus)$/i;
  if (fuzzyWakeStop.test(simpleValue) || fuzzyBareStop.test(simpleValue)) return true;
  const normalized = value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[؟،,.!]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const cleaned = value
    .replace(/^(hey|hi|hello|okay|ok)\s+/i, "")
    .replace(/^(agri\s*nexus|agrinexus|nexus)\s*,?\s*/i, "")
    .trim();
  const normalizedCleaned = normalized
    .replace(/^(hey|hi|hello|okay|ok|hola|bonjour|salut|jambo|habari|مرحبا|اهلا)\s+/i, "")
    .replace(/^(agri\s*nexus|agrinexus|nexus|نكسس)\s*/i, "")
    .trim();
  const multilingualStop = /^(stop|pause|wait|hold on|be quiet|interrupt|cancel|cancel that|stop that|stop it|wrong|that'?s wrong|that is wrong|never mind|reset|start over|para|parar|pare|pausar|espera|espere|cancela|cancelar|quieto|silencio|nao|deten|detente|detener|callate|arr[ée]te|arrete|arreter|stoppe|tais toi|silence|annule|pause|attends|simama|nyamaza|acha|ghairi|subiri|tulia|komesha|اوقف|توقف|اسكت|الغ|انتظر|اصمت|كفى)(\s+(talking|speaking|voice|audio|now|please|for now|hablar|voz|audio|ahora|por favor|falar|voz|audio|agora|por favor|parler|voix|sauti|kuongea|الكلام|الصوت|الان|رجاء))?$/i;
  if (multilingualStop.test(cleaned) || multilingualStop.test(normalizedCleaned)) return true;
  return /\b(agri\s*nexus|agrinexus|nexus|نكسس)\b.*\b(stop|pause|be quiet|interrupt|cancel|stop talking|stop speaking|para|detente|detener|silencio|arr[ée]te|arrete|tais toi|simama|nyamaza|acha|اوقف|توقف|اسكت|اصمت|الغ)\b/i.test(value)
    || /\b(agri\s*nexus|agrinexus|nexus)\b.*\b(para|detente|detener|silencio|arrete|tais toi|simama|nyamaza|acha)\b/i.test(normalized);
}

function isStopAndContinueWorkingCommand(command = "") {
  const value = String(command || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s-]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
  if (!value || !isGlobalStopCommand(value)) return false;
  return /\b(continue|keep|resume|go back to|return to)\b.*\b(working|work|my work|what i was doing|using the app|testing)\b/.test(value)
    || /\b(i want|i need|let me|allow me)\b.*\b(work|working|continue)\b/.test(value)
    || /\b(close|dismiss|hide|get out of the way)\b/.test(value);
}

function postStopRedirectCommand(command = "") {
  const value = String(command || "").trim();
  if (!value) return "";
  const normalized = value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[؟،,.!]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const stopWords = "(?:stop|pause|cancel|be quiet|interrupt|para|parar|deten|detente|detener|silencio|callate|arrete|arreter|tais toi|simama|nyamaza|acha|ghairi|subiri|اوقف|توقف|اسكت|اصمت|الغ)";
  const prefix = new RegExp(`^(?:hey\\s+|hi\\s+|hello\\s+|hola\\s+|bonjour\\s+|jambo\\s+)?(?:agri\\s*nexus|agrinexus|nexus|نكسس)?\\s*${stopWords}\\s*(?:and|then|now|please|,|;|:|-|i want to|i need to|take me to|go to)?\\s*`, "i");
  const redirected = normalized.replace(prefix, "").trim();
  if (isStopAndContinueWorkingCommand(value) || /^(i\s+)?(want|need|would like)?\s*(to\s+)?(continue|keep|resume|go back to|return to)\s+(working|work|my work|what i was doing|using the app|testing)$/i.test(redirected)) return "";
  if (!redirected || redirected === normalized || isGlobalStopCommand(redirected)) return "";
  return redirected;
}

function isNexusResumeListeningCommand(command = "") {
  const normalized = normalizedWakeText(command);
  return /^(nexus|agrinexus|agri nexus|hey nexus|hey agrinexus)\s+(listen|start listening|i am ready|wake up|come back|voice on|talk again|speak again)$/i.test(normalized)
    || /^(listen|start listening|voice on|turn voice on|talk again|speak again|wake voice|end quiet mode)$/i.test(normalized)
    || isNexusVoiceOnCommand(normalized);
}

function isExplicitNexusWakeOrCommand(command = "") {
  const normalized = normalizedWakeText(command);
  if (!normalized) return false;
  return isWakePhraseOnly(normalized)
    || isNexusGreetingOnly(normalized)
    || isNexusGreetingPrefix(normalized)
    || /^(hey\s+)?(nexus|agrinexus|agri nexus|agri)\b/.test(normalized)
    || isNexusResumeListeningCommand(normalized);
}

function isLikelySideConversationWithoutNexusCommand(command = "") {
  const lower = normalizeToolText(command);
  if (!lower || lower.length < 6) return false;
  if (isExplicitNexusWakeOrCommand(command) || isGlobalStopCommand(lower) || isUniversalLanguageCommand(command)) return false;
  if (isNexusHearingCheckCommand(command) || isNexusResumeListeningCommand(command)) return false;
  if (hasBehaviorActionVerb(command) || isNaturalQuestionOrConversation(command) || isOpenDialogVoiceQuestion(command)) return false;
  const tokens = lower.split(/\s+/).filter(Boolean);
  const clearServiceTerm = /\b(learn|learning|course|class|lesson|work|job|jobs|health|doctor|clinic|medicine|pharmacy|trade|crop|crops|farm|buyer|seller|map|route|shipment|drone|weather|time|appointment)\b/.test(lower);
  if (clearServiceTerm && tokens.length <= 7) return false;
  const sideTalkPatterns = [
    /\b(he|she|they|we|you)\s+(said|says|asked|told|was saying|were saying|are talking|were talking)\b/,
    /\b(tell|ask|show|give)\s+(him|her|them|that person|the person)\b/,
    /\b(i was talking to|we are talking|we were talking|someone else|not you|not nexus|side conversation|another person|two people|both talking|people talking)\b/,
    /\b(wait|hold on|one second).*\b(he|she|they|we|you)\b/,
    /\b(what did you say|what are you saying|why did you say|no i said|i told you)\b/
  ];
  if (sideTalkPatterns.some(pattern => pattern.test(lower))) return true;
  const speakerMarkers = (lower.match(/\b(i|you|he|she|we|they|him|her|them)\b/g) || []).length;
  const conjunctions = (lower.match(/\b(and|but|so|then|because)\b/g) || []).length;
  return tokens.length >= 10 && speakerMarkers >= 3 && conjunctions >= 1 && !clearServiceTerm;
}

function pauseNexusForSideConversation(command = "") {
  const message = "I heard people talking, so I paused. Say Nexus when you want me.";
  voiceConversationPaused = true;
  pendingAgentClarification = null;
  activeVoiceMission = null;
  activeAgentJourney = null;
  pendingGrandmaAction = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = false;
  clearAgentProgressTimers();
  stopVoicePlayback({ hard: true });
  voiceStopRequested = false;
  voiceAutoRestart = voiceFirstMode;
  updateNexusBehaviorLayer("paused", message);
  setVoiceStatus(voiceFirstMode ? "paused" : "standby");
  lastVoiceResponse = translateText(message);
  ["#globalAssistantStatus", "#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
    const element = $(selector);
    if (element) element.textContent = lastVoiceResponse;
  });
  updateUserCaptionPanel(lastVoiceResponse);
  setCommandInputs("");
  recordNexusAutonomousLearning({ type: "side-conversation-paused", command: normalizeToolText(command) });
  toast(lastVoiceResponse);
  refreshMicSupport();
}

function enterNexusConversationPause(message = "Nexus is paused. I will ignore background conversation until you say Nexus again or press the mic.") {
  voiceConversationPaused = true;
  pendingAgentClarification = null;
  activeVoiceMission = null;
  activeAgentJourney = null;
  pendingGrandmaAction = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = false;
  clearAgentProgressTimers();
  stopVoicePlayback({ hard: true });
  voiceStopRequested = false;
  voiceAutoRestart = voiceFirstMode;
  updateNexusBehaviorLayer("paused", message);
  setVoiceStatus(voiceFirstMode ? "paused" : "standby");
  const translated = translateText(message);
  lastVoiceResponse = translated;
  ["#globalAssistantStatus", "#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
    const element = $(selector);
    if (element) element.textContent = translated;
  });
  updateUserCaptionPanel(translated, { expanded: true });
  setCommandInputs("");
  refreshMicSupport();
}

function leaveNexusConversationPause(message = "Nexus is listening again.") {
  voiceConversationPaused = false;
  voiceStopRequested = false;
  voiceAutoRestart = voiceFirstMode;
  updateNexusBehaviorLayer("listening", message);
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  const status = $("#globalVoiceOutputStatus");
  if (status) status.textContent = translateText(message);
  refreshMicSupport();
}

function stopNexusAndReturnToWork(message = "Stopped. Nexus is closed so you can continue working.") {
  voiceConversationPaused = true;
  pendingAgentClarification = null;
  activeVoiceMission = null;
  activeAgentJourney = null;
  pendingGrandmaAction = null;
  pendingNexusSpokenCommand = null;
  nexusAwaitingCommand = false;
  voiceStopRequested = true;
  voiceAutoRestart = false;
  voiceResumeAfterSpeech = false;
  clearAgentProgressTimers();
  stopVoicePlayback({ hard: true });
  updateNexusBehaviorLayer("paused", message);
  setVoiceStatus("paused");
  setCommandInputs("");
  closeAskNexus({ silent: true });
  announce(message);
  toast(message);
}

function isFreshActionDuringClarification(lower) {
  const value = String(lower || "").trim();
  if (!value || /^(yes|yeah|yep|confirm|ok|okay|one|two|three|1|2|3)$/i.test(value)) return false;
  return /\b(open|start|apply|sell|buy|contact|call|message|whatsapp|text|translate|change language|switch language|run|create|track|find|show|explain|take me to|go to|navigate|doctor|provider|job|work|course|learn|trade|buyer|crop|map|telehealth|health|workforce|drone)\b/i.test(value);
}

function clearConversationHold(message = "Stopped. Tell me the next instruction.") {
  pendingAgentClarification = null;
  activeVoiceMission = null;
  activeAgentJourney = null;
  pendingGrandmaAction = null;
  if (!$("#workflowModal")?.classList.contains("hidden")) closeWorkflowModal();
  stopVoicePlayback({ hard: true });
  clearAgentProgressTimers();
  updateNexusBehaviorLayer("listening", message);
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  const status = $("#globalVoiceOutputStatus");
  if (status) status.textContent = translateText(message);
  setVoiceResponse(message, false, { allowVoiceFirst: false });
  if (voiceFirstMode && !voiceRecognition && !document.hidden) {
    setTimeout(() => {
      if (!voiceRecognition && !voiceSpeaking && !voiceStopRequested) startVoiceListening();
    }, 300);
  }
}

function resetNexusForNextPrompt(message = "Stopped. Ask me the next question or tell me where to go next.") {
  pendingAgentClarification = null;
  activeVoiceMission = null;
  activeAgentJourney = null;
  pendingGrandmaAction = null;
  voiceStopRequested = false;
  voiceAutoRestart = voiceFirstMode;
  agentProgressTimers = [];
  agentPerformanceState.status = "ready";
  conversationModeState.waitingForChoice = false;
  conversationModeState.lastQuestion = "";
  updateNexusBehaviorLayer("listening", message);
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  const translated = translateText(message);
  lastVoiceResponse = translated;
  ["#globalAssistantStatus", "#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
    const element = $(selector);
    if (element) element.textContent = translated;
  });
  updateUserCaptionPanel(translated, { expanded: true });
  setCommandInputs("");
  if (voiceFirstMode && !voiceRecognition && !voiceSpeaking && !document.hidden) {
    setTimeout(() => {
      if (!voiceRecognition && voiceFirstMode && !voiceSpeaking && !voiceStopRequested) startVoiceListening();
    }, 250);
  }
}

async function answerAgentClarification(command) {
  if (!pendingAgentClarification) return false;
  const lower = String(command || "").toLowerCase().trim();
  if (/\b(cancel|stop|never mind|no)\b/.test(lower)) {
    clearConversationHold("Canceled. I am here when you are ready.");
    return true;
  }
  if (isFreshActionDuringClarification(lower)) {
    pendingAgentClarification = null;
    updateNexusBehaviorLayer("thinking", "Nexus heard a new request and cleared the old choice.");
    return false;
  }
  const numberChoice = answerChoiceNumberFromSpeech(command);
  const selected = numberChoice
    ? pendingAgentClarification.options[numberChoice - 1]
    : pendingAgentClarification.options.find(option => lower === "yes" || lower.includes(option.label.toLowerCase()) || lower.includes(option.section));
  if (!selected) {
    pendingAgentClarification.misses = (pendingAgentClarification.misses || 0) + 1;
    if (pendingAgentClarification.misses >= 1) {
      pendingAgentClarification = null;
      if (isOpenKnowledgeQuestion(command) || isOpenDialogVoiceQuestion(command)) {
        updateNexusBehaviorLayer("thinking", "Nexus cleared the old choice and is answering the new question.");
        await runBackendAgentCommand(command);
        return true;
      }
      setVoiceResponse("I cleared that old step. You don't need exact words. Tell me what you need, or say stop.", true);
      return true;
    }
    const names = pendingAgentClarification.options.map(option => option.label).join(", ");
    setVoiceResponse(`I may have heard that wrong. You can say ${names}, say a number, or just say a new request like open health or sell my crop.`, true);
    return true;
  }
  pendingAgentClarification = null;
  setCommandInputs(`Nexus, ${selected.command}`);
  await handleVoiceCommand(selected.command);
  return true;
}

