function isVoiceMissionRequest(command = "") {
  const lower = String(command || "").toLowerCase();
  return /\b(help|assist|walk me through|guide|start|run|i need|i want|please)\b/.test(lower)
    && /\b(sell|selling|crop|produce|harvest|doctor|health|job|work|learn|course|training)\b/.test(lower)
    && Object.values(voiceMissionTemplates()).some(item => item.match.test(lower));
}

async function startVoiceMission(command = "") {
  const lower = String(command || "").toLowerCase();
  const mission = Object.values(voiceMissionTemplates()).find(item => item.match.test(lower));
  if (!mission) return false;
  activeVoiceMission = { ...mission, index: 0, startedAt: Date.now(), mode: conversationPlatformMode() };
  recordVoiceEvent(`Mission started: ${mission.label}. First step: ${mission.steps[0].label}.`, "progress");
  pendingAgentClarification = null;
  setVoiceResponse(`We can do this together. I am starting the ${mission.label} and opening the first step now.`, true);
  await continueVoiceMission();
  return true;
}

async function continueVoiceMission() {
  if (!activeVoiceMission) return false;
  const step = activeVoiceMission.steps[activeVoiceMission.index];
  if (!step) {
    recordVoiceEvent(`${activeVoiceMission.label} is complete.`, "done");
    setVoiceResponse(`${activeVoiceMission.label} is complete.`, true);
    activeVoiceMission = null;
    return true;
  }
  recordVoiceEvent(`Mission step ${activeVoiceMission.index + 1}: ${step.label}.`, "progress");
  activeVoiceMission.index += 1;
  await handleVoiceCommand(step.command);
  return true;
}

function voiceMissionStatus() {
  if (!activeVoiceMission) return "No voice mission is active. Say help me sell my crop, I need a doctor, I need work, or help me learn.";
  const current = activeVoiceMission.steps[activeVoiceMission.index] || null;
  const done = activeVoiceMission.steps.slice(0, activeVoiceMission.index).map(step => step.label).join(", ") || "none yet";
  return `${activeVoiceMission.label}: completed ${done}. Next step: ${current ? current.label : "mission complete"}. Say continue mission to keep going.`;
}

function voiceWorkflowStatus() {
  const open = pendingWorkflow ? `${pendingWorkflow.title || "workflow"} is open and waiting for confirmation.` : "No workflow window is open.";
  const events = voiceEventStream.slice(0, 3).map(item => item.message).join(" ");
  return `${open} ${activeAgentJourneySummary()} ${voiceMissionStatus()} Latest voice events: ${events || "none yet"}.`;
}

function activeWorkflowFieldCandidates() {
  const inlineFields = $$(".user-inline-workflow:not(.hidden) [data-workflow-field]");
  if (inlineFields.length) return inlineFields;
  if (!$("#workflowModal")?.classList.contains("hidden")) return $$("#workflowModal [data-workflow-field]");
  return [];
}

function healthIntakeVoiceFieldMatch(command = "") {
  const providerMode = isHealthProviderWorkflow(pendingWorkflow);
  if (!isHealthIntakeWorkflow(pendingWorkflow) && !providerMode) return null;
  const raw = String(command || "").trim();
  const lower = normalizeToolText(raw);
  if (!raw || isUniversalLanguageCommand(raw) || isGlobalStopCommand(lower)) return null;
  const nameMatch = raw.match(/\b(?:patient name is|household name is|my name is|this is|name is|i am|i'm|im|call me)\s+([\p{L}\p{M}' -]{2,48})\b/iu);
  if (nameMatch) return { requested: "patient household name", value: cleanSpokenUserName(nameMatch[1]) || nameMatch[1].trim() };
  const languageMatch = lower.match(/\b(?:preferred language is|language is|speak|speaks|use)\s+(english|french|kiswahili|swahili|arabic|spanish|portuguese)\b/)
    || /^(english|french|kiswahili|swahili|arabic|spanish|portuguese)$/.exec(lower);
  if (languageMatch) return { requested: "preferred language", value: ({ swahili: "sw", kiswahili: "sw", english: "en", french: "fr", arabic: "ar", spanish: "es", portuguese: "pt" }[languageMatch[1]] || languageMatch[1]) };
  const contactMatch = lower.match(/\b(whatsapp|sms|text|call|phone|callback|community aide|caregiver)\b/);
  if (contactMatch && /\b(contact|reach|call|message|whatsapp|sms|text|phone|callback|aide|caregiver|video)\b/.test(lower)) {
    const contactValues = {
      call: "Low-bandwidth callback",
      phone: "Low-bandwidth callback",
      callback: "Low-bandwidth callback",
      text: "SMS",
      sms: "SMS",
      whatsapp: "WhatsApp",
      "community aide": "Community aide",
      caregiver: "Community aide"
    };
    const value = contactValues[contactMatch[1]] || contactMatch[1];
    return { requested: providerMode ? "best provider connection" : "best contact method", value };
  }
  if (providerMode && /\b(video call|video|camera)\b/.test(lower)) {
    return { requested: "best provider connection", value: "video call" };
  }
  const urgencyMatch = lower.match(/\b(routine|priority|urgent|high|emergency)\b/);
  if (urgencyMatch && /\b(urgency|urgent|emergency|serious|priority|bad|danger)\b/.test(lower)) {
    return { requested: "urgency", value: urgencyMatch[1] === "urgent" ? "Priority" : urgencyMatch[1].replace(/^./, char => char.toUpperCase()) };
  }
  if (/\b(caption|captions|large print|blind|vision|deaf|hearing|audio|caregiver|aide|screen reader)\b/.test(lower)) {
    return { requested: "accessibility needs", value: raw.replace(/[.?!]$/, "") };
  }
  if (/\b(photo|video|wound|rash|swelling|injury|bleeding|fall|show provider|camera)\b/.test(lower)) {
    return { requested: "photo video note", value: raw.replace(/[.?!]$/, "") };
  }
  if (/\b(i need|need|pain|fever|medicine|doctor|clinic|sick|injury|hurt|headache|stomach|cough|dizzy|weak|bleeding|swelling)\b/.test(lower)) {
    return { requested: providerMode ? "what kind of help is needed" : "primary health need", value: raw.replace(/[.?!]$/, "") };
  }
  return null;
}

function fillWorkflowFieldByVoice(command = "") {
  if (!pendingWorkflow) return false;
  const candidates = activeWorkflowFieldCandidates();
  if (!candidates.length) return false;
  const naturalMatch = healthIntakeVoiceFieldMatch(command);
  const match = naturalMatch || [/(?:set|change|enter|put|make)\s+(.+?)\s+(?:to|as)\s+(.+)/i, /(.+?)\s+(?:is|equals)\s+(.+)/i]
    .map(pattern => command.match(pattern))
    .find(Boolean);
  if (!match) return false;
  const requested = normalizeToolText(naturalMatch ? match.requested : match[1]);
  const value = String(naturalMatch ? match.value : match[2]).trim().replace(/[.?!]$/, "");
  const field = candidates.find(item => {
    const label = normalizeToolText(item.closest("label")?.textContent || item.dataset.workflowField || "");
    const name = normalizeToolText(item.dataset.workflowField || "");
    return label.includes(requested) || requested.includes(name) || name.includes(requested);
  });
  if (!field || !value) return false;
  field.value = value;
  field.dispatchEvent(new Event("input", { bubbles: true }));
  field.dispatchEvent(new Event("change", { bubbles: true }));
  recordVoiceEvent(`Updated ${field.dataset.workflowField} to ${value}.`, "progress");
  const next = isHealthProviderWorkflow(pendingWorkflow) ? nextGuidedProviderPrompt(field.dataset.workflowField) : nextGuidedIntakePrompt(field.dataset.workflowField);
  setVoiceResponse(next ? `I added that. ${next}` : `I added that. Say yes when the intake looks right.`, true);
  return true;
}

function isNewServiceRequestOverWorkflow(command = "") {
  const lower = normalizeToolText(command);
  if (!lower) return false;
  if (isNexusCommandConfirmation(lower) || isNexusCommandRejection(lower)) return false;
  if (/^(read|repeat|say that again|yes|no|cancel|close|stop|routine|priority|urgent|high|emergency|english|spanish|french|kiswahili|swahili|arabic|portuguese)$/i.test(lower)) return false;
  if (/^(patient name is|my name is|name is|call me|phone is|number is|use whatsapp|sms|video call|call me)\b/.test(lower)) return false;
  const requestShape = /\b(can you|could you|please|i need|need|i want|want|help me|find|open|show|build|make|start|apply|sell|track|where|what can you do|how can you help)\b/.test(lower);
  const domainShape = /\b(work|job|clinic|doctor|provider|medicine|pharmacy|telehealth|health|patient|baby|child|sick|crop|farm|field|buyer|sell|trade|map|route|tracking|caption|captions|transcript|course|learn|learning|lesson|training)\b/.test(lower);
  const shortProblem = /\b(my crop is bad|crop is bad|crop bad|field is bad|baby is sick|child is sick|i need a doctor|need a doctor|i want a doctor|doctor help|need medicine|i want medicine|need work|clinic near me|find my clinic|find me a clinic|build captions|telehealth captions)\b/.test(lower);
  return shortProblem || (requestShape && domainShape);
}

function clearOpenWorkflowForNewVoiceRequest(command = "") {
  const visibleInlineWorkflow = $(".user-inline-workflow:not(.hidden)");
  if (visibleInlineWorkflow) visibleInlineWorkflow.classList.add("hidden");
  $("#workflowModal")?.classList.add("hidden");
  pendingWorkflow = null;
  pendingGrandmaAction = null;
  pendingAgentClarification = null;
  updateNexusBehaviorLayer("thinking", `Nexus switched to the new request: ${command}`);
  recordNexusAutonomousLearning({ type: "workflow-switched", command });
}

function voiceReadbackText() {
  if (pendingWorkflow && !$("#workflowModal")?.classList.contains("hidden")) return workflowSpeechText();
  return `${modeSpecificVoicePersona()} Current section is ${currentSectionId()}. ${activeVoiceMission ? voiceMissionStatus() : "Ask me to open a service, start a mission, fill a form, or explain the next step."}`;
}

function voiceErrorRecovery(error, command = "") {
  const message = error?.message || String(error || "That did not work.");
  recordVoiceEvent(`Recovery: ${message}`, "error");
  const tool = bestDynamicVoiceTool(command);
  if (tool) {
    pendingAgentClarification = { original: command, options: [{ label: tool.label, section: tool.section || currentSectionId(), command: tool.command || `${tool.workflow} ${tool.action}`, detail: "Retry with the closest registered tool." }] };
    setVoiceResponse(`That did not go through cleanly, but you are not stuck. I found ${tool.label}. Say yes and I will try it, or tell me what you want instead.`, true);
    return true;
  }
  setVoiceResponse("That did not go through cleanly, but I can still help. Tell me what you need, even if the words are not perfect.", true);
  return true;
}

function htmlSafe(value) {
  return String(value ?? "").replace(/[&<>"']/g, char => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;", "'": "&#39;" }[char]));
}

