function nexusAutonomousActionTypeForRoute(route = {}, actionTypes = {}) {
  const domain = String(route.intentDomain || "");
  if (domain === "communication-request") return actionTypes.CALL || "call";
  if (domain === "appointment-request") return actionTypes.APPOINTMENT || "appointment";
  if (domain === "marketplace-request") return actionTypes.MARKETPLACE || "marketplace";
  if (domain === "payment-request") return actionTypes.PAYMENT || "payment";
  if (domain === "location-request") return actionTypes.LOCATION || "location";
  if (domain === "camera-media-request") return actionTypes.CAMERA_MEDIA || "camera-media";
  if (domain === "health-medical-request") return actionTypes.HEALTH_MEDICAL || "health-medical";
  if (domain === "emergency-request") return actionTypes.EMERGENCY || "emergency";
  return actionTypes.INFORMATION || "information";
}

function nexusPermissionDataNeededForRoute(route = {}) {
  const domain = String(route.intentDomain || "");
  if (domain === "communication-request") return ["resolved recipient", "visible provider", "message or call purpose", "explicit user approval"];
  if (domain === "appointment-request") return ["verified provider", "appointment purpose", "available time window", "explicit user approval"];
  if (domain === "marketplace-request") return ["verified item or listing", "transaction terms", "counterparty review", "explicit user approval"];
  if (domain === "payment-request") return ["verified payment provider", "amount preview", "recipient review", "explicit user approval"];
  if (domain === "location-request") return ["location purpose", "permission prompt", "sharing boundary", "explicit user approval"];
  if (domain === "camera-media-request") return ["media purpose", "camera or upload permission", "sharing boundary", "explicit user approval"];
  if (domain === "health-medical-request") return ["verified health provider", "consent boundary", "medical safety review", "explicit user approval"];
  if (domain === "emergency-request") return ["local emergency service boundary", "safety escalation notice", "explicit user action outside Nexus"];
  return ["clear action target", "verified integration readiness", "explicit user approval"];
}

function nexusAutonomousPreviewSteps(route = {}) {
  const domain = String(route.intentDomain || "general-assistant");
  if (domain === "agriculture-support") {
    return [
      { title: "Review agriculture request", description: "Nexus checks the prompt for safe agriculture support.", riskLevel: "low" },
      { title: "Show agriculture support card", description: "Nexus keeps guidance general unless a verified source is connected.", riskLevel: "low" },
      { title: "Stop before action", description: "No provider, marketplace, location, camera, or payment action is started.", riskLevel: "low" }
    ];
  }
  if (domain === "source-review") {
    return [
      { title: "Review source status", description: "Nexus explains whether guidance is source-backed or general.", riskLevel: "low" },
      { title: "Show confidence and freshness", description: "Nexus does not invent a verified source, freshness, or confidence.", riskLevel: "low" }
    ];
  }
  if (route.permissionRequired || route.blocked) {
    return [
      { title: "Identify requested action", description: "Nexus recognizes this request needs permission, verified integrations, or a safety block.", riskLevel: route.riskLevel || "high" },
      { title: "Show safety boundary", description: "Nexus explains what would be required before any future action.", riskLevel: route.riskLevel || "high" },
      { title: "Stop before execution", description: "No provider, message, call, appointment, transaction, permission, media, medical, or emergency action has started.", riskLevel: route.riskLevel || "high" }
    ];
  }
  return [
    { title: "Understand request", description: "Nexus classifies the prompt and prepares review-only next steps.", riskLevel: "low" },
    { title: "Answer safely", description: "Nexus can provide information without triggering real-world actions.", riskLevel: "low" }
  ];
}

function nexusEvidenceModeForRoute(route = {}, helpers = nexusAutonomousRuntimeHelpers()) {
  if (helpers.modeEvidenceRequirements && typeof helpers.modeEvidenceRequirements.modeForIntentDomain === "function") {
    return helpers.modeEvidenceRequirements.modeForIntentDomain(route.intentDomain);
  }
  const domain = String(route.intentDomain || "");
  if (domain === "agriculture-support") return "agriculture";
  if (domain === "health-medical-request" || domain === "appointment-request" || domain === "emergency-request" || domain === "camera-media-request") return "telehealth";
  if (domain === "marketplace-request" || domain === "payment-request") return "marketplace";
  if (domain === "location-request") return "maps";
  return "general";
}

function nexusEvidenceSourcesForRoute(route = {}) {
  if (route.intentDomain === "agriculture-support" && window.NexusAgricultureSourceRegistry?.normalizeAgricultureSourceRecord) {
    const normalized = window.NexusAgricultureSourceRegistry.normalizeAgricultureSourceRecord(null);
    return {
      sourceSupportedClaims: [],
      nexusInferences: [
        "Nexus inferred this is an agriculture support request from the prompt.",
        "No verified agriculture source contract or live source lookup was used for this preview."
      ],
      limitations: [
        normalized.disclosure,
        normalized.escalation
      ]
    };
  }
  if (route.intentDomain === "source-review") {
    return {
      sourceSupportedClaims: [],
      nexusInferences: [
        "Nexus inferred the user is asking about source, freshness, confidence, or verification status.",
        "No live source lookup was performed for this preview."
      ],
      limitations: ["Nexus must not invent a source, citation, freshness label, or confidence level."]
    };
  }
  if (route.permissionRequired || route.blocked) {
    return {
      sourceSupportedClaims: [],
      nexusInferences: [
        `Nexus inferred this request belongs to ${route.intentDomain || "a restricted"} domain.`,
        "The request requires permission, a verified integration, an audit path, or a safety block before any future action."
      ],
      limitations: [route.userVisibleDisclosure || "No action has been taken."]
    };
  }
  return {
    sourceSupportedClaims: [],
    nexusInferences: [
      "Nexus inferred a general assistant request from the prompt.",
      "No verified source contract or live source lookup was used for this preview."
    ],
    limitations: ["This preview is general guidance only."]
  };
}

function buildNexusEvidencePacketForPreview(route = {}, helpers = nexusAutonomousRuntimeHelpers()) {
  if (!helpers.evidencePacket || typeof helpers.evidencePacket.buildEvidencePacket !== "function") return null;
  const mode = nexusEvidenceModeForRoute(route, helpers);
  const modeRequirements = helpers.modeEvidenceRequirements && typeof helpers.modeEvidenceRequirements.getModeEvidenceRequirements === "function"
    ? helpers.modeEvidenceRequirements.getModeEvidenceRequirements(mode)
    : null;
  const evidenceInputs = nexusEvidenceSourcesForRoute(route);
  const packet = helpers.evidencePacket.buildEvidencePacket({
    mode,
    modeLabel: modeRequirements?.label,
    modeRequirements,
    sourceSupportedClaims: evidenceInputs.sourceSupportedClaims,
    nexusInferences: evidenceInputs.nexusInferences,
    limitations: [
      ...(Array.isArray(evidenceInputs.limitations) ? evidenceInputs.limitations : []),
      ...(Array.isArray(modeRequirements?.limitations) ? modeRequirements.limitations : [])
    ],
    blockedClaims: Array.isArray(modeRequirements?.blockedClaims) ? modeRequirements.blockedClaims : []
  });
  if (typeof helpers.evidencePacket.assertEvidencePacketSafe === "function" && !helpers.evidencePacket.assertEvidencePacketSafe(packet)) return null;
  return packet;
}

function nexusEvidenceMarkup(packet) {
  if (!packet) return "";
  const sources = Array.isArray(packet.sources) && packet.sources.length
    ? packet.sources.map(source => `<li>${htmlSafe(source.name)} (${htmlSafe(source.sourceType)}): ${htmlSafe(source.freshnessLabel)}; ${htmlSafe(source.confidenceLabel)}</li>`).join("")
    : "<li>No verified source connected for this preview.</li>";
  const claims = Array.isArray(packet.sourceSupportedClaims) && packet.sourceSupportedClaims.length
    ? packet.sourceSupportedClaims.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>No source-supported claims are asserted in this preview.</li>";
  const inferences = Array.isArray(packet.nexusInferences) && packet.nexusInferences.length
    ? packet.nexusInferences.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>Nexus did not add extra inference details.</li>";
  const limitations = Array.isArray(packet.limitations) && packet.limitations.length
    ? packet.limitations.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>Use this as general guidance only.</li>";
  const blockedClaims = Array.isArray(packet.blockedClaims) && packet.blockedClaims.length
    ? packet.blockedClaims.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>No completed action, live source, provider contact, or permission grant is claimed.</li>";

  return `
    <section class="nexus-preview-review-block" data-nexus-evidence-verification="true">
      <h4>Evidence & Verification</h4>
      <p>${htmlSafe(packet.disclosure)}</p>
      <dl>
        <div><dt>Mode</dt><dd>${htmlSafe(packet.modeLabel)}</dd></div>
        <div><dt>Source status</dt><dd>${htmlSafe(packet.sourceStatus)}</dd></div>
        <div><dt>Freshness</dt><dd>${htmlSafe(packet.freshnessLabel)}</dd></div>
        <div><dt>Confidence</dt><dd>${htmlSafe(packet.confidenceLabel)}</dd></div>
      </dl>
      <strong>Verified sources</strong>
      <ul>${sources}</ul>
      <strong>Source-supported claims</strong>
      <ul>${claims}</ul>
      <strong>Nexus inferences</strong>
      <ul>${inferences}</ul>
      <strong>Limits and required verification</strong>
      <ul>${limitations}</ul>
      <strong>Claims Nexus is not making</strong>
      <ul>${blockedClaims}</ul>
      <p>No provider contact, call, message, appointment, payment, marketplace transaction, location share, camera action, medical action, pharmacy action, emergency dispatch, backend write, storage write, network lookup, or external handoff has occurred.</p>
    </section>
  `;
}

function renderNexusAutonomousRuntimePreview(prompt = "", options = {}) {
  const text = String(prompt || "").replace(/\s+/g, " ").trim();
  const source = String(options.source || "").toLowerCase();
  if (
    experienceMode === "user" &&
    (source === "voice" || source.includes("genesis") || source.includes("orb")) &&
    !options.explicitUserRequestedPreview
  ) {
    setNexusGenesisTrustChainState("waiting", {
      transcript: text,
      visibleFeedback: "Nexus will stay in conversation until you ask for a workflow.",
      reason: "standard-user-preview-isolated"
    });
    return null;
  }
  const helpers = nexusAutonomousRuntimeHelpers();
  if (!text || !helpers.router || typeof helpers.router.routeNexusIntent !== "function") return null;
  const route = helpers.router.routeNexusIntent(text);
  if (!route || typeof route !== "object") return null;
  const actionTypes = helpers.actionContract?.ACTION_TYPES || {};
  const actionContract = typeof helpers.actionContract?.buildActionContract === "function"
    ? helpers.actionContract.buildActionContract({
      actionType: nexusAutonomousActionTypeForRoute(route, actionTypes),
      summary: route.userVisibleDisclosure || "Nexus can prepare a review-only preview."
    })
    : null;
  const planPreview = typeof helpers.plannerPreview?.buildPlannerPreview === "function"
    ? helpers.plannerPreview.buildPlannerPreview({
      title: "Nexus Plan Preview",
      steps: nexusAutonomousPreviewSteps(route)
    })
    : null;
  const needsTrustPreview = route.permissionRequired === true || route.blocked === true;
  const permissionReview = needsTrustPreview && typeof helpers.permissionReview?.buildPermissionReview === "function"
    ? helpers.permissionReview.buildPermissionReview({
      actionType: route.intentDomain || actionContract?.actionType || "review-only-action",
      domain: route.intentDomain || "general",
      riskLevel: route.riskLevel || actionContract?.riskLevel || "high",
      summary: route.userVisibleDisclosure || actionContract?.summary || "Nexus can explain what would be required, but cannot execute this now.",
      dataNeeded: nexusPermissionDataNeededForRoute(route),
      blocked: route.blocked === true
    })
    : null;
  const auditEvent = needsTrustPreview && typeof helpers.auditEvent?.buildAuditEventPreview === "function"
    ? helpers.auditEvent.buildAuditEventPreview({
      eventType: "permission-review-preview",
      riskLevel: route.riskLevel || actionContract?.riskLevel || "high",
      domain: route.intentDomain || "general",
      actionType: route.intentDomain || actionContract?.actionType || "review-only-action",
      summary: "Previewed future permission and audit requirements.",
      sourceStatus: route.intentDomain === "agriculture-support" ? "general guidance" : "not source-backed",
      permissionStatus: permissionReview?.status || "preview-only"
    })
    : null;
  const evidencePacket = buildNexusEvidencePacketForPreview(route, helpers);
  const visiblePreviewTarget = selector => {
    const element = $(selector);
    if (!element || element.classList?.contains("hidden")) return null;
    const box = element.getBoundingClientRect?.();
    return box && (box.width > 0 || box.height > 0) ? element : null;
  };
  const target = visiblePreviewTarget("#globalAssistantBar")
    || visiblePreviewTarget("#jarvisInsightPanel")
    || visiblePreviewTarget("#userWorkspace")
    || $("#globalAssistantBar")
    || $("#userWorkspace")
    || document.body;
  if (!target) return null;
  target.querySelectorAll("[data-nexus-autonomous-runtime-preview]").forEach(existing => existing.remove());

  const article = document.createElement("article");
  article.className = "nexus-autonomous-runtime-preview";
  article.setAttribute("data-nexus-autonomous-runtime-preview", "true");
  article.setAttribute("data-intent-domain", route.intentDomain || "general-assistant");
  article.setAttribute("data-route-status", route.routeStatus || "informational");
  article.setAttribute("data-risk-level", route.riskLevel || "low");
  article.setAttribute("data-execution-allowed", "false");
  article.setAttribute("data-side-effects-allowed", "false");
  article.setAttribute("aria-label", "Nexus preview-only plan");

  const statusLabel = route.blocked ? "Blocked" : route.permissionRequired ? "Permission required" : "Preview only";
  const steps = Array.isArray(planPreview?.steps) ? planPreview.steps : nexusAutonomousPreviewSteps(route);
  const noExecution = actionContract?.userVisibleDisclosure || route.userVisibleDisclosure || "No action has been taken.";
  const permissionMarkup = permissionReview ? `
    <section class="nexus-preview-review-block" data-nexus-permission-review-preview="true">
      <h4>Permission Review Preview</h4>
      <p>${htmlSafe(permissionReview.disclosure)}</p>
      <p>${htmlSafe(permissionReview.summary)}</p>
      <dl>
        <div><dt>Confirmation</dt><dd>Required before any future execution</dd></div>
        <div><dt>Confirm control</dt><dd>Disabled</dd></div>
        <div><dt>Cancel path</dt><dd>Available</dd></div>
      </dl>
      <ul>${permissionReview.dataNeeded.map(item => `<li>${htmlSafe(item)}</li>`).join("")}</ul>
    </section>
  ` : "";
  const auditMarkup = auditEvent ? `
    <section class="nexus-preview-review-block" data-nexus-audit-event-preview="true">
      <h4>Audit Event Preview</h4>
      <p>${htmlSafe(auditEvent.disclosure)}</p>
      <dl>
        <div><dt>Event type</dt><dd>${htmlSafe(auditEvent.eventType)}</dd></div>
        <div><dt>Permission status</dt><dd>${htmlSafe(auditEvent.permissionStatus)}</dd></div>
        <div><dt>Redaction</dt><dd>${htmlSafe(auditEvent.redactionPolicy)}</dd></div>
      </dl>
      <p>No backend write, storage write, network call, or execution has occurred.</p>
    </section>
  ` : "";
  const evidenceMarkup = nexusEvidenceMarkup(evidencePacket);
  article.innerHTML = `
    <div class="tag-row">
      <span>${htmlSafe(route.intentDomain || "general-assistant")}</span>
      <span>Status: ${htmlSafe(statusLabel)}</span>
      <span>Risk: ${htmlSafe(route.riskLevel || "low")}</span>
    </div>
    <h3>Nexus Plan Preview</h3>
    <p>${htmlSafe(noExecution)}</p>
    <p><strong>No action has been taken.</strong></p>
    <div class="nexus-autonomous-preview-controls">
      <button type="button" disabled aria-disabled="true" data-nexus-preview-control="confirm-disabled">Confirm disabled</button>
      <button type="button" data-nexus-preview-control="cancel" onclick="this.closest('[data-nexus-autonomous-runtime-preview]')?.remove()">Cancel preview</button>
    </div>
    <ul>${steps.map(step => `<li><strong>${htmlSafe(step.title)}</strong>: ${htmlSafe(step.description)}</li>`).join("")}</ul>
    ${evidenceMarkup}
    ${permissionMarkup}
    ${auditMarkup}
  `;
  const cancelButton = article.querySelector('[data-nexus-preview-control="cancel"]');
  if (cancelButton) {
    cancelButton.setAttribute("data-cancel-listener", "true");
    const removePreview = event => {
      event.preventDefault();
      event.stopPropagation();
      article.remove();
    };
    cancelButton.addEventListener("pointerdown", removePreview);
    cancelButton.addEventListener("mousedown", removePreview);
    cancelButton.addEventListener("click", removePreview);
  }
  const globalPreviewAnchor = target.id === "globalAssistantBar"
    ? target.querySelector(".mobile-permission-strip, #mobilePermissionStatus, #globalAssistantStatus")
    : null;
  if (globalPreviewAnchor) {
    target.insertBefore(article, globalPreviewAnchor);
  } else {
    target.appendChild(article);
  }
  if (options.updateStatus !== false) {
    const status = $("#globalAssistantStatus");
    if (status) status.textContent = translateText("Nexus prepared a preview-only plan. No action has been taken.");
  }
  return Object.freeze({ route, actionContract, planPreview, element: article });
}

function installNexusAutonomousRuntimePreview() {
  if (document.documentElement.getAttribute("data-nexus-autonomous-runtime-preview-installed") === "true") return;
  document.documentElement.setAttribute("data-nexus-autonomous-runtime-preview-installed", "true");
  const readPrompt = source => {
    const input = source === "caption"
      ? $("#userCaptionInput")
      : source === "global"
        ? $("#globalCommandInput")
        : $("#jarvisCommandInput");
    return input ? input.value : "";
  };
  const schedulePreview = (prompt, source) => {
    const value = String(prompt || "").trim();
    if (!value) return;
    setTimeout(() => renderNexusAutonomousRuntimePreview(value, { source }), 140);
    setTimeout(() => renderNexusAutonomousRuntimePreview(value, { source, updateStatus: false }), 620);
    setTimeout(() => renderNexusAutonomousRuntimePreview(value, { source, updateStatus: false }), 1400);
  };
  document.addEventListener("click", event => {
    const target = event.target;
    if (!target || !target.closest) return;
    if (target.closest('[data-nexus-preview-control="cancel"]')) {
      target.closest("[data-nexus-autonomous-runtime-preview]")?.remove();
      return;
    }
    if (target.closest("#jarvisRunBtn")) schedulePreview(readPrompt("jarvis"), "jarvis");
    if (target.closest("#globalRunBtn")) schedulePreview(readPrompt("global"), "global");
    if (target.closest('[data-caption-action="send"]')) schedulePreview(readPrompt("caption"), "caption");
  }, true);
  document.addEventListener("keydown", event => {
    if (event.key === "Enter" && event.target?.id === "jarvisCommandInput") schedulePreview(readPrompt("jarvis"), "jarvis");
    if (event.key === "Enter" && event.target?.id === "globalCommandInput") schedulePreview(readPrompt("global"), "global");
    if (event.key === "Enter" && event.target?.id === "userCaptionInput") schedulePreview(readPrompt("caption"), "caption");
  }, true);
}

function localizedVoiceSuggestionItems(result = {}, fallback = []) {
  const raw = Array.isArray(result.metadata?.suggestedReplies) && result.metadata.suggestedReplies.length ? result.metadata.suggestedReplies : fallback;
  const translated = result.metadata?.localized?.suggestedReplies || [];
  return raw.map((command, index) => ({
    command,
    label: translated[index] && translated[index] !== command ? translated[index] : translateText(command)
  }));
}

function voiceCommandButton(command) {
  const value = typeof command === "object" ? command.command || command.value || command.label || "" : command;
  const label = typeof command === "object" ? command.label || command.text || value : translateText(value);
  return `<button type="button" data-voice-example="${htmlSafe(value)}">${htmlSafe(label)}</button>`;
}

function voicePhrase(command) {
  return `<span class="sample-phrase">${translateText(command)}</span>`;
}

function normalizeLocalizedVoiceCommand(rawCommand) {
  const value = String(rawCommand || "").trim();
  if (!value) return value;
  const localizedWake = value.replace(/^\s*(نكسس|نيكسس|أجرينيكسس|جارفيس|كوتش)\s*[,،:\-]?\s*/i, "Nexus, ");
  const lowered = localizedWake.toLowerCase();
  const langMap = contentTranslations[languageCode()] || {};
  const match = voiceCommandExamples().find(command => {
    const translated = langMap[command] || command;
    return translated.toLowerCase() === lowered || cleanWakeCommand(translated).toLowerCase() === cleanWakeCommand(localizedWake).toLowerCase();
  });
  return match || localizedWake;
}

