function redactCallPhoneDisplay(value = "") {
  const clean = String(value || "").replace(/[^\d+]/g, "");
  if (!clean) return "";
  if (clean.includes("*")) return clean;
  const prefix = clean.startsWith("+") ? "+" : "";
  const digits = clean.replace(/[^\d]/g, "");
  if (digits.length <= 4) return `${prefix}${"*".repeat(Math.max(0, digits.length - 2))}${digits.slice(-2)}`;
  return `${prefix}${digits.slice(0, Math.min(3, digits.length))}${"*".repeat(Math.max(3, digits.length - 6))}${digits.slice(-3)}`;
}

function callProviderLabel(provider = "") {
  const value = String(provider || "").toLowerCase();
  if (value === "twilio") return "Phone";
  if (value === "native-phone") return "Native phone dialer";
  if (value === "whatsapp") return "WhatsApp";
  if (value === "telegram") return "Telegram";
  if (value === "browser-fallback") return "Browser fallback";
  return value ? value.replace(/-/g, " ") : "Phone";
}

function callProviderDisplayLabel(callLike = {}) {
  const metadata = callLike.providerMetadata
    || callLike.metadata?.providerMetadata
    || callLike.handoff?.providerMetadata
    || {};
  const label = typeof metadata.label === "string" ? metadata.label.trim() : "";
  if (label) return label;
  return callProviderLabel(callLike.provider || callLike.requestedProvider || callLike.metadata?.provider || callLike.metadata?.requestedProvider || callLike.handoff?.provider);
}

function pendingCallDetails(action = {}) {
  const target = action.target || {};
  const resolution = action.resolution || {};
  const handoff = action.handoff || {};
  const provider = action.provider || action.requestedProvider || "";
  const phone = target.redactedPhone || redactCallPhoneDisplay(target.phone || target.e164Phone || action.recipientPhone || action.to);
  const displayName = target.displayName || action.contactName || action.action || "Requested contact";
  const resolutionStatus = resolution.status || (target.displayName || phone ? "resolved" : "needs-details");
  const fallback = handoff.fallbackText || (provider === "native-phone"
    ? "In the browser/PWA, Nexus can stage this only as a safe instruction. Native dialer launch is not part of this phase."
    : "");
  return {
    actionLabel: action.action || `Call ${displayName}`,
    displayName,
    phone,
    providerLabel: callProviderDisplayLabel(action),
    resolutionStatus,
    confirmationPrompt: action.confirmationPrompt || "Before I call anyone, please confirm.",
    fallback,
    handoffUrl: handoff.url || ""
  };
}

function pendingCallDetailRows(details) {
  return [
    ["Contact", details.displayName],
    ["Number", details.phone || "Not shown"],
    ["Provider", details.providerLabel],
    ["Status", details.resolutionStatus],
    details.fallback ? ["Fallback", details.fallback] : null
  ].filter(Boolean).map(([label, value]) => `
    <div>
      <strong>${escapeHtml(translateText(label))}</strong>
      <span>${escapeHtml(translateText(value))}</span>
    </div>
  `).join("");
}

function isConfirmedCallHandoffResult(result = {}) {
  const metadata = result.metadata || {};
  const provider = metadata.provider || metadata.requestedProvider || "";
  return Boolean(metadata.executionConfirmed && provider && (
    result.intent === "conversation.confirmed"
    || result.intent === "call.handoff_instruction"
    || result.intent === "phone.outbound_call_requested"
  ));
}

function safeConfirmedCallHandoffUrl(result = {}) {
  const metadata = result.metadata || {};
  const handoff = metadata.handoff || {};
  const provider = String(metadata.provider || metadata.requestedProvider || "").toLowerCase();
  const url = String(handoff.url || "");
  if (provider === "native-phone" && /^tel:\+?\d[\d\s().-]*$/i.test(url)) return url;
  if (provider === "whatsapp" && /^https:\/\/wa\.me\/\d+$/i.test(url)) return url;
  if (provider === "telegram" && /^https:\/\/t\.me\/[A-Za-z0-9_]{3,64}$/i.test(url)) return url;
  return "";
}

function confirmedNativeCallHandoffPayload(result = {}) {
  const metadata = result.metadata || {};
  const handoff = metadata.handoff || {};
  const target = metadata.target || {};
  const provider = String(metadata.provider || metadata.requestedProvider || "").toLowerCase();
  const safeUrl = safeConfirmedCallHandoffUrl(result);
  if (!metadata.executionConfirmed) return null;
  if (provider !== "native-phone") return null;
  if (handoff.nativeCommand !== "call.launch") return null;
  if (!safeUrl || !safeUrl.startsWith("tel:")) return null;
  return {
    provider: "native-phone",
    url: safeUrl,
    displayName: target.displayName || target.rawName || "the contact",
    redactedPhone: target.redactedPhone || target.e164Phone || target.phone || metadata.redactedTo || "",
    confirmationId: metadata.confirmationId || metadata.callId || `${provider}:${safeUrl}:${target.displayName || target.rawName || ""}`,
    executionConfirmed: true,
    source: "confirmed-call-handoff"
  };
}

function nativeCallLaunchBridgeAvailable() {
  return Boolean(
    window.AgriNexusNativeVoice?.launchCall
    || window.AndroidAgriNexus?.postMessage
    || window.webkit?.messageHandlers?.agrinexusNative?.postMessage
  );
}

function postNativeCallLaunch(payload) {
  try {
    if (typeof window.AgriNexusNativeVoice?.launchCall === "function") {
      window.AgriNexusNativeVoice.launchCall(payload);
      return true;
    }
    if (window.AndroidAgriNexus?.postMessage) {
      window.AndroidAgriNexus.postMessage(JSON.stringify({ type: "agrinexus.native.command", command: "call.launch", payload }));
      return true;
    }
    if (window.webkit?.messageHandlers?.agrinexusNative?.postMessage) {
      window.webkit.messageHandlers.agrinexusNative.postMessage({ command: "call.launch", payload });
      return true;
    }
  } catch {
    return false;
  }
  return false;
}

function maybeDispatchConfirmedNativeCallHandoff(result = {}) {
  const payload = confirmedNativeCallHandoffPayload(result);
  if (!payload || !nativeCallLaunchBridgeAvailable()) return false;
  const dispatchKey = `${payload.confirmationId}|${payload.url}`;
  if (sessionStorage.getItem("agrinexusLastNativeCallDispatch") === dispatchKey) return false;
  const sent = postNativeCallLaunch(payload);
  if (sent) sessionStorage.setItem("agrinexusLastNativeCallDispatch", dispatchKey);
  return sent;
}

function renderConfirmedCallHandoffCard(result = {}) {
  const metadata = result.metadata || {};
  const target = metadata.target || {};
  const handoff = metadata.handoff || {};
  const provider = metadata.provider || metadata.requestedProvider || "";
  const providerLabel = callProviderDisplayLabel(result);
  const targetLabel = target.displayName || target.rawName || "the contact";
  const redactedNumber = target.redactedPhone || target.e164Phone || target.phone || metadata.redactedTo || "";
  const safeUrl = safeConfirmedCallHandoffUrl(result);
  const isTwilio = provider === "twilio";
  const title = isTwilio
    ? metadata.liveCallPlaced ? "Twilio call started" : "Twilio setup needed"
    : "Confirmed call handoff";
  const actionText = provider === "whatsapp"
    ? "Open WhatsApp contact"
    : provider === "telegram"
      ? "Open Telegram contact"
      : "Open call handoff";
  const linkHtml = safeUrl
    ? `<a class="primary confirmed-call-link" data-confirmed-call-handoff="true" href="${escapeHtml(safeUrl)}" target="_blank" rel="noopener noreferrer">${escapeHtml(translateText(actionText))}</a>`
    : "";
  return `<div class="conversation-turn assistant confirmed-call-handoff-card" data-confirmed-call-card="true">
    <strong>${escapeHtml(translateText(title))}</strong>
    <span>${escapeHtml(translateText(result.response || "The call action was confirmed."))}</span>
    <div class="pending-call-details">
      <div>
        <strong>${escapeHtml(translateText("Contact"))}</strong>
        <span>${escapeHtml(translateText(targetLabel))}</span>
      </div>
      <div>
        <strong>${escapeHtml(translateText("Provider"))}</strong>
        <span>${escapeHtml(translateText(providerLabel))}</span>
      </div>
      <div>
        <strong>${escapeHtml(translateText("Number"))}</strong>
        <span>${escapeHtml(redactedNumber ? translateText(redactedNumber) : translateText("Not shown"))}</span>
      </div>
      <div>
        <strong>${escapeHtml(translateText("Status"))}</strong>
        <span>${escapeHtml(translateText(metadata.deliveryStatus || metadata.callStatus || result.status || "confirmed"))}</span>
      </div>
    </div>
    ${handoff.fallbackText ? `<small>${escapeHtml(translateText(handoff.fallbackText))}</small>` : ""}
    ${provider === "whatsapp" ? `<small>${escapeHtml(translateText("WhatsApp voice-call deep links are not reliable; Nexus can only offer the confirmed contact/chat handoff."))}</small>` : ""}
    ${provider === "telegram" ? `<small>${escapeHtml(translateText("Telegram direct calls need a known Telegram account; Nexus can only offer a confirmed profile handoff when available."))}</small>` : ""}
    ${isTwilio && !metadata.liveCallPlaced ? `<small>${escapeHtml(translateText("Live dialing did not start because provider configuration is incomplete."))}</small>` : ""}
    ${linkHtml ? `<div class="confirmed-call-actions">${linkHtml}</div>` : `<small>${escapeHtml(translateText("No browser-launchable handoff link is available. Use the provider instruction above."))}</small>`}
  </div>`;
}

function renderPendingCallActionCard(pending = {}) {
  const details = pendingCallDetails(pending);
  return `<div class="conversation-turn assistant agent-pending-confirm-card pending-call-card" data-pending-call-card="true">
    <strong>${escapeHtml(translateText("Confirm call before launch"))}</strong>
    <span>${escapeHtml(translateText(details.actionLabel))}</span>
    <div class="pending-call-details">${pendingCallDetailRows(details)}</div>
    <small>${escapeHtml(translateText(details.confirmationPrompt))}</small>
    <small>${escapeHtml(translateText("Nexus will use the existing confirmation path. No call is launched from the first request."))}</small>
    <div class="agent-pending-confirm-actions">
      <button type="button" class="primary" data-agent-pending-confirm="yes">${translateText("Do this now")}</button>
      <button type="button" data-agent-pending-confirm="no">${translateText("Cancel")}</button>
    </div>
  </div>`;
}

function renderCallStatusCard(result = {}) {
  const metadata = result.metadata || {};
  const target = metadata.target || {};
  const resolution = metadata.resolution || {};
  const matches = resolution.matches || metadata.pendingContactCall?.matches || [];
  const provider = metadata.provider || metadata.requestedProvider || "";
  const status = result.intent === "call.multiple_matches"
    ? "Choose a contact"
    : result.intent === "call.number_needed" || result.intent === "call.target_needed"
      ? "Phone number needed"
      : result.status || "Call request";
  const rows = [
    ["Requested", target.displayName || target.rawName || "Not specified"],
    ["Provider", callProviderDisplayLabel(result)],
    ["Status", resolution.status || result.status || "needs input"]
  ];
  const matchHtml = matches.length
    ? `<div class="pending-call-matches">${matches.slice(0, 4).map((match, index) => `
      <span>${escapeHtml(`${index + 1}. ${match.displayName || match.name || "Contact"}${match.source ? ` (${match.source})` : ""}`)}</span>
    `).join("")}</div>`
    : "";
  return `<div class="conversation-turn assistant call-status-card" data-call-status-card="true">
    <strong>${escapeHtml(translateText(status))}</strong>
    <span>${escapeHtml(translateText(result.response || "Nexus needs one more detail before it can stage a call."))}</span>
    <div class="pending-call-details">${rows.map(([label, value]) => `
      <div>
        <strong>${escapeHtml(translateText(label))}</strong>
        <span>${escapeHtml(translateText(value))}</span>
      </div>
    `).join("")}</div>
    ${matchHtml}
    <small>${escapeHtml(translateText("No executable call is available until Nexus has a resolved contact and asks for confirmation."))}</small>
  </div>`;
}

function renderConversationPanel() {
  const panel = $("#globalConversationPanel");
  if (!panel || !data) return;
  const turns = data.profile.agentConversation || [];
  const pending = data.profile.agentPendingAction;
  const latestResult = data.commandResult || {};
  const recentTurns = turns.slice(-8);
  const pendingHtml = pending
    ? pending.kind === "call" || pending.pendingActionType === "outbound_call" || pending.tool === "communications.outbound_call"
      ? renderPendingCallActionCard(pending)
      : `<div class="conversation-turn assistant agent-pending-confirm-card">
        <strong>${translateText("Ready to continue?")}</strong>
        <span>${escapeHtml(translateText(`Nexus is ready to ${String(pending.action || "run this workflow").toLowerCase()}. Press Do this now to continue, or Cancel to stop.`))}</span>
        <div class="agent-pending-confirm-actions">
          <button type="button" class="primary" data-agent-pending-confirm="yes">${translateText("Do this now")}</button>
          <button type="button" data-agent-pending-confirm="no">${translateText("Cancel")}</button>
        </div>
      </div>`
    : "";
  const callStatusHtml = !pending && /^call\./.test(String(latestResult.intent || "")) ? renderCallStatusCard(latestResult) : "";
  const confirmedCallHtml = !pending && isConfirmedCallHandoffResult(latestResult) ? renderConfirmedCallHandoffCard(latestResult) : "";
  panel.innerHTML = (recentTurns.length ? recentTurns.map(turn => `
    <div class="conversation-turn ${turn.role === "user" ? "user" : "assistant"}">
      <strong>${turn.role === "user" ? "You" : "AgriNexus"}</strong>
      <span>${escapeHtml(turn.text)}</span>
    </div>
  `).join("") : `<div class="conversation-turn assistant"><strong>AgriNexus</strong><span>Ask me to open telehealth, apply for a job, start training, contact a buyer, run a drone scan, or check provider engines.</span></div>`) + callStatusHtml + confirmedCallHtml + pendingHtml;
}

