function a100ChronicCareReport(kind = "general", command = "") {
  const text = normalizeA100RuntimeCommand(command);
  const reading = (text.match(/\b\d{2,3}\s*\/\s*\d{2,3}\b/) || text.match(/\b\d{2,3}\s*(mg\/dl|mmol|percent|%)?\b/gi) || ["not provided"])[0];
  const symptoms = [
    ["chest pain", "chest pain"],
    ["stroke", "stroke-like symptoms"],
    ["dizzy", "dizziness"],
    ["headache", "headache"],
    ["shortness of breath", "shortness of breath"],
    ["fatigue", "fatigue"],
    ["nausea", "nausea"]
  ].filter(([term]) => text.includes(term)).map(([, label]) => label);
  const medicationQuestion = /\b(medication|medicine|insulin|dose|dosage|pill|prescription|metformin)\b/.test(text) ? "mentioned; provider review required" : "not mentioned";
  const adherenceConcern = /\b(missed|forgot|adherence|not taking|ran out|side effect|side effects|cost|afford|access)\b/.test(text) ? "possible adherence concern mentioned; provider review required" : "not provided";
  const lifestyleBarrier = /\b(food|diet|salt|activity|exercise|sleep|stress|transport|cost|access)\b/.test(text) ? "mentioned in session text" : "not provided";
  const reportAudience = kind === "chw" ? "community health worker, nurse supervisor, physician/provider, or care coordinator" : kind === "wellness" ? "coach, nurse, physician/provider, or community health worker" : kind === "rpm" ? "physician/provider, RPM nurse, RTM coach, or care coordinator" : kind === "telehealth" || kind === "care-team-summary" ? "physician/provider, nurse, coach, or community health worker" : "physician/provider or qualified clinical reviewer";
  const reportType = kind === "chw" ? "Community health worker report" : kind === "care-team-summary" ? "Care team report" : kind === "telehealth" ? "Telehealth report" : "Physician Report";
  const conditionAreaMap = {
    diabetes: "Diabetes",
    hypertension: "Hypertension / blood pressure",
    asthma: "Asthma / chronic respiratory disease",
    "heart-risk": "Heart disease risk",
    "kidney-risk": "Kidney disease risk",
    "maternal-risk": "Maternal chronic risk support",
    "medication-reminder": "Medication adherence and appointment follow-up",
    navigator: "Chronic Care AI Navigator for Africa",
    wellness: "Obesity / weight wellness",
    rpm: "RPM/RTM monitoring readiness",
    telehealth: "Telehealth chronic-care visit preparation",
    chw: "Community health worker chronic-care support",
    "care-team-summary": "Care team chronic-care summary",
    general: "General chronic care"
  };
  const titleMap = {
    diabetes: "Diabetes physician report",
    hypertension: "Blood pressure physician report",
    asthma: "Asthma and respiratory review report",
    "heart-risk": "Heart disease risk review report",
    "kidney-risk": "Kidney disease risk review report",
    "maternal-risk": "Maternal chronic risk review report",
    "medication-reminder": "Medication reminder planner report",
    navigator: "Chronic Care Navigator report",
    wellness: "Weight and wellness physician report",
    rpm: "RPM/RTM physician report",
    telehealth: "Telehealth visit report",
    chw: "Community health worker review report",
    "care-team-summary": "Care team summary report",
    general: "Chronic care physician report"
  };
  const conditionFields = {
    diabetes: [
      { label: "Diabetes focus", value: "blood sugar concern, glucose reading collection, A1c education, hypo/hyperglycemia safety, food/activity context, and diabetes telehealth prep" },
      { label: "Diabetes report detail", value: "blood sugar concern; glucose reading if mentioned; hypoglycemia/hyperglycemia warning language; A1c discussion prompt; medication/insulin questions routed to provider review" },
      { label: "Diabetes evidence label", value: "guideline-backed education; RPM glucose data needed for trend; provider review required" }
    ],
    hypertension: [
      { label: "Blood pressure focus", value: "home BP reading checklist, measurement context, warning signs, sodium/activity education, and provider-review prep" },
      { label: "Hypertension report detail", value: "blood pressure concern; BP reading if mentioned; symptoms if mentioned; home BP technique/checklist; severe BP, chest pain, or stroke symptoms routed to urgent guidance" },
      { label: "Blood pressure evidence label", value: "guideline-backed education; repeated BP data needed for trend; provider review required" }
    ],
    asthma: [
      { label: "Respiratory focus", value: "asthma/chronic respiratory education, symptom and trigger tracking, inhaler-technique questions, clinic visit preparation, and urgent breathing warning signs" },
      { label: "Respiratory evidence label", value: "general chronic-care education; manual/session-only information; provider review required for treatment or medication questions" }
    ],
    "heart-risk": [
      { label: "Heart risk focus", value: "heart disease risk questions, chest-pain warning signs, blood pressure/diabetes context, medication adherence questions, and clinic follow-up prep" },
      { label: "Heart risk evidence label", value: "general chronic-care education; urgent warning guidance for chest pain, stroke signs, severe shortness of breath, or fainting" }
    ],
    "kidney-risk": [
      { label: "Kidney risk focus", value: "kidney screening questions, diabetes/BP context, swelling or urine concerns, lab follow-up questions, and medication-safety review prompts" },
      { label: "Kidney risk evidence label", value: "manual/session-only information; complex labs need clinician interpretation; provider review required" }
    ],
    "maternal-risk": [
      { label: "Maternal chronic risk focus", value: "pregnancy with hypertension/diabetes concerns, headache, swelling, vision changes, bleeding, severe pain, and antenatal clinic review prep" },
      { label: "Maternal risk evidence label", value: "urgent warning guidance for pregnancy danger signs; clinician, nurse, or midwife review required" }
    ],
    "medication-reminder": [
      { label: "Reminder planner focus", value: "daily medication times from existing instructions, refill dates, clinic follow-ups, BP/glucose checks, lab appointments, and CHW visit reminders" },
      { label: "Reminder safety label", value: "adherence support as prescribed; no medication change, automatic notification, pharmacy order, or external calendar mutation" }
    ],
    navigator: [
      { label: "Navigator intake", value: "age range, country/region, preferred language, known condition, current symptoms, medication schedule, clinic access, last BP/glucose reading if known, and red-flag symptoms" },
      { label: "Navigator output", value: "condition support summary, safety notice, questions to ask, tracking checklist, urgent red-flag guidance, and next safe action" },
      { label: "Africa-ready delivery", value: "text-first, low-bandwidth, simple language, community health worker support, and rural telehealth review readiness" }
    ],
    wellness: [
      { label: "Wellness focus", value: "weight goal, nutrition, physical activity, sleep, stress, behavior barriers, and coach/provider review prep" },
      { label: "Weight wellness report detail", value: "weight or wellness concern; nutrition/activity/sleep/stress barriers; behavior coaching support; medication/supplement requests gated to provider review" },
      { label: "RTM behavior signal", value: "self-reported barrier, activity, sleep, stress, and nutrition context; human review required before care changes" },
      { label: "Wellness evidence label", value: "education and RTM behavior check-in; no medication, supplement, purchase, or product recommendation" }
    ],
    rpm: [
      { label: "RPM data inputs", value: "blood pressure cuff, glucose meter/CGM, weight scale, activity tracker, and manual entry can be listed for review if already available" },
      { label: "RTM self-report", value: "activity, adherence, symptoms, sleep, stress, and therapy barriers require human review before any care action" },
      { label: "Monitoring readiness label", value: "device-ready, not connected; no automatic data capture, alerting, billing, or external transmission" }
    ],
    telehealth: [
      { label: "Clinician Visit Summary", value: "recent readings, symptoms/concerns, medication questions to ask provider, food/activity barriers, and goals since last visit" },
      { label: "Telehealth Report basis", value: "session-only visit preparation; no provider handoff, message, call, medical record write, or external sharing" }
    ],
    "care-team-summary": [
      { label: "Clinician Visit Summary", value: "recent readings, symptoms/concerns, medication questions to ask provider, food/activity barriers, and goals since last visit" },
      { label: "Telehealth Report basis", value: "session-only care team summary; no provider handoff, message, call, medical record write, or external sharing" }
    ],
    chw: [
      { label: "CHW intake checklist", value: "BP/glucose/weight collection, symptoms, barriers, patient education needs, referral guidance, and follow-up preparation" },
      { label: "Clinician handoff summary", value: "low-literacy explanation prompts and patient education scripts prepared for human review only" }
    ]
  };
  const riskSignal = /chest pain|stroke|200\s*\/\s*120|extremely high|extremely low|severe|fainting|pass out|cannot breathe|emergency/.test(text)
    ? "urgent review signal mentioned"
    : reading !== "not provided"
      ? "reading mentioned; pattern not established"
      : "insufficient data";
  const dataSufficiency = reading !== "not provided" || symptoms.length || lifestyleBarrier !== "not provided" || adherenceConcern !== "not provided"
    ? "partial session data only; insufficient for diagnosis or treatment"
    : "insufficient data; user-provided inputs needed";
  const escalationReason = riskSignal === "urgent review signal mentioned"
    ? "urgent symptom or extreme reading language mentioned"
    : "routine review unless symptoms, very abnormal readings, or clinician instructions indicate urgent care";
  const reviewType = riskSignal === "urgent review signal mentioned"
    ? "Urgent/emergency care guidance"
    : medicationQuestion !== "not mentioned" || kind === "diabetes" || kind === "hypertension"
      ? "Physician/provider review"
      : kind === "rpm"
        ? "Nurse review"
        : kind === "wellness" || kind === "chw"
          ? "Coach or community health worker review"
          : "Education / self-management support";
  const evidenceLabel = [
    "General chronic-care education",
    kind === "rpm" ? "RPM data needed" : "",
    kind === "wellness" || kind === "chw" ? "RTM behavior data needed" : "",
    "Manual/session-only information",
    reading === "not provided" ? "Insufficient data" : "",
    "Provider review required",
    riskSignal === "urgent review signal mentioned" ? "Urgent warning guidance" : ""
  ].filter(Boolean).join("; ");
  const rpmReadiness = "not connected; manual entry only; review required; no automatic data transmission";
  const manualRpmRtmSessionSummary = a100RpmRtmSessionDataSummary();
  const safetyBoundary = "Nexus prepared this report for review only. Nexus did not diagnose, prescribe, adjust medication, dispatch emergency services, contact a provider, connect a device, transmit data, or store sensitive health data persistently.";
  return {
    type: "session-only",
    title: titleMap[kind] || titleMap.general,
    summary: "Prepare a report for review. Session-only summary; Nexus does not diagnose or prescribe.",
    capability: "physician-report-builder",
    copyReady: true,
    localOnly: true,
    reviewOnly: true,
    externalTransmission: false,
    providerReviewRequired: true,
    noDiagnosis: true,
    noPrescribing: true,
    noMedicationAdjustment: true,
    noProviderContact: true,
    noExternalShare: true,
    fields: [
      { label: "Report Type", value: reportType },
      { label: "Condition Area", value: conditionAreaMap[kind] || conditionAreaMap.general },
      { label: "Report audience", value: reportAudience },
      { label: "Patient concern", value: text || "not provided" },
      { label: "Patient Concern", value: text || "not provided" },
      { label: "Current Session Data", value: `manual/session-only user information from the current Nexus prompt; low-bandwidth summary ready for physician/care-team review; RPM/RTM manual notes: ${manualRpmRtmSessionSummary}` },
      { label: "Readings mentioned", value: reading },
      { label: "Readings Mentioned", value: reading },
      { label: "Data source", value: "session-only user text; source of data is user-provided/manual unless a reviewed RPM/RTM program exists outside Nexus" },
      { label: "Symptoms mentioned", value: symptoms.length ? symptoms.join(", ") : "not provided" },
      { label: "Symptoms Mentioned", value: symptoms.length ? symptoms.join(", ") : "not provided" },
      { label: "Medication questions", value: medicationQuestion },
      { label: "Medication Questions", value: medicationQuestion },
      { label: "RPM/RTM Readiness", value: rpmReadiness },
      { label: "RPM/RTM Manual Session Data", value: manualRpmRtmSessionSummary },
      { label: "Adherence concerns", value: adherenceConcern },
      { label: "Lifestyle barriers", value: lifestyleBarrier },
      { label: "Lifestyle / Adherence Barriers", value: `${lifestyleBarrier}; adherence: ${adherenceConcern}` },
      { label: "Trend or risk signal", value: riskSignal },
      { label: "Risk / Safety Flags", value: riskSignal },
      { label: "Data sufficiency label", value: dataSufficiency },
      ...(conditionFields[kind] || []),
      { label: "Evidence basis", value: "guideline-backed education; provider review required; insufficient data for diagnosis" },
      { label: "Evidence / Source Label", value: evidenceLabel },
      { label: "Missing data", value: "confirmed readings, timing, duration, full symptoms, medication list, history, and clinician context" },
      { label: "Missing Information", value: "confirmed readings, timing, duration, full symptoms, medication list, history, clinician context, and RPM/RTM source verification" },
      { label: "Escalation reason", value: escalationReason },
      { label: "Safety boundary applied", value: "review-only; Nexus did not diagnose, prescribe, adjust medication, connect devices, transmit data, or contact providers" },
      { label: "Recommended review", value: reviewType },
      { label: "Recommended Review Level", value: reviewType },
      { label: "Nexus Safety Boundary", value: safetyBoundary }
    ],
    safety: safetyBoundary
  };
}

function a100ChronicCareReadinessCards() {
  return [
    { id: "bp-cuff", label: "Blood pressure cuff", status: "device-ready, not connected", detail: "Home cuff readings may be manually listed for review; Nexus does not pair, verify, or transmit cuff data." },
    { id: "glucose-device", label: "Glucose meter/CGM", status: "device-ready, not connected", detail: "Glucose meter or CGM values may be prepared as user-provided notes only; no automatic device connection starts here." },
    { id: "weight-scale", label: "Weight scale", status: "device-ready, not connected", detail: "Weight scale values can be discussed if the user already knows them; Nexus does not collect or sync scale data." },
    { id: "activity-tracker", label: "Activity tracker", status: "device-ready, not connected", detail: "Activity tracker context stays self-reported unless a clinician-approved RTM program exists outside this preview." },
    { id: "rpm-device", label: "RPM device", status: "device-ready, not connected", detail: "Current state remains device not connected. No automatic glucose, blood pressure, weight, or wearable device connection starts from this card." },
    { id: "manual-entry", label: "Manual entry", status: "manual entry available if supported", detail: "Users can prepare readings they already know for review; Nexus does not verify device accuracy." },
    { id: "rtm-coaching", label: "RTM coaching", status: "provider review needed", detail: "Therapeutic monitoring notes stay education-first until a coach, nurse, or clinician reviews them." },
    { id: "clinical-review", label: "Clinical review", status: "review required", detail: "Medication, diagnosis, treatment, and urgent decisions require qualified professional review." },
    { id: "data-sharing", label: "Data sharing", status: "no external data transmission", detail: "No readings, summaries, messages, or health records are sent externally from this preview." },
    { id: "africa-deployment", label: "Rural support", status: "low-bandwidth friendly", detail: "Designed for multilingual education, rural telehealth, and community health worker or coach support." }
  ];
}

