async function refreshNexusProductionPlatformRails(options = {}) {
  try {
    const [readiness, storage, integrations, admin, privacy] = await Promise.all([
      request("/api/nexus/production-readiness", { method: "GET" }),
      request("/api/nexus/storage/status", { method: "GET" }),
      request("/api/nexus/integrations/status", { method: "GET" }),
      request("/api/nexus/admin/operations", { method: "GET" }),
      request("/api/nexus/privacy/summary", { method: "GET" })
    ]);
    nexusProductionReadinessStatus = readiness || null;
    nexusProductionStorageStatus = storage || null;
    nexusProductionIntegrationStatus = Array.isArray(integrations?.integrations) ? integrations.integrations : [];
    nexusProductionAdminOperations = admin || null;
    nexusProductionPrivacySummary = privacy || null;
    if (options.rerender !== false && experienceMode === "user") renderUserWorkspace();
    return nexusProductionReadinessStatus;
  } catch {
    return null;
  }
}

async function handleNexusProductionRailsClick(event) {
  const button = event.target?.closest?.("[data-nexus-production-rail-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.nexusProductionRailAction || "";
  button.disabled = true;
  try {
    if (action === "refresh") {
      nexusProductionRailActionStatus = "Production prototype rails refreshed. Live execution remains gated.";
      await refreshNexusProductionPlatformRails({ rerender: true });
      return true;
    }
    if (action === "export-request" || action === "delete-request") {
      const requestPath = action === "export-request" ? "/api/nexus/privacy/export-request" : "/api/nexus/privacy/delete-request";
      const result = await request(requestPath, {
        method: "POST",
        body: { reason: `${action.replace("-", " ")} prepared from Standard User privacy controls.` }
      });
      nexusProductionRailActionStatus = result?.request
        ? `${nexusProductionStatusLabel(result.request.requestType)} request recorded for local review. No data was transmitted or removed silently.`
        : "Privacy request recorded for local review.";
      await refreshNexusProductionPlatformRails({ rerender: true });
      return true;
    }
    if (action === "prepare-integration") {
      const integrationType = button.dataset.nexusIntegrationType || "";
      const result = await request(`/api/nexus/integrations/${encodeURIComponent(integrationType)}/prepare`, {
        method: "POST",
        body: { purpose: "Standard User provider readiness preparation" }
      });
      nexusProductionRailActionStatus = result?.attempt
        ? `${result.attempt.providerName} readiness attempt prepared locally. No provider request was sent.`
        : "Provider readiness attempt prepared locally.";
      await refreshNexusProductionPlatformRails({ rerender: true });
      return true;
    }
    return true;
  } catch (error) {
    nexusProductionRailActionStatus = error.message || "Production rails action needs attention.";
    toast(nexusProductionRailActionStatus);
    if (experienceMode === "user") renderUserWorkspace();
    return true;
  } finally {
    button.disabled = false;
  }
}

function nexusKnowledgeStatusLabel(value = "") {
  const text = String(value || "disabled").replace(/_/g, " ");
  return text.charAt(0).toUpperCase() + text.slice(1);
}

function isNexusLiveKnowledgeQuestion(command = "") {
  const lower = String(command || "").toLowerCase().trim();
  if (!lower) return false;
  if (/\b(i need|need help|help me|help with|open|start|prepare)\b/.test(lower) && !/\b(research|source|sources|cite|citation|current|latest|internet|web|search)\b/.test(lower)) return false;
  if (/\b(open|start|send|call|message|pay|checkout|book|schedule|delete|upload|camera|share my location)\b/.test(lower)) return false;
  return /\b(current|latest|today|now|recent|research|source-backed|source|sources|cite|citation|internet|web|search|best practices|what causes|what should|safe storage|market price|price for|farm jobs|training do i need|advice for|doctor about|solar installation)\b/.test(lower);
}

function nexusKnowledgeCategoryForCommand(command = "") {
  const lower = String(command || "").toLowerCase();
  if (/\b(email|sms|text|message|whatsapp|telegram|phone call|call|dial|communication)\b/.test(lower)) return "communications";
  if (/\b(telehealth|virtual visit|video visit|doctor visit|provider visit|intake)\b/.test(lower)) return "telehealth";
  if (/\b(pharmacy|medicine|medication|drug|prescription|refill|insulin storage|safe storage)\b/.test(lower)) return "pharmacy";
  if (/\b(mobile clinic|community health|outreach clinic|clinic van)\b/.test(lower)) return "mobileClinic";
  if (/\b(blood pressure|bp|hypertension|diabetes|glucose|obesity|weight|chronic|rpm|rtm)\b/.test(lower)) return "chronicCare";
  if (/\b(blood pressure|hypertension|diabetes|obesity|chronic|health|symptom|doctor|clinic|medical|patient)\b/.test(lower)) return "health";
  if (/\b(crop disease|yellow leaves|cassava|maize|safe pest|pest management|soil fertility|fertilizer|fertiliser|irrigation|climate-smart|farm visit|field visit|farm planning|harvest planning|post-harvest|post harvest|agriculture logistics|farm inputs|input vendor)\b/.test(lower)) return "agriculture";
  if (/\b(price|market|buyer|seller|sell|agritade|agritrade|commodity|vendor|supplier|logistics|delivery|cold chain|storage|warehouse|purchase|checkout)\b/.test(lower)) return "marketplace";
  if (/\b(job|jobs|workforce|career|training|solar installation|skills|employment|employer|credential|certificate|resume|interview|role|hiring)\b/.test(lower)) return "jobs";
  if (/\b(lesson|learning|literacy|course|study|school|training|ai literacy|digital literacy|health literacy|agriculture literacy)\b/.test(lower)) return "learning";
  if (/\b(crop|maize|tomato|tomatoes|cassava|soil|pest|farm|farmer|agriculture|irrigation|fertilizer|yellow leaves)\b/.test(lower)) return "agriculture";
  if (/\b(route|map|field visit|distance|travel|directions)\b/.test(lower)) return "maps";
  if (/\b(music|media|song|playlist|r&b|rnb|afrobeats|african music|amapiano|gospel|spotify|youtube|apple music)\b/.test(lower)) return "music_media";
  if (/\b(reminder|reminders|remind me|follow up|follow-up)\b/.test(lower)) return "reminders";
  if (/\b(offline|low bandwidth|low-bandwidth|queue for later|save for later)\b/.test(lower)) return "offline";
  if (/\b(provider|admin|administrator|review queue|operations|partner account)\b/.test(lower)) return "providerAdmin";
  return "general";
}

function nexusKnowledgeCategoryForModeId(modeId = "") {
  return ({
    agriculture: "agriculture",
    "chronic-care": "chronicCare",
    "telehealth-intake": "telehealth",
    "mobile-clinic": "mobileClinic",
    "pharmacy-support": "pharmacy",
    learning: "learning",
    jobs: "jobs",
    agritrade: "marketplace",
    maps: "maps",
    media: "music_media",
    reminders: "reminders",
    offline: "offline"
  })[modeId] || "";
}

