async function refreshNexusUserTestingRuntimeStatus(options = {}) {
  if (nexusUserTestingRuntimeLoading) return nexusUserTestingRuntimeStatus;
  nexusUserTestingRuntimeLoading = true;
  try {
    const status = await request("/api/nexus/user-testing/status");
    nexusUserTestingRuntimeStatus = status;
    return status;
  } catch (error) {
    nexusUserTestingRuntimeLastResult = {
      title: "Runtime status unavailable",
      message: error.message || "Nexus could not load the user testing runtime."
    };
    return nexusUserTestingRuntimeStatus;
  } finally {
    nexusUserTestingRuntimeLoading = false;
    if (options.rerender !== false && experienceMode === "user") renderUserWorkspace();
  }
}

function ensureNexusUserTestingRuntimeBootstrap() {
  if (nexusUserTestingRuntimeStatus || nexusUserTestingRuntimeLoading) return;
  setTimeout(() => {
    if (experienceMode === "user" && document.querySelector("[data-nexus-user-testing-runtime='true']")) {
      refreshNexusUserTestingRuntimeStatus({ rerender: true }).catch(() => {});
    }
  }, 0);
}

async function runNexusUserTestingRuntimeAction(action = "refresh") {
  const safeAction = String(action || "refresh");
  try {
    let response;
    if (safeAction === "run-harness") {
      response = await request("/api/nexus/user-testing/e2e-harness");
      nexusUserTestingRuntimeLastResult = { title: "E2E harness complete", message: `${response.flowsCreated || 0} local-safe flows prepared. No live provider action occurred.` };
    } else if (safeAction === "save-sample-record") {
      response = await request("/api/nexus/user-testing/memory", {
        method: "POST",
        body: {
          type: "health_chronic_care",
          title: "Controlled user testing memory",
          summary: "Local memory record for chronic care, agriculture, workforce, and provider-ready workflow testing.",
          ownerRole: "Standard User",
          data: { diabetes: "tracking only", hypertension: "tracking only", noDiagnosis: true }
        }
      });
      nexusUserTestingRuntimeLastResult = { title: "Memory saved", message: response.record?.title || "Local memory record saved." };
    } else if (safeAction === "predict-next-step") {
      response = await request("/api/nexus/user-testing/predict", {
        method: "POST",
        body: { domain: "controlled_user_testing", signals: ["chronic care", "crop issue", "marketplace", "workforce"] }
      });
      nexusUserTestingRuntimeLastResult = { title: "Prediction prepared", message: `${response.prediction?.riskLevel || "watch"} risk, ${response.prediction?.confidence || "low"} confidence.` };
    } else if (safeAction === "prepare-action") {
      response = await request("/api/nexus/user-testing/execute", {
        method: "POST",
        body: { actionType: "send_sms", confirmed: false }
      });
      nexusUserTestingRuntimeLastResult = { title: "Action gated", message: response.execution?.outcome || "Sensitive action requires confirmation." };
    } else if (safeAction === "create-consent") {
      response = await request("/api/nexus/user-testing/consent", {
        method: "POST",
        body: {
          actionType: "provider_referral_preparation",
          riskTier: "high",
          actionSummary: "Prepare a provider-ready summary for review.",
          dataIncluded: ["summary", "user-entered details", "receipt id"],
          recipientDisplay: "Provider not selected",
          providerDisplay: "Provider not connected"
        }
      });
      nexusUserTestingRuntimeLastResult = { title: "Consent gate created", message: response.consentGate?.actionSummary || "Consent gate created." };
    } else if (safeAction === "verify-outcome") {
      response = await request("/api/nexus/user-testing/verify", {
        method: "POST",
        body: { status: "completed_local", summary: "Local user testing runtime verified without external execution." }
      });
      nexusUserTestingRuntimeLastResult = { title: "Outcome verified", message: response.verification?.summary || "Outcome verified locally." };
    } else {
      response = await refreshNexusUserTestingRuntimeStatus({ rerender: false });
      nexusUserTestingRuntimeLastResult = { title: "Runtime refreshed", message: response?.database?.userMessage || "Runtime status refreshed." };
    }
    await refreshNexusUserTestingRuntimeStatus({ rerender: false });
    toast(nexusUserTestingRuntimeLastResult.message);
  } catch (error) {
    nexusUserTestingRuntimeLastResult = { title: "Runtime action failed safely", message: error.message || "Nexus kept the workflow safe." };
    toast(nexusUserTestingRuntimeLastResult.message);
  }
  renderUserWorkspace();
  return true;
}

function nexusFormDataForWorkflow(workflowId = "") {
  const workspace = $("#nexus-workspace");
  const values = {};
  workspace?.querySelectorAll?.("[data-nexus-mode-field]")?.forEach(field => {
    const key = field.dataset.nexusModeField || field.name || "field";
    values[key] = String(field.value || "").trim();
  });
  values.workflowId = workflowId;
  return values;
}

function buildNexusPacket(workflowId, formData = {}, options = {}) {
  const definition = nexusWorkflowDefinition(workflowId, options.command || "");
  const registry = nexusWorkflowRegistryEntry(definition?.id || workflowId);
  const lane = nexusIntegrationLaneById(registry?.integrationLaneId);
  const now = new Date().toISOString();
  const packetId = `nexus-packet-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  const userEnteredData = Object.fromEntries(Object.entries(formData || {}).filter(([, value]) => String(value || "").trim()));
  const normalizedData = Object.fromEntries(Object.entries(userEnteredData).map(([key, value]) => [key, String(value || "").trim()]));
  const summary = `${registry?.label || definition?.presentation?.title || "Nexus workflow"} packet prepared for ${lane?.label || "local review"}.`;
  return {
    packetId,
    workflowId: definition?.id || workflowId,
    workflowLabel: registry?.label || definition?.presentation?.title || "Nexus workflow",
    category: registry?.category || "platform",
    packetType: registry?.packetType || "nexus_packet",
    riskLevel: registry?.riskLevel || "moderate",
    userEnteredData,
    normalizedData,
    summary,
    urgency: userEnteredData.urgency || userEnteredData.priority || "not specified",
    consentText: `${registry?.label || "Nexus"} will share only the reviewed packet with ${lane?.partnerName || "the selected lane"} after explicit approval.`,
    consentAccepted: Boolean(options.consentAccepted),
    destinationLaneId: lane?.id || "",
    destinationLabel: lane?.label || "Local Nexus review",
    integrationStatus: lane?.status || "not_configured",
    adapterType: lane?.category || registry?.category || "local",
    confirmationStatus: registry?.requiresConfirmationBeforeExecution ? "required_before_external_execution" : "not_required_for_local_preparation",
    outcomeStatus: "prepared",
    createdAt: now,
    updatedAt: now,
    createdBy: "standard-user",
    region: lane?.region || "global",
    country: lane?.country || "multi-country",
    language: languageCode?.() || "en",
    offlineEligible: Boolean(registry?.offlineSupport),
    retryEligible: true,
    attachmentsMeta: [],
    auditTrail: [{
      event: "packet_created",
      timestamp: now,
      actor: "nexus-runtime",
      laneStatus: lane?.status || "not_configured"
    }]
  };
}

function prepareNexusAction(packet) {
  const lane = nexusIntegrationLaneById(packet.destinationLaneId);
  return {
    packet,
    lane,
    actionType: packet.packetType,
    status: lane?.status === "active_live" ? "waiting_for_confirmation" : "prepared",
    message: lane?.status === "active_live"
      ? "This lane can execute when configured, but final confirmation is still required."
      : "Packet prepared. The integration lane is not live, so Nexus will not claim submission.",
    requiresConfirmation: Boolean(lane?.requiresConfirmation),
    noExternalExecutionWithoutConfirmation: true
  };
}

function requestNexusConfirmation(packet) {
  return {
    packetId: packet.packetId,
    confirmationStatus: "waiting_for_confirmation",
    message: "Review the packet, destination lane, and outcome before approving any external action.",
    allowedConfirmations: ["Confirm after review"],
    blockedConfirmations: ["okay", "sure", "do it automatically", "always send"],
    auditRequired: true
  };
}

const NEXUS_VERIFIED_EXECUTION_STATES = Object.freeze([
  "draft",
  "prepared",
  "handoff_required",
  "queued",
  "attempting",
  "provider_accepted",
  "provider_rejected",
  "failed",
  "user_completed_external_step",
  "verified_complete"
]);

function normalizeNexusExecutionState(status = "", result = {}, lane = null) {
  const text = `${status || ""} ${result.status || ""} ${result.outcomeStatus || ""} ${result.verificationStatus || ""} ${result.errorCode || ""}`.toLowerCase();
  if (!text.trim()) return "draft";
  if (/verified_complete|test_verified|verified/.test(text)) return "verified_complete";
  if (/user_completed_external_step|external_completion_confirmed/.test(text)) return "user_completed_external_step";
  if (/provider_rejected|rejected|declined/.test(text)) return "provider_rejected";
  if (/failed|error|timeout/.test(text)) return "failed";
  if (/provider_accepted|test_submitted|submitted|accepted/.test(text)) return "provider_accepted";
  if (/attempting|in_progress|sending|processing/.test(text)) return "attempting";
  if (/queued|queue|inactive|offline/.test(text)) return "queued";
  if (/waiting|confirmation|credential_required|handoff_prepared|pending_external_completion/.test(text)) return "handoff_required";
  if (/prepared|draft|cancelled/.test(text)) return /prepared/.test(text) ? "prepared" : "draft";
  return lane?.status === "active_live" ? "attempting" : "prepared";
}

function buildNexusVerifiedExecutionAttemptRecord(packet = {}, result = {}, lane = null) {
  const adapter = nexusAdapterForPacket(packet, lane);
  const executionState = normalizeNexusExecutionState(result.outcomeStatus || result.status, result, lane);
  const providerName = lane?.partnerName || lane?.label || packet.destinationLabel || "Local Nexus";
  const providerAvailable = Boolean(lane && ["active_test_mode", "active_live", "configured_inactive"].includes(lane.status));
  const providerResponse = result.resultMessage || result.userMessage || "No provider response recorded.";
  const failureReason = result.errorMessage || result.errorCode || (providerAvailable ? "" : "Provider unavailable or credentials missing.");
  return {
    schemaVersion: "nexus-verified-execution-attempt.v1",
    action: packet.packetType || result.actionType || "nexus_action",
    provider: providerName,
    providerAvailable,
    adapterType: result.adapterType || adapter.adapterType,
    attemptTime: result.timestamp || new Date().toISOString(),
    requestStatus: result.status || result.outcomeStatus || executionState,
    normalizedExecutionState: executionState,
    providerResponse,
    verificationEvidence: result.verificationStatus || "not_started",
    failureReason,
    retryEligibility: Boolean(packet.retryEligible !== false && !["provider_accepted", "verified_complete"].includes(executionState)),
    receiptReference: result.resultId || result.externalReference || packet.packetId || "",
    noFakeSuccess: !["provider_accepted", "verified_complete", "user_completed_external_step"].includes(executionState) || Boolean(result.externalReference || result.verificationStatus === "test_verified"),
    noExecutionWithoutConfirmation: true,
    localOnlyUnlessProviderAccepted: executionState !== "provider_accepted" || lane?.status !== "active_live"
  };
}

function renderNexusVerifiedExecutionStatus(attempt = null) {
  if (!attempt) return "";
  return `
    <section class="nexus-verified-execution-status" data-nexus-verified-execution-status="true" data-nexus-normalized-execution-state="${escapeHtml(attempt.normalizedExecutionState)}" data-no-fake-success="true">
      <strong>${escapeHtml(translateText("Verified execution status"))}</strong>
      <dl>
        <div><dt>${escapeHtml(translateText("Action"))}</dt><dd>${escapeHtml(translateText(attempt.action))}</dd></div>
        <div><dt>${escapeHtml(translateText("Provider"))}</dt><dd>${escapeHtml(translateText(attempt.provider))}</dd></div>
        <div><dt>${escapeHtml(translateText("Attempt time"))}</dt><dd>${escapeHtml(translateText(attempt.attemptTime))}</dd></div>
        <div><dt>${escapeHtml(translateText("Request status"))}</dt><dd>${escapeHtml(translateText(attempt.requestStatus))}</dd></div>
        <div><dt>${escapeHtml(translateText("Provider response"))}</dt><dd>${escapeHtml(translateText(attempt.providerResponse))}</dd></div>
        <div><dt>${escapeHtml(translateText("Verification evidence"))}</dt><dd>${escapeHtml(translateText(attempt.verificationEvidence))}</dd></div>
        <div><dt>${escapeHtml(translateText("Failure reason"))}</dt><dd>${escapeHtml(translateText(attempt.failureReason || "None recorded"))}</dd></div>
        <div><dt>${escapeHtml(translateText("Retry eligibility"))}</dt><dd>${escapeHtml(translateText(attempt.retryEligibility ? "Retry can be attempted after gates are satisfied." : "Retry is not needed for this state."))}</dd></div>
        <div><dt>${escapeHtml(translateText("Receipt reference"))}</dt><dd>${escapeHtml(translateText(attempt.receiptReference || "pending"))}</dd></div>
      </dl>
      <p>${escapeHtml(translateText(`Nexus state: ${attempt.normalizedExecutionState}. Nexus will not claim provider acceptance, completion, payment, send, booking, dispatch, or handoff unless provider evidence exists.`))}</p>
    </section>
  `;
}

const NEXUS_MISSION_HISTORY_STATUSES = Object.freeze([
  "active",
  "paused",
  "completed",
  "failed",
  "queued",
  "cancelled",
  "archived"
]);

function nexusApprovedMemoryType(typeId = "") {
  return NEXUS_APPROVED_MEMORY_TYPES.find(item => item.id === typeId) || NEXUS_APPROVED_MEMORY_TYPES[0];
}

function buildNexusApprovedMemoryRecord(input = {}) {
  const type = nexusApprovedMemoryType(input.type || "saved_preference");
  const now = new Date().toISOString();
  return {
    id: input.id || `memory-${Date.now()}-${Math.random().toString(16).slice(2, 7)}`,
    schemaVersion: "nexus-approved-memory-record.v1",
    type: type.id,
    typeLabel: type.label,
    title: String(input.title || type.label || "Approved memory").trim().slice(0, 120),
    value: String(input.value || "").trim().slice(0, 1000),
    status: input.status || "active",
    consentStatus: input.consentStatus || "approved_by_user",
    persistenceScope: input.persistenceScope || "local_browser",
    storageScopeExplanation: "Stored in this browser only unless a future provider-backed connector is configured and separately approved.",
    localVsProviderBackedStorage: type.providerBacked
      ? "Provider-backed storage is not active here. Nexus keeps this local and review-only."
      : "Local browser memory only.",
    sensitive: Boolean(type.sensitive),
    providerBacked: Boolean(type.providerBacked),
    modelTraining: false,
    noSilentPersistence: true,
    noExternalExecutionAuthorized: true,
    createdAt: input.createdAt || now,
    updatedAt: now,
    lastReviewedAt: input.lastReviewedAt || "",
    retentionNote: input.retentionNote || (type.providerBacked ? "Provider-managed retention rules may restrict deletion; archive is available." : "User can forget or delete this local memory."),
    authorizedHandling: input.authorizedHandling || ""
  };
}

function nexusApprovedMemoryCounts() {
  return nexusApprovedMemoryRecords.reduce((counts, record) => {
    counts.total += 1;
    counts[record.status] = (counts[record.status] || 0) + 1;
    if (record.sensitive) counts.sensitive += 1;
    if (record.providerBacked) counts.providerBacked += 1;
    return counts;
  }, { total: 0, active: 0, archived: 0, deactivated: 0, forgotten: 0, sensitive: 0, providerBacked: 0 });
}

