const NEXUS_UNIVERSAL_CONSENT_CATEGORIES = Object.freeze([
  { id: "health_data_sharing", label: "Health-data sharing", pattern: /\b(health|clinical|diabetes|hypertension|obesity|rpm|rtm|telehealth|pharmacy|provider|care|clinic|chw)\b/ },
  { id: "provider_handoff", label: "Provider handoff", pattern: /\b(provider|clinic|telehealth|mobile clinic|pharmacy|advisor|partner|handoff|referral)\b/ },
  { id: "communications", label: "Communications", pattern: /\b(message|sms|whatsapp|email|call|phone|telegram|contact)\b/ },
  { id: "payments", label: "Payments", pattern: /\b(payment|pay|checkout|buy|purchase|invoice|marketplace)\b/ },
  { id: "applications", label: "Applications", pattern: /\b(application|apply|enroll|job|workforce|training|learning)\b/ },
  { id: "referrals", label: "Referrals", pattern: /\b(referral|refer|provider|employer|training|workforce|clinic|partner)\b/ },
  { id: "sensitive_persistent_memory", label: "Sensitive persistent memory", pattern: /\b(memory|save|store|persistent|record|medical|health|location|payment)\b/ }
]);

function nexusUniversalConsentRequirements(review = {}) {
  const text = [
    review.workflowId,
    review.workflowLabel,
    review.category,
    review.riskLevel,
    review.plannedAction,
    review.destinationOrRecipient,
    review.dataBeingShared,
    review.providerOrChannel
  ].join(" ").toLowerCase();
  return NEXUS_UNIVERSAL_CONSENT_CATEGORIES.filter(category => category.pattern.test(text)).map(category => ({
    ...category,
    required: true,
    explicitConsentRequired: true
  }));
}

function nexusUniversalActionReviewForWorkflow(definition = {}, packet = null, lane = null, options = {}) {
  const id = definition.id || packet?.workflowId || nexusActiveWorkflowState?.id || "nexus-workflow";
  const registry = nexusWorkflowRegistryEntry(id) || {};
  const presentation = definition.presentation || {};
  const title = packet?.workflowLabel || registry.label || presentation.title || "Nexus workflow";
  const category = registry.category || lane?.category || "general";
  const riskLevel = registry.riskLevel || (lane?.requiresConfirmation ? "review-required" : "local-review");
  const missing = Array.from(new Set([
    ...(lane?.requiredCredentials || []),
    ...(lane?.missingCredentials || []),
    ...((lane && lane.liveModeAvailable === false && lane.status !== "active_test_mode") ? ["live provider/vendor configuration"] : [])
  ].filter(Boolean)));
  const providerUnavailable = missing.length > 0 || /not_configured|missing|inactive|blocked/i.test(String(lane?.status || ""));
  const executionLive = Boolean(lane?.liveModeAvailable && lane?.status === "active_live");
  const executionLocal = !executionLive;
  const willQueue = providerUnavailable || Boolean(options.willQueue) || /queue|offline|prepared|inactive/i.test(String(packet?.outcomeStatus || lane?.lastActionStatus || ""));
  const dataFields = packet?.payload && typeof packet.payload === "object"
    ? Object.keys(packet.payload).filter(key => String(packet.payload[key] || "").trim()).slice(0, 6)
    : [];
  const providerOrChannel = lane?.partnerName || lane?.label || registry.integrationLaneId || "Local Nexus review";
  const review = {
    schemaVersion: "nexus-universal-action-review.v1",
    workflowId: id,
    workflowLabel: title,
    category,
    riskLevel,
    plannedAction: `Prepare and review ${title}.`,
    destinationOrRecipient: providerUnavailable ? "No external destination until provider is configured and approved." : providerOrChannel,
    dataBeingShared: dataFields.length ? dataFields.join(", ") : "Only the visible packet details after user review.",
    providerOrChannel,
    knownCost: "No known cost in this local review.",
    knownFee: "No known fee in this local review.",
    knownRisk: /clinical|healthcare/i.test(category)
      ? "Sensitive health context requires consent, provider review, and no diagnosis or prescribing."
      : /payment|marketplace|external-execution|high/i.test(`${category} ${riskLevel}`)
        ? "External action risk requires final confirmation, audit, and configured provider."
        : "Local preparation risk only until an external provider is configured.",
    reversible: executionLive ? "Unknown - depends on provider confirmation and action type." : "Yes - this local review can be edited, cancelled, delayed, or saved as a draft.",
    executionLive,
    executionLocal,
    willQueue,
    providerUnavailable,
    missingRequirements: missing,
    explicitApprovalRequired: Boolean(registry.requiresConfirmationBeforeExecution || lane?.requiresConfirmation || /clinical|external|high|payment/i.test(`${category} ${riskLevel}`)),
    approvalIntentOnly: true,
    finalExecutionGateRequired: true,
    executionAuthority: false,
    noExecutionAuthorized: true,
    providerHandoffAllowed: false,
    noSilentSend: true,
    noSilentCall: true,
    noHiddenProviderHandoff: true
  };
  return {
    ...review,
    consentRequirements: nexusUniversalConsentRequirements(review)
  };
}

function renderNexusUniversalActionReviewLayer(review = nexusUniversalActionReviewForWorkflow()) {
  const consent = review.consentRequirements || [];
  const rows = [
    ["What Nexus plans to do", review.plannedAction],
    ["Destination or recipient", review.destinationOrRecipient],
    ["Data being shared", review.dataBeingShared],
    ["Provider or channel", review.providerOrChannel],
    ["Known cost", review.knownCost],
    ["Known fee", review.knownFee],
    ["Known risk", review.knownRisk],
    ["Reversible", review.reversible],
    ["Execution is live", review.executionLive ? "Yes - only after final provider and confirmation gates." : "No"],
    ["Execution is local", review.executionLocal ? "Yes - local review/preparation only." : "No"],
    ["Will queue", review.willQueue ? "Yes - queued or draftable until ready." : "No"],
    ["Provider unavailable", review.providerUnavailable ? "Yes - missing setup blocks live handoff." : "No"]
  ];
  return `
    <section class="nexus-universal-action-review" data-nexus-universal-action-review-layer="true" data-nexus-action-review-schema="${escapeHtml(review.schemaVersion)}" data-execution-authority="false" data-provider-handoff="false" data-no-silent-send="true" data-no-silent-call="true" data-final-execution-gate-required="true">
      <div class="nexus-universal-action-review-heading">
        <div>
          <span class="eyebrow">${escapeHtml(translateText("Universal action review"))}</span>
          <strong>${escapeHtml(translateText("Review before approval"))}</strong>
        </div>
        <span>${escapeHtml(translateText(review.explicitApprovalRequired ? "Explicit consent required" : "Local review"))}</span>
      </div>
      <dl>
        ${rows.map(([label, value]) => `
          <div>
            <dt>${escapeHtml(translateText(label))}</dt>
            <dd>${escapeHtml(translateText(value || "Not specified"))}</dd>
          </div>
        `).join("")}
      </dl>
      <div class="nexus-universal-consent-list" data-nexus-explicit-consent-categories="true">
        <strong>${escapeHtml(translateText("Explicit consent categories"))}</strong>
        ${(consent.length ? consent : [{ id: "local_review", label: "Local preparation review", explicitConsentRequired: false }]).map(item => `
          <span data-nexus-consent-category="${escapeHtml(item.id)}">${escapeHtml(translateText(item.label))}${item.explicitConsentRequired ? ` - ${escapeHtml(translateText("required before external execution"))}` : ""}</span>
        `).join("")}
      </div>
      ${review.missingRequirements?.length ? `
        <p class="nexus-universal-action-review-warning">${escapeHtml(translateText(`Provider unavailable until setup is complete: ${review.missingRequirements.join(", ")}.`))}</p>
      ` : ""}
      <p>${escapeHtml(translateText("Approving here records approval intent only. Nexus still requires a final execution gate, configured provider, consent, audit, and result verification before any live action."))}</p>
      <div class="nexus-universal-action-review-actions">
        <button type="button" class="primary" data-nexus-universal-action-review="approve" data-workflow-id="${escapeHtml(review.workflowId)}">${escapeHtml(translateText("Approve"))}</button>
        <button type="button" data-nexus-universal-action-review="edit" data-workflow-id="${escapeHtml(review.workflowId)}">${escapeHtml(translateText("Edit"))}</button>
        <button type="button" data-nexus-universal-action-review="cancel" data-workflow-id="${escapeHtml(review.workflowId)}">${escapeHtml(translateText("Cancel"))}</button>
        <button type="button" data-nexus-universal-action-review="delay" data-workflow-id="${escapeHtml(review.workflowId)}">${escapeHtml(translateText("Delay"))}</button>
        <button type="button" data-nexus-universal-action-review="save-draft" data-workflow-id="${escapeHtml(review.workflowId)}">${escapeHtml(translateText("Save as draft"))}</button>
      </div>
    </section>
  `;
}

function renderNexusActionReceipt(packet = null, entry = null) {
  const status = entry?.outcomeStatus || packet?.outcomeStatus || "draft";
  const receiptAttempt = entry?.executionAttempt || buildNexusVerifiedExecutionAttemptRecord(
    packet || {
      packetId: "nexus-draft-workflow",
      packetType: "workflow_opened",
      destinationLabel: "Local Nexus review"
    },
    {
      status,
      outcomeStatus: status,
      resultMessage: status === "draft"
        ? "Workflow opened locally. No provider response recorded."
        : "Outcome pending local review.",
      verificationStatus: "not_started"
    },
    packet ? nexusIntegrationLaneById(packet.destinationLaneId) : null
  );
  const readableReceipt = entry?.readableReceipt || buildNexusReadableReceipt(packet || {}, {
    outcomeStatus: status,
    normalizedExecutionState: receiptAttempt.normalizedExecutionState,
    providerResponse: receiptAttempt.providerResponse,
    verificationEvidence: receiptAttempt.verificationEvidence,
    timestamp: receiptAttempt.attemptTime,
    followUpStatus: "Review next step before any external action."
  });
  return `
    <section class="nexus-action-receipt" data-nexus-action-receipt="true">
      <strong>${escapeHtml(translateText("Action receipt"))}</strong>
      <div>
        <b>${escapeHtml(translateText("Nexus did:"))}</b>
        <ul>
          <li>${escapeHtml(translateText(packet ? `Prepared ${packet.workflowLabel}.` : "Opened the workflow safely."))}</li>
          <li>${escapeHtml(translateText(/queued/i.test(status) ? "Created a local queue item." : "Kept the work in local review."))}</li>
        </ul>
      </div>
      <div>
        <b>${escapeHtml(translateText("Nexus did not:"))}</b>
        <ul>
          <li>${escapeHtml(translateText("Send externally, contact a provider, approve a refill, book, pay, dispatch, call, or message anyone unless a configured provider confirmed success."))}</li>
          <li>${escapeHtml(translateText("Hide missing credentials or claim unavailable live action."))}</li>
        </ul>
      </div>
      <p>${escapeHtml(translateText(`Status: ${nexusStatusBadgeLabel(status)}`))}${entry?.resultMessage ? ` - ${escapeHtml(translateText(entry.resultMessage))}` : ""}</p>
      ${renderNexusReadableReceiptFields(readableReceipt)}
      ${renderNexusVerifiedExecutionStatus(receiptAttempt)}
    </section>
  `;
}

function saveNexusRuntimeMemory() {
  try {
    localStorage.setItem("nexusActiveWorkflowState", JSON.stringify(nexusActiveWorkflowState || {}));
    localStorage.setItem("nexusPreparedPackets", JSON.stringify(nexusPreparedPackets.slice(0, 25)));
    localStorage.setItem("nexusActionHistory", JSON.stringify(nexusActionHistory.slice(0, 25)));
    localStorage.setItem("nexusMissionHistory", JSON.stringify(nexusMissionHistory.slice(0, 50)));
    localStorage.setItem("nexusApprovedMemoryRecords", JSON.stringify(nexusApprovedMemoryRecords.slice(0, 50)));
    localStorage.setItem("nexusPartnerProfiles", JSON.stringify(nexusPartnerProfiles.slice(0, 25)));
    localStorage.setItem("nexusLaneConfigOverrides", JSON.stringify(nexusLaneConfigOverrides || {}));
    localStorage.setItem("nexusRecentWorkflows", JSON.stringify(nexusRecentWorkflows.slice(0, 8)));
    localStorage.setItem("nexusAgenticCommandMissions", JSON.stringify(nexusAgenticCommandMissions.slice(0, 25)));
    localStorage.setItem("nexusAgenticCommandLocalMemory", JSON.stringify(nexusAgenticCommandLocalMemory || {}));
    localStorage.setItem(NEXUS_CHRONIC_PREDICTIVE_STORAGE_KEY, JSON.stringify(nexusChronicPredictiveModelerState || buildEmptyNexusChronicPredictiveModelerState()));
    localStorage.setItem(NEXUS_AGRICULTURE_PREDICTIVE_STORAGE_KEY, JSON.stringify(nexusAgriculturePredictiveModelerState || buildEmptyNexusAgriculturePredictiveModelerState()));
    localStorage.setItem(NEXUS_MULTI_DOMAIN_PREDICTIVE_STORAGE_KEY, JSON.stringify(nexusMultiDomainPredictiveState || {}));
    localStorage.setItem(NEXUS_PREDICTIVE_MATURITY_STORAGE_KEY, JSON.stringify(nexusPredictiveMaturityMemory || buildEmptyNexusPredictiveMaturityMemory()));
    localStorage.setItem(NEXUS_PERSISTENT_MEMORY_STORAGE_KEY, JSON.stringify(nexusPersistentMemoryState || {}));
    localStorage.setItem("nexusUserExperienceRole", nexusUserExperienceRole);
    localStorage.setItem("nexusLowBandwidthMode", nexusLowBandwidthMode ? "true" : "false");
    localStorage.setItem("nexusLanguagePreference", nexusLanguagePreference || "");
    localStorage.setItem("nexusGuidedWorkflowAnswers", JSON.stringify(nexusGuidedWorkflowAnswers || {}));
  } catch {
    // Local storage can be unavailable; Nexus keeps the current session state.
  }
}

function restoreNexusRuntimeMemory() {
  try {
    nexusActiveWorkflowState = JSON.parse(localStorage.getItem("nexusActiveWorkflowState") || "null") || nexusActiveWorkflowState;
    nexusPreparedPackets = JSON.parse(localStorage.getItem("nexusPreparedPackets") || "[]") || [];
    nexusActionHistory = JSON.parse(localStorage.getItem("nexusActionHistory") || "[]") || [];
    nexusMissionHistory = JSON.parse(localStorage.getItem("nexusMissionHistory") || "[]") || [];
    nexusApprovedMemoryRecords = JSON.parse(localStorage.getItem("nexusApprovedMemoryRecords") || "[]") || [];
    nexusPartnerProfiles = JSON.parse(localStorage.getItem("nexusPartnerProfiles") || "[]") || [];
    nexusLaneConfigOverrides = JSON.parse(localStorage.getItem("nexusLaneConfigOverrides") || "{}") || {};
    nexusRecentWorkflows = JSON.parse(localStorage.getItem("nexusRecentWorkflows") || "[]") || [];
    nexusAgenticCommandMissions = JSON.parse(localStorage.getItem("nexusAgenticCommandMissions") || "[]") || [];
    nexusAgenticCommandLocalMemory = {
      ...nexusAgenticCommandLocalMemory,
      ...(JSON.parse(localStorage.getItem("nexusAgenticCommandLocalMemory") || "{}") || {})
    };
    nexusChronicPredictiveModelerState = {
      ...buildEmptyNexusChronicPredictiveModelerState(),
      ...(JSON.parse(localStorage.getItem(NEXUS_CHRONIC_PREDICTIVE_STORAGE_KEY) || "{}") || {})
    };
    nexusAgriculturePredictiveModelerState = {
      ...buildEmptyNexusAgriculturePredictiveModelerState(),
      ...(JSON.parse(localStorage.getItem(NEXUS_AGRICULTURE_PREDICTIVE_STORAGE_KEY) || "{}") || {})
    };
    nexusMultiDomainPredictiveState = JSON.parse(localStorage.getItem(NEXUS_MULTI_DOMAIN_PREDICTIVE_STORAGE_KEY) || "{}") || {};
    nexusPredictiveMaturityMemory = {
      ...buildEmptyNexusPredictiveMaturityMemory(),
      ...(JSON.parse(localStorage.getItem(NEXUS_PREDICTIVE_MATURITY_STORAGE_KEY) || "{}") || {})
    };
    if (nexusPersistentMemoryService) {
      nexusPersistentMemoryState = JSON.parse(localStorage.getItem(NEXUS_PERSISTENT_MEMORY_STORAGE_KEY) || "null")
        || nexusPersistentMemoryService.emptyState(nexusPersistentMemoryService.persistenceStatus({}, "local_browser"));
    }
    nexusUserExperienceRole = localStorage.getItem("nexusUserExperienceRole") || "Standard User";
    nexusLowBandwidthMode = localStorage.getItem("nexusLowBandwidthMode") === "true";
    nexusLanguagePreference = localStorage.getItem("nexusLanguagePreference") || "";
    nexusGuidedWorkflowAnswers = JSON.parse(localStorage.getItem("nexusGuidedWorkflowAnswers") || "{}") || {};
  } catch {
    nexusPreparedPackets = [];
    nexusActionHistory = [];
    nexusMissionHistory = [];
    nexusApprovedMemoryRecords = [];
    nexusPartnerProfiles = [];
    nexusLaneConfigOverrides = {};
    nexusRecentWorkflows = [];
    nexusAgenticCommandMissions = [];
    nexusAgenticCommandLocalMemory = {
      healthIntakes: [],
      chronicReadings: [],
      providerPackets: [],
      buyers: [],
      sellers: [],
      marketplaceRecords: [],
      shipmentRecords: [],
      tradeRoutePlans: [],
      shipments: [],
      employmentRecords: [],
      jobApplicationDrafts: [],
      employers: [],
      learningPlans: [],
      droneMissions: [],
      communicationDrafts: [],
      missions: [],
      receipts: []
    };
    nexusChronicPredictiveModelerState = buildEmptyNexusChronicPredictiveModelerState();
    nexusAgriculturePredictiveModelerState = buildEmptyNexusAgriculturePredictiveModelerState();
    nexusMultiDomainPredictiveState = {};
    nexusPredictiveMaturityMemory = buildEmptyNexusPredictiveMaturityMemory();
    nexusPersistentMemoryState = nexusPersistentMemoryService ? nexusPersistentMemoryService.emptyState(nexusPersistentMemoryService.persistenceStatus({}, "local_browser")) : nexusPersistentMemoryState;
    nexusGuidedWorkflowAnswers = {};
  }
}

function clearNexusSensitiveLocalData() {
  nexusPreparedPackets = [];
  nexusActionHistory = [];
  nexusMissionHistory = [];
  nexusApprovedMemoryRecords = [];
  nexusPartnerProfiles = [];
  nexusLaneConfigOverrides = {};
  nexusRecentWorkflows = [];
  nexusAgenticCommandMissions = [];
  nexusAgenticCommandLocalMemory = {
    healthIntakes: [],
    chronicReadings: [],
    providerPackets: [],
    buyers: [],
    sellers: [],
    marketplaceRecords: [],
    shipmentRecords: [],
    tradeRoutePlans: [],
    shipments: [],
    employmentRecords: [],
    jobApplicationDrafts: [],
    employers: [],
    learningPlans: [],
    droneMissions: [],
    communicationDrafts: [],
    missions: [],
    receipts: []
  };
  nexusChronicPredictiveModelerState = buildEmptyNexusChronicPredictiveModelerState();
  nexusAgriculturePredictiveModelerState = buildEmptyNexusAgriculturePredictiveModelerState();
  nexusMultiDomainPredictiveState = {};
  nexusPredictiveMaturityMemory = buildEmptyNexusPredictiveMaturityMemory();
  nexusGuidedWorkflowAnswers = {};
  nexusActiveWorkflowState = { id: "", command: "", source: "cleared", workflow: "", action: "", openedAt: 0 };
  try {
    localStorage.removeItem("nexusActiveWorkflowState");
    localStorage.removeItem("nexusPreparedPackets");
    localStorage.removeItem("nexusActionHistory");
    localStorage.removeItem("nexusMissionHistory");
    localStorage.removeItem("nexusApprovedMemoryRecords");
    localStorage.removeItem("nexusPartnerProfiles");
    localStorage.removeItem("nexusLaneConfigOverrides");
    localStorage.removeItem("nexusRecentWorkflows");
    localStorage.removeItem("nexusAgenticCommandMissions");
    localStorage.removeItem("nexusAgenticCommandLocalMemory");
    localStorage.removeItem(NEXUS_CHRONIC_PREDICTIVE_STORAGE_KEY);
    localStorage.removeItem(NEXUS_AGRICULTURE_PREDICTIVE_STORAGE_KEY);
    localStorage.removeItem(NEXUS_MULTI_DOMAIN_PREDICTIVE_STORAGE_KEY);
    localStorage.removeItem(NEXUS_PREDICTIVE_MATURITY_STORAGE_KEY);
    localStorage.removeItem(NEXUS_PERSISTENT_MEMORY_STORAGE_KEY);
    localStorage.removeItem("nexusGuidedWorkflowAnswers");
  } catch {}
  nexusAgenticBrainLastResult = {
    ok: true,
    status: "nexus_local_sensitive_data_cleared",
    mode: "Nexus memory",
    message: "Local workflow memory, prepared packets, and action history were cleared from this browser.",
    preparedCards: [],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_runtime_memory"
  };
  renderUserWorkspace();
}

function runNexusWorkflowControllerAction(action = "", workflowId = "") {
  const id = normalizeNexusWorkflowId(workflowId || nexusActiveWorkflowState?.id || "", nexusActiveWorkflowState?.command || "");
  const registry = nexusWorkflowRegistryEntry(id);
  if (!registry) return false;
  const packet = buildNexusPacket(id, nexusFormDataForWorkflow(id), { command: nexusActiveWorkflowState?.command || "" });
  const prepared = prepareNexusAction(packet);
  let result = null;
  if (action === "request-confirmation") {
    const confirmation = requestNexusConfirmation(packet);
    result = {
      resultId: `nexus-result-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      packetId: packet.packetId,
      laneId: packet.destinationLaneId,
      adapterType: prepared.lane ? nexusAdapterForPacket(packet, prepared.lane).adapterType : "local",
      mode: "confirmation",
      status: "waiting_for_confirmation",
      laneStatus: packet.integrationStatus,
      outcomeStatus: "waiting_for_confirmation",
      userMessage: confirmation.message,
      resultMessage: confirmation.message,
      externalReference: "",
      verificationStatus: "not_started",
      timestamp: new Date().toISOString(),
      errorCode: "",
      errorMessage: "",
      nextSteps: ["Confirm reviewed packet", "Edit packet", "Queue packet", "Cancel"],
      followUpStatus: "waiting for explicit user approval"
    };
  } else if (action === "queue-packet") {
    result = queueNexusAction(packet, "manual_queue");
  } else if (action === "execute-confirmed-test") {
    result = executeNexusAction(packet, prepared.lane, { confirmed: true });
  } else {
    result = {
      packetId: packet.packetId,
      laneId: packet.destinationLaneId,
      adapterType: prepared.lane ? nexusAdapterForPacket(packet, prepared.lane).adapterType : "local",
      mode: "prepare",
      status: prepared.status === "waiting_for_confirmation" ? "waiting_for_confirmation" : "prepared",
      laneStatus: packet.integrationStatus,
      outcomeStatus: prepared.status === "waiting_for_confirmation" ? "waiting_for_confirmation" : "prepared",
      userMessage: prepared.message,
      resultMessage: prepared.message,
      externalReference: "",
      verificationStatus: "prepared_local_only",
      timestamp: new Date().toISOString(),
      errorCode: "",
      errorMessage: "",
      nextSteps: ["Review confirmation", "Queue if inactive", "Export/copy packet"],
      followUpStatus: prepared.requiresConfirmation ? "review confirmation" : "review packet"
    };
  }
  packet.outcomeStatus = result.outcomeStatus;
  packet.updatedAt = new Date().toISOString();
  nexusPreparedPackets = [packet, ...nexusPreparedPackets].slice(0, 25);
  showNexusOutcome(packet, result);
  saveNexusRuntimeMemory();
  renderUserWorkspace();
  requestAnimationFrame(() => focusNexusActiveWorkflow());
  return true;
}

function handleNexusWorkflowControllerClick(event) {
  const button = event.target?.closest?.("[data-nexus-action-controller]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  return runNexusWorkflowControllerAction(button.dataset.nexusActionController || "prepare-packet", button.dataset.workflowId || "");
}

function handleNexusPacketActionClick(event) {
  const button = event.target?.closest?.("[data-nexus-packet-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.nexusPacketAction || "";
  const packetId = button.dataset.packetId || "";
  if (action === "confirm") return confirmNexusPacket(packetId);
  if (action === "cancel") return cancelNexusPacket(packetId);
  if (action === "edit") return editNexusPacket(packetId);
  if (action === "queue") {
    const packet = nexusPreparedPackets.find(item => item.packetId === packetId);
    if (!packet) return false;
    queueNexusPreparedPacket(packet, "confirmation_panel_queue");
    renderUserWorkspace();
    return true;
  }
  if (action === "retry") return retryNexusAction(button.dataset.actionId || "");
  return false;
}

function handleNexusGlobalActivationCenterClick(event) {
  const button = event.target?.closest?.("[data-nexus-activation-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.nexusActivationAction || "";
  const lanes = nexusAllIntegrationLanes().map(lane => ({ ...lane, ...(nexusLaneConfigOverrides[lane.id] || {}) }));
  const summary = nexusGlobalActivationCenterSummary(lanes);
  if (action === "export-global-lanes") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_activation_lane_registry_export_prepared",
      mode: "Activation Center",
      message: `Global activation lane registry export is ready with ${summary.laneCount} lane(s), ${summary.partnerProfileCount} partner profile(s), and no secret values.`,
      preparedCards: [{
        type: "global_activation_lane_registry_export",
        title: "Global activation lane registry",
        status: "secret-safe local export prepared",
        localOnly: true
      }],
      summary,
      lanes: lanes.map(lane => ({
        id: lane.id,
        label: lane.label,
        category: lane.category,
        region: lane.region,
        status: lane.status,
        testModeAvailable: Boolean(lane.testModeAvailable),
        liveModeAvailable: Boolean(lane.liveModeAvailable),
        requiresConfirmation: Boolean(lane.requiresConfirmation),
        packetType: lane.packetType,
        requiredCredentials: lane.requiredCredentials || [],
        missingCredentials: lane.missingCredentials || (lane.liveModeAvailable ? [] : ["live credentials / approval"]),
        secretsIncluded: false
      })),
      noExecutionAuthorized: true,
      noSecretsExposed: true,
      noProviderContactAuthorized: true,
      localOnly: true,
      source: "nexus_global_activation_center"
    };
  }
  if (action === "show-partner-registry") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_partner_registry_listed",
      mode: "Activation Center",
      message: `${nexusPartnerProfiles.length} local partner profile(s) available. Profiles are local review records and do not contact partners or expose secrets.`,
      preparedCards: (nexusPartnerProfiles.length ? nexusPartnerProfiles : [{ organizationName: "No partner profiles yet", serviceCategories: "Add one below" }]).slice(0, 6).map(profile => ({
        type: "global_partner_registry_profile",
        title: profile.organizationName || "Partner profile",
        status: profile.serviceCategories || "local review",
        localOnly: true
      })),
      partnerProfileCount: nexusPartnerProfiles.length,
      noExecutionAuthorized: true,
      noSecretsExposed: true,
      noProviderContactAuthorized: true,
      localOnly: true,
      source: "nexus_global_activation_center"
    };
  }
  saveNexusRuntimeMemory();
  renderUserWorkspace();
  return true;
}

function handleNexusLaneActionClick(event) {
  const button = event.target?.closest?.("[data-nexus-lane-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const laneId = button.dataset.laneId || "";
  const action = button.dataset.nexusLaneAction || "";
  const lane = nexusIntegrationLaneById(laneId);
  if (!lane) return false;
  const laneFields = {};
  document.querySelectorAll("[data-nexus-lane-config-field]").forEach(field => {
    if (field.dataset.laneId !== laneId) return;
    laneFields[field.dataset.nexusLaneConfigField] = String(field.value || "").trim();
  });
  if (action === "test") {
    const workflow = nexusAllAgenticWorkflows().find(item => item.integrationLaneId === laneId) || nexusAllAgenticWorkflows()[0];
    const packet = buildNexusPacket(workflow.id, { activationTest: lane.label }, { command: "activation center test", consentAccepted: true });
    const testLane = { ...lane, status: "active_test_mode" };
    const result = executeNexusAction(packet, testLane, { confirmed: true });
    packet.outcomeStatus = result.outcomeStatus;
    nexusPreparedPackets = [packet, ...nexusPreparedPackets].slice(0, 25);
    showNexusOutcome(packet, result);
    saveNexusRuntimeMemory();
    renderUserWorkspace();
    return true;
  }
  if (action === "configure") {
    nexusLaneConfigOverrides[laneId] = { ...(nexusLaneConfigOverrides[laneId] || {}), ...laneFields, status: "configured_inactive", lastVerifiedAt: new Date().toISOString() };
  }
  if (action === "link-partner") {
    const latestPartner = nexusPartnerProfiles[0];
    nexusLaneConfigOverrides[laneId] = {
      ...(nexusLaneConfigOverrides[laneId] || {}),
      ...laneFields,
      partnerName: latestPartner?.organizationName || laneFields.partnerName || lane.partnerName,
      linkedPartnerId: latestPartner?.id || "",
      status: "configured_inactive",
      lastVerifiedAt: new Date().toISOString()
    };
  }
  if (action === "export") {
    const exported = { ...lane, ...laneFields, ...(nexusLaneConfigOverrides[laneId] || {}), exportedAt: new Date().toISOString(), secretsIncluded: false };
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_lane_profile_export_prepared",
      mode: "Activation Center",
      message: `${exported.label} lane profile is ready to copy/export locally. No secrets are included and no provider was contacted.`,
      preparedCards: [{ type: "lane_profile_export", title: exported.label, status: exported.status, localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_activation_center"
    };
  }
  if (action === "disable") {
    nexusLaneConfigOverrides[laneId] = { ...(nexusLaneConfigOverrides[laneId] || {}), ...laneFields, status: "disabled", lastVerifiedAt: new Date().toISOString() };
  }
  saveNexusRuntimeMemory();
  renderUserWorkspace();
  return true;
}

function handleNexusPartnerOnboardingClick(event) {
  const button = event.target?.closest?.("[data-nexus-partner-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.nexusPartnerAction || "save";
  const form = button.closest("[data-nexus-partner-onboarding-form]");
  const profile = {};
  form?.querySelectorAll?.("[data-nexus-partner-field]")?.forEach(field => {
    profile[field.dataset.nexusPartnerField] = String(field.value || "").trim();
  });
  if (action === "export") {
    const latestPartner = nexusPartnerProfiles[0] || profile;
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_partner_profile_export_prepared",
      mode: "Activation Center",
      message: `${latestPartner.organizationName || "Partner profile"} is ready to copy/export locally. No secrets are included and no provider was contacted.`,
      preparedCards: [{ type: "partner_profile_export", title: latestPartner.organizationName || "Partner profile", status: "local export prepared", localOnly: true }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_activation_center"
    };
    renderUserWorkspace();
    return true;
  }
  profile.id = `nexus-partner-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  profile.createdAt = new Date().toISOString();
  profile.testModeAvailable = String(profile.testModeAvailable || "true").toLowerCase() !== "false";
  profile.liveModeApproved = String(profile.liveModeApproved || "false").toLowerCase() === "true" && Boolean(profile.organizationName && profile.serviceCategories);
  nexusPartnerProfiles = [profile, ...nexusPartnerProfiles].slice(0, 25);
  saveNexusRuntimeMemory();
  nexusAgenticBrainLastResult = {
    ok: true,
    status: "nexus_partner_profile_saved",
    mode: "Activation Center",
    message: "Partner profile saved locally. No secrets were stored and no provider was contacted.",
    preparedCards: [{ type: "partner_profile", title: profile.organizationName || "Partner profile", status: "local profile saved", localOnly: true }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_activation_center"
  };
  renderUserWorkspace();
  return true;
}

function showNexusRuntimeList(kind = "pending") {
  const statusByKind = {
    pending: ["prepared", "waiting_for_confirmation", "queued"],
    queued: ["queued"],
    failed: ["failed"],
    "follow-up": ["follow_up_needed", "response_received"]
  }[kind] || ["prepared", "waiting_for_confirmation", "queued"];
  const matchingHistory = nexusActionHistory.filter(entry => statusByKind.includes(entry.outcomeStatus));
  const matchingPackets = nexusPreparedPackets.filter(packet => statusByKind.includes(packet.outcomeStatus));
  nexusAgenticBrainLastResult = {
    ok: true,
    status: `nexus_${kind}_actions_listed`,
    mode: "Nexus action history",
    message: `${matchingPackets.length + matchingHistory.length} ${kind} item(s) found in local Nexus runtime memory.`,
    preparedCards: [
      ...matchingPackets.map(packet => ({ type: "nexus_packet", title: packet.workflowLabel, status: packet.outcomeStatus, localOnly: true })),
      ...matchingHistory.map(entry => ({ type: "nexus_action_history", title: entry.workflowId, status: entry.outcomeStatus, localOnly: entry.laneStatus !== "active_live" }))
    ],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_runtime_memory"
  };
  renderUserWorkspace();
  return true;
}

