function resolveNexusCapability(input = "", options = {}) {
  const text = String(input || "").toLowerCase().trim();
  const explicitId = String(options.capabilityId || options.modeId || "").toLowerCase().replace(/^sidebar-/, "").replace(/^core-/, "");
  if (explicitId && NEXUS_CAPABILITIES[explicitId]) return NEXUS_CAPABILITIES[explicitId];
  if (isNexusLiveKnowledgeQuestion(text)) return NEXUS_CAPABILITIES["live-knowledge"];
  const workflowId = normalizeNexusWorkflowId(explicitId, text);
  const directByWorkflow = Object.values(NEXUS_CAPABILITIES).find(item => item.workflowId === workflowId || item.id === workflowId);
  if (directByWorkflow) return directByWorkflow;
  return Object.values(NEXUS_CAPABILITIES).find(item => (item.aliases || []).some(alias => text.includes(String(alias).toLowerCase()))) || null;
}

function renderActiveNexusWorkspace(state = nexusActiveWorkflowState) {
  return renderNexusFunctionWindow(state);
}

function renderNexusFunctionWindow(state = nexusActiveWorkflowState) {
  return renderNexusActiveWorkflowWorkspace(state);
}

function closeNexusFunctionWindow(options = {}) {
  nexusActiveWorkflowState = null;
  nexusMinimizedFunctionWindowState = null;
  if (options.resetResult !== false) nexusAgenticBrainLastResult = buildNexusCapabilityOverviewResult(options.command || "What can Nexus do?");
  saveNexusRuntimeMemory();
  if (experienceMode === "user" || document.body.classList.contains("user-mode")) {
    renderUserWorkspace();
    $("#nexusCommandCenterInput")?.focus?.({ preventScroll: true });
  }
  return true;
}

function minimizeNexusFunctionWindow() {
  if (!nexusActiveWorkflowState?.id) return false;
  nexusMinimizedFunctionWindowState = { ...nexusActiveWorkflowState };
  nexusActiveWorkflowState = {
    ...nexusActiveWorkflowState,
    minimized: true,
    updatedAt: Date.now()
  };
  saveNexusRuntimeMemory();
  if (experienceMode === "user" || document.body.classList.contains("user-mode")) renderUserWorkspace();
  return true;
}

function restoreNexusFunctionWindow(functionIdOverride = "") {
  const previousState = nexusActiveWorkflowState?.id || nexusActiveWorkflowState?.functionId
    ? nexusActiveWorkflowState
    : nexusMinimizedFunctionWindowState || {};
  const overrideId = normalizeNexusFunctionId(functionIdOverride, previousState?.command || "");
  if (!previousState?.id && !previousState?.functionId && !overrideId) return false;
  const functionId = overrideId || normalizeNexusFunctionId(previousState.functionId || previousState.workflow || previousState.id, previousState.command || "");
  const workflowId = previousState.id || NEXUS_FUNCTION_WINDOW_ROUTE_MAP[functionId] || normalizeNexusWorkflowId(functionId, previousState.command || "") || "resource-assistant";
  nexusActiveWorkflowState = {
    ...(previousState || {}),
    id: workflowId,
    functionId,
    command: previousState?.command || NEXUS_FUNCTION_WINDOW_LABELS[functionId] || "Open Nexus function",
    source: previousState?.source || "function-window-dock-restore",
    workflow: previousState?.workflow || functionId,
    action: previousState?.action || "restore",
    openedAt: previousState?.openedAt || Date.now(),
    minimized: false,
    updatedAt: Date.now()
  };
  nexusMinimizedFunctionWindowState = null;
  saveNexusRuntimeMemory();
  if (experienceMode === "user" || document.body.classList.contains("user-mode")) {
    renderUserWorkspace();
    scheduleNexusActiveWorkflowFocus({ instant: true });
  }
  return true;
}

function openNexusFunctionWindow(functionId, options = {}) {
  const command = options.command || options.response || NEXUS_FUNCTION_WINDOW_LABELS[functionId] || functionId || "";
  const resolved = resolveNexusFunctionIntent(command, { ...options, functionId });
  const targetFunctionId = resolved.functionId || normalizeNexusFunctionId(functionId, command) || "live-knowledge";
  const definition = nexusFunctionWindowDefinition(targetFunctionId, command);
  const workflowId = definition?.id || NEXUS_FUNCTION_WINDOW_ROUTE_MAP[targetFunctionId] || normalizeNexusWorkflowId(options.workflowId || targetFunctionId, command) || "resource-assistant";
  nexusActiveWorkflowState = {
    id: workflowId,
    functionId: targetFunctionId,
    command,
    source: options.source || "nexus-function-window-system",
    workflow: options.workflow || targetFunctionId,
    action: options.action || resolved.type || "open",
    openedAt: Date.now(),
    minimized: false,
    guidedMode: options.guidedMode === true,
    transcript: options.transcript || (options.source === "voice-command" ? command : "")
  };
  recordNexusRecentWorkflow(workflowId, {
    status: "draft",
    command,
    title: definition?.presentation?.title || NEXUS_FUNCTION_WINDOW_LABELS[targetFunctionId],
    category: nexusWorkflowRegistryEntry(workflowId)?.category || "platform"
  });
  saveNexusRuntimeMemory();
  const panelResult = buildNexusHomeModePanelResult(workflowId, command);
  nexusAgenticBrainLastResult = options.preparedResult || panelResult || {
    ok: true,
    status: "nexus_function_window_opened",
    mode: definition?.presentation?.title || "Nexus function",
    message: `${definition?.presentation?.title || "Nexus function"} opened in a focused function window. No external action was executed.`,
    preparedCards: [{
      type: "nexus_function_window",
      title: definition?.presentation?.title || "Nexus function",
      status: "focused window open",
      localOnly: true,
      noExecutionAuthorized: true
    }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_function_window_system"
  };
  if (experienceMode === "user" || document.body.classList.contains("user-mode")) {
    renderUserWorkspace();
    scheduleNexusActiveWorkflowFocus({ instant: options.instant !== false });
  }
  return true;
}

function resolveNexusAppIntent(input, options = {}) {
  return resolveNexusFunctionIntent(input, { ...options, source: options.source || "nexus-app-window" });
}

function openNexusAppWindow(windowId, options = {}) {
  return openNexusFunctionWindow(windowId, { ...options, source: options.source || "nexus-app-window" });
}

function renderNexusAppWindow(state = nexusActiveWorkflowState) {
  return renderNexusFunctionWindow(state);
}

function closeNexusAppWindow(options = {}) {
  return closeNexusFunctionWindow(options);
}

function minimizeNexusAppWindow() {
  return minimizeNexusFunctionWindow();
}

function restoreNexusAppWindow(windowIdOverride = "") {
  return restoreNexusFunctionWindow(windowIdOverride);
}

function openNexusCapability(capabilityId, options = {}) {
  const capability = NEXUS_CAPABILITIES[String(capabilityId || "").toLowerCase()] || resolveNexusCapability(options.command || capabilityId, options);
  if (!capability) return false;
  const command = options.command || capability.title || capability.id;
  if (capability.id === "live-knowledge" || capability.action === "research") {
    openNexusFunctionWindow("live-knowledge", {
      ...options,
      command,
      source: options.source || "agentic-capability",
      action: "research",
      instant: true
    });
    runNexusKnowledgeQuery(command, {
      source: options.source || "agentic-capability",
      workflowId: capability.workflowId || "resource-assistant",
      functionId: "live-knowledge",
      sourceSurface: options.sourceSurface || "active_workspace"
    }).catch(error => {
      nexusKnowledgeActionStatus = error.message || "Live Knowledge needs attention.";
      if (experienceMode === "user") renderUserWorkspace();
    });
    return true;
  }
  if (capability.action === "continue") return continueLastNexusWorkflow() || openNexusWorkflow(capability.workflowId, { command, source: options.source || "agentic-capability", action: capability.action });
  if (capability.action === "status" || capability.action === "review-queue") {
    return openNexusFunctionWindow(capability.id === "admin-review" ? "admin-review" : capability.workflowId || "live-knowledge", {
      ...options,
      command,
      source: options.source || "agentic-capability",
      action: capability.action || "open",
      workflow: capability.id,
      instant: true
    });
  }
  return openNexusFunctionWindow(capability.id, {
    command,
    source: options.source || "agentic-capability",
    action: capability.action || "open",
    workflowId: capability.workflowId || capability.id,
    workflow: capability.id,
    instant: options.instant,
    preparedResult: options.preparedResult
  });
}

function launchCapabilityFromAskNexus(input = "") {
  if (isNexusPersistentOperationsCommand(input)) return false;
  const functionIntent = resolveNexusFunctionIntent(input, { source: "typed-command" });
  if (functionIntent.functionId) {
    const opened = openNexusFunctionWindow(functionIntent.functionId, { command: input, source: "typed-command", sourceSurface: "ask_nexus" });
    if (functionIntent.functionId === "live-knowledge") {
      runNexusKnowledgeQuery(input, { source: "typed-command", functionId: "live-knowledge", sourceSurface: "ask_nexus" }).catch(error => {
        nexusKnowledgeActionStatus = error.message || "Live Knowledge needs attention.";
        if (experienceMode === "user") renderUserWorkspace();
      });
    }
    return opened;
  }
  const capability = resolveNexusCapability(input);
  return capability ? openNexusCapability(capability.id, { command: input, source: "typed-command", sourceSurface: "ask_nexus" }) : false;
}

function launchCapabilityFromVoice(transcript = "") {
  if (isNexusPersistentOperationsCommand(transcript)) return false;
  const capability = resolveNexusCapability(transcript);
  const functionIntent = resolveNexusFunctionIntent(transcript, { source: "voice-command" });
  if (functionIntent.functionId) {
    const opened = openNexusFunctionWindow(functionIntent.functionId, { command: transcript, transcript, source: "voice-command", sourceSurface: "voice_audio" });
    if (functionIntent.functionId === "live-knowledge") {
      runNexusKnowledgeQuery(transcript, { source: "voice-command", functionId: "live-knowledge", sourceSurface: "voice_audio" }).catch(error => {
        nexusKnowledgeActionStatus = error.message || "Live Knowledge needs attention.";
        if (experienceMode === "user") renderUserWorkspace();
      });
    }
    return opened;
  }
  return capability ? openNexusCapability(capability.id, { command: transcript, source: "voice-command", sourceSurface: "voice_audio" }) : false;
}

function launchCapabilityFromClick(eventOrElement) {
  const target = eventOrElement?.target?.closest ? eventOrElement.target : eventOrElement;
  const shortcut = target?.closest?.("[data-nexus-mode-shortcut]");
  if (!shortcut) return false;
  const command = shortcut.dataset.nexusCommand || shortcut.textContent || "";
  const capability = resolveNexusCapability(command, { modeId: shortcut.dataset.nexusModeShortcut || "" });
  return capability ? openNexusCapability(capability.id, { command, source: "mode-click", sourceSurface: "click" }) : false;
}

function nexusUniversalNavigationRuntime() {
  return typeof window !== "undefined" ? window.NexusUniversalNavigationRuntime : null;
}

function nexusCurrentUniversalWorkspaceId() {
  return nexusActiveWorkflowState?.id
    || nexusActiveWorkflowState?.functionId
    || currentSectionId?.()
    || "health-home";
}

function buildNexusUniversalExplanationResult(explanation = {}, route = {}) {
  const isGlobal = explanation.type === "global";
  const cards = isGlobal
    ? (nexusUniversalNavigationRuntime()?.WORKSPACES || []).slice(0, 12).map(item => ({
      type: "universal_navigation_workspace",
      title: item.title,
      status: item.statusLabel,
      routeTarget: item.routeTarget,
      localOnly: true,
      noExecutionAuthorized: true
    }))
    : [{
      type: "universal_navigation_workspace_explanation",
      title: explanation.title,
      status: explanation.statusLabel || "Workspace explained",
      routeTarget: route.routeTarget || explanation.id || "",
      localOnly: true,
      noExecutionAuthorized: true
    }];
  return {
    ok: true,
    status: isGlobal ? "nexus_global_capability_explained" : "nexus_workspace_explained",
    mode: explanation.title || "Nexus Universal Navigation",
    message: explanation.message || "Nexus explained this workspace. No external action was executed.",
    explanation,
    routeIntent: route,
    preparedCards: cards,
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_universal_navigation_runtime"
  };
}

function handleNexusUniversalNavigationCommand(input = "", options = {}) {
  const runtime = nexusUniversalNavigationRuntime();
  if (!runtime) return false;
  const text = String(input || "").trim();
  if (!text) return false;
  const route = runtime.route(text, {
    inputType: options.inputType || "text",
    sourceElement: options.sourceElement || options.source || "",
    modeId: options.modeId || "",
    routeTarget: options.routeTarget || "",
    currentWorkspaceId: options.currentWorkspaceId || nexusCurrentUniversalWorkspaceId(),
    explanationRequired: options.explanationRequired
  });
  if (!route || route.confidence < 0.6) return false;
  if (route.kind === "global-explanation" || route.requiredAction === "show_global_capabilities") {
    nexusAgenticBrainLastResult = buildNexusUniversalExplanationResult(runtime.globalExplanation(), route);
    nexusActiveWorkflowState = {
      id: "resource-assistant",
      command: text,
      source: options.source || `${route.inputType}-universal-navigation`,
      workflow: "universal-navigation",
      action: "explain-global-capabilities",
      openedAt: Date.now()
    };
    saveNexusRuntimeMemory();
    if (experienceMode === "user" || document.body.classList.contains("user-mode")) renderUserWorkspace();
    return true;
  }
  if (route.kind === "workspace-explanation" || route.requiredAction === "explain_workspace") {
    const workspaceId = route.workspace?.id || nexusCurrentUniversalWorkspaceId();
    nexusAgenticBrainLastResult = buildNexusUniversalExplanationResult(runtime.workspaceExplanation(workspaceId), route);
    saveNexusRuntimeMemory();
    if (experienceMode === "user" || document.body.classList.contains("user-mode")) renderUserWorkspace();
    return true;
  }
  if (route.routeTarget && nexusWorkflowDefinition(route.routeTarget, text)) {
    const opened = openNexusWorkflow(route.routeTarget, {
      command: text,
      source: options.source || `${route.inputType}-universal-navigation`,
      universalNavigationIntent: route
    });
    if (opened) {
      nexusActiveWorkflowState = {
        ...(nexusActiveWorkflowState || {}),
        universalNavigationIntent: route,
        matchedMiniApp: route.matchedMiniApp,
        matchedMode: route.matchedMode,
        requiredAction: route.requiredAction,
        providerRequired: route.providerRequired,
        explanationRequired: route.explanationRequired,
        safetyLevel: route.safetyLevel
      };
      saveNexusRuntimeMemory();
    }
    return opened;
  }
  return false;
}

function routeNexusPredictiveSuggestion(suggestion = {}) {
  const runtime = nexusUniversalNavigationRuntime();
  if (!runtime) return false;
  const route = runtime.predictiveSuggestionRoute(suggestion);
  return handleNexusUniversalNavigationCommand(route.rawInput || suggestion.command || suggestion.title || "", {
    inputType: "suggestion",
    sourceElement: suggestion.id || "predictive-suggestion",
    routeTarget: route.matchedMiniApp
  });
}

function routeNexusProviderReadinessCard(provider = {}) {
  const runtime = nexusUniversalNavigationRuntime();
  if (!runtime) return false;
  const route = runtime.providerReadinessRoute(provider);
  return handleNexusUniversalNavigationCommand(route.rawInput || provider.name || provider.id || "provider readiness", {
    inputType: "providerCard",
    sourceElement: provider.id || provider.providerId || "provider-card",
    routeTarget: route.matchedMiniApp
  });
}

function routeNexusSavedRecordLink(record = {}) {
  const runtime = nexusUniversalNavigationRuntime();
  if (!runtime) return false;
  const route = runtime.savedRecordRoute(record);
  return handleNexusUniversalNavigationCommand(route.rawInput || record.title || record.type || "", {
    inputType: record.receiptType ? "receipt" : "savedRecord",
    sourceElement: record.id || record.recordId || "saved-record",
    routeTarget: route.matchedMiniApp
  });
}

function resolveNexusIntent(input, options = {}) {
  const text = String(input || "").trim();
  const functionId = normalizeNexusFunctionId(options.functionId || options.modeId || options.workflowId || "", text);
  if (functionId) {
    return { type: functionId === "live-knowledge" ? "research" : "function-window", functionId, workflowId: NEXUS_FUNCTION_WINDOW_ROUTE_MAP[functionId] || normalizeNexusWorkflowId(functionId, text), text };
  }
  const capability = resolveNexusCapability(text, options);
  if (capability) return { type: capability.action === "research" ? "research" : "workflow", workflowId: capability.workflowId, capabilityId: capability.id, text };
  const workflowId = normalizeNexusWorkflowId(options.workflowId || "", text) || detectNexusHomeModePanelId(text);
  if (/\b(activation center|provider vendor registry|provider\/vendor registry|admin console|pilot readiness)\b/i.test(text)) {
    return { type: "activation-center", workflowId: "activation-center", text };
  }
  if (/\b(command center|pilot status|activation status|live lanes|test lanes)\b/i.test(text)) {
    return { type: "command-center", workflowId: "command-center", text };
  }
  if (/\b(provider queue|vendor queue|admin queue|clinical queue|pharmacy queue|mobile clinic queue|marketplace queue|workforce referrals)\b/i.test(text)) {
    return { type: "review-queue", workflowId: "review-queue", text };
  }
  return { type: workflowId ? "workflow" : "unknown", workflowId, text };
}

function resolveNexusFunctionIntent(input, options = {}) {
  const text = String(input || "").trim();
  const routeFirstText = text.toLowerCase();
  const routeFirstIntent = /\b(map|maps|route|routes|directions|field visit|farm visit)\b/.test(routeFirstText)
    || /\bfrom\s+.{2,}\s+to\s+.{2,}/.test(routeFirstText);
  if (routeFirstIntent) {
    return {
      type: "function-window",
      functionId: "maps",
      workflowId: NEXUS_FUNCTION_WINDOW_ROUTE_MAP.maps || normalizeNexusWorkflowId("maps", text),
      text
    };
  }
  const explicit = normalizeNexusFunctionId(options.functionId || options.modeId || options.workflowId || options.capabilityId || "", text);
  if (explicit) return { type: explicit === "live-knowledge" ? "research" : "function-window", functionId: explicit, workflowId: NEXUS_FUNCTION_WINDOW_ROUTE_MAP[explicit] || normalizeNexusWorkflowId(explicit, text), text };
  const capability = resolveNexusCapability(text, options);
  const fromCapability = normalizeNexusFunctionId(capability?.id || capability?.workflowId || "", text);
  if (fromCapability) return { type: fromCapability === "live-knowledge" ? "research" : "function-window", functionId: fromCapability, workflowId: NEXUS_FUNCTION_WINDOW_ROUTE_MAP[fromCapability] || capability?.workflowId || normalizeNexusWorkflowId(fromCapability, text), text };
  const inferred = normalizeNexusFunctionId("", text);
  return { type: inferred ? "function-window" : "unknown", functionId: inferred, workflowId: inferred ? (NEXUS_FUNCTION_WINDOW_ROUTE_MAP[inferred] || normalizeNexusWorkflowId(inferred, text)) : "", text };
}

if (typeof window !== "undefined") {
  window["openNexusFunctionWindow"] = openNexusFunctionWindow;
  window["closeNexusFunctionWindow"] = closeNexusFunctionWindow;
  window["minimizeNexusFunctionWindow"] = minimizeNexusFunctionWindow;
  window["restoreNexusFunctionWindow"] = restoreNexusFunctionWindow;
  window["resolveNexusFunctionIntent"] = resolveNexusFunctionIntent;
  window["openNexusAppWindow"] = openNexusAppWindow;
  window["renderNexusAppWindow"] = renderNexusAppWindow;
  window["closeNexusAppWindow"] = closeNexusAppWindow;
  window["minimizeNexusAppWindow"] = minimizeNexusAppWindow;
  window["restoreNexusAppWindow"] = restoreNexusAppWindow;
  window["resolveNexusAppIntent"] = resolveNexusAppIntent;
  window["handleNexusUniversalNavigationCommand"] = handleNexusUniversalNavigationCommand;
  window["routeNexusPredictiveSuggestion"] = routeNexusPredictiveSuggestion;
  window["routeNexusProviderReadinessCard"] = routeNexusProviderReadinessCard;
  window["routeNexusSavedRecordLink"] = routeNexusSavedRecordLink;
}

function updateNexusWorkflowState(workflowId, data = {}) {
  const id = normalizeNexusWorkflowId(workflowId || nexusActiveWorkflowState?.id || "", data.command || "");
  nexusActiveWorkflowState = {
    ...(nexusActiveWorkflowState || {}),
    id,
    command: data.command || nexusActiveWorkflowState?.command || "",
    source: data.source || "runtime-update",
    workflow: workflowId || id,
    action: data.action || nexusActiveWorkflowState?.action || "",
    openedAt: nexusActiveWorkflowState?.openedAt || Date.now(),
    updatedAt: Date.now()
  };
  saveNexusRuntimeMemory();
  return nexusActiveWorkflowState;
}

function queueNexusPreparedPacket(packet, reason = "manual_queue") {
  const result = queueNexusAction(packet, reason);
  packet.outcomeStatus = "queued";
  packet.updatedAt = new Date().toISOString();
  packet.auditTrail = [...(packet.auditTrail || []), { event: "packet_queued", reason, timestamp: packet.updatedAt }];
  nexusPreparedPackets = [packet, ...nexusPreparedPackets.filter(item => item.packetId !== packet.packetId)].slice(0, 25);
  showNexusOutcome(packet, result);
  saveNexusRuntimeMemory();
  return result;
}

function continueLastNexusWorkflow() {
  const lastId = nexusActiveWorkflowState?.id || nexusPreparedPackets[0]?.workflowId || nexusActionHistory[0]?.workflowId || "";
  if (lastId && nexusWorkflowDefinition(lastId, "continue last workflow")) return openNexusWorkflow(lastId, { command: "continue last workflow", source: "runtime-continuation" });
  return false;
}

function showNexusPendingActions() {
  return showNexusRuntimeList("pending");
}

function showNexusQueuedActions() {
  return showNexusRuntimeList("queued");
}

function showNexusFailedActions() {
  return showNexusRuntimeList("failed");
}

function showNexusFollowUps() {
  return showNexusRuntimeList("follow-up");
}

function nexusGlobalReviewQueueAuditSummary() {
  const preparedPackets = nexusPreparedPackets.filter(packet => packet.outcomeStatus === "prepared");
  const waitingPackets = nexusPreparedPackets.filter(packet => packet.outcomeStatus === "waiting_for_confirmation");
  const queuedPackets = nexusPreparedPackets.filter(packet => packet.outcomeStatus === "queued");
  const failedHistory = nexusActionHistory.filter(entry => ["failed", "credential_required"].includes(entry.outcomeStatus));
  const blockedHistory = nexusActionHistory.filter(entry => /blocked|credential|inactive|confirmation/i.test(`${entry.outcomeStatus} ${entry.resultMessage} ${entry.errorMessage}`));
  const outcomeHistory = nexusActionHistory.filter(entry => ["prepared", "queued", "waiting_for_confirmation", "test_submitted", "handoff_prepared", "submitted", "sent", "failed", "credential_required", "cancelled", "completed"].includes(entry.outcomeStatus));
  const auditEventCount = nexusPreparedPackets.reduce((count, packet) => count + (Array.isArray(packet.auditTrail) ? packet.auditTrail.length : 0), 0) + nexusActionHistory.length;
  return {
    preparedCount: preparedPackets.length,
    waitingConfirmationCount: waitingPackets.length,
    queuedCount: queuedPackets.length,
    failedCount: failedHistory.length,
    blockedCount: blockedHistory.length,
    outcomeCount: outcomeHistory.length,
    auditEventCount,
    latestOutcome: nexusActionHistory[0]?.outcomeStatus || "none",
    storageMode: "local browser memory only; no secrets or provider credentials",
    safeRetryPolicy: "Retry controls only re-check local/test-mode lane readiness and never bypass confirmation, credentials, or provider gates.",
    stateDefinitions: "Prepared means locally assembled; queued means held for review; confirmed means explicitly approved for the current packet; executed/sent applies only to configured future providers; failed/blocked requires review.",
    exportPolicy: "Exports include packet IDs, lane IDs, statuses, timestamps, and redacted metadata only."
  };
}

