function renderNexusReviewQueues() {
  const queueCards = NEXUS_REVIEW_QUEUE_TYPES.map(type => {
    const items = nexusPreparedPackets.filter(packet => {
      const text = `${type} ${packet.category} ${packet.packetType} ${packet.destinationLaneId}`.toLowerCase();
      return text.includes(type.split("-")[0]) || (type === "provider" && /clinical|health|telehealth|pharmacy|mobile/.test(text)) || (type === "vendor" && /agriculture|marketplace|logistics/.test(text));
    });
    return `
      <article data-nexus-review-queue="${escapeHtml(type)}">
        <strong>${escapeHtml(translateText(`${type} queue`))}</strong>
        <span>${escapeHtml(translateText(`${items.length} packet(s)`))}</span>
        ${(items.slice(0, 3).map(packet => `
          <div>
            <b>${escapeHtml(packet.packetId)}</b>
            <small>${escapeHtml(`${packet.workflowLabel} / ${packet.urgency} / ${packet.outcomeStatus}`)}</small>
            <button type="button" data-nexus-packet-action="edit" data-packet-id="${escapeHtml(packet.packetId)}">${escapeHtml(translateText("Review"))}</button>
            <button type="button" data-nexus-packet-action="retry" data-action-id="${escapeHtml(nexusActionHistory.find(entry => entry.packetId === packet.packetId)?.id || "")}">${escapeHtml(translateText("Retry"))}</button>
          </div>
        `).join("")) || `<small>${escapeHtml(translateText("No local packets yet."))}</small>`}
      </article>
    `;
  });
  return `
    <details class="nexus-review-queues nexus-glass-card" data-nexus-review-queues="true">
      <summary>${escapeHtml(translateText("Provider / vendor / admin review queues"))}</summary>
      <div class="nexus-review-queue-grid">${queueCards.join("")}</div>
    </details>
  `;
}

function handleNexusGlobalReviewQueueAuditClick(event) {
  const button = event.target?.closest?.("[data-nexus-global-review-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.nexusGlobalReviewAction || "";
  const summary = nexusGlobalReviewQueueAuditSummary();
  if (action === "show-queued") return showNexusQueuedActions();
  if (action === "show-failed") return showNexusFailedActions();
  if (action === "show-outcomes") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_outcome_records_listed",
      mode: "Review, queue, audit, and outcomes",
      message: `${summary.outcomeCount} local outcome record(s) are available for review.`,
      preparedCards: nexusActionHistory.slice(0, 8).map(entry => ({
        type: "outcome_record_packet",
        title: entry.workflowId || entry.actionType || "Nexus outcome",
        status: entry.outcomeStatus,
        localOnly: entry.laneStatus !== "active_live",
        noExecutionAuthorized: true
      })),
      noExecutionAuthorized: true,
      noSecretsExposed: true,
      localOnly: true,
      source: "nexus_global_review_queue_audit_system"
    };
    renderUserWorkspace();
    return true;
  }
  if (action === "export-review-audit") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_review_audit_export_prepared",
      mode: "Review, queue, audit, and outcomes",
      message: "Review queue, audit, and outcome export is ready locally with redacted metadata only.",
      preparedCards: [{
        type: "review_queue_packet",
        title: "Global review queue export",
        status: "local redacted export prepared",
        localOnly: true,
        noExecutionAuthorized: true
      }, {
        type: "audit_event_packet",
        title: "Global audit event summary",
        status: `${summary.auditEventCount} audit event(s) summarized`,
        localOnly: true,
        noExecutionAuthorized: true
      }, {
        type: summary.failedCount || summary.blockedCount ? "failed_action_packet" : "outcome_record_packet",
        title: "Outcome and blocked-state summary",
        status: `queued ${summary.queuedCount}; failed ${summary.failedCount}; blocked ${summary.blockedCount}`,
        localOnly: true,
        noExecutionAuthorized: true
      }],
      summary,
      packets: nexusPreparedPackets.slice(0, 25).map(packet => ({
        packetId: packet.packetId,
        workflowId: packet.workflowId,
        packetType: packet.packetType,
        outcomeStatus: packet.outcomeStatus,
        destinationLaneId: packet.destinationLaneId,
        auditTrailCount: Array.isArray(packet.auditTrail) ? packet.auditTrail.length : 0,
        secretsIncluded: false
      })),
      outcomes: nexusActionHistory.slice(0, 25).map(entry => ({
        id: entry.id,
        packetId: entry.packetId,
        workflowId: entry.workflowId,
        laneId: entry.laneId,
        laneStatus: entry.laneStatus,
        outcomeStatus: entry.outcomeStatus,
        timestamp: entry.timestamp,
        secretsIncluded: false
      })),
      noExecutionAuthorized: true,
      noSecretsExposed: true,
      noUnsafeRetryAuthorized: true,
      localOnly: true,
      source: "nexus_global_review_queue_audit_system"
    };
    renderUserWorkspace();
    return true;
  }
  return false;
}

function handleNexusGlobalOfflineAccessClick(event) {
  const button = event.target?.closest?.("[data-nexus-global-offline-action]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  event.stopImmediatePropagation?.();
  const action = button.dataset.nexusGlobalOfflineAction || "";
  const state = nexusGlobalOfflineAccessState();
  if (action === "show-offline-queue") return showNexusQueuedActions();
  if (action === "prepare-low-bandwidth-packet") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_low_bandwidth_packet_prepared",
      mode: "Offline and low-bandwidth access",
      message: "Low-bandwidth access packet prepared locally. Nexus did not claim live provider access, fresh citations, dispatch, sync, payment, or location sharing.",
      preparedCards: [{
        type: "low_bandwidth_guidance_packet",
        title: "Low-bandwidth access packet",
        status: "local review packet prepared",
        localOnly: true,
        noExecutionAuthorized: true
      }, {
        type: "offline_access_packet",
        title: "Offline access posture",
        status: state.connectivityStatus,
        localOnly: true,
        noExecutionAuthorized: true
      }],
      state,
      noExecutionAuthorized: true,
      noProviderAccessClaimed: true,
      noLocationSharingAuthorized: true,
      noAutomaticSync: true,
      noSecretsExposed: true,
      localOnly: true,
      source: "nexus_global_offline_access_layer"
    };
    renderUserWorkspace();
    return true;
  }
  if (action === "show-stale-data-warning") {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_global_stale_data_warning_shown",
      mode: "Offline and low-bandwidth access",
      message: state.staleDataWarning,
      preparedCards: [{
        type: "stale_data_warning_packet",
        title: "Stale data warning",
        status: "refresh required before source-backed claims",
        localOnly: true,
        noExecutionAuthorized: true
      }],
      state,
      noExecutionAuthorized: true,
      noFreshCitationClaimed: true,
      noProviderAccessClaimed: true,
      noSecretsExposed: true,
      localOnly: true,
      source: "nexus_global_offline_access_layer"
    };
    renderUserWorkspace();
    return true;
  }
  return false;
}

