function nexusGlobalAssistantBrainDomainForCommand(command = "") {
  const text = String(command || "").toLowerCase();
  if (/\b(queue this action|queue.*inactive|offline queue|because the lane is inactive)\b/.test(text)) return "offlineQueue";
  if (/\b(whatsapp|telegram|sms|text message|email|phone call|call|message)\b/.test(text)) return "communications";
  if (/\b(pharmacy|prescription|refill|medicine|medication)\b/.test(text)) return "pharmacy";
  if (/\b(telehealth|provider bridge|provider handoff|care team|video visit|provider questions|mobile clinic visit packet|mobile clinic)\b/.test(text)) return "providerAccess";
  if (/\b(diabetes|blood pressure|hypertension|obesity|rpm|rtm|community health worker|chw|chronic|glucose|a1c)\b/.test(text)) return "chronicCare";
  if (/\b(crop|maize|farm|field|irrigation|pest|disease guidance|agriculture)\b/.test(text)) return "agriculture";
  if (/\b(farm visit|field visit|route|map|transport|directions)\b/.test(text)) return "maps";
  if (/\b(workforce|training|literacy|job|jobs|skills|course|learner)\b/.test(text)) return "workforce";
  if (/\b(vendor|supplier|cold storage|marketplace|agritrade|buyer|seller)\b/.test(text)) return "marketplace";
  return "";
}

function nexusGlobalAssistantBrainRiskForCommand(command = "", domainKey = "") {
  const text = String(command || "").toLowerCase();
  if (/\b(emergency|ambulance|dispatch|suicide|stroke|heart attack|can't breathe|cannot breathe)\b/.test(text)) return "emergency";
  if (/\b(send|call|dial|message|whatsapp|telegram|email|contact|schedule|book|prescribe|diagnose|refill|pay|buy|checkout|share location|camera|video visit|submit|dispatch)\b/.test(text)) return "high";
  if (["chronicCare", "providerAccess", "pharmacy", "communications", "maps", "marketplace"].includes(domainKey)) return "medium";
  return "low";
}

function buildNexusGlobalAssistantBrainPlan(command = "", options = {}) {
  const rawCommand = String(command || "").trim();
  const domainKey = options.domainKey || nexusGlobalAssistantBrainDomainForCommand(rawCommand) || "offlineQueue";
  const domain = NEXUS_GLOBAL_ASSISTANT_BRAIN_DOMAINS[domainKey] || NEXUS_GLOBAL_ASSISTANT_BRAIN_DOMAINS.offlineQueue;
  const riskTier = nexusGlobalAssistantBrainRiskForCommand(rawCommand, domainKey);
  const confirmationRequired = riskTier !== "low";
  const finalExecutionGateRequired = riskTier === "high" || riskTier === "emergency" || /queue|prepare|contact|send|call|provider|pharmacy|telehealth/i.test(rawCommand);
  return {
    schemaVersion: "nexus-global-assistant-brain.v1",
    source: "nexus-global-assistant-brain",
    intentId: `global-brain-${domainKey}`,
    rawCommand,
    mode: domain.mode,
    domain: domain.label,
    workflowId: domain.workflowId,
    packetType: domain.packetType,
    actionClassifier: {
      actionType: finalExecutionGateRequired ? "prepared_or_queued_action" : "local_guidance",
      riskTier,
      confirmationRequired,
      finalExecutionGateRequired,
      noExecutionAuthorized: true,
      providerHandoffAuthorized: false
    },
    routing: {
      priority: riskTier === "emergency" ? "emergency_boundary_first" : confirmationRequired ? "safety_gate_before_execution" : "low_risk_preview_first",
      modeDispatcher: domain.mode,
      liveKnowledgeRouting: domain.needsLiveKnowledge
        ? "route to Live Knowledge when configured; fall back to built-in safe guidance and source honesty when disabled"
        : "use local packet builder; do not claim live retrieval",
      packetBuilder: domain.packetType,
      queueConnector: finalExecutionGateRequired ? "review_queue_or_offline_queue_only" : "not_required",
      confirmationConnector: confirmationRequired ? "user_confirmation_gate_required_before_any_future_execution" : "not_required_for_local_preview"
    },
    followUpState: {
      status: "awaiting_user_detail_or_review",
      nextPrompt: domain.followUpPrompt,
      noDeadEndResponse: true
    },
    userFacingStatus: riskTier === "emergency"
      ? "Emergency language detected. Nexus cannot dispatch emergency help; seek local emergency services now."
      : `Nexus prepared the ${domain.label} path. It can prepare packets, ask for missing details, and keep any real-world action behind final gates.`,
    auditPosture: "local plan/audit metadata prepared; persistent audit write requires configured approved runtime",
    noExecutionAuthorized: true,
    localOnly: true
  };
}

function shouldNexusGlobalAssistantBrainHandle(command = "") {
  const text = String(command || "").toLowerCase();
  if (!text) return false;
  if (/\b(open agriculture help|open agri.?trade|open maps|open offline queue|play music|show reminders)\b/.test(text)) return false;
  return /\b(diabetes intake|review my blood pressure|start obesity support|record rpm|community health worker|crop disease|plan a farm visit|prepare a whatsapp|prepare an sms|prepare an email|prepare a phone call|workforce training|provider bridge|pharmacy support|telehealth questions|vendor options|cold storage|mobile clinic visit packet|queue this action)\b/.test(text);
}

function buildNexusGlobalAssistantBrainResult(command = "", options = {}) {
  const plan = buildNexusGlobalAssistantBrainPlan(command, options);
  return {
    ok: true,
    status: "nexus_global_assistant_brain_plan_prepared",
    mode: "Nexus Global Assistant Brain",
    message: plan.userFacingStatus,
    preparedCards: [{
      type: "nexus_global_assistant_brain_plan",
      title: "Global assistant brain plan",
      status: `${plan.domain} - ${plan.actionClassifier.riskTier}`,
      localOnly: true,
      needsRealProvider: plan.actionClassifier.finalExecutionGateRequired,
      globalAssistantBrainPlan: plan
    }, {
      type: plan.packetType,
      title: `${plan.domain} packet`,
      status: "prepared locally / review-only",
      localOnly: true,
      needsRealProvider: plan.actionClassifier.finalExecutionGateRequired
    }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_global_assistant_brain"
  };
}

function renderNexusGlobalAssistantBrainPlan(card = {}) {
  const plan = card.globalAssistantBrainPlan || null;
  if (!plan) return "";
  const action = plan.actionClassifier || {};
  const routing = plan.routing || {};
  const followUp = plan.followUpState || {};
  return `
    <div class="nexus-global-assistant-brain-plan" data-nexus-global-assistant-brain-plan="true" data-workflow-id="${escapeHtml(plan.workflowId || "")}" data-risk-tier="${escapeHtml(action.riskTier || "")}" data-execution-authority="false">
      <small>${escapeHtml(translateText("Workflow"))}: ${escapeHtml(plan.workflowId || "review-only")}</small>
      <small>${escapeHtml(translateText("Packet"))}: ${escapeHtml(plan.packetType || "local_packet")}</small>
      <small>${escapeHtml(translateText("Priority"))}: ${escapeHtml(routing.priority || "safe_preview_first")}</small>
      <small>${escapeHtml(translateText("Live Knowledge"))}: ${escapeHtml(routing.liveKnowledgeRouting || "not required")}</small>
      <small>${escapeHtml(translateText("Confirmation"))}: ${escapeHtml(action.confirmationRequired ? "required before future execution" : "not required for local preview")}</small>
      <small>${escapeHtml(translateText("Final gate"))}: ${escapeHtml(action.finalExecutionGateRequired ? "required" : "not required for local preview")}</small>
      <small>${escapeHtml(translateText("Next"))}: ${escapeHtml(followUp.nextPrompt || "Add missing details or review the prepared packet.")}</small>
    </div>
  `;
}

function renderNexusEndgameCommandCenter() {
  const lanes = nexusAllIntegrationLanes();
  const laneCounts = lanes.reduce((counts, lane) => {
    counts[lane.status] = (counts[lane.status] || 0) + 1;
    return counts;
  }, {});
  const pending = nexusPreparedPackets.filter(packet => ["prepared", "waiting_for_confirmation", "queued"].includes(packet.outcomeStatus)).length;
  const failed = nexusActionHistory.filter(entry => entry.outcomeStatus === "failed" || entry.outcomeStatus === "credential_required").length;
  const followUps = nexusActionHistory.filter(entry => ["follow_up_needed", "response_received"].includes(entry.outcomeStatus)).length;
  return `
    <details class="nexus-endgame-command-center nexus-glass-card" data-nexus-endgame-command-center="true" open>
      <summary>${escapeHtml(translateText("Nexus Command Center"))}</summary>
      <div class="nexus-command-center-grid">
        <article><strong>${escapeHtml(translateText("Active workflow"))}</strong><span>${escapeHtml(nexusActiveWorkflowState?.id || "none")}</span></article>
        <article><strong>${escapeHtml(translateText("Pending packets"))}</strong><span>${pending}</span></article>
        <article><strong>${escapeHtml(translateText("Failed / credential-required"))}</strong><span>${failed}</span></article>
        <article><strong>${escapeHtml(translateText("Follow-up needed"))}</strong><span>${followUps}</span></article>
        <article><strong>${escapeHtml(translateText("Test-mode lanes"))}</strong><span>${laneCounts.active_test_mode || 0}</span></article>
        <article><strong>${escapeHtml(translateText("Live-mode lanes"))}</strong><span>${laneCounts.active_live || 0}</span></article>
        <article><strong>${escapeHtml(translateText("Credential-missing lanes"))}</strong><span>${laneCounts.credential_missing || lanes.filter(lane => !lane.liveModeAvailable).length}</span></article>
        <article><strong>${escapeHtml(translateText("Global/Africa readiness"))}</strong><span>${escapeHtml(NEXUS_GLOBAL_READINESS_TAGS.join(" / "))}</span></article>
      </div>
      ${renderNexusGlobalReviewQueueAuditSystem()}
      ${renderNexusGlobalOfflineAccessLayer()}
      <div class="nexus-command-center-actions">
        ${["health-intake", "clinical-support", "telehealth-intake", "pharmacy-support", "mobile-clinic", "diabetes", "hypertension", "obesity", "rpm", "rtm", "agriculture", "crop-support", "farm-planning", "field-visit", "logistics", "agritrade", "workforce", "jobs", "learning", "training", "employer-partner", "maps", "route-planning", "communications", "email", "sms", "whatsapp", "phone", "telegram"].map(id => `<button type="button" data-nexus-mode-shortcut="${escapeHtml(id)}" data-nexus-command="open ${escapeHtml(id)}">${escapeHtml(translateText(id.replace(/-/g, " ")))}</button>`).join("")}
      </div>
    </details>
  `;
}

const NEXUS_AGENT_RUNTIME = Object.freeze({
  resolveIntent: resolveNexusIntent,
  openWorkflow: openNexusWorkflow,
  updateWorkflowState: updateNexusWorkflowState,
  buildPacket: buildNexusPacket,
  prepareAction: prepareNexusAction,
  requestConfirmation: requestNexusConfirmation,
  executeAction: executeNexusAction,
  queueAction: queueNexusPreparedPacket,
  retryAction: retryNexusAction,
  recordOutcome: recordNexusOutcome,
  showOutcome: showNexusOutcome,
  continueLastWorkflow: continueLastNexusWorkflow,
  showPendingActions: showNexusPendingActions,
  showQueuedActions: showNexusQueuedActions,
  showFailedActions: showNexusFailedActions,
  showFollowUps: showNexusFollowUps,
  liveKnowledgeStatus: () => nexusKnowledgeStatus,
  liveKnowledgeQuery: runNexusKnowledgeQuery,
  buildLiveKnowledgePacket: answer => answer?.liveKnowledgeResearchPacket || answer?.packet || { packetType: "live_knowledge_research_packet", noExecutionAuthorized: true },
  clearSensitiveLocalData: clearNexusSensitiveLocalData
});

function normalizeNexusWorkflowId(workflowId = "", command = "") {
  const raw = String(workflowId || "").toLowerCase().trim()
    .replace(/^sidebar-/, "")
    .replace(/^core-/, "")
    .replace(/^suggested-\d+$/, "");
  const text = `${raw} ${command || ""}`.toLowerCase();
  if (NEXUS_FUNCTION_WINDOW_IDS.includes(raw)) return NEXUS_FUNCTION_WINDOW_ROUTE_MAP[raw] || raw;
  if (NEXUS_HOME_MODE_IDS.includes(raw)) return raw;
  if (nexusAllAgenticWorkflows().some(item => item.id === raw)) return raw;
  if (raw === "health") return "chronic-care";
  if (/\b(provider queue|provider & case queue|case queue|review queue|admin queue|provider response inbox|case timeline)\b/.test(text)) return "provider-review";
  if (raw === "providers" || raw === "provider" || raw === "doctor") return "provider-support";
  if (raw === "messages" || raw === "communication" || raw === "communications") return "communications";
  if (raw === "ask" || raw === "agent" || raw === "resource") return "resource-assistant";
  if (raw === "home") return "";
  if (/\b(diabetes|blood sugar|glucose)\b/.test(text)) return "diabetes";
  if (/\b(hypertension|blood pressure|bp)\b/.test(text)) return "hypertension";
  if (/\b(obesity|weight support|weight)\b/.test(text)) return "obesity";
  if (/\b(remote patient monitoring|rpm|manual vitals)\b/.test(text)) return "rpm";
  if (/\b(remote therapeutic monitoring|rtm|therapy update)\b/.test(text)) return "rtm";
  if (/\b(community health worker|chw|health worker)\b/.test(text)) return "community-health-worker";
  if (/\b(clinical|clinical support|health support|health access)\b/.test(text)) return "clinical-support";
  if (/\b(patient intake|intake|symptom intake|health intake)\b/.test(text)) return "telehealth-intake";
  if (/\b(telehealth|doctor|appointment preparation|provider|care team)\b/.test(text)) return /\bprovider|doctor|care team\b/.test(text) ? "provider-support" : "telehealth-intake";
  if (/\b(pharmacy|medication|medicine|refill)\b/.test(text)) return "pharmacy-support";
  if (/\b(mobile clinic|clinic outreach|community clinic|clinic)\b/.test(text)) return "mobile-clinic";
  if (/\b(chronic|chronic care)\b/.test(text)) return "chronic-care";
  if (/\b(process|make|send|submit|pay|payment|checkout|purchase|buy|refund|wallet)\b/.test(text) && /\b(payment|pay|checkout|purchase|buy|refund|wallet|money)\b/.test(text)) return "payment-gate";
  if (/\b(book|booking|schedule|appointment|reserve|calendar)\b/.test(text)) return "booking-gate";
  if (/\b(dispatch|send help|emergency help|emergency\s+dispatch|send clinic|send vehicle|send ambulance|send field team|send drone)\b/.test(text)) return "dispatch-gate";
  if (/\b(employer partner|hiring partner|employer)\b/.test(text)) return "employer-partner";
  if (/\b(workforce referral|workforce)\b/.test(text)) return "workforce";
  if (/\b(jobs|employment|career|farm jobs|find jobs)\b/.test(text)) return "jobs";
  if (/\b(training enrollment|training)\b/.test(text)) return "training";
  if (/\b(learning|literacy|course)\b/.test(text)) return "learning";
  if (/\b(route planning|route review|directions)\b/.test(text)) return "route-planning";
  if (/\b(field visit|extension visit|farm visit)\b/.test(text)) return "field-visit";
  if (/\b(maps|map|route|routes)\b/.test(text)) return "maps";
  if (/\b(logistics|transport crop|delivery)\b/.test(text)) return "logistics";
  if (/\b(farm planning|farm plan|season plan)\b/.test(text)) return "farm-planning";
  if (/\b(crop support|crop issue|pest|disease)\b/.test(text)) return "crop-support";
  if (/\b(agriculture|farm|crop|irrigation|field guidance)\b/.test(text)) return "agriculture";
  if (/\b(marketplace|trade|agritrade|buyer|seller)\b/.test(text)) return "agritrade";
  if (/\b(email|mailto)\b/.test(text)) return "email";
  if (/\b(sms|text message)\b/.test(text)) return "sms";
  if (/\b(whatsapp|wa)\b/.test(text)) return "whatsapp";
  if (/\b(phone|call|call intent)\b/.test(text)) return "phone";
  if (/\b(telegram)\b/.test(text)) return "telegram";
  if (/\b(media|music|afrobeats|r&b|rnb|gospel|spotify|youtube)\b/.test(text)) return "media";
  if (/\b(reminder|reminders|follow up|follow-up)\b/.test(text)) return "reminders";
  if (/\b(offline|queue|low bandwidth|low-bandwidth)\b/.test(text)) return "offline";
  if (/\b(message|messages|sms|whatsapp|telegram|email|call|communications?)\b/.test(text)) return "communications";
  if (/\b(resource assistant|source|citation|internet resource|knowledge)\b/.test(text)) return "resource-assistant";
  return raw || "";
}

