function nexusIntentRouterSafetyCategory(workflowId = "", command = "") {
  const text = String(command || "").toLowerCase();
  if (/\b(emergency|dispatch|diagnose|prescribe|refill|pay|payment|checkout|purchase|buy|send|sms|whatsapp|telegram|email|call|phone|share location|camera|book|schedule|submit)\b/.test(text)) return "confirmation-gated";
  if (/\b(health|provider|clinic|pharmacy|location|route|buyer|seller|marketplace|admin)\b/.test(text) || /payment|booking|dispatch|communications/.test(workflowId)) return "review-gated";
  return "low-risk-local";
}

function nexusIntentRouterMissingInformation(rule = {}, command = "") {
  const text = String(command || "").toLowerCase();
  const missing = [];
  if (rule.id === "health-care" && !/\b(diabetes|blood pressure|hypertension|obesity|rpm|rtm|glucose|bp)\b/.test(text)) missing.push("health topic or reading");
  if (rule.id === "agriculture-food-security" && !/\b(maize|tomato|cassava|crop|field|soil|pest|disease|irrigation|farm)\b/.test(text)) missing.push("crop or farm context");
  if (rule.id === "marketplace-trade" && !/\b(maize|tomato|buyer|seller|price|quantity|product|invoice)\b/.test(text)) missing.push("product, party, or trade detail");
  if (rule.id === "logistics-maps-shipments" && !/\b(from|to|origin|destination|shipment|delivery|pickup|route|clinic)\b/.test(text)) missing.push("origin and destination");
  if (rule.id === "learning-workforce-development" && !/\b(electrical safety|literacy|training|course|certificate|skill)\b/.test(text)) missing.push("training topic");
  if (rule.id === "employment-hiring" && !/\b(job|workers|hiring|resume|interview|applicant)\b/.test(text)) missing.push("job seeker or hiring need");
  if (rule.id === "communications-media" && !/\b(doctor|provider|buyer|seller|pharmacy|youtube|spotify|music|sms|email|whatsapp|telegram|phone|call)\b/.test(text)) missing.push("recipient or media provider");
  return missing.length ? missing : [];
}

function resolveNexusIntentDrivenWorkflowRoute(command = "", options = {}) {
  const text = String(command || "").trim();
  if (!text) return null;
  const lower = text.toLowerCase();
  const matches = NEXUS_INTENT_WORKFLOW_ROUTE_RULES
    .map(rule => ({ rule, matched: new RegExp(rule.pattern, "i").test(lower) }))
    .filter(item => item.matched);
  if (!matches.length) {
    return {
      interpretedGoal: "Clarify broad support request",
      domain: "General Nexus Assistant",
      intent: "clarify_goal",
      confidence: /\b(i need help|help me|support)\b/.test(lower) ? 0.42 : 0.28,
      missingInformation: ["support area"],
      nextQuestion: "What would you like help with: health, farming, jobs, training, trade, maps, communications, or providers?",
      safetyCategory: "low-risk-local",
      confirmationRequired: false,
      providerRequirement: "none",
      executionPath: "clarify_before_opening_workflow",
      recommendedWorkflow: "",
      source: options.source || "nexus-intent-driven-router"
    };
  }
  const rule = matches[0].rule;
  const workflowId = normalizeNexusWorkflowId(rule.workflowId, lower) || rule.workflowId;
  const missingInformation = nexusIntentRouterMissingInformation(rule, lower);
  const safetyCategory = nexusIntentRouterSafetyCategory(workflowId, lower);
  const confirmationRequired = safetyCategory !== "low-risk-local";
  return {
    interpretedGoal: `${rule.intent.replace(/_/g, " ")} from "${text}"`,
    domain: rule.domain,
    intent: rule.intent,
    confidence: Math.max(0.1, Math.min(0.99, missingInformation.length ? rule.confidence - 0.08 : rule.confidence)),
    missingInformation,
    nextQuestion: missingInformation.length ? rule.nextQuestion : "Review the focused workflow and add any missing details.",
    safetyCategory,
    confirmationRequired,
    providerRequirement: confirmationRequired ? "provider credentials, consent, final confirmation, and audit may be required before execution" : "not required for local guidance",
    executionPath: confirmationRequired ? "prepare_review_confirm_before_any_external_action" : "open_local_workflow",
    recommendedWorkflow: workflowId,
    source: options.source || "nexus-intent-driven-router"
  };
}

function buildNexusIntentDrivenRoutingResult(route = {}, command = "") {
  return {
    ok: true,
    status: route.recommendedWorkflow ? "nexus_intent_workflow_route_ready" : "nexus_intent_workflow_clarification_needed",
    mode: "Intent-driven workflow routing",
    message: route.recommendedWorkflow
      ? `${route.domain} selected. Nexus opened ${route.recommendedWorkflow.replace(/-/g, " ")} without executing an external action.`
      : route.nextQuestion,
    preparedCards: [{
      type: "nexus_intent_workflow_route",
      title: route.domain || "Nexus route",
      status: route.recommendedWorkflow ? "workflow selected" : "clarification needed",
      interpretedGoal: route.interpretedGoal,
      domain: route.domain,
      intent: route.intent,
      confidence: route.confidence,
      missingInformation: route.missingInformation || [],
      nextQuestion: route.nextQuestion,
      safetyCategory: route.safetyCategory,
      confirmationRequired: route.confirmationRequired,
      providerRequirement: route.providerRequirement,
      executionPath: route.executionPath,
      recommendedWorkflow: route.recommendedWorkflow,
      localOnly: true,
      noExecutionAuthorized: true
    }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "nexus_intent_driven_workflow_router"
  };
}

function renderNexusIntentDrivenWorkflowStatus() {
  const route = nexusIntentDrivenWorkflowLastRoute;
  if (!route) return "";
  return `
    <div class="nexus-intent-route-status nexus-glass-card" data-nexus-intent-route-status="true">
      <span class="eyebrow">${escapeHtml(translateText("Intent-driven workflow routing"))}</span>
      <strong>${escapeHtml(translateText(route.domain || "Nexus workflow"))}</strong>
      <p>${escapeHtml(translateText(route.recommendedWorkflow ? `${route.domain} workflow selected.` : route.nextQuestion || "Nexus needs one detail before opening a workflow."))}</p>
      <div class="nexus-intent-route-grid">
        <span>${escapeHtml(translateText("Intent"))}: ${escapeHtml(String(route.intent || "clarify_goal").replace(/_/g, " "))}</span>
        <span>${escapeHtml(translateText("Confidence"))}: ${escapeHtml(String(Math.round(Number(route.confidence || 0) * 100)))}%</span>
        <span>${escapeHtml(translateText("Safety"))}: ${escapeHtml(translateText(route.safetyCategory || "low-risk-local"))}</span>
        <span>${escapeHtml(translateText("Confirmation"))}: ${escapeHtml(translateText(route.confirmationRequired ? "Required before execution" : "Not required for local guidance"))}</span>
      </div>
      <small>${escapeHtml(translateText("No external action was executed. Nexus only opened or prepared the focused workflow."))}</small>
    </div>
  `;
}

function updateNexusIntentDrivenWorkflowStatusDom() {
  if (typeof document === "undefined") return;
  const commandInputValue = document.querySelector("#nexusCommandCenterInput")?.value || nexusIntentDrivenLastCommandText || "";
  if (/\b(blood pressure|bp|hypertension|diabetes|glucose|obesity|rpm|rtm|chronic)\b/i.test(commandInputValue)) {
    setNexusIntentDrivenWorkflowStatusForCommand(commandInputValue, {
      source: "visible-command-input-intent-router"
    });
  }
  const existing = document.querySelector("[data-nexus-intent-route-status='true']");
  if (!nexusIntentDrivenWorkflowLastRoute) {
    existing?.remove?.();
    return;
  }
  const composer = document.querySelector("[data-nexus-command-composer='true']");
  if (!composer) return;
  const wrapper = document.createElement("div");
  wrapper.innerHTML = renderNexusIntentDrivenWorkflowStatus().trim();
  const panel = wrapper.firstElementChild;
  if (!panel) return;
  if (existing) {
    existing.replaceWith(panel);
    return;
  }
  composer.insertAdjacentElement("afterend", panel);
}

function routeNexusIntentDrivenWorkflowCommand(command = "", options = {}) {
  const route = resolveNexusIntentDrivenWorkflowRoute(command, options);
  if (!route) return false;
  if (!route.recommendedWorkflow && route.confidence < 0.4) return false;
  nexusIntentDrivenWorkflowLastRoute = route;
  const result = buildNexusIntentDrivenRoutingResult(route, command);
  if (!route.recommendedWorkflow || route.confidence < 0.55) {
    nexusAgenticBrainLastResult = result;
    renderUserWorkspace();
    return true;
  }
  const opened = openNexusWorkflow(route.recommendedWorkflow, {
    command,
    source: options.source || "intent-driven-router",
    preparedResult: result
  });
  if (opened) return true;
  nexusAgenticBrainLastResult = result;
  renderUserWorkspace();
  updateNexusIntentDrivenWorkflowStatusDom();
  return true;
}

function setNexusIntentDrivenWorkflowStatusForCommand(command = "", options = {}) {
  const route = resolveNexusIntentDrivenWorkflowRoute(command, options);
  if (!route || (!route.recommendedWorkflow && route.confidence < 0.4)) return false;
  nexusIntentDrivenWorkflowLastRoute = route;
  return true;
}

function handleNexusIntentDrivenCommandCenterSubmit(event) {
  const submit = event?.target?.closest?.("[data-nexus-command-center-submit]");
  if (!submit) return false;
  const input = nexusCommandInputForSubmit(submit);
  const command = input?.value?.trim() || "";
  if (!command) return false;
  if (!routeNexusIntentDrivenWorkflowCommand(command, { source: "typed-command-submit" })) return false;
  event?.preventDefault?.();
  event?.stopPropagation?.();
  event?.stopImmediatePropagation?.();
  if (input) input.value = command;
  setCommandInputs(command);
  return true;
}

function nexusFunctionWindowCategory(functionId = "") {
  const id = normalizeNexusFunctionId(functionId);
  if (/virtual-care|telehealth|video-visit|chronic|diabetes|hypertension|obesity|rpm|rtm|physician|follow-up|emergency/.test(id)) return "healthcare";
  if (/pharmacy|medication|refill|supplies/.test(id)) return "pharmacy";
  if (/mobile-clinic|vitals|rural-clinic|community-outreach/.test(id)) return "mobile-clinic";
  if (/agriculture|agronomy|crop|pest|soil|irrigation|climate|farmer|drone|farm-visit/.test(id)) return "agriculture";
  if (/agritrade|marketplace|vendor|buyer|seller|produce|input|quote/.test(id)) return "marketplace";
  if (/logistics|route-support|pickup|delivery|cold-chain|storage/.test(id)) return "logistics";
  if (/workforce|training|literacy|job|youth|employer|certification|lms/.test(id)) return "workforce";
  if (/live-knowledge|internet|research|source-backed/.test(id)) return "research";
  if (/maps|field-visit|route-planning|location-sharing/.test(id)) return "maps";
  if (/email|sms|whatsapp|phone|telegram|communications/.test(id)) return "communications";
  if (/music|media|youtube/.test(id)) return "media";
  if (/offline|low-bandwidth|sync|local-fallback/.test(id)) return "offline";
  if (/admin|queue|timeline|inbox/.test(id)) return "admin";
  if (/payment|booking|dispatch|approval/.test(id)) return "gate";
  return "research";
}

function nexusFunctionWindowDefinition(functionId = "", command = "") {
  const id = normalizeNexusFunctionId(functionId, command) || normalizeNexusFunctionId("", command);
  const workflowId = NEXUS_FUNCTION_WINDOW_ROUTE_MAP[id] || normalizeNexusWorkflowId(id, command) || "resource-assistant";
  const workflow = nexusWorkflowDefinition(workflowId, command);
  const category = nexusFunctionWindowCategory(id || workflowId);
  const title = NEXUS_FUNCTION_WINDOW_LABELS[id] || workflow?.presentation?.title || "Nexus Function";
  const fields = NEXUS_FUNCTION_WINDOW_CATEGORY_FIELDS[category] || workflow?.fields || [];
  const quickActions = workflow?.content?.quickActions || [];
  return {
    ...(workflow || {}),
    id: workflow?.id || workflowId,
    functionId: id || workflowId,
    category,
    presentation: {
      ...(workflow?.presentation || {}),
      title,
      description: workflow?.presentation?.description || "Focused Nexus function window"
    },
    content: {
      ...(workflow?.content || {}),
      explanation: workflow?.content?.explanation || "Nexus opened this function as a focused workspace.",
      nextPrompt: workflow?.content?.nextPrompt || "Add the missing details and review the next safe step.",
      limitation: workflow?.content?.limitation || "External actions remain gated by credentials, consent, confirmation, audit, and outcome verification.",
      quickActions
    },
    fields
  };
}

function nexusWorkflowDefinition(workflowId = "", command = "") {
  const id = normalizeNexusWorkflowId(workflowId, command);
  if (!id) return null;
  const extra = NEXUS_FULL_WORKFLOW_EXTRAS[id] || null;
  const registry = nexusWorkflowRegistryEntry(id);
  const baseId = /diabetes|hypertension|obesity|rpm|rtm|community-health-worker/.test(id) ? "chronic-care"
    : /crop-support|farm-planning|field-visit|logistics/.test(id) ? "agriculture"
      : /workforce|employer-partner/.test(id) ? "jobs"
        : /training/.test(id) ? "learning"
          : /route-planning/.test(id) ? "maps"
            : /email|sms|whatsapp|phone|telegram/.test(id) ? "communications"
              : id;
  const presentation = extra?.presentation || NEXUS_HOME_MODE_PRESENTATION[id] || NEXUS_HOME_MODE_PRESENTATION[baseId] || {
    title: registry?.label || "Nexus Workflow",
    description: "Structured workflow with packet preparation, confirmation, queueing, and outcome history.",
    accent: "blue",
    icon: "N"
  };
  const content = extra?.content || NEXUS_HOME_MODE_PANEL_CONTENT[id] || NEXUS_HOME_MODE_PANEL_CONTENT[baseId] || {
    explanation: `${registry?.label || "Nexus"} is a full workspace for structured intake, packet preparation, lane review, confirmation, queueing, and outcome logging.`,
    nextPrompt: "Add the required details, prepare the packet, review consent, and choose queue/test/handoff based on lane status.",
    limitation: "Live external execution requires configured credentials, explicit confirmation, consent, approval, and audit logging.",
    quickActions: [
      { label: "Prepare packet", command: `open ${id}` },
      { label: "Review confirmation", command: "Show activation status" },
      { label: "Queue if inactive", command: "Show queued actions" }
    ]
  };
  const fields = extra?.fields || NEXUS_HOME_MODE_PANEL_FIELDS[id] || NEXUS_HOME_MODE_PANEL_FIELDS[baseId] || [
    ["purpose", "Purpose", "What should Nexus prepare?"],
    ["details", "Details", "Relevant context and requirements"],
    ["recipientOrLane", "Recipient or lane", "Provider, vendor, employer, communications, or local review"],
    ["consent", "Consent status", "Not requested, needs review, approved later"],
    ["notes", "Notes", "Anything else for review"]
  ];
  return { id, presentation, content, fields };
}

function isNexusHealthcareWorkflow(id = "") {
  return ["clinical-support", "chronic-care", "diabetes", "hypertension", "obesity", "rpm", "rtm", "community-health-worker", "telehealth-intake", "mobile-clinic", "pharmacy-support", "provider-support"].includes(id);
}

function renderNexusWorkflowFields(id, fields = []) {
  if (!fields.length) return "";
  return `
    <form class="nexus-workflow-field-grid" data-nexus-mode-form="${escapeHtml(id)}" aria-label="${escapeHtml(translateText("Workflow details"))}">
      ${fields.map(field => {
        const [name, label, placeholder] = Array.isArray(field) ? field : [field.name, field.label, field.placeholder];
        const rows = /notes|details|symptoms|questions|draft|issue|concern|context/i.test(name || "") ? 3 : 2;
        return `
          <label>
            <span>${escapeHtml(translateText(label || name || "Detail"))}</span>
            <textarea rows="${rows}" data-nexus-mode-field="${escapeHtml(name || "field")}" name="${escapeHtml(name || "field")}" placeholder="${escapeHtml(translateText(placeholder || ""))}"></textarea>
          </label>
        `;
      }).join("")}
    </form>
  `;
}

function nexusWorkflowLandingKind(definition = {}) {
  const id = normalizeNexusFunctionId(definition.functionId || definition.id || "", definition?.command || "");
  const category = definition.category || nexusFunctionWindowCategory(id);
  if (/mobile-clinic|vitals-check|diabetes-follow-up|hypertension-follow-up|obesity-support|rural-clinic|community-outreach/.test(id)) return "mobile-clinic";
  if (/pharmacy|medication|refill|supplies/.test(id)) return "pharmacy";
  if (/virtual-care|telehealth|video-visit|chronic-disease|diabetes|hypertension|obesity|rpm|rtm|physician-review|follow-up|emergency-guidance/.test(id)) return "telehealth";
  if (/agriculture|agronomy|crop|pest|soil|irrigation|climate|farmer|drone|farm-visit/.test(id)) return "agriculture";
  if (/agritrade|marketplace|vendor|buyer|seller|produce|input|quote/.test(id)) return "marketplace";
  if (/logistics|pickup|delivery|cold-chain|storage/.test(id)) return "logistics";
  if (/maps|field-visit|route-planning|location-sharing|route-support/.test(id) || category === "maps") return "maps";
  if (/live-knowledge|internet|research|source-backed/.test(id) || category === "research") return "research";
  if (/workforce|training|literacy|job|youth|employer|certification|lms/.test(id)) return "workforce";
  if (/email|sms|whatsapp|phone|telegram|communications/.test(id) || category === "communications") return "communications";
  if (/admin|queue|timeline|inbox/.test(id) || category === "admin") return "admin";
  if (/music|media|youtube/.test(id) || category === "media") return "media";
  if (/offline|low-bandwidth|sync|local-fallback/.test(id) || category === "offline") return "offline";
  if (/payment|booking|dispatch|approval/.test(id) || category === "gate") return "gate";
  return NEXUS_WORKFLOW_LANDING_WINDOWS[category] ? category : "research";
}

function nexusWorkflowLandingConfig(definition = {}, state = {}) {
  const kind = nexusWorkflowLandingKind(definition);
  const config = NEXUS_WORKFLOW_LANDING_WINDOWS[kind] || NEXUS_WORKFLOW_LANDING_WINDOWS.research;
  const title = definition?.presentation?.title || config.title;
  return {
    ...config,
    kind,
    title: config.title || title,
    resolvedTitle: title,
    command: state.command || ""
  };
}

function parseNexusRoutePoints(command = "") {
  const text = String(command || "").trim();
  const match = text.match(/\b(?:route|map|plan|prepare)?[\s\S]*?\bfrom\s+(.+?)\s+\bto\s+(.+?)(?:[.!?]|$)/i);
  if (!match) return { start: "", destination: "" };
  return {
    start: match[1].replace(/\b(route|map|plan|mobile clinic|logistics|farm visit)\b/gi, "").trim(),
    destination: match[2].replace(/\b(route|map|plan|mobile clinic|logistics|farm visit)\b/gi, "").trim()
  };
}

function renderNexusLandingField(field = {}, state = {}) {
  const name = field.name || "field";
  const label = field.label || name;
  const placeholder = field.placeholder || "";
  const safeName = escapeHtml(name);
  const value = name === "researchQuery" ? state.command || "" : "";
  if (field.type === "select") {
    return `
      <label class="nexus-landing-field">
        <span>${escapeHtml(translateText(label))}</span>
        <select data-nexus-landing-field="${safeName}" name="${safeName}">
          ${(field.options || ["Needs review"]).map(option => `<option>${escapeHtml(translateText(option))}</option>`).join("")}
        </select>
      </label>
    `;
  }
  if (field.type === "checkboxes") {
    return `
      <fieldset class="nexus-landing-field nexus-landing-checkboxes" data-nexus-landing-field="${safeName}">
        <legend>${escapeHtml(translateText(label))}</legend>
        ${(field.options || []).map(option => `
          <label><input type="checkbox" data-nexus-landing-checkbox="${safeName}" value="${escapeHtml(option)}"> <span>${escapeHtml(translateText(option))}</span></label>
        `).join("")}
      </fieldset>
    `;
  }
  if (field.type === "checkbox") {
    return `
      <label class="nexus-landing-field nexus-landing-single-checkbox">
        <span>${escapeHtml(translateText(label))}</span>
        <input type="checkbox" data-nexus-landing-field="${safeName}" name="${safeName}">
        <small>${escapeHtml(translateText(placeholder))}</small>
      </label>
    `;
  }
  if (field.type === "textarea") {
    return `
      <label class="nexus-landing-field">
        <span>${escapeHtml(translateText(label))}</span>
        <textarea rows="3" data-nexus-landing-field="${safeName}" name="${safeName}" placeholder="${escapeHtml(translateText(placeholder))}">${escapeHtml(value)}</textarea>
      </label>
    `;
  }
  return `
    <label class="nexus-landing-field">
      <span>${escapeHtml(translateText(label))}</span>
      <input data-nexus-landing-field="${safeName}" name="${safeName}" placeholder="${escapeHtml(translateText(placeholder))}" value="${escapeHtml(value)}">
    </label>
  `;
}

function renderNexusRoutePlanningLandingArea(config = {}, state = {}) {
  const route = parseNexusRoutePoints(state.command || "");
  const providerReadiness = typeof nexusProviderReadiness !== "undefined" ? nexusProviderReadiness : null;
  const configured = Boolean(providerReadiness?.providers?.maps?.testability === "ready" || nexusKnowledgeStatus?.providers?.maps?.ready);
  return `
    <section class="nexus-landing-route-panel" data-nexus-route-planning-window="true" data-route-provider-configured="${configured ? "true" : "false"}" data-geolocation-used="false" data-location-permission-requested="false">
      <div>
        <strong>${escapeHtml(translateText("Route summary area"))}</strong>
        <p>${escapeHtml(translateText(configured ? "A configured route provider may return route metadata after explicit typed origin/destination review." : "Route provider is not configured. Nexus can prepare the route request, but no live route calculation has executed."))}</p>
      </div>
      <div class="nexus-route-input-row">
        <label><span>${escapeHtml(translateText("Start point"))}</span><input data-nexus-route-start value="${escapeHtml(route.start)}" placeholder="${escapeHtml(translateText("Typed start point"))}"></label>
        <label><span>${escapeHtml(translateText("Destination"))}</span><input data-nexus-route-destination value="${escapeHtml(route.destination)}" placeholder="${escapeHtml(translateText("Typed destination"))}"></label>
      </div>
      <div class="nexus-route-map-surface" data-nexus-existing-map-component="true" data-nexus-route-map-container="true">
        <span>${escapeHtml(translateText("Map / route preview surface"))}</span>
        <small>${escapeHtml(translateText("Existing Nexus map review can be opened from here. Browser geolocation stays off unless a future explicit permission flow is approved."))}</small>
      </div>
      <div class="nexus-route-actions">
        <button type="button" data-nexus-mode-shortcut="maps" data-nexus-command="Prepare route from ${escapeHtml(route.start || "start")} to ${escapeHtml(route.destination || "destination")}">${escapeHtml(translateText("Calculate or prepare route"))}</button>
        <button type="button" data-nexus-mode-shortcut="maps" data-nexus-command="Open map review">${escapeHtml(translateText("Open map review"))}</button>
      </div>
    </section>
  `;
}

function renderNexusLiveKnowledgeLandingArea(config = {}, state = {}) {
  const missing = Array.isArray(nexusKnowledgeStatus?.missingEnvNames) ? nexusKnowledgeStatus.missingEnvNames : [];
  const provider = nexusKnowledgeStatus?.provider || nexusKnowledgeStatus?.selectedProvider || "not configured";
  return `
    <section class="nexus-landing-research-panel" data-nexus-live-knowledge-landing="true" data-fake-citations="false">
      <div>
        <strong>${escapeHtml(translateText("Live Knowledge provider status"))}</strong>
        <p>${escapeHtml(translateText(`Provider: ${provider}. ${missing.length ? `Missing: ${missing.join(", ")}` : "Ready when configured provider returns citable results."}`))}</p>
      </div>
      <label class="nexus-landing-field">
        <span>${escapeHtml(translateText("Research query field"))}</span>
        <textarea rows="3" data-nexus-live-knowledge-query placeholder="${escapeHtml(translateText("Research climate-smart agriculture in Africa"))}">${escapeHtml(state.command || "")}</textarea>
      </label>
      <button type="button" data-nexus-mode-shortcut="live-knowledge" data-nexus-command="${escapeHtml(state.command || "Research climate-smart agriculture in Africa and show sources.")}">${escapeHtml(translateText("Run research"))}</button>
      <div class="nexus-source-card-list" data-nexus-source-card-list="true">
        ${renderNexusKnowledgeAnswerCard(nexusKnowledgeLastResult)}
        ${nexusKnowledgeLastResult ? "" : `<p>${escapeHtml(translateText("Source cards and citation metadata appear here only when the configured provider returns real sources."))}</p>`}
      </div>
    </section>
  `;
}

const NEXUS_DYNAMIC_WORKFLOW_PRESENTATION_TYPES = Object.freeze([
  "conversational_interview",
  "one_question_prompt",
  "multi_step_intake",
  "option_comparison",
  "profile_review",
  "measurement_entry",
  "timeline",
  "shipment_tracking",
  "map_and_route",
  "learning_activity",
  "document_review",
  "provider_handoff",
  "confirmation",
  "receipt",
  "completion_summary",
  "error_recovery",
  "blocked_state_explanation"
]);

function buildNexusDynamicWorkflowMissionState(definition = {}, state = {}) {
  const activeMission = typeof getActiveNexusOsMission === "function" ? getActiveNexusOsMission() : null;
  const route = nexusIntentDrivenWorkflowLastRoute || buildNexusIntentDrivenRoutingResult(state.command || definition?.content?.nextPrompt || "");
  return {
    workflowId: definition.id || "",
    functionId: definition.functionId || definition.id || "",
    command: state.command || "",
    title: definition?.presentation?.title || "Nexus workflow",
    category: definition.category || nexusFunctionWindowCategory(definition.functionId || definition.id || ""),
    route,
    mission: activeMission,
    currentState: activeMission?.currentState || "collect",
    missingInformation: route?.missingInformation || activeMission?.missingInformation || [],
    safetyCategory: route?.safetyCategory || activeMission?.safetyClassification || "low-risk",
    confirmationRequirement: route?.confirmationRequirement || activeMission?.requiredConsent || "review-before-external-action",
    providerRequirement: route?.providerRequirement || activeMission?.providerRequirement || "none",
    executionPath: route?.executionPath || "local-review-only",
    recommendedWorkflow: route?.recommendedWorkflow || definition.id || ""
  };
}

function nexusDynamicWorkflowPresentationType(definition = {}, missionState = {}) {
  const id = normalizeNexusWorkflowId(definition.id || missionState.workflowId || "", missionState.command || "");
  const functionId = normalizeNexusFunctionId(definition.functionId || id, missionState.command || "");
  const category = missionState.category || definition.category || nexusFunctionWindowCategory(functionId || id);
  const text = `${id} ${functionId} ${category} ${missionState.command || ""}`.toLowerCase();
  if (missionState.currentState === "failed") return "error_recovery";
  if (/blocked|missing|not_configured/.test(missionState.executionPath || "") || /blocked|high-risk|regulated/i.test(missionState.safetyCategory || "")) return "blocked_state_explanation";
  if (/complete|return_home/.test(missionState.currentState || "")) return "completion_summary";
  if (/receipt|history|audit/.test(text)) return "receipt";
  if (/confirm|approval|payment|booking|dispatch/.test(text) || /required/i.test(missionState.confirmationRequirement || "")) return "confirmation";
  if (/provider|telehealth|pharmacy|clinic|doctor|physician|refill|mobile-clinic/.test(text)) return "provider_handoff";
  if (/map|route|field-visit|location/.test(text)) return "map_and_route";
  if (/shipment|tracking|logistics|cold-chain|delivery|pickup/.test(text)) return "shipment_tracking";
  if (/learning|training|literacy|course|lms|workforce|job|employment/.test(text)) return "learning_activity";
  if (/blood pressure|glucose|rpm|rtm|diabetes|hypertension|obesity|measurement|vitals/.test(text)) return "measurement_entry";
  if (/marketplace|agritrade|buyer|seller|quote|compare|vendor/.test(text)) return "option_comparison";
  if (/profile|patient|farmer|employer|applicant/.test(text)) return "profile_review";
  if (/knowledge|research|source|document|citation|internet/.test(text)) return "document_review";
  if ((missionState.missingInformation || []).length === 1) return "one_question_prompt";
  if ((missionState.missingInformation || []).length > 1 || /intake|support|prepare/.test(text)) return "multi_step_intake";
  if (/timeline|follow-up|plan/.test(text)) return "timeline";
  return "conversational_interview";
}

function nexusDynamicWorkflowTypeCopy(type = "conversational_interview", missionState = {}) {
  const title = missionState.title || "Nexus workflow";
  const nextQuestion = missionState.route?.nextQuestion || (missionState.missingInformation || [])[0] || "What detail should Nexus collect next?";
  const copy = {
    conversational_interview: {
      label: "Conversational interview",
      summary: `Nexus is guiding ${title} as a short conversation instead of a large form.`,
      primary: nextQuestion,
      items: ["Listen to the request", "Ask one useful follow-up", "Keep voice and text available"]
    },
    one_question_prompt: {
      label: "One-question prompt",
      summary: "Nexus needs one missing detail before it can prepare the next safe step.",
      primary: nextQuestion,
      items: missionState.missingInformation || ["One missing detail"]
    },
    multi_step_intake: {
      label: "Multi-step intake",
      summary: `Nexus is collecting only the details relevant to ${title}.`,
      primary: nextQuestion,
      items: ["Purpose", "Context", "Recipient or lane", "Review before action"]
    },
    option_comparison: {
      label: "Option comparison",
      summary: "Nexus can compare choices without buying, contacting, or committing.",
      primary: "Which option or criteria should Nexus compare first?",
      items: ["Price or value", "Availability", "Distance or timing", "Risk notes"]
    },
    profile_review: {
      label: "Profile review",
      summary: "Nexus can review local profile details and identify what is still missing.",
      primary: "Which profile detail should be reviewed or corrected?",
      items: ["Identity or role", "Needs", "Preferences", "Consent state"]
    },
    measurement_entry: {
      label: "Measurement entry",
      summary: "Nexus can record or review measurements for education and provider-ready summaries.",
      primary: "What reading, date, or context should be added?",
      items: ["Reading", "Time", "Context", "Provider review note"]
    },
    timeline: {
      label: "Timeline",
      summary: "Nexus can organize steps, follow-ups, and checkpoints.",
      primary: "What milestone should Nexus place on the timeline?",
      items: ["Now", "Next", "Follow-up", "Review"]
    },
    shipment_tracking: {
      label: "Shipment tracking",
      summary: "Nexus can prepare shipment tracking and route review without dispatching.",
      primary: "What shipment ID, pickup point, or delivery point should be reviewed?",
      items: ["Shipment ID", "Pickup", "Delivery", "Status note"]
    },
    map_and_route: {
      label: "Map and route",
      summary: "Nexus can prepare typed route details without requesting browser location.",
      primary: "What origin and destination should Nexus review?",
      items: ["Typed origin", "Typed destination", "Travel purpose", "No geolocation requested"]
    },
    learning_activity: {
      label: "Learning activity",
      summary: "Nexus can guide training, literacy, jobs, and workforce steps.",
      primary: "What skill, course, or job goal should Nexus focus on?",
      items: ["Skill goal", "Learning level", "Provider or course", "Next practice step"]
    },
    document_review: {
      label: "Document review",
      summary: "Nexus can review source-backed material and show citations only when real sources exist.",
      primary: "What source, document, or research question should Nexus review?",
      items: ["Question", "Source status", "Citation readiness", "No fake citations"]
    },
    provider_handoff: {
      label: "Provider handoff",
      summary: "Nexus can prepare a provider-ready packet; live submission remains gated.",
      primary: "Which provider, service, or review lane should be prepared?",
      items: ["Recipient", "Purpose", "Consent", "Final confirmation"]
    },
    confirmation: {
      label: "Confirmation",
      summary: "Nexus is holding the action for explicit review and approval.",
      primary: "Review the purpose, recipient, and risk before any future execution.",
      items: ["Visible action", "Cancellation path", "Audit note", "No silent execution"]
    },
    receipt: {
      label: "Receipt",
      summary: "Nexus can show what it did and what it did not do.",
      primary: "Review the latest safe action receipt.",
      items: ["Did", "Did not", "Outcome", "Audit reference"]
    },
    completion_summary: {
      label: "Completion summary",
      summary: "Nexus can summarize the completed workflow and return home.",
      primary: "Review the outcome before closing.",
      items: ["Outcome", "Limitations", "Next follow-up", "Return home"]
    },
    error_recovery: {
      label: "Error recovery",
      summary: "Nexus can recover safely without claiming a completed action.",
      primary: "What should Nexus retry, revise, or cancel?",
      items: ["Problem", "Retry option", "Revise option", "Cancel path"]
    },
    blocked_state_explanation: {
      label: "Blocked-state explanation",
      summary: "Nexus cannot execute this action until the required gate is satisfied.",
      primary: "Review what is blocked and what can be prepared locally.",
      items: ["Missing credential or approval", "Safe local preparation", "Cancellation path", "No external execution"]
    }
  };
  return copy[type] || copy.conversational_interview;
}

