function renderNexusActiveWorkflowWorkspace() {
  const state = nexusActiveWorkflowState || {};
  if (!state.id && !state.functionId) {
    return `
      <section id="nexus-workspace" class="nexus-active-workflow nexus-active-workflow-empty nexus-glass-card" data-nexus-workspace="true" data-nexus-active-workflow="none" data-execution-authority="false" aria-label="${escapeHtml(translateText("Nexus active workflow"))}">
        <div class="nexus-workflow-header">
          <span class="eyebrow">${escapeHtml(translateText("Workspace"))}</span>
          <h3 id="nexusActiveWorkflowHeading" tabindex="-1">${escapeHtml(translateText("Choose a workflow to begin"))}</h3>
          <p>${escapeHtml(translateText("Selected functions open as focused windows above the dashboard, with review-only controls and safety gates intact."))}</p>
        </div>
      </section>
    `;
  }
  const definition = nexusFunctionWindowDefinition(state.functionId || state.workflow || state.id, state.command);
  if (!definition) {
    return `
      <section id="nexus-workspace" class="nexus-active-workflow nexus-active-workflow-empty nexus-glass-card" data-nexus-workspace="true" data-nexus-active-workflow="none" data-execution-authority="false" aria-label="${escapeHtml(translateText("Nexus active workflow"))}">
        <div class="nexus-workflow-header">
          <span class="eyebrow">${escapeHtml(translateText("Workspace"))}</span>
          <h3 id="nexusActiveWorkflowHeading" tabindex="-1">${escapeHtml(translateText("Choose a workflow to begin"))}</h3>
          <p>${escapeHtml(translateText("Selected workflows open here as the main working area, with review-only controls and safety gates intact."))}</p>
        </div>
      </section>
    `;
  }
  const { id, functionId, presentation, content, fields } = definition;
  if (state.minimized) {
    return `
    <div class="nexus-function-window-dock nexus-glass-card" data-nexus-app-window-dock="true" data-nexus-function-window-dock="true" data-nexus-function-window="${escapeHtml(functionId || id)}" role="status">
        <strong>${escapeHtml(translateText(presentation.title))}</strong>
        <span>${escapeHtml(translateText("Minimized - external actions remain gated."))}</span>
        <button type="button" data-nexus-window-restore data-nexus-function-window-restore="${escapeHtml(functionId || id)}" data-nexus-command="${escapeHtml(state.command || presentation.title || "Open Nexus function")}" onclick="window.restoreNexusFunctionWindow && window.restoreNexusFunctionWindow('${escapeHtml(functionId || id)}')" aria-label="${escapeHtml(translateText("Restore function window"))}">${escapeHtml(translateText("Restore"))}</button>
        <button type="button" data-nexus-workflow-close data-nexus-command="What can Nexus do?" aria-label="${escapeHtml(translateText("Close function window"))}">${escapeHtml(translateText("Close"))}</button>
      </div>
    `;
  }
  const healthcare = isNexusHealthcareWorkflow(id);
  const latestPacket = nexusPreparedPackets.find(packet => packet && packet.workflowId === id);
  const latestEntry = latestPacket ? nexusActionHistory.find(entry => entry && entry.packetId === latestPacket.packetId) : null;
  const latestLane = latestPacket ? nexusIntegrationLaneById(latestPacket.destinationLaneId) : nexusIntegrationLaneById(nexusWorkflowRegistryEntry(id)?.integrationLaneId);
  const steps = healthcare
    ? ["Add context", "Review safety boundaries", "Prepare provider-ready summary", "Confirm before any future handoff"]
    : id === "maps"
      ? ["Enter typed locations", "Review route questions", "Keep location sharing off", "Confirm before external navigation"]
      : id === "agritrade"
        ? ["Describe need", "Review marketplace details", "Prepare inquiry", "Confirm before any transaction"]
        : ["Add details", "Review prepared next steps", "Save or change workflow", "Confirm before external action"];
  return `
    <div class="nexus-workflow-modal-backdrop" data-nexus-workflow-modal="true" data-nexus-app-window-backdrop="true" data-nexus-function-window-backdrop="true" role="presentation">
    <section id="nexus-workspace" class="nexus-active-workflow nexus-active-workflow-modal nexus-function-window nexus-function-window-${escapeHtml(functionId || id)} nexus-active-workflow-${escapeHtml(id)} nexus-glass-card" data-nexus-workspace="true" data-nexus-app-window="true" data-nexus-app-window-id="${escapeHtml(functionId || id)}" data-nexus-function-window="true" data-nexus-function-window-id="${escapeHtml(functionId || id)}" data-nexus-active-workflow="${escapeHtml(id)}" data-execution-authority="false" data-provider-handoff="false" data-no-live-execution="true" role="dialog" aria-modal="true" aria-labelledby="nexusActiveWorkflowHeading">
      <div class="nexus-workflow-header">
        <span class="nexus-workflow-icon" aria-hidden="true">${escapeHtml(presentation.icon || "")}</span>
        <div>
          <span class="eyebrow">${escapeHtml(translateText("Focused Nexus function window"))}</span>
          <h3 id="nexusActiveWorkflowHeading" tabindex="-1">${escapeHtml(translateText(presentation.title))}</h3>
          ${renderNexusStatusBadge(latestEntry?.outcomeStatus || latestPacket?.outcomeStatus || latestLane?.status || "draft")}
          <p>${escapeHtml(translateText(content.explanation))}</p>
        </div>
        <div class="nexus-workflow-window-actions">
          <button type="button" data-nexus-workflow-back aria-label="${escapeHtml(translateText("Back to Nexus home"))}">${escapeHtml(translateText("Back"))}</button>
          <button type="button" data-nexus-workflow-minimize aria-label="${escapeHtml(translateText("Minimize function window"))}">${escapeHtml(translateText("Minimize"))}</button>
          <button type="button" data-nexus-mode-shortcut="home" data-nexus-command="What can Nexus do?">${escapeHtml(translateText("Change"))}</button>
          <button type="button" data-nexus-workflow-close data-nexus-command="What can Nexus do?" aria-label="${escapeHtml(translateText("Close function window"))}">${escapeHtml(translateText("Close"))}</button>
        </div>
      </div>
      <div class="nexus-workflow-purpose">
        <strong>${escapeHtml(translateText("Next step"))}</strong>
        <span>${escapeHtml(translateText(content.nextPrompt))}</span>
      </div>
      ${renderNexusAppWindowCommandRow(state.command || "")}
      ${renderNexusAppWindowSwitcher(id)}
      <div class="nexus-workflow-launch-status" data-testid="nexus-workflow-launch-status" role="status">
        <strong>${escapeHtml(translateText("Opened in active workspace"))}</strong>
        <span>${escapeHtml(translateText(nexusWorkflowBlockedReason(id)))}</span>
      </div>
      <section class="nexus-function-window-summary" data-nexus-function-window-summary="true">
        <strong>${escapeHtml(translateText("Assistant summary"))}</strong>
        <p>${escapeHtml(translateText(`Nexus resolved this request to ${presentation.title}. Complete the relevant fields here, review the packet preview, then choose a safe next action.`))}</p>
      </section>
      ${renderNexusDynamicWorkflowRenderer(definition, state)}
      ${id === "operations-memory" ? renderNexusOperationsMemoryWindow() : `
        ${renderNexusWorkflowLandingWindow(definition, state)}
        ${renderNexusWorkflowLaneStatus(id)}
        ${renderNexusConfirmationSummary(latestPacket, latestLane)}
        ${renderNexusUniversalActionReviewLayer(nexusUniversalActionReviewForWorkflow(definition, latestPacket, latestLane))}
      `}
      <div class="nexus-workflow-steps" aria-label="${escapeHtml(translateText("Workflow steps"))}">
        ${steps.map((step, index) => `<span><b>${index + 1}</b>${escapeHtml(translateText(step))}</span>`).join("")}
      </div>
      <div class="nexus-workflow-actions">
        <button type="button" class="primary" data-nexus-action-controller="prepare-packet" data-workflow-id="${escapeHtml(id)}">${escapeHtml(translateText("Prepare packet"))}</button>
        <button type="button" data-nexus-action-controller="request-confirmation" data-workflow-id="${escapeHtml(id)}">${escapeHtml(translateText("Review confirmation"))}</button>
        <button type="button" data-nexus-action-controller="queue-packet" data-workflow-id="${escapeHtml(id)}">${escapeHtml(translateText("Queue if inactive"))}</button>
        <button type="button" data-nexus-action-controller="execute-confirmed-test" data-workflow-id="${escapeHtml(id)}">${escapeHtml(translateText("Run confirmed test mode"))}</button>
        <button type="button" data-nexus-command-prefill="${escapeHtml(content.nextPrompt)}">${escapeHtml(translateText("Use as prompt"))}</button>
        <span>${escapeHtml(translateText(content.limitation))}</span>
      </div>
      <section class="nexus-function-window-preview" data-nexus-function-window-preview="true">
        <strong>${escapeHtml(translateText("Results / packet preview"))}</strong>
        ${renderNexusKnowledgeAnswerCard(functionId === "live-knowledge" || id === "resource-assistant" ? nexusKnowledgeLastResult : null)}
        ${latestPacket ? "" : renderNexusSmartEmptyState(functionId === "live-knowledge" || id === "resource-assistant" ? "research" : "packet")}
        <p>${escapeHtml(translateText(latestPacket ? `${latestPacket.workflowLabel || presentation.title} packet is prepared for review.` : "No full packet has been prepared yet. Use Prepare packet to generate a short review preview inside this window."))}</p>
      </section>
      ${latestPacket ? renderNexusConfirmationPanel(latestPacket, latestLane) : ""}
      ${renderNexusActionReceipt(latestPacket, latestEntry)}
      ${renderNexusWorkflowActionHistory()}
    </section>
    </div>
  `;
}

function focusNexusActiveWorkflow(options = {}) {
  const workspace = $("#nexus-workspace");
  const heading = $("#nexusActiveWorkflowHeading");
  if (!workspace) return;
  const behavior = options.instant ? "auto" : "smooth";
  workspace.classList.add("nexus-workflow-focus-ring");
  workspace.scrollIntoView?.({ block: "start", behavior });
  setTimeout(() => heading?.focus?.({ preventScroll: true }), options.instant ? 0 : 80);
  setTimeout(() => workspace.classList.remove("nexus-workflow-focus-ring"), 1600);
}

function scheduleNexusActiveWorkflowFocus(options = {}) {
  if (experienceMode !== "user" && !document.body.classList.contains("user-mode")) return;
  const focusOptions = { instant: Boolean(options.instant) };
  requestAnimationFrame(() => {
    focusNexusActiveWorkflow(focusOptions);
    setTimeout(() => focusNexusActiveWorkflow({ instant: true }), 120);
  });
}

function openNexusWorkflow(workflowId, options = {}) {
  if (!options.__fromFunctionWindow) {
    return openNexusFunctionWindow(options.functionId || workflowId, {
      ...options,
      workflowId,
      source: options.source || "standard-user"
    });
  }
  const command = options.command || options.response || "";
  const definition = nexusWorkflowDefinition(workflowId, command);
  const safeId = definition?.id || normalizeNexusWorkflowId(workflowId, command) || "unknown";
  nexusActiveWorkflowState = {
    id: definition?.id || safeId,
    functionId: options.functionId || normalizeNexusFunctionId(workflowId, command),
    command,
    source: options.source || "standard-user",
    workflow: options.workflow || workflowId || "",
    action: options.action || "",
    openedAt: Date.now(),
    minimized: false,
    guidedMode: options.guidedMode === true
  };
  recordNexusRecentWorkflow(definition?.id || safeId, {
    status: "draft",
    command,
    title: definition?.presentation?.title,
    category: nexusWorkflowRegistryEntry(definition?.id || safeId)?.category || "platform"
  });
  saveNexusRuntimeMemory();
  if (definition) {
    const panelResult = buildNexusHomeModePanelResult(definition.id, command);
    nexusAgenticBrainLastResult = options.preparedResult || panelResult || {
      ok: true,
      status: "nexus_workflow_opened",
      mode: definition.presentation.title,
      message: `${definition.presentation.title} opened in the main workspace. No external action was executed.`,
      preparedCards: [{
        type: "nexus_full_workflow_workspace",
        title: definition.presentation.title,
        status: "main workspace open",
        localOnly: true,
        noExecutionAuthorized: true
      }],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_full_workflow_workspace"
    };
  } else {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "unknown_workflow_safe_fallback",
      mode: "Nexus workflow",
      message: "I could not identify that workflow, so I kept the request in a safe local review state. No action was executed.",
      preparedCards: [],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_full_workflow_workspace"
    };
  }
  renderUserWorkspace();
  scheduleNexusActiveWorkflowFocus({ instant: options.instant });
  return true;
}

function buildNexusHomeModePanelResult(modeId = "", command = "") {
  const presentation = NEXUS_HOME_MODE_PRESENTATION[modeId] || {};
  const content = NEXUS_HOME_MODE_PANEL_CONTENT[modeId] || null;
  if (!presentation.title || !content) return null;
  return {
    ok: true,
    status: "standard_user_mode_panel_ready",
    mode: presentation.title,
    message: `${presentation.title} is ready. Choose a quick action or tell Nexus what you want to do next.`,
    preparedCards: [{
      type: "standard_user_mode_panel",
      title: `${presentation.icon || ""} ${presentation.title}`.trim(),
      status: "guided mode ready",
      localOnly: true,
      needsRealProvider: ["chronic-care", "telehealth-intake", "mobile-clinic", "pharmacy-support"].includes(modeId),
      modePanel: {
        id: modeId,
        icon: presentation.icon || "",
        title: presentation.title,
        explanation: content.explanation,
        quickActions: content.quickActions,
        fields: NEXUS_HOME_MODE_PANEL_FIELDS[modeId] || [],
        nextPrompt: content.nextPrompt,
        limitation: content.limitation,
        command
      }
    }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "standard_user_home_mode_panel"
  };
}

function detectNexusHomeModePanelId(command = "") {
  const alias = normalizeNexusWorkflowId("", command);
  if (NEXUS_HOME_MODE_IDS.includes(alias)) return alias;
  if (["diabetes", "hypertension", "obesity", "rpm", "rtm", "community-health-worker"].includes(alias)) return alias;
  const text = String(command || "").toLowerCase();
  if (/\b(agriculture help|agriculture support|crop issue|crop issues|irrigation|field guidance)\b/.test(text)) return "agriculture";
  if (/\b(chronic care|blood pressure|glucose|blood sugar|diabetes|obesity|hypertension|rpm|rtm|vitals)\b/.test(text)) return "chronic-care";
  if (/\b(telehealth intake|start.*telehealth|virtual visit intake|clinic intake)\b/.test(text)) return "telehealth-intake";
  if (/\b(mobile clinic|clinic outreach|community clinic|field clinic)\b/.test(text)) return "mobile-clinic";
  if (/\b(pharmacy support|prepare pharmacy|medication list|refill question|medicine question)\b/.test(text)) return "pharmacy-support";
  if (/\b(learning|literacy|training|course|learn a new skill|ai basics)\b/.test(text)) return "learning";
  if (/\b(jobs|workforce|farm jobs|job skills|interview|work readiness)\b/.test(text)) return "jobs";
  if (/\b(agritrade|marketplace|buyer|seller|listing|listings)\b/.test(text)) return "agritrade";
  if (/\b(open maps|open map|field visit route|map|maps|route|routes)\b/.test(text)) return "maps";
  if (/\b(play music|open music|music media|music\/media|open media|media mode)\b/.test(text)) return "media";
  if (/\b(reminder|reminders|remind me|follow-up|follow up)\b/.test(text)) return "reminders";
  if (/\b(offline queue|offline mode|queued work|low bandwidth|low-bandwidth)\b/.test(text)) return "offline";
  return null;
}

function buildNexusHomeModeSummaryResult(modeId = "", values = {}) {
  const presentation = NEXUS_HOME_MODE_PRESENTATION[modeId] || {};
  const content = NEXUS_HOME_MODE_PANEL_CONTENT[modeId] || {};
  const fields = NEXUS_HOME_MODE_PANEL_FIELDS[modeId] || [];
  const labels = Object.fromEntries(fields.map(field => {
    const [name, label] = Array.isArray(field) ? field : [field.name, field.label];
    return [name, label || name];
  }));
  const enteredValues = Object.fromEntries(Object.entries(values || {}).filter(([, value]) => String(value || "").trim()));
  const healthcareMode = ["chronic-care", "telehealth-intake", "mobile-clinic", "pharmacy-support"].includes(modeId);
  const commerceMode = modeId === "agritrade";
  const locationMode = modeId === "maps" || modeId === "mobile-clinic";
  const summaryTitle = `${presentation.icon || ""} ${presentation.title || "Nexus"} summary`.trim();
  const safetyNote = healthcareMode
    ? "Provider-ready preparation only. Nexus does not diagnose, prescribe, book, launch video, contact providers, request refills, dispatch services, share records, or handle emergencies."
    : commerceMode
      ? "Marketplace preparation only. Nexus does not contact buyers or sellers, place orders, process payments, book logistics, or move goods."
      : locationMode
        ? "Route and access preparation only. Nexus does not request browser location, share location, dispatch transport, or navigate externally without approval."
        : modeId === "media"
          ? "Media preparation only. Nexus does not host, download, rip, cache, scrape, or redistribute copyrighted music."
          : "Local preparation only. Nexus did not execute external actions, send messages, make calls, process payments, or submit data.";
  const nextStep = content.nextPrompt || "Review this summary and choose a safe next step.";
  return {
    ok: true,
    status: "standard_user_mode_summary_prepared",
    mode: presentation.title || "Nexus mode",
    message: `${presentation.title || "Nexus"} summary prepared locally. Review it before taking any next step.`,
    preparedCards: [{
      type: "standard_user_mode_summary",
      title: summaryTitle,
      status: "local summary ready",
      localOnly: true,
      needsRealProvider: healthcareMode,
      modeSummary: {
        id: modeId,
        title: summaryTitle,
        labels,
        values: enteredValues,
        nextStep,
        safetyNote
      }
    }],
    noExecutionAuthorized: true,
    localOnly: true,
    source: "standard_user_mode_summary"
  };
}

function handleNexusHomeModeSummaryClick(event) {
  const button = event.target?.closest?.("[data-nexus-mode-summary]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const modeId = button.dataset.nexusModeSummary || "";
  const normalizedModeId = normalizeNexusWorkflowId(modeId, "");
  if (!NEXUS_HOME_MODE_IDS.includes(normalizedModeId)) {
    nexusAgenticBrainLastResult = {
      ok: true,
      status: "nexus_workflow_local_summary_ready",
      mode: nexusWorkflowDefinition(normalizedModeId)?.presentation?.title || "Nexus workflow",
      message: "Local workflow notes are ready for human review. No provider, payment, call, message, location, camera, medical, pharmacy, emergency, or backend action was executed.",
      preparedCards: [],
      noExecutionAuthorized: true,
      localOnly: true,
      source: "nexus_full_workflow_workspace"
    };
    renderUserWorkspace();
    return true;
  }
  const form = button.closest("[data-nexus-mode-form]");
  const values = {};
  form?.querySelectorAll?.("[data-nexus-mode-field]")?.forEach(field => {
    values[field.dataset.nexusModeField || field.name || "field"] = field.value || "";
  });
  const summary = buildNexusHomeModeSummaryResult(normalizedModeId, values);
  if (!summary) return false;
  nexusAgenticBrainLastResult = summary;
  renderUserWorkspace();
  return true;
}

