function resolveNexusDomainToneSafetyAdapter(domain = "general", context = {}) {
  const normalized = normalizeNexusExperienceMode(domain || context.mode || context.command || context.message || "general");
  const adapter = NEXUS_DOMAIN_TONE_SAFETY_ADAPTERS[normalized] || NEXUS_DOMAIN_TONE_SAFETY_ADAPTERS.general;
  return {
    schemaVersion: NEXUS_DOMAIN_TONE_SAFETY_ADAPTER_CONTRACT.schemaVersion,
    adapterName: NEXUS_DOMAIN_TONE_SAFETY_ADAPTER_CONTRACT.adapterName,
    domain: adapter.domain,
    tone: adapter.tone,
    pace: adapter.pace,
    plainLanguageFrame: adapter.plainLanguageFrame,
    safetyBoundary: adapter.safetyBoundary,
    forbiddenClaims: Array.from(adapter.forbiddenClaims),
    confirmationRequirement: adapter.confirmationRequirement,
    highRiskActionsRemainGated: true,
    noFakeCompletion: true
  };
}

function inferNexusConversationStyleMode(context = {}) {
  const text = [
    context.mode,
    context.command,
    context.message,
    context.domain,
    context.intent,
    context.source
  ].filter(Boolean).join(" ").toLowerCase();
  if (/\b(emergency|urgent|severe|cannot breathe|chest pain|stroke|danger)\b/.test(text)) return "URGENT";
  if (/\b(diabetes|hypertension|obesity|blood pressure|bp|rpm|rtm|clinic|telehealth|pharmacy|provider|symptom|medicine|medication)\b/.test(text)) return "CLINICAL";
  if (/\b(step|guide|teach|learn|literacy|training|explain|help me understand)\b/.test(text)) return "GUIDE";
  if (/\b(status|summary|receipt|what happened|quick|short|brief)\b/.test(text)) return "FOCUS";
  return "STANDARD";
}

function nexusConversationStyleModeConfig(styleMode = "STANDARD") {
  return NEXUS_PRESENCE_RUNTIME_BASELINE.deliveryModes[styleMode] || NEXUS_PRESENCE_RUNTIME_BASELINE.deliveryModes.STANDARD;
}

function nexusConversationStyleSafetyBoundary(styleMode = "STANDARD", domain = "general") {
  const domainAdapter = resolveNexusDomainToneSafetyAdapter(domain);
  if (styleMode === "CLINICAL") {
    return "I can organize health information for education and provider review, but I do not diagnose, prescribe, change medication, or handle emergencies.";
  }
  if (styleMode === "URGENT") {
    return "If this may be an emergency, contact local emergency services or urgent professional care now. Nexus cannot dispatch help.";
  }
  if (domainAdapter.domain === "marketplace") return "I do not buy, sell, pay, or contact anyone without the required gates.";
  if (domainAdapter.domain === "communications") return "I do not send messages or start calls without provider setup and explicit confirmation.";
  return domainAdapter.safetyBoundary;
}

function normalizeNexusConversationText(text = "") {
  return String(text || "").replace(/\s+/g, " ").trim();
}

function composeNexusConversationStyleResponse(context = {}) {
  const styleMode = context.styleMode || inferNexusConversationStyleMode(context);
  const modeConfig = nexusConversationStyleModeConfig(styleMode);
  const domain = normalizeNexusExperienceMode(context.domain || context.mode || context.command || "general");
  const domainAdapter = resolveNexusDomainToneSafetyAdapter(domain, context);
  const acknowledgment = context.acknowledgment || getNexusExperienceAcknowledgment(domain, context.command || "");
  const plainLanguageSummary = normalizeNexusConversationText(context.message || context.summary || `I can ${domainAdapter.plainLanguageFrame}.`);
  const safetyBoundary = context.safetyBoundary || nexusConversationStyleSafetyBoundary(styleMode, domain);
  const nextQuestion = context.nextQuestion || getNextBestQuestion(domain, context.missingInfo || [], context.currentState || {});
  const pieces = [acknowledgment, plainLanguageSummary, safetyBoundary, `Next: ${nextQuestion}`].filter(Boolean);
  const spokenText = normalizeNexusConversationText(pieces.join(" "));
  return {
    schemaVersion: NEXUS_CONVERSATION_STYLE_ENGINE_CONTRACT.schemaVersion,
    engineName: NEXUS_CONVERSATION_STYLE_ENGINE_CONTRACT.engineName,
    styleMode,
    domain,
    tone: domainAdapter.tone || modeConfig.tone,
    styleTone: modeConfig.tone,
    domainTone: domainAdapter.tone,
    pace: domainAdapter.pace || modeConfig.pace,
    stylePace: modeConfig.pace,
    domainPace: domainAdapter.pace,
    speechRate: modeConfig.speechRate,
    domainAdapter,
    plainLanguageFrame: domainAdapter.plainLanguageFrame,
    forbiddenClaims: domainAdapter.forbiddenClaims,
    confirmationRequirement: domainAdapter.confirmationRequirement,
    acknowledgment,
    plainLanguageSummary,
    safetyBoundary,
    nextQuestion,
    spokenText,
    captionText: spokenText,
    highRiskActionsRemainGated: true,
    noFakeCompletion: true
  };
}

function normalizeNexusExperienceMode(mode = "") {
  const text = String(mode || "").toLowerCase();
  if (/\b(diabetes|hypertension|obesity|blood pressure|bp|rpm|rtm|chronic|health|clinic|provider|telehealth|pharmacy|mobile clinic|chw)\b/.test(text)) return "health";
  if (/\b(crop|agriculture|farm|field|irrigation|soil|pest|disease|yield|storage|food security)\b/.test(text)) return "agriculture";
  if (/\b(marketplace|agritrade|buyer|seller|listing|trade|vendor)\b/.test(text)) return "marketplace";
  if (/\b(logistics|shipment|delivery|route|transport|field visit|maps)\b/.test(text)) return "logistics";
  if (/\b(workforce|job|resume|employer|application|interview)\b/.test(text)) return "workforce";
  if (/\b(learning|training|literacy|course|study|class|lms)\b/.test(text)) return "learning";
  if (/\b(drone|aerial|imagery|flight|survey)\b/.test(text)) return "drone";
  if (/\b(message|sms|whatsapp|telegram|email|call|communication|phone)\b/.test(text)) return "communications";
  return text || "general";
}

function nexusExperienceModeFromMission(mission = null) {
  if (!mission) return "general";
  return normalizeNexusExperienceMode([
    mission.mode,
    mission.submode,
    mission.actionType,
    mission.title,
    mission.goal,
    mission.command,
    mission.source
  ].filter(Boolean).join(" "));
}

function nexusExperienceModeFromCommand(command = "", mission = null) {
  return normalizeNexusExperienceMode([command, mission?.mode, mission?.title, mission?.goal].filter(Boolean).join(" "));
}

function getNexusExperienceAcknowledgment(mode = "general", command = "") {
  const normalized = normalizeNexusExperienceMode(mode || command);
  const map = {
    health: "I hear you. I’ll organize this as health preparation and keep it educational, intake-focused, and provider-review ready.",
    agriculture: "Got it. I’ll structure the crop or farm details and keep the guidance educational until a local expert or source confirms it.",
    marketplace: "Understood. I’ll prepare marketplace details for review without contacting buyers, sellers, or payment systems.",
    logistics: "I’ll prepare the route or shipment context locally and avoid live dispatch, tracking, or carrier handoff.",
    workforce: "I’ll organize the workforce goal into skills, gaps, and next preparation steps without submitting anything.",
    learning: "I’ll shape this into a learning path and keep enrollment or LMS actions gated.",
    drone: "I’ll prepare a drone-service review packet only. No flight, imaging, or operator dispatch will start.",
    communications: "I’ll draft the communication and keep it unsent until the required provider, recipient, and confirmation gates are satisfied."
  };
  return map[normalized] || "I’m on it. I’ll prepare the safest local next step and tell you clearly what happened.";
}

function getNexusExperienceProgressSteps(mode = "general") {
  const normalized = normalizeNexusExperienceMode(mode);
  const map = {
    health: ["Understanding health goal", "Checking safety limits", "Preparing provider-ready summary"],
    agriculture: ["Reading farm context", "Checking missing field data", "Preparing source-ready guidance"],
    marketplace: ["Checking listing or partner details", "Reviewing trade-readiness gaps", "Preparing a safe review packet"],
    logistics: ["Checking route context", "Reviewing missing origin/destination details", "Preparing local handoff notes"],
    workforce: ["Checking career goal", "Finding skill gaps", "Preparing a readiness summary"],
    learning: ["Checking learning goal", "Matching pathway needs", "Preparing next study steps"],
    drone: ["Checking field request", "Reviewing safety prerequisites", "Preparing a no-flight review packet"],
    communications: ["Checking recipient and purpose", "Reviewing confirmation gates", "Preparing an unsent draft"]
  };
  return map[normalized] || ["Understanding request", "Checking safety gates", "Preparing the next local step"];
}

function getNextBestQuestion(mode = "general", missingData = [], currentState = {}) {
  const missing = Array.isArray(missingData) ? missingData.filter(Boolean) : [];
  if (missing.length) return `What can you share about ${String(missing[0]).replace(/[_-]/g, " ")}?`;
  const normalized = normalizeNexusExperienceMode(mode);
  const map = {
    health: "What is the main health detail you want organized for provider review?",
    agriculture: "What crop, field condition, or local weather detail should I use next?",
    marketplace: "Who is the buyer or seller, and what product details should I prepare?",
    logistics: "What origin, destination, and timing should I use for the route plan?",
    workforce: "What job role, skill, or training goal should I focus on next?",
    learning: "What topic do you want to learn, and how much time can you study each week?",
    drone: "What field size, crop, and observation goal should the review packet cover?",
    communications: "Who is the recipient, and what should the draft say?"
  };
  return currentState?.nextQuestion || map[normalized] || "What detail should I use for the next step?";
}

function getNexusExperienceConfidenceExplanation(mode = "general", mission = {}) {
  const missing = Array.isArray(mission?.missingInfo) ? mission.missingInfo.length : 0;
  const collected = Array.isArray(mission?.collectedInfo) ? mission.collectedInfo.length : 0;
  if (missing > 2) return "Confidence is limited because several details are still missing. I can improve it as you answer the next question.";
  if (missing > 0) return "Confidence is moderate because I have some useful context, but one or more details would make the next step clearer.";
  if (collected > 1 || /completed|ready|predictive/i.test(String(mission?.status || mission?.executionStatus || ""))) {
    return "Confidence is stronger for local preparation because the request has enough structure for a review-ready next step.";
  }
  return "Confidence is preliminary because I’m working from a short request and no live external system has been used.";
}

function getSuggestedNextActions(mode = "general", state = {}) {
  const normalized = normalizeNexusExperienceMode(mode);
  const map = {
    health: ["Add a reading", "Prepare provider summary", "Ask what is missing"],
    agriculture: ["Add crop details", "Review risk factors", "Prepare expert checklist"],
    marketplace: ["Prepare listing", "Check buyer readiness", "Review trade risk"],
    logistics: ["Add origin and destination", "Prepare route plan", "Review dispatch gates"],
    workforce: ["Check skill gaps", "Prepare resume summary", "Find training steps"],
    learning: ["Build study plan", "Review completion risk", "Choose next lesson"],
    drone: ["Prepare field checklist", "Review no-fly gates", "Ask for field size"],
    communications: ["Review draft", "Add recipient", "Confirm no send yet"]
  };
  const suggested = map[normalized] || ["Show next step", "Show last receipt", "Ask what is missing"];
  return Array.isArray(state?.suggestedActions) && state.suggestedActions.length ? state.suggestedActions : suggested;
}

function getNexusExperienceReceiptMessage(mode = "general", mission = {}, kind = "local_update") {
  const normalized = normalizeNexusExperienceMode(mode);
  const didNot = "No provider handoff, message, call, payment, booking, dispatch, location sharing, camera capture, diagnosis, prescription, or external execution occurred.";
  const map = {
    health: "I organized the health details locally for review and kept care decisions gated.",
    agriculture: "I updated the local agriculture support view and prepared source-ready next steps.",
    marketplace: "I prepared the marketplace review context locally without contacting anyone.",
    logistics: "I prepared the logistics context locally without live tracking or dispatch.",
    workforce: "I updated the workforce preparation context locally.",
    learning: "I prepared the learning pathway context locally.",
    drone: "I prepared the drone-service review context locally without starting any flight workflow.",
    communications: "I prepared communication context locally and did not send anything."
  };
  return `${map[normalized] || "I prepared the local Nexus result."} ${didNot}`;
}

function isNexusExperienceHelpCommand(command = "") {
  return /^(nexus,?\s*)?(what can (nexus|you) do|show me nexus modes|show me what you can help with|help me get started|what can nexus do across all modes)\??$/i.test(String(command || "").trim());
}

function isNexusExperienceStatusCommand(command = "") {
  return /\b(what happened|what did you do|did it send|what do i need to do next|show my last receipt|last receipt|show receipt)\b/i.test(String(command || ""));
}

function buildNexusExperienceStarterResponse(command = "", options = {}) {
  const greeting = options.greeting || nexusPresenceGreeting();
  const styled = composeNexusConversationStyleResponse({
    command,
    mode: "general",
    message: "You can ask me for health intake, chronic care tracking, crop support, marketplace preparation, logistics, jobs, learning, drone review, or unsent communications.",
    acknowledgment: greeting,
    nextQuestion: "What would you like Nexus to prepare or assess first?"
  });
  return {
    message: styled.spokenText,
    nextQuestion: styled.nextQuestion,
    style: styled,
    suggestions: [
      "help with diabetes intake",
      "predict crop risk",
      "prepare a marketplace listing",
      "plan logistics",
      "build a learning plan",
      "prepare an SMS",
      "show my last receipt"
    ]
  };
}

function handleNexusExperienceStarterCommand(command = "", options = {}) {
  if (!isNexusExperienceHelpCommand(command)) return false;
  const starter = buildNexusExperienceStarterResponse(command);
  setNexusPresenceState(NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP, {
    lastUserInput: String(command || "").trim(),
    lastResponse: starter.message,
    nextQuestion: starter.nextQuestion,
    activeMission: "Ready to help"
  });
  renderLiveVoiceSuggestions?.(starter.suggestions);
  setVoiceResponse(starter.message, options.speak !== false, {
    allowHandoff: false,
    command,
    source: options.source || "nexus-experience-polish-layer",
    skipPresenceUpdate: true
  });
  return true;
}

function latestNexusExperienceMission() {
  return nexusActiveWorkflowState?.agenticMission || nexusAgenticCommandMissions[0] || null;
}

function handleNexusExperienceStatusCommand(command = "", options = {}) {
  if (!isNexusExperienceStatusCommand(command)) return false;
  const mission = latestNexusExperienceMission();
  const receipt = mission?.receipts?.[0] || nexusAgenticCommandLocalMemory.receipts?.[0] || null;
  if (!mission && !receipt) {
    const styled = composeNexusConversationStyleResponse({
      command,
      styleMode: "FOCUS",
      message: "I do not have a recent local Nexus action to report yet. Ask me to prepare a health, agriculture, marketplace, logistics, workforce, learning, drone, or communication step first.",
      nextQuestion: "What should Nexus prepare first?"
    });
    const message = styled.spokenText;
    setNexusPresenceState(NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP, {
      lastUserInput: String(command || "").trim(),
      lastResponse: message,
      nextQuestion: styled.nextQuestion,
      activeMission: "Ready to help"
    });
    setVoiceResponse(message, options.speak !== false, { allowHandoff: false, command, source: "nexus-experience-polish-layer", skipPresenceUpdate: true });
    return true;
  }
  const mode = nexusExperienceModeFromMission(mission || {});
  const missing = mission?.missingInfo?.length ? mission.missingInfo.join(", ") : "nothing required for the current local review";
  const rawMessage = [
    `What happened: ${receipt?.happened || mission?.receiptMessage || getNexusExperienceReceiptMessage(mode, mission)}.`,
    `What did not happen: ${receipt?.didNot || "No external action was executed."}`,
    `Confidence: ${mission?.confidenceExplanation || getNexusExperienceConfidenceExplanation(mode, mission)}.`,
    `Still needed: ${missing}.`,
    `Next: ${mission?.nextBestQuestion || mission?.nextStep || getNextBestQuestion(mode, mission?.missingInfo, mission)}`
  ].join(" ");
  const styled = composeNexusConversationStyleResponse({
    command,
    styleMode: "FOCUS",
    mode,
    message: rawMessage,
    nextQuestion: mission?.nextBestQuestion || mission?.nextStep || getNextBestQuestion(mode, mission?.missingInfo, mission)
  });
  const message = styled.spokenText;
  setNexusPresenceState(NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP, {
    lastUserInput: String(command || "").trim(),
    lastResponse: message,
    nextQuestion: styled.nextQuestion,
    activeMission: mission?.title || "Nexus local result"
  });
  setVoiceResponse(message, options.speak !== false, { allowHandoff: false, command, source: "nexus-experience-polish-layer", skipPresenceUpdate: true });
  return true;
}

function applyNexusExperiencePolishToMission(mission = {}, command = "", message = "") {
  const mode = nexusExperienceModeFromCommand(command || mission.goal || mission.command || "", mission);
  const missingInfo = Array.isArray(mission.missingInfo) ? mission.missingInfo : [];
  const nextBestQuestion = getNextBestQuestion(mode, missingInfo, mission);
  const suggestedNextActions = getSuggestedNextActions(mode, mission);
  const confidenceExplanation = getNexusExperienceConfidenceExplanation(mode, mission);
  const receiptMessage = getNexusExperienceReceiptMessage(mode, mission);
  const progressSteps = getNexusExperienceProgressSteps(mode);
  const styled = composeNexusConversationStyleResponse({
    command,
    mode,
    message: message || mission.message || mission.summary || mission.title || "Nexus prepared the local result.",
    acknowledgment: getNexusExperienceAcknowledgment(mode, command || mission.goal || ""),
    nextQuestion: nextBestQuestion,
    missingInfo
  });
  mission.experienceMode = mode;
  mission.experienceAcknowledgment = styled.acknowledgment;
  mission.experienceProgress = progressSteps;
  mission.nextBestQuestion = nextBestQuestion;
  mission.confidenceExplanation = confidenceExplanation;
  mission.suggestedNextActions = suggestedNextActions;
  mission.receiptMessage = receiptMessage;
  mission.conversationStyle = styled;
  mission.nextStep = mission.nextStep || nextBestQuestion;
  mission.timeline = [
    { at: new Date().toISOString(), event: "experience_polish_applied", detail: "Nexus added acknowledgment, progress, confidence, next question, suggested actions, and receipt copy." },
    ...(mission.timeline || [])
  ].slice(0, 20);
  const summaryParts = [
    styled.spokenText,
    `Progress: ${progressSteps.join(" > ")}.`,
    `Confidence: ${confidenceExplanation}`,
    `Suggested next actions: ${suggestedNextActions.slice(0, 3).join(", ")}.`,
    receiptMessage
  ];
  return summaryParts.filter(Boolean).join(" ");
}

function parseNexusExperienceFollowUp(mode = "general", text = "") {
  const normalized = normalizeNexusExperienceMode(mode);
  const value = String(text || "").trim();
  if (!value) return null;
  if (normalized === "health" && /\b(\d{2,3})\s*(?:\/|over)\s*(\d{2,3})\b|\b(bp|blood pressure|glucose|weight|symptom|rpm|rtm)\b/i.test(value)) {
    return { label: "Health follow-up", removeMissing: /(reading|symptom|time|bp|blood pressure|rpm|rtm)/i };
  }
  if (normalized === "agriculture" && /\b(crop|field|rain|rainfall|irrigation|soil|pest|disease|acre|hectare|maize|tomato|cassava|yield)\b/i.test(value)) {
    return { label: "Agriculture follow-up", removeMissing: /(crop|field|rain|soil|pest|disease|irrigation|location)/i };
  }
  if (normalized === "marketplace" && /\b(buyer|seller|bags?|kg|price|location|market|transport|maize|produce|listing)\b/i.test(value)) {
    return { label: "Marketplace follow-up", removeMissing: /(buyer|seller|product|quantity|price|location|transport)/i };
  }
  if (normalized === "logistics" && /\b(carrier|dhl|origin|destination|from|to|tracking|shipment|route|delivery|nairobi|mombasa|stockton|sacramento)\b/i.test(value)) {
    return { label: "Logistics follow-up", removeMissing: /(carrier|origin|destination|route|tracking|delivery)/i };
  }
  if (normalized === "workforce" && /\b(job|role|resume|skill|credential|certificate|training|experience|employer|interview|osha)\b/i.test(value)) {
    return { label: "Workforce follow-up", removeMissing: /(role|skill|credential|experience|resume|employer)/i };
  }
  if (normalized === "learning" && /\b(study|course|lesson|days?|hours?|literacy|training|certificate|learn|class)\b/i.test(value)) {
    return { label: "Learning follow-up", removeMissing: /(topic|schedule|time|course|skill)/i };
  }
  if (normalized === "drone" && /\b(drone|field|hectare|acre|battery|operator|flight|survey|image|imagery)\b/i.test(value)) {
    return { label: "Drone follow-up", removeMissing: /(field|size|operator|purpose|safety|battery)/i };
  }
  if (normalized === "communications" && /\b(recipient|manager|clinic|buyer|seller|message|sms|whatsapp|email|call|tone|send|draft)\b/i.test(value)) {
    return { label: "Communication follow-up", removeMissing: /(recipient|purpose|message|tone|provider|language)/i };
  }
  return null;
}

function handleNexusPresenceFollowUp(command = "", options = {}) {
  const presenceMission = String(nexusPresenceState.activeMission || "");
  const presenceMatchedMission = presenceMission
    ? nexusAgenticCommandMissions.find(mission => {
      const label = String([mission?.title, mission?.mode, mission?.submode].filter(Boolean).join(" "));
      return label && (label.includes(presenceMission) || presenceMission.includes(label));
    })
    : null;
  const activeMission = nexusActiveWorkflowState?.agenticMission
    || presenceMatchedMission
    || nexusAgenticCommandMissions[0]
    || null;
  const followUpReady = nexusPresenceState.state === NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP
    || nexusPresenceState.state === NEXUS_PRESENCE_STATES.LISTENING;
  if (!activeMission || !followUpReady) return false;
  const text = String(command || "").trim();
  if (!text || /^(nexus|hello nexus|hey nexus)$/i.test(text) || isNexusExperienceHelpCommand(text) || isNexusExperienceStatusCommand(text)) return false;
  if (/^(?:hello\s+|hey\s+)?nexus\b|^(?:open|start|help|record|prepare|plan|show)\b/i.test(text)) return false;
  const mode = nexusExperienceModeFromCommand(text, activeMission);
  const parsedFollowUp = parseNexusExperienceFollowUp(mode, text);
  if (!parsedFollowUp) return false;
  activeMission.collectedInfo = [...(activeMission.collectedInfo || []), text].slice(-8);
  activeMission.missingInfo = (activeMission.missingInfo || []).filter(item => !parsedFollowUp.removeMissing.test(String(item)));
  activeMission.nextBestQuestion = getNextBestQuestion(mode, activeMission.missingInfo, activeMission);
  activeMission.nextStep = activeMission.missingInfo?.length
    ? `Thanks. I still need ${activeMission.missingInfo.slice(0, 3).join(", ")}.`
    : activeMission.nextBestQuestion;
  activeMission.timeline = [
    { at: new Date().toISOString(), event: "experience_follow_up_added", detail: `${parsedFollowUp.label} attached locally; no external action occurred.` },
    ...(activeMission.timeline || [])
  ].slice(0, 20);
  nexusActiveWorkflowState = { agenticMission: activeMission };
  const message = `${getNexusExperienceAcknowledgment(mode, text)} ${activeMission.nextStep} ${getNexusExperienceReceiptMessage(mode, activeMission)}`;
  setNexusPresenceState(activeMission.missingInfo?.length ? NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP : NEXUS_PRESENCE_STATES.COMPLETED_LOCAL, {
    lastUserInput: text,
    lastResponse: message,
    nextQuestion: activeMission.nextBestQuestion || activeMission.nextStep,
    activeMission: activeMission.title || "Nexus local mission"
  });
  setNexusAgenticCommandResult(activeMission, message);
  return true;
}

function handleNexusPresenceInputActivity(event) {
  const input = event?.target?.closest?.("#nexusCommandCenterInput, [data-nexus-command-input]");
  if (!input) return;
  const text = input.value?.trim?.() || "";
  if (text) {
    nexusIntentDrivenLastCommandText = text;
    setNexusIntentDrivenWorkflowStatusForCommand(text, {
      source: "visible-command-input-activity-intent-router"
    });
    updateNexusIntentDrivenWorkflowStatusDom();
  }
  setNexusPresenceState(NEXUS_PRESENCE_STATES.LISTENING, {
    lastUserInput: text || nexusPresenceState.lastUserInput,
    lastResponse: nexusPresenceState.lastResponse,
    nextQuestion: text ? "Press Send when you are ready." : "Tell Nexus what you need.",
    activeMission: nexusPresenceState.activeMission
  });
}

function handleNexusPresenceVoiceButton(event) {
  const button = event?.target?.closest?.("[data-nexus-command-center-voice]");
  if (!button) return;
  setNexusPresenceState(NEXUS_PRESENCE_STATES.LISTENING, {
    lastResponse: nexusPresenceState.lastResponse,
    nextQuestion: "Speak when the browser voice prompt is ready.",
    activeMission: nexusPresenceState.activeMission
  });
}

async function handleNexusPresenceCommandSendSubmit(event) {
  const composer = event?.target?.closest?.("[data-nexus-command-composer]");
  const submit = event?.target?.closest?.(".nexus-command-send[data-nexus-command-center-submit]")
    || composer?.querySelector?.(".nexus-command-send[data-nexus-command-center-submit]");
  if (!submit) return false;
  const input = nexusCommandInputForSubmit(submit);
  const command = input?.value?.trim() || "";
  if (!command) return false;
  nexusTrueExperienceSessionStarted = true;
  recordNexusOsConversationTurn("user", command, { source: "typed-command-send-button" });
  clearNexusTrueExperienceStaleWorkflowState();
  event.preventDefault();
  event.stopPropagation();
  event.stopImmediatePropagation?.();
  const source = "typed-command-send-button";
  if (isNexusTrueExperienceReturnHomeCommand(command)) {
    if (input) input.value = "";
    setCommandInputs("");
    await handleNexusOsMissionLifecycleAction("return-home");
    return true;
  }
  if (isNexusPresenceWakePhrase(command)) {
    if (input) input.value = command;
    setCommandInputs(command);
    await handleNexusUnifiedBrainRuntimeCommand(command, { source });
    renderUserWorkspace();
    return true;
  }
  if (handleNexusVoiceTroubleshootingCommand(command, { source: "typed-command-send-button" })) {
    if (input) input.value = command;
    setCommandInputs(command);
    renderUserWorkspace();
    return true;
  }
  if (handleNexusGenesisProviderOrchestrationCommand(command, { source })) {
    if (input) input.value = "";
    setCommandInputs("");
    return true;
  }
  if (handleNexusGenesisProviderAbstractionCommand(command, { source })) {
    if (input) input.value = "";
    setCommandInputs("");
    return true;
  }
  if (isNexusGenesisAfricaAgOpportunityFallbackCommand(command)) {
    const handledAfricaOpportunity = await handleNexusGenesisAfricaAgOpportunityCommandAsync(command, { source });
    if (!handledAfricaOpportunity) {
      const blockedMessage = "Nexus could not load the Africa agriculture opportunity packet in this browser session. No provider, buyer, training, finance, transport, or country-specific action was selected or executed.";
      recordNexusOsConversationTurn("assistant", blockedMessage, { source: "nexus-genesis-africa-ag-opportunity-safe-fallback", noExecutionAuthorized: true });
      setVoiceResponse(blockedMessage, false, { allowHandoff: false, source: "nexus-genesis-africa-ag-opportunity-safe-fallback" });
    }
    if (input) input.value = "";
    setCommandInputs(command);
    renderUserWorkspace();
    return true;
  }
  if (handleNexusEnterpriseHealthEvidenceTrustCommand(command, { source })) {
    if (input) input.value = "";
    setCommandInputs("");
    return true;
  }
  if (handleNexusMentalHealthBehavioralWellnessCommand(command, { source })) {
    if (input) input.value = "";
    setCommandInputs("");
    return true;
  }
  const routedCommand = normalizeNexusPresenceRoutableCommand(command);
  if (routeNexusIntentDrivenWorkflowCommand(command, { source })) {
    if (input) input.value = command;
    setCommandInputs(command);
    return true;
  }
  const predictiveCommand = isNexusMultiDomainPredictiveCommand(routedCommand)
    || isNexusAgriculturePredictiveModelerCommand(routedCommand)
    || isNexusChronicPredictiveModelerCommand(routedCommand)
    || isNexusPredictiveMaturityCommand(routedCommand);
  if (predictiveCommand && runNexusAgenticCommandRuntime(routedCommand, { source, originalCommand: command })) {
    if (input) input.value = "";
    setCommandInputs(command);
    return true;
  }
  if (await handleNexusUnifiedBrainRuntimeCommand(command, { source })) {
    const directExperienceCommand = isNexusExperienceHelpCommand(command) || isNexusExperienceStatusCommand(command);
    if (input) input.value = directExperienceCommand ? "" : command;
    setCommandInputs(directExperienceCommand ? "" : command);
    renderUserWorkspace();
    return true;
  }
  const fallbackResponse = "I'm here. Tell me the goal, and I will ask for only the missing details before opening the right workflow.";
  recordNexusOsConversationTurn("assistant", fallbackResponse, { source: "true-conversation-fallback" });
  setVoiceResponse(fallbackResponse, false, { allowHandoff: false, source: "true-conversation-fallback" });
  if (input) input.value = command;
  setCommandInputs(command);
  renderUserWorkspace();
  return true;
}

function handleNexusTrueCommandComposerKeydown(event) {
  const input = event?.target?.closest?.("#nexusCommandCenterInput[data-nexus-primary-typed-entry]");
  if (!input || event.key !== "Enter" || event.shiftKey) return;
  const composer = input.closest?.("[data-nexus-command-composer]");
  const submit = composer?.querySelector?.(".nexus-command-send[data-nexus-command-center-submit]");
  if (!submit) return;
  event.preventDefault();
  event.stopPropagation();
  event.stopImmediatePropagation?.();
  void handleNexusPresenceCommandSendSubmit({
    target: submit,
    preventDefault() {},
    stopPropagation() {},
    stopImmediatePropagation() {}
  });
}

function openNexusOnboardingModal() {
  const modal = $("#nexusOnboardingModal");
  if (!modal) return;
  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  $("#nexusOnboardingClose")?.focus?.();
}

function closeNexusOnboardingModal() {
  const modal = $("#nexusOnboardingModal");
  if (!modal) return;
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
  const commandInput = $("#nexusCommandCenterInput");
  commandInput?.scrollIntoView?.({ block: "center", behavior: "smooth" });
  setTimeout(() => commandInput?.focus?.(), 0);
}

const NEXUS_TRUE_EXPERIENCE_LOAD_EPOCH = Date.now();
let nexusTrueExperienceSessionStarted = false;
let nexusTrueExperienceHomeResetEpoch = 0;
let nexusGenesisExperienceActivated = false;
let nexusGenesisExperienceAnimationFrame = 0;
let nexusGenesisExperienceStartedAt = 0;

const NEXUS_GENESIS_EXPERIENCE_OWNERSHIP_REGISTRY = Object.freeze({
  engine: "Nexus Genesis Experience Engine 1.0",
  coreStateOwner: "nexusCoreRuntimeState",
  orbRendererOwner: "renderNexusTrueCoreOrb",
  particleRendererOwner: "CSS/rAF-driven nexus-genesis-particle-field",
  audioHookOwner: "existing Nexus speech synthesis and voice runtime",
  voiceSynchronizationOwner: "setNexusCoreState and Nexus Presence voice events",
  missionTransitionOwner: "nexusTrueExperienceMode and renderNexusAgenticMissionWorkspace",
  performanceTierOwner: "nexusGenesisExperiencePerformanceTier",
  cacheBuildOwner: "AGRINEXUS_BUILD_VERSION / AGRINEXUS_PWA_CACHE_VERSION",
  duplicateOrbPolicy: "Genesis orb is one non-interactive visual presence indicator",
  animationLoopPolicy: "single interruptible requestAnimationFrame loop, paused when hidden",
  hiddenLegacyPolicy: "legacy Home controls are not mounted or focusable in orb-only idle"
});

function nexusGenesisExperienceReducedMotion() {
  return Boolean(typeof window !== "undefined" && window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches);
}

function nexusGenesisExperiencePerformanceTier() {
  if (nexusGenesisExperienceReducedMotion()) return "reduced-motion";
  const nav = typeof navigator !== "undefined" ? navigator : {};
  const cores = Number(nav.hardwareConcurrency || 4);
  const memory = Number(nav.deviceMemory || 4);
  if (cores <= 2 || memory <= 2) return "low-power";
  if (cores >= 8 && memory >= 8) return "high";
  return "standard";
}

function exposeNexusGenesisExperienceRuntime() {
  const target = typeof globalThis !== "undefined" ? globalThis : (typeof window !== "undefined" ? window : null);
  if (!target) return;
  target.NEXUS_GENESIS_EXPERIENCE_OWNERSHIP_REGISTRY = NEXUS_GENESIS_EXPERIENCE_OWNERSHIP_REGISTRY;
  target.getNexusGenesisExperienceRuntime = () => ({
    activated: nexusGenesisExperienceActivated,
    tier: nexusGenesisExperiencePerformanceTier(),
    state: nexusCoreRuntimeState.current,
    ownership: NEXUS_GENESIS_EXPERIENCE_OWNERSHIP_REGISTRY
  });
}

function updateNexusGenesisExperienceDom() {
  if (typeof document === "undefined") return;
  const tier = nexusGenesisExperiencePerformanceTier();
  const mode = nexusTrueExperienceMode();
  if (document.body) {
    document.body.dataset.nexusGenesisMode = mode;
    document.body.dataset.nexusGenesisActivated = nexusGenesisExperienceActivated ? "true" : "false";
  }
  document.querySelectorAll("[data-nexus-genesis-engine-root]").forEach(root => {
    root.dataset.nexusGenesisPerformanceTier = tier;
    root.dataset.nexusGenesisActivated = nexusGenesisExperienceActivated ? "true" : "false";
    root.dataset.nexusGenesisCoreState = normalizeNexusCoreState(nexusCoreRuntimeState.current || "idle");
  });
}

function startNexusGenesisExperienceEngine() {
  if (typeof window === "undefined" || nexusGenesisExperienceAnimationFrame) return;
  exposeNexusGenesisExperienceRuntime();
  nexusGenesisExperienceStartedAt = Date.now();
  const tick = () => {
    nexusGenesisExperienceAnimationFrame = 0;
    updateNexusGenesisExperienceDom();
    const root = document.querySelector("[data-nexus-genesis-engine-root]");
    if (!root || document.hidden || nexusGenesisExperiencePerformanceTier() === "reduced-motion") return;
    const elapsed = Math.min(3600, Date.now() - nexusGenesisExperienceStartedAt);
    root.style.setProperty("--nexus-genesis-time", String(Math.round(elapsed / 40)));
    nexusGenesisExperienceAnimationFrame = window.requestAnimationFrame(tick);
  };
  nexusGenesisExperienceAnimationFrame = window.requestAnimationFrame(tick);
  document.addEventListener("visibilitychange", () => {
    if (document.hidden && nexusGenesisExperienceAnimationFrame) {
      window.cancelAnimationFrame(nexusGenesisExperienceAnimationFrame);
      nexusGenesisExperienceAnimationFrame = 0;
      return;
    }
    if (!document.hidden) startNexusGenesisExperienceEngine();
  }, { passive: true });
}

function nexusTrustChainOrbStateFor(state = nexusGenesisTrustChainState.state) {
  if (state === "listening" || state === "speech_detected") return "listening";
  if (state === "transcript_finalized" || state === "conversation_submitted" || state === "response_pending" || state === "speech_preparing") return "processing";
  if (state === "speaking") return "speaking";
  if (state === "waiting" || state === "response_ready") return "waiting";
  if (NEXUS_GENESIS_TRUST_CHAIN_FAILURE_STATES.includes(state)) return "error";
  if (state === "wake_requested" || state === "voice_permission_pending") return "wake";
  return "idle";
}

function setNexusGenesisTrustChainState(state = "idle", details = {}) {
  const normalized = NEXUS_GENESIS_TRUST_CHAIN_STATES.includes(state) ? state : "response_failed";
  const visibleFeedback = String(details.visibleFeedback || details.statusText || nexusGenesisTrustChainState.visibleFeedback || "Nexus is ready.").trim();
  const screenReaderFeedback = String(details.screenReaderFeedback || visibleFeedback).trim();
  nexusGenesisTrustChainState = {
    ...nexusGenesisTrustChainState,
    state: normalized,
    orbState: nexusTrustChainOrbStateFor(normalized),
    visibleFeedback,
    screenReaderFeedback,
    lastTranscript: details.transcript ?? nexusGenesisTrustChainState.lastTranscript,
    lastResponse: details.response ?? nexusGenesisTrustChainState.lastResponse,
    failureRecovery: details.failureRecovery || "",
    textFallbackRequired: details.textFallbackRequired !== false,
    updatedAt: new Date().toISOString()
  };
  updateNexusOsVoiceRuntimeState({
    trustChainState: normalized,
    trustChainOrbState: nexusGenesisTrustChainState.orbState,
    captionText: visibleFeedback,
    assistantSpeaking: normalized === "speaking"
  }, details.reason || `trust-chain-${normalized}`);
  syncNexusPresenceSurfaces(nexusGenesisTrustChainState.orbState, {
    source: "nexus-genesis-trust-chain",
    captionText: visibleFeedback,
    assistantSpeaking: normalized === "speaking"
  });
  const firstImpression = document.querySelector("[data-nexus-first-impression-status]");
  if (firstImpression) firstImpression.textContent = translateText(screenReaderFeedback);
  return nexusGenesisTrustChainState;
}

function isNexusConversationOnlyTrustChainInput(command = "") {
  const text = normalizeToolText(command);
  if (!text) return true;
  return /\b(hello|hi|hey nexus|hello nexus|can you hear me|do you hear me|are you there|how are you|what can you do|show me nexus modes|tell me something interesting|explain ai|repeat that|speak more slowly|speak slower|use text only|text only|stop speaking|i can't hear you|i cant hear you|i can t hear you|still can't hear you|still cant hear you|still can t hear you|why aren't you speaking|why arent you speaking|why aren t you speaking|turn on voice|talk to me|is my microphone working|is my mic working)\b/.test(text)
    && !/\b(sell|record|track|find work|apply|blood pressure|bp|shipment|maize|crop issue|telehealth|pharmacy|marketplace|route|dispatch|pay|book|schedule|call|message|whatsapp|sms)\b/.test(text);
}

function nexusConversationOnlyTrustChainResponse(command = "") {
  const text = normalizeToolText(command);
  if (!text) return "I am here. You can speak or type what you need.";
  const voiceConcern = nexusVoiceTroubleshootingResponse(command, { source: "voice" });
  if (voiceConcern) return voiceConcern;
  if (/\b(hello|hi|hey nexus|hello nexus)\b/.test(text)) return "Hello. I am listening. What do you need help with today?";
  if (/\b(what can you do|show me nexus modes)\b/.test(text)) return "I can help with agriculture, health preparation, learning, jobs, marketplace review, maps, messages, reminders, language, offline support, and safe provider preparation. Tell me what you want to do next.";
  if (/\b(explain ai)\b/.test(text)) return "AI is software that can recognize patterns, answer questions, and help organize tasks. I will keep actions gated and ask before anything important happens.";
  if (/\b(tell me something interesting)\b/.test(text)) return "Here is something interesting: small improvements in irrigation timing, soil care, and storage can often protect more value than a bigger harvest alone.";
  if (/\b(repeat that)\b/.test(text)) return lastVoiceResponse || "I am ready. Tell me what you need.";
  if (/\b(speak more slowly|speak slower)\b/.test(text)) return "I will speak more slowly. You can keep talking naturally.";
  if (/\b(use text only|text only|stop speaking)\b/.test(text)) return "Okay. I will continue in text.";
  return "I heard you. Tell me a little more so I can help the right way.";
}

function isNexusVoiceTroubleshootingCommand(command = "") {
  const text = normalizeToolText(command);
  if (!text) return false;
  return /\b(can you hear me|do you hear me|can nexus hear me|are you listening|are you hearing me|you hear me|you listening|i can't hear you|i cant hear you|i can t hear you|can't hear you|cant hear you|can t hear you|still can't hear you|still cant hear you|still can t hear you|why aren't you speaking|why arent you speaking|why aren t you speaking|why are you not speaking|turn on voice|nexus talk to me|talk to me|speak to me|is my microphone working|is my mic working|microphone working|mic working|speech not working|voice not working|sound not working|audio not working)\b/.test(text)
    || /\b(me escuchas|me oyes|puedes oirme|puedes escucharme|no te escucho|microfono funciona)\b/.test(text)
    || /\b(tu m entends|vous m entendez|je ne t entends pas|tu ecoutes|micro fonctionne)\b/.test(text)
    || /\b(unanisikia|unasikia|sikuskii|siskii sauti|mic inafanya kazi|kipaza sauti kinafanya kazi)\b/.test(text)
    || /(?:\u0647\u0644 \u062a\u0633\u0645\u0639\u0646\u064a|\u062a\u0633\u0645\u0639\u0646\u064a|\u0644\u0627 \u0627\u0633\u0645\u0639\u0643|\u0627\u0644\u0635\u0648\u062a \u0644\u0627 \u064a\u0639\u0645\u0644|\u0627\u0644\u0645\u064a\u0643\u0631\u0648\u0641\u0648\u0646 \u064a\u0639\u0645\u0644)/.test(command);
}

function nexusVoiceTroubleshootingState() {
  const profile = typeof window !== "undefined" ? browserVoiceRuntimeProfile() : { supported: false, secureEnough: false, browserName: "this browser" };
  const recognitionActive = Boolean(voiceRecognition || genesisVoiceConversationActive?.());
  const synthesisSupported = typeof window !== "undefined" && Boolean(window.speechSynthesis || activeVoiceAudio || browserSpeechFallbackEnabled?.());
  const quiet = Boolean(voiceDemoQuietMode || nexusOsConversationMuted);
  const permissionState = normalizeNexusMicrophonePermissionState(nexusOsVoiceRuntimeState.permissionState || "unknown");
  const listeningState = recognitionActive
    ? "Voice ready"
    : !profile.secureEnough
      ? "Voice unavailable in this browser"
      : profile.supported
        ? "Microphone permission required"
        : "Speech recognition unavailable";
  const outputState = quiet
    ? "Speech output muted"
    : synthesisSupported
      ? "Speech output available"
      : "Speech output unavailable";
  return {
    profile,
    recognitionActive,
    synthesisSupported,
    quiet,
    permissionState,
    listeningState,
    outputState,
    typedFallback: "Workflow forms available after Nexus opens them"
  };
}

function nexusVoiceTroubleshootingResponse(command = "", options = {}) {
  if (!isNexusVoiceTroubleshootingCommand(command)) return "";
  const source = String(options.source || "").toLowerCase();
  const state = nexusVoiceTroubleshootingState();
  const text = normalizeToolText(command);
  const usedTypedInput = source.includes("typed") || source.includes("command-send") || source.includes("chat");
  if (/\b(i can't hear you|i cant hear you|i can t hear you|can't hear you|cant hear you|can t hear you|still can't hear you|still cant hear you|still can t hear you|why aren't you speaking|why arent you speaking|why aren t you speaking|why are you not speaking|sound not working|audio not working|voice not working)\b/.test(text)) {
    if (state.quiet) return "I can respond, but voice is muted right now. Reload Genesis after audio is available.";
    if (!state.synthesisSupported) return "I can respond, but I cannot speak aloud in this browser right now. Try a supported browser with audio enabled.";
    return "I received your message. If you cannot hear me, check browser audio, then reload Genesis.";
  }
  if (/\b(turn on voice|talk to me|speak to me|nexus talk to me)\b/.test(text)) {
    if (!state.profile.secureEnough) return "Voice needs a secure browser page before Genesis can listen.";
    if (!state.profile.supported) return "Voice listening is not available in this browser right now. Try Chrome or Edge for microphone support.";
    return "Genesis starts voice automatically. Allow the browser microphone prompt if it appears.";
  }
  if (/\b(is my microphone working|is my mic working|microphone working|mic working|can you hear me|do you hear me|are you listening|are you hearing me|you hear me|you listening)\b/.test(text)) {
    if (state.recognitionActive) return "Yes. Recognition is active and Nexus is listening now.";
    if (nexusVoiceLastFinalTranscriptAt) return "I received a voice transcript earlier, but recognition is not actively listening right now. Reload Genesis to restart the automatic voice session.";
    if (usedTypedInput) return "I received this as on-screen text. Microphone recognition is not active right now, so I will not claim I can hear audio until recognition starts.";
    if (state.profile.supported) return "Microphone permission may be available, but recognition is not actively listening now. Reload Genesis to restart the automatic voice session.";
    return "I received your message on screen. Microphone speech recognition is unavailable in this browser.";
  }
  return "I received your message. Voice status is visible here, and Genesis keeps the home screen audio-first until a workflow opens.";
}

function handleNexusVoiceTroubleshootingCommand(command = "", options = {}) {
  const response = nexusVoiceTroubleshootingResponse(command, options);
  if (!response) return false;
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  const state = nexusVoiceTroubleshootingState();
  recordNexusOsConversationTurn("assistant", response, { source: options.source || "nexus-voice-troubleshooting" });
  setNexusGenesisTrustChainState(state.recognitionActive ? "response_ready" : "recognition_unavailable", {
    transcript: command,
    response,
    visibleFeedback: response,
    failureRecovery: "Reload Genesis after browser microphone access is available, or return Home.",
    reason: "voice-troubleshooting"
  });
  updateNexusOsVoiceRuntimeState({
    mode: state.recognitionActive ? "listening" : state.quiet ? "muted" : "typed-fallback",
    listeningState: state.recognitionActive ? "active" : "typed",
    permissionState: state.permissionState,
    microphoneUnavailable: !state.profile.supported,
    assistantSpeaking: false,
    captionText: response
  }, options.source || "nexus-voice-troubleshooting");
  setNexusPresenceState(NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP, {
    lastUserInput: command,
    lastResponse: response,
    nextQuestion: "Reload Genesis after browser microphone access is available, or return Home.",
    source: options.source || "nexus-voice-troubleshooting"
  });
  renderLiveVoiceSuggestions(["Reload Genesis", "Return Home"]);
  setVoiceResponse(response, false, { allowHandoff: false, allowVoiceFirst: false, command, source: options.source || "nexus-voice-troubleshooting" });
  return true;
}

function saveNexusDailyCompanionState(patch = {}) {
  nexusDailyCompanionState = {
    ...nexusDailyCompanionState,
    ...patch,
    schemaVersion: "nexus-daily-companion.v1",
    approvedMemoryOnly: true,
    updatedAt: new Date().toISOString()
  };
  try {
    localStorage.setItem("nexusDailyCompanionState", JSON.stringify(nexusDailyCompanionState));
  } catch {
    // Companion continuity remains session-safe if storage is unavailable.
  }
  return nexusDailyCompanionState;
}

function nexusDailyCompanionIntent(command = "") {
  const text = normalizeToolText(command);
  if (!text) return null;
  const activeTopic = nexusDailyCompanionState.activeMissionTopic || nexusDailyCompanionState.pausedMissionTopic || "";
  if (/\b(good morning|good afternoon|good evening|hello|hi|hey nexus)\b/.test(text)) {
    return { type: "conversation", topic: "greeting", response: "Good morning. I am here with you. What would you like to focus on today?" };
  }
  if (/\b(can you hear me|do you hear me|are you there)\b/.test(text)) {
    return { type: "conversation", topic: "hearing-check", response: nexusVoiceTroubleshootingResponse(command, { source: "daily-companion" }) || "I received your message. What are we working on today?" };
  }
  if (isNexusVoiceTroubleshootingCommand(command)) {
    return { type: "conversation", topic: "voice-support", response: nexusVoiceTroubleshootingResponse(command, { source: "daily-companion" }) || "Voice status is visible here, and typed conversation remains available." };
  }
  if (/\b(hard day|feeling lonely|i feel lonely|lonely today|sad today|rough day)\b/.test(text)) {
    return { type: "conversation", topic: "support", response: "I am glad you reached out. Would you like to talk for a while, or is there something specific you would like help with?" };
  }
  if (/\b(explain ai|new to it|explain this to me|i don't understand|i dont understand|didn't understand|didnt understand)\b/.test(text)) {
    return { type: "conversation", topic: "teaching", response: "Of course. I can explain it in plain steps. AI is software that can notice patterns, answer questions, and help organize tasks, but important actions still need your approval." };
  }
  if (/\b(what should i work on first|what should i focus on today|focus on today)\b/.test(text)) {
    return { type: "conversation", topic: "decision-support", response: "Let us choose one useful next step. We can focus on health, farm work, learning, jobs, messages, or something personal you want to handle today." };
  }
  if (/\b(tell me something interesting)\b/.test(text)) {
    return { type: "conversation", topic: "curiosity", response: "Here is something interesting: in farming and health, the best results often come from small habits repeated consistently, not one big change." };
  }
  if (/\b(repeat that|read that again)\b/.test(text)) {
    return { type: "conversation", topic: "repeat", response: lastVoiceResponse || "I am here and ready. Tell me what you need." };
  }
  if (/\b(talk more slowly|speak more slowly|repeat that more slowly)\b/.test(text)) {
    setTemporaryNexusVoicePreference({ speechRatePreset: "slow" }, "slower speech pace");
    return { type: "conversation", topic: "voice-preference", response: "I will slow down. I can repeat things as many times as you need." };
  }
  if (/\b(remember that i prefer short answers|prefer short answers|keep answers short)\b/.test(text)) {
    setTemporaryNexusVoicePreference({ answerLength: "concise" }, "short answer preference");
    return { type: "conversation", topic: "memory-consent", response: "I can use short answers for now. If you want me to remember that preference, just say yes when I ask." };
  }
  if (/\b(forget that preference|forget my preference|clear that preference)\b/.test(text)) {
    forgetNexusVoicePreferences();
    return { type: "conversation", topic: "memory-clear", response: "Okay. I cleared that voice preference. You can set it again anytime." };
  }
  if (/\b(what were we discussing earlier|what were we talking about|go back to what we were discussing)\b/.test(text)) {
    const topic = activeTopic || nexusDailyCompanionState.lastTopic || "your last request";
    return { type: "conversation", topic: "continuity", response: `We were discussing ${topic}. Would you like to continue there or switch to something else?` };
  }
  if (/\b(help me sell maize|help me sell my maize|buyer for maize|sell maize)\b/.test(text)) {
    saveNexusDailyCompanionState({ mode: "mission", activeMissionTopic: "maize buyer support", lastTopic: "maize buyer support", lastUserNeed: command });
    return { type: "mission-context", topic: "maize buyer support", response: "I can help with that. What type of maize are you selling, how much do you have, and where is it located? I will not contact a buyer or create a transaction without your confirmation." };
  }
  if (/\b(weather tomorrow|weather outside|what is the weather)\b/.test(text)) {
    const returnPrompt = activeTopic ? ` After that, would you like to return to ${activeTopic}?` : "";
    return { type: "conversation", topic: "weather", response: `I can help with weather when a live weather source is configured. I will not guess live conditions. Tell me the location, and I can check the connected source or explain what configuration is missing.${returnPrompt}` };
  }
  if (/\b(let'?s go back to the maize|go back to maize|return to maize|back to maize)\b/.test(text)) {
    saveNexusDailyCompanionState({ mode: "mission", activeMissionTopic: "maize buyer support", pausedMissionTopic: "" });
    return { type: "mission-context", topic: "maize buyer support", response: "Back to the maize. Tell me the quantity, location, and whether you already have a buyer in mind." };
  }
  if (/\b(pause this until later|pause this|save this for later)\b/.test(text)) {
    const topic = activeTopic || "this conversation";
    saveNexusDailyCompanionState({ mode: "companion", activeMissionTopic: "", pausedMissionTopic: topic });
    return { type: "conversation", topic: "pause", response: `Okay. I paused ${topic}. When you are ready, say let us go back, and I will help you continue.` };
  }
  if (/\b(call my daughter|call my son|call my wife|call my husband|call my family|call my caregiver)\b/.test(text)) {
    return { type: "conversation", topic: "contact-prep", response: "I can help you prepare that call, but a phone provider is not connected unless it is configured and you confirm. I can help you write what to say or show the contact details instead." };
  }
  if (/\b(can't remember whether i took my medication|cant remember whether i took my medication|did i take my medication|missed my medication|forgot my medicine)\b/.test(text)) {
    return { type: "conversation", topic: "medication-safety", response: "That can feel worrying. I cannot tell you to take or skip medicine, but I can help you check your routine, write down what you remember, and prepare a question for a pharmacist or clinician. If you feel very unwell, seek local urgent help." };
  }
  if (/\b(i need help|help me)\b/.test(text) && !/\b(sell|maize|crop|buyer|doctor|clinic|emergency|pay|call|message|location)\b/.test(text)) {
    return { type: "conversation", topic: "clarification", response: "I am here. Tell me a little more about what kind of help you need, and I will take it one step at a time." };
  }
  return null;
}

function handleNexusDailyCompanionCommand(command = "", options = {}) {
  const intent = nexusDailyCompanionIntent(command);
  if (!intent) return false;
  saveNexusDailyCompanionState({
    mode: intent.type === "mission-context" ? "mission" : nexusDailyCompanionState.mode || "companion",
    lastTopic: intent.topic || nexusDailyCompanionState.lastTopic,
    lastUserNeed: command
  });
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  openAskNexus();
  enableHeyAgriNexusMode();
  setNexusGenesisTrustChainState("response_ready", {
    transcript: command,
    response: intent.response,
    visibleFeedback: intent.response,
    reason: "daily-companion-response"
  });
  setVoiceResponse(intent.response, options.speak !== false, {
    allowHandoff: false,
    command,
    source: options.source || "nexus-daily-companion",
    turnToken: options.turnToken
  });
  return true;
}

async function activateNexusGenesisExperience(source = "voice") {
  nexusGenesisExperienceActivated = true;
  nexusTrueExperienceSessionStarted = true;
  setNexusGenesisTrustChainState("waiting", { visibleFeedback: "Nexus is ready.", reason: `genesis-${source}` });
  setNexusCoreState("waiting", { source: `genesis-${source}`, statusText: "Nexus is ready." });
  renderUserWorkspace();
  updateNexusGenesisExperienceDom();
  requestAnimationFrame(() => {
    $("#nexusCommandCenterInput")?.focus?.();
    setNexusCoreState("waiting", { source: `genesis-${source}`, statusText: "Nexus is ready for your request." });
  });
  return true;
}

function resetNexusGenesisHomeViewport() {
  if (typeof window === "undefined") return;
  requestAnimationFrame(() => {
    const home = document.querySelector("[data-nexus-genesis-orb-only-home]");
    if (!home) return;
    window.scrollTo?.({ top: 0, left: 0, behavior: "instant" });
  });
}

function nexusTrueExperienceHasActiveWorkflow() {
  if (!nexusTrueExperienceSessionStarted) return false;
  if (!nexusTrueExperienceHasCurrentWorkflowState()) return false;
  return Boolean(
    nexusActiveWorkflowState?.id
    || nexusActiveWorkflowState?.functionId
    || nexusActiveWorkflowState?.agenticMission
    || nexusIntentDrivenWorkflowLastRoute?.recommendedWorkflow
    || nexusAgenticCommandMissions?.length
  );
}

function nexusTrueExperienceEpoch(value) {
  const numeric = Number(value || 0);
  if (Number.isFinite(numeric) && numeric > 0) return numeric;
  const parsed = Date.parse(String(value || ""));
  return Number.isFinite(parsed) ? parsed : 0;
}

function nexusTrueExperienceHasCurrentWorkflowState() {
  const workflowTimes = [
    nexusActiveWorkflowState?.openedAt,
    nexusActiveWorkflowState?.startedAt,
    nexusActiveWorkflowState?.createdAt,
    nexusActiveWorkflowState?.timestamp,
    nexusIntentDrivenWorkflowLastRoute?.openedAt,
    nexusIntentDrivenWorkflowLastRoute?.startedAt,
    nexusIntentDrivenWorkflowLastRoute?.createdAt,
    nexusIntentDrivenWorkflowLastRoute?.timestamp,
    ...(Array.isArray(nexusAgenticCommandMissions) ? nexusAgenticCommandMissions.flatMap(mission => [
      mission?.openedAt,
      mission?.startedAt,
      mission?.createdAt,
      mission?.timestamp,
      mission?.updatedAt
    ]) : [])
  ].map(nexusTrueExperienceEpoch);
  return workflowTimes.some(epoch => epoch >= NEXUS_TRUE_EXPERIENCE_LOAD_EPOCH);
}

function clearNexusTrueExperienceStaleWorkflowState() {
  if (nexusTrueExperienceHasCurrentWorkflowState()) return;
  nexusActiveWorkflowState = { id: "", command: "", source: "true-experience-stale-reset", workflow: "", action: "", openedAt: 0 };
  nexusIntentDrivenWorkflowLastRoute = null;
  nexusAgenticCommandMissions = [];
}

function nexusTrueExperienceHasCurrentConversation() {
  if (nexusGenesisExperienceActivated || nexusTrueExperienceSessionStarted) return true;
  const minimumEpoch = Math.max(NEXUS_TRUE_EXPERIENCE_LOAD_EPOCH, nexusTrueExperienceHomeResetEpoch);
  return nexusOsConversationTurns.some(turn => turn.role === "user" && Number(turn.epoch || 0) >= minimumEpoch);
}

function nexusTrueExperienceMode() {
  if (nexusTrueExperienceHasActiveWorkflow()) return "mission";
  if (nexusTrueExperienceHasCurrentConversation()) return "conversation";
  return "home";
}

function isNexusTrueExperienceReturnHomeCommand(command = "") {
  const normalized = String(command || "").toLowerCase().replace(/[.!?]+$/g, "").trim();
  return /^(home|go home|return home|back home|take me home|nexus home|open nexus home|main screen)$/.test(normalized);
}

function nexusCoreStateClass(state = "idle") {
  const normalized = normalizeNexusCoreState(state);
  return `nexus-core-state-${escapeHtml(normalized)}`;
}

