function handleNexusPrimaryVoiceButtonClick(event) {
  event?.preventDefault?.();
  event?.stopPropagation?.();
  event?.stopImmediatePropagation?.();
  void handleNexusOsVoiceControlAction("toggle-listening", { source: "nexus-primary-visible-voice-button" });
  return false;
}

function bindNexusPrimaryVoiceControls() {
  if (typeof document === "undefined") return;
  document.querySelectorAll("[data-nexus-command-center-voice],[data-nexus-os-voice-control]").forEach(control => {
    if (control.dataset.nexusPrimaryVoiceControlBound === "true") return;
    control.dataset.nexusPrimaryVoiceControlBound = "true";
    control.addEventListener("click", event => {
      event.preventDefault();
      event.stopPropagation();
      event.stopImmediatePropagation?.();
      const action = control.dataset.nexusOsVoiceControl || "toggle-listening";
      void handleNexusOsVoiceControlAction(action, { source: "bound-visible-voice-control" });
    }, true);
  });
}

function renderNexusBrowserVoiceAvailabilityHint() {
  if (typeof window === "undefined") return "";
  const profile = browserVoiceRuntimeProfile();
  const realtimeMicAvailable = typeof realtimeMicrophoneUiAvailable === "function" && realtimeMicrophoneUiAvailable();
  const message = realtimeMicAvailable
    ? "Voice uses the secure browser microphone with OpenAI Realtime. Workflow fields appear only after Nexus opens a workflow."
    : profile.supported
      ? "Voice uses browser support. Workflow forms may ask for exact details after Nexus opens them."
      : "Enable microphone from a secure browser page. If permission is blocked, change site settings and reload Genesis.";
  return `
    <p class="nexus-browser-voice-fallback" data-nexus-browser-voice-fallback="true" data-browser-voice-supported="${profile.supported || realtimeMicAvailable ? "true" : "false"}" role="status">
      ${escapeHtml(translateText(message))}
    </p>
  `;
}

function renderNexusVoiceFirstPresenceControls() {
  const profile = typeof window !== "undefined" ? browserVoiceRuntimeProfile() : { supported: false };
  const permissionState = nexusOsVoiceRuntimeState.permissionState || "unknown";
  const recognitionActive = Boolean(voiceRecognition || genesisVoiceConversationActive?.());
  const realtimeMicAvailable = typeof realtimeMicrophoneUiAvailable === "function" && realtimeMicrophoneUiAvailable();
  const voiceReady = Boolean((profile.supported || realtimeMicAvailable) && profile.secureEnough !== false);
  const enableLabel = recognitionActive
    ? "Stop listening"
    : permissionState === "denied" || nexusVoicePermissionDeniedThisSession
      ? "Mic blocked"
      : nexusMicrophonePermissionCanAttemptStart(permissionState) || realtimeMicAvailable
      ? "Start listening"
      : "Enable voice";
  const enableAction = recognitionActive ? "stop-listening" : "enable-voice";
  const help = permissionState === "denied" || nexusVoicePermissionDeniedThisSession
    ? "Microphone permission is blocked. Change microphone permission in your browser to speak with Nexus."
    : voiceReady
      ? "Enable microphone access to start the Realtime conversation. Provider errors will not remove this control."
      : "Use a secure browser page with microphone access for the Genesis voice front door.";
  const statusText = recognitionActive
    ? "Nexus is listening."
    : voiceFirstMode
      ? "Hands-free Nexus is on while this page stays open."
      : voiceReady
        ? "Microphone control is ready."
        : "Enable microphone from a secure browser page.";
  return `
    <div class="nexus-voice-first-presence" data-nexus-voice-first-presence="true" data-nexus-hands-free-active="${voiceFirstMode ? "true" : "false"}" data-nexus-microphone-permission="${escapeHtml(permissionState)}">
      <span class="nexus-voice-first-status" data-nexus-voice-first-status="true" aria-live="polite">${escapeHtml(translateText(statusText))}</span>
      <small>${escapeHtml(translateText(help))}</small>
      <div class="nexus-voice-first-actions" aria-label="${escapeHtml(translateText("Nexus voice controls"))}">
        <button type="button" data-nexus-os-voice-control="${escapeHtml(enableAction)}" ${voiceReady || recognitionActive ? "" : "disabled"}>${escapeHtml(translateText(enableLabel))}</button>
        <button type="button" data-nexus-os-voice-control="toggle-hands-free" aria-pressed="${voiceFirstMode ? "true" : "false"}" ${voiceReady ? "" : "disabled"}>${escapeHtml(translateText("Hands-free Nexus"))}</button>
        <button type="button" data-nexus-os-voice-control="stop-listening">${escapeHtml(translateText("Stop listening"))}</button>
        <button type="button" data-nexus-os-voice-control="stop-speaking">${escapeHtml(translateText("Stop speaking"))}</button>
        <button type="button" data-nexus-os-voice-control="repeat-response">${escapeHtml(translateText("Repeat"))}</button>
        <button type="button" data-nexus-os-voice-control="${nexusOsConversationMuted ? "unmute" : "mute"}">${escapeHtml(translateText(nexusOsConversationMuted ? "Unmute" : "Mute"))}</button>
      </div>
    </div>
  `;
}

function nexusGenesisVoiceDebugEnabled() {
  return /(?:[?&])voiceDebug=1(?:&|$)/i.test(window.location.search || "");
}

function nexusGenesisTruthfulVoiceState() {
  const profile = typeof window !== "undefined" ? browserVoiceRuntimeProfile() : { supported: false, secureEnough: false };
  const state = nexusOsVoiceRuntimeState || {};
  const permissionState = normalizeNexusMicrophonePermissionState(state.permissionState || "unknown");
  const realtimeMicAvailable = typeof realtimeMicrophoneUiAvailable === "function" && realtimeMicrophoneUiAvailable();
  const recognitionSupported = Boolean((profile.supported || realtimeMicAvailable) && profile.secureEnough !== false);
  const activeTrack = Boolean(state.microphoneStreamActive && state.microphoneTrackState !== "stopped");
  const constructed = Boolean(state.recognitionConstructed);
  const startRequested = Boolean(state.recognitionStartRequested);
  const onstart = Boolean(state.recognitionOnStartReceived);
  const audioStart = Boolean(state.recognitionAudioStartReceived);
  const soundStart = Boolean(state.recognitionSoundStartReceived);
  const speechStart = Boolean(state.recognitionSpeechStartReceived);
  const resultReceived = Boolean(state.recognitionResultReceived);
  const finalTranscript = Boolean(state.recognitionFinalTranscriptReceived);
  const commandRequest = Boolean(state.commandRequestStarted);
  const commandResponse = Boolean(state.commandResponseReceived);
  const utteranceRequested = Boolean(state.utteranceRequested);
  const utteranceOnStart = Boolean(state.utteranceOnStartReceived);
  const utteranceOnEnd = Boolean(state.utteranceOnEndReceived);
  const utteranceError = state.utteranceError || state.speechErrorCode || "";
  const errorState = Boolean(state.lastError || state.lastRuntimeError || state.utteranceError || state.mode === "recognition-interrupted" || state.mode === "caption-fallback");
  let statusText = "Microphone permission is required before Nexus can hear.";
  if (!recognitionSupported) statusText = "Nexus cannot access the microphone from this page.";
  else if (permissionState === "denied" || nexusVoicePermissionDeniedThisSession) statusText = "Microphone permission is blocked.";
  else if (errorState && state.mode === "caption-fallback") statusText = "Nexus generated a response, but audio playback did not start.";
  else if (errorState) statusText = "Nexus could not start voice recognition.";
  else if (utteranceOnStart && !utteranceOnEnd) statusText = "Nexus is speaking.";
  else if (commandResponse) statusText = "Nexus generated a response.";
  else if (commandRequest) statusText = "Nexus is processing your request.";
  else if (finalTranscript) statusText = "Nexus received your transcript.";
  else if (resultReceived) statusText = "Nexus received speech results.";
  else if (speechStart) statusText = "Nexus detected speech.";
  else if (soundStart || audioStart) statusText = "Nexus detected microphone audio.";
  else if (onstart) statusText = "Nexus is listening.";
  else if (startRequested) statusText = "Microphone permission granted. Speech recognition has not started.";
  else if (constructed) statusText = "Microphone permission granted. Speech recognition has not started.";
  else if (activeTrack || permissionState === "granted" || permissionState === "browser-managed") statusText = "Microphone permission granted. Speech recognition has not started.";
  else if (permissionState === "prompt" || permissionState === "unknown") statusText = "Nexus is preparing voice.";
  return {
    profile,
    permissionState,
    recognitionSupported,
    activeTrack,
    constructed,
    startRequested,
    onstart,
    audioStart,
    soundStart,
    speechStart,
    resultReceived,
    finalTranscript,
    commandRequest,
    commandResponse,
    utteranceRequested,
    utteranceOnStart,
    utteranceOnEnd,
    utteranceError,
    voiceCount: typeof speechSynthesis !== "undefined" && speechSynthesis.getVoices ? speechSynthesis.getVoices().length : 0,
    statusText
  };
}

