function userModulePreviewHtml(sectionId) {
  if (sectionId === "trade") {
    const latestOrder = data.profile.orders?.[data.profile.orders.length - 1];
    const product = latestOrder
      ? (data.products || []).find(item => item.id === latestOrder.productId) || firstProduct()
      : firstProduct();
    return `
      <div class="user-module-preview user-trade-preview">
        ${userServicePhotoHtml("trade", "Sell crops")}
        ${userRealMapHtml(latestOrder ? "Your shipment map" : "Crop market map")}
        <div class="user-preview-summary">
          <strong>${translateText(latestOrder ? "Shipment status" : "Ready to sell")}</strong>
          <span>${translateText(latestOrder ? `${latestOrder.product || product?.name || "Crop"} is at ${latestOrder.checkpoint || data.profile.activeCheckpoint}.` : `Start with ${product?.name || "your crop"}, then choose buyer, order, route, or farm scan.`)}</span>
          ${userPreviewActionsHtml([
            { label: latestOrder ? "Track Route" : "Create Order", command: latestOrder ? "track my route" : "create a crop order" },
            { label: "Contact Buyer", command: "contact my buyer" },
            { label: "Scan Farm", command: "run drone scan" }
          ])}
        </div>
      </div>
    `;
  }
  if (sectionId === "map") {
    return `
      <div class="user-module-preview user-map-readiness-preview">
        ${userMapProviderReadinessHtml()}
        ${userSafeRoutePlanningPreviewHtml()}
        ${userMapPreviewHtml()}
      </div>
    `;
  }
  if (sectionId === "learning") {
    return `
      <div class="user-module-preview user-learning-preview user-choice-preview">
        ${userServicePhotoHtml("learning", "Learning")}
        ${learningCourseChoicesHtml()}
      </div>
    `;
  }
  if (sectionId === "workforce") {
    return `
      <div class="user-module-preview user-workforce-preview user-choice-preview">
        ${userServicePhotoHtml("workforce", "Find work")}
        ${workforceJobChoicesHtml()}
      </div>
    `;
  }
  if (sectionId === "health") {
    const country = activeCountry();
    const intake = (data.profile.healthIntakes || [])[0];
    const provider = (data.profile.telehealthProviderAssignments || [])[0];
    return `
      <div class="user-module-preview user-health-preview">
        ${userServicePhotoHtml("health", "Health support")}
        ${userHealthRegionalMapHtml("Regional health risk")}
        <div class="provider-contact-card">
          <strong>${translateText(provider?.providerName || "Telehealth provider desk")}</strong>
          <span>${translateText(intake ? `Case ${intake.patientRef}: ${intake.needSummary || "care support needed"}` : "Start intake first, then Nexus prepares provider contact.")}</span>
          <div>
            <button type="button" data-simple-command="talk to provider">${translateText("Speak")}</button>
            <button type="button" data-simple-command="call provider">${translateText("Call")}</button>
            <button type="button" data-simple-command="message provider">${translateText("Message")}</button>
          </div>
        </div>
        <div class="user-preview-summary">
          <strong>${translateText("Health support")}</strong>
          <span>${translateText(`${country.name} is marked ${country.risk} risk with ${country.queue}. Use Start Intake, Talk to Provider, or Check Region.`)}</span>
          ${userPreviewActionsHtml([
            { label: "Start Intake", command: "start telehealth intake" },
            { label: "Check Region", command: "check health risk in my region" },
            { label: "Accessibility Help", command: "create audio guide and captions" }
          ])}
        </div>
      </div>
    `;
  }
  if (sectionId === "agent") {
    return `<div class="user-module-preview">${userServicePhotoHtml("agent", "Talk to Nexus")}<div class="user-preview-summary"><strong>${translateText("Talk naturally")}</strong><span>${translateText("Ask Nexus what to do, ask it to explain the platform, or ask it to open a service.")}</span>${userPreviewActionsHtml([
      { label: "Ask Question", command: "help me understand the platform" },
      { label: "Plan Mission", command: "create an agent plan" },
      { label: "Read to Me", command: "read the current response" }
    ])}</div></div>`;
  }
  if (sectionId === "profile") {
    return `<div class="user-module-preview">${userServicePhotoHtml("profile", "Your record")}<div class="user-preview-summary"><strong>${translateText("Your record")}</strong><span>${translateText("Review progress, messages, certificates, and saved activity without seeing admin controls.")}</span>${userPreviewActionsHtml([
      { label: "My Progress", command: "summarize my progress" },
      { label: "My Messages", command: "show my messages" },
      { label: "Help Me", command: "help me" }
    ])}</div></div>`;
  }
  return "";
}

function renderUserSimpleActiveSection(sectionId = currentSectionId()) {
  if (experienceMode !== "user" || sectionId === "dashboard") return;
  const config = simpleUserSections[sectionId];
  const target = config ? $(`#${sectionId}`) : null;
  if (!target) return;
  document.body.classList.toggle("user-map-full-open", sectionId === "map");
  target.querySelector(":scope > .user-simple-module")?.remove();
  target.insertAdjacentHTML("afterbegin", `
    <section class="user-simple-module ${sectionId === "learning" || sectionId === "workforce" ? "user-choice-module" : ""}" aria-label="${translateText(config.title)}">
      <div class="user-module-nav">
        <button type="button" class="user-module-back" data-simple-section="dashboard">${translateText("Back")}</button>
        <button type="button" class="user-module-close" data-simple-section="dashboard" aria-label="${translateText("Close")}">${translateText("Close")}</button>
      </div>
      <span class="eyebrow">${translateText("AgriNexus")}</span>
      <h2>${translateText(config.title)}</h2>
      <p>${translateText(config.prompt || "Tap one button.")}</p>
      ${userLanguageQuickSwitchHtml()}
      <div class="user-inline-workflow hidden" role="dialog" aria-live="polite"></div>
      ${userModulePreviewHtml(sectionId)}
      ${sectionId === "learning" || sectionId === "workforce" ? `<span class="user-actions-label">${translateText("More actions")}</span>` : ""}
      <div id="grandmaConfirmPanel" class="grandma-confirm-panel hidden" role="status" aria-live="polite"></div>
      <div class="user-service-buttons user-module-buttons">
        ${config.buttons.map(action => `<button type="button" class="${escapeHtml(config.className)}" data-simple-command="${escapeHtml(action.command)}">
          <strong>${translateText(action.label)}</strong>
        </button>`).join("")}
      </div>
      <div class="user-module-status" role="status">${translateText("Nexus is ready.")}</div>
    </section>
  `);
  if (sectionId === "map" || sectionId === "trade") setTimeout(() => {
    try {
      renderUserRealMap();
    } catch (error) {
      console.error("User map failed to render", error);
      const canvas = $("#userMapCanvas");
      if (canvas) canvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Map could not load yet. The workflow is still ready; refresh the map or continue safely.")}</div>`;
    }
  }, 80);
  if (sectionId === "health") setTimeout(() => {
    try {
      renderUserHealthMap();
    } catch (error) {
      console.error("Health map failed to render", error);
      const canvas = $("#userHealthMapCanvas");
      if (canvas) canvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Health map could not load yet. Clinic, pharmacy, and provider support are still available.")}</div>`;
    }
  }, 80);
}

function renderUserInlineWorkflow(sectionId, config) {
  if (experienceMode !== "user" || !config) return;
  const panel = $(`#${sectionId} .user-inline-workflow`);
  if (!panel) return;
  const coach = workflowRealUseCoach(config);
  panel.classList.remove("hidden");
  panel.innerHTML = `
    <strong>${translateText(config.title || "Ready?")}</strong>
    <span>${translateText(coach.plain || "Do you want Nexus to do this now?")}</span>
    <div class="user-inline-coach">
      <div><strong>${translateText("Answer")}</strong><span>${translateText(coach.question)}</span></div>
      <div><strong>${translateText("Careful")}</strong><span>${translateText(coach.watch)}</span></div>
      <div><strong>${translateText("Try saying")}</strong><span>${translateText(coach.sayNext)}</span></div>
    </div>
    <div class="user-inline-workflow-actions">
      <button type="button" class="primary" data-inline-workflow-confirm>${translateText("Yes")}</button>
      <button type="button" data-inline-workflow-cancel>${translateText("No")}</button>
    </div>
  `;
  panel.scrollIntoView({ behavior: "smooth", block: "center" });
}

function userProcessSteps(config = {}) {
  const mode = workflowMode(config);
  const title = (experienceMode === "user" && config.userTitle) || config.title || "This step";
  const action = config.confirmLabel || "Do this now";
  const next = config.userOutcome || config.success || config.record || "Nexus saves this and shows the next step.";
  if (mode === "learning") {
    return [
      { title: "Choose learning", detail: title },
      { title: "Nexus helps", detail: "Captions, audio, progress, and certificate evidence stay connected." },
      { title: "Save progress", detail: next }
    ];
  }
  if (mode === "workforce") {
    return [
      { title: "Choose job step", detail: title },
      { title: "Check readiness", detail: "Nexus reviews skills, certificates, role fit, and next action." },
      { title: "Move forward", detail: next }
    ];
  }
  if (mode === "health") {
    return [
      { title: "Share care need", detail: title },
      { title: "Prepare support", detail: "Nexus organizes intake, access needs, provider contact, and safety notes." },
      { title: "Connect to help", detail: next }
    ];
  }
  if (mode === "trade" || mode === "map") {
    return [
      { title: "Choose farm task", detail: title },
      { title: "Check route or crop", detail: "Nexus connects buyer, crop, route, drone, and location information." },
      { title: "Track result", detail: next }
    ];
  }
  return [
    { title: "Tell Nexus", detail: title },
    { title: "Nexus reasons", detail: "The assistant prepares the safest next step in plain language." },
    { title: "Continue", detail: action }
  ];
}

function isHealthIntakeWorkflow(config = {}) {
  return workflowMode(config) === "health" && (config.body?.type === "intake" || /intake/i.test(`${config.title || ""} ${config.userTitle || ""}`));
}

function isHealthProviderWorkflow(config = {}) {
  return workflowMode(config) === "health" && (config.body?.type === "provider" || /provider|doctor|nurse|clinician|care team/i.test(`${config.title || ""} ${config.userTitle || ""} ${config.summary || ""}`));
}

function guidedHealthIntakeSteps() {
  return [
    { field: "patientName", title: "Step 1: Who needs care?", say: "Say: patient name is Ron, or type the name." },
    { field: "needSummary", title: "Step 2: What is happening?", say: "Say: I need medicine, I have pain, or I need a clinic." },
    { field: "urgency", title: "Step 3: How serious is it?", say: "Say: routine, priority, high, or emergency." },
    { field: "preferredLanguage", title: "Step 4: What language should we use?", say: "Say: English, French, Kiswahili, Arabic, Spanish, or Portuguese." },
    { field: "contactMethod", title: "Step 5: How should help reach you?", say: "Say: call me, SMS, WhatsApp, or community aide." }
  ];
}

function guidedHealthProviderHtml(config = {}) {
  if (!isHealthProviderWorkflow(config)) return "";
  const steps = [
    { title: "Step 1: What help is needed?", say: "Say: I need a doctor, I need medicine, or I need a clinic." },
    { title: "Step 2: How should the provider connect?", say: "Say: call me, video call, WhatsApp, SMS, or community aide." },
    { title: "Step 3: What language or access support?", say: "Say: English, French, Kiswahili, Arabic, Spanish, captions, audio, or large print." },
    { title: "Step 4: Confirm the request", say: "Say: yes, or press Do this now when the request looks right." }
  ];
  return `
    <div class="user-guided-provider" role="group" aria-label="${escapeHtml(translateText("Doctor and provider guide"))}">
      <div class="user-guided-provider-current">
        <small>${translateText("Doctor help is open")}</small>
        <strong>${translateText("Tell Nexus what kind of care connection you need.")}</strong>
        <span>${translateText("Nexus helps organize provider contact, language, access support, and callback details. It does not diagnose or replace a licensed clinician.")}</span>
      </div>
      <div class="user-guided-provider-steps">
        ${steps.map((step, index) => `<article>
          <b>${index + 1}</b>
          <strong>${translateText(step.title)}</strong>
          <span>${translateText(step.say)}</span>
        </article>`).join("")}
      </div>
    </div>
  `;
}

function nextGuidedIntakePrompt(fieldName = "") {
  const steps = guidedHealthIntakeSteps();
  const index = steps.findIndex(step => step.field === fieldName);
  return steps[index + 1]?.title || "Review the intake, then say yes or press Do this now.";
}

function nextGuidedProviderPrompt(fieldName = "") {
  const prompts = {
    patientName: "What kind of care connection is needed?",
    careNeed: "How should the provider connect: call, video, WhatsApp, SMS, or community health worker?",
    connectionType: "What language or access support is needed?",
    preferredLanguage: "Review the request, then say yes or press Do this now.",
    accessibilityNeeds: "Review the request, then say yes or press Do this now."
  };
  return prompts[fieldName] || "Review the request, then say yes or press Do this now.";
}

function guidedHealthIntakeHtml(config = {}) {
  if (!isHealthIntakeWorkflow(config)) return "";
  const steps = guidedHealthIntakeSteps();
  return `
    <div class="user-guided-intake" role="group" aria-label="${escapeHtml(translateText("Telehealth intake guide"))}">
      <div class="user-guided-intake-current">
        <small>${translateText("Nexus will walk you through this")}</small>
        <strong>${translateText("Step 1: Who needs care?")}</strong>
        <span>${translateText("Speak naturally or type in the boxes below. Nexus will not diagnose. It prepares a care request, access needs, language, and callback path.")}</span>
      </div>
      <div class="user-guided-intake-steps">
        ${steps.map((step, index) => `<article>
          <b>${index + 1}</b>
          <strong>${translateText(step.title)}</strong>
          <span>${translateText(step.say)}</span>
        </article>`).join("")}
      </div>
      <p>${translateText("If anything sounds dangerous or urgent, contact local emergency help or a health worker immediately. Nexus is only organizing access and information.")}</p>
    </div>
  `;
}

function workflowFieldsHtml(fields = [], className = "workflow-fields") {
  if (!fields.length) return "";
  return `<div class="${escapeHtml(className)}">${fields.map(field => {
    const value = field.value || "";
    const options = field.options || [];
    if (field.type === "select") {
      return `<label class="field-label">${translateText(field.label)}<select data-workflow-field="${field.name}">${options.map(option => `<option value="${option.value}" ${option.value === value ? "selected" : ""}>${translateText(option.label)}</option>`).join("")}</select></label>`;
    }
    if (field.type === "textarea") {
      return `<label class="field-label">${translateText(field.label)}<textarea rows="${field.rows || 3}" data-workflow-field="${field.name}" placeholder="${translateText(field.placeholder || "")}">${translateText(value)}</textarea></label>`;
    }
    return `<label class="field-label">${translateText(field.label)}<input type="${field.type === "password" ? "password" : "text"}" data-workflow-field="${field.name}" value="${translateText(value)}" placeholder="${translateText(field.placeholder || "")}"></label>`;
  }).join("")}</div>`;
}

function userProcessScreenHtml(config = {}, mapped = {}, label = "Selected action") {
  const mode = workflowMode(config);
  const coach = config.realUseCoach || workflowRealUseCoach(config);
  const title = (experienceMode === "user" && config.userTitle) || config.title || label;
  const summary = (experienceMode === "user" && config.userSummary) || config.summary || coach.plain;
  const steps = userProcessSteps(config);
  const route = config.routePreview?.route || activeRoute();
  const country = config.healthPreview?.country || activeCountry();
  const directHealthGuide = isHealthIntakeWorkflow(config) || isHealthProviderWorkflow(config);
  const focus = mode === "health"
    ? `${country.name}: ${country.risk} risk`
    : mode === "trade" || mode === "map"
      ? route.name
      : coach.question;
  return `
    <section class="user-process-screen user-process-${escapeHtml(mode)}" aria-label="${translateText("Guided process")}">
      <div class="user-process-head">
        <small>${translateText("Guided process")}</small>
        <strong>${translateText(title)}</strong>
        <span>${translateText(summary)}</span>
      </div>
      ${directHealthGuide ? "" : `<div class="user-process-focus">
        <strong>${translateText("Focus")}</strong>
        <span>${translateText(focus)}</span>
      </div>
      <div class="user-process-steps">
        ${steps.map((step, index) => `<div>
          <b>${index + 1}</b>
          <strong>${translateText(step.title)}</strong>
          <span>${translateText(step.detail)}</span>
        </div>`).join("")}
      </div>`}
      ${guidedHealthIntakeHtml(config)}
      ${guidedHealthProviderHtml(config)}
      ${workflowFieldsHtml(config.fields || [], "user-process-fields")}
      <div class="user-process-actions">
        <button type="button" class="primary" data-inline-workflow-confirm aria-label="${escapeHtml(translateText(config.confirmLabel || "Do this now"))}">${translateText("Do this now")}</button>
        <button type="button" data-inline-workflow-cancel>${translateText("Choose another")}</button>
      </div>
      <p>${translateText("You stay in control. Nothing is submitted until you press the main button.")}</p>
    </section>
  `;
}

function renderUserProcessScreen(sectionId, config, mapped = {}, label = "Selected action", options = {}) {
  if (experienceMode !== "user" || !config) return false;
  const panel = $(`#${sectionId} .user-inline-workflow`);
  if (!panel) return false;
  pendingWorkflow = config;
  closeAskNexus({ silent: true });
  $("#workflowModal")?.classList.add("hidden");
  panel.classList.remove("hidden");
  panel.innerHTML = userProcessScreenHtml(config, mapped, label);
  if (options.speak !== false) updateUserCaptionPanel(mapped.response || "Process is ready. Press Do this now to continue.", { expanded: true });
  const moduleShell = panel.closest(".user-simple-module");
  if (moduleShell) moduleShell.scrollTo({ top: Math.max(0, panel.offsetTop - 12), behavior: "smooth" });
  panel.scrollIntoView({ behavior: "smooth", block: "nearest" });
  $(`#${sectionId} .user-module-status`) && ($(`#${sectionId} .user-module-status`).textContent = translateText("Process opened. Review it, then press Do this now."));
  if (options.speak !== false) setVoiceResponse(mapped.response || "Process is ready. Review it, then press Do this now.", true);
  return true;
}

function forceOpenUserProcessScreen(sectionId, config, mapped = {}, label = "Selected action") {
  if (experienceMode !== "user" || !config) return false;
  const centralWorkflowId = normalizeNexusWorkflowId(sectionId, `${config.userTitle || ""} ${config.title || ""} ${config.action || ""} ${label || ""} ${mapped.response || ""}`);
  if (nexusWorkflowDefinition(centralWorkflowId, mapped.response || label || "")) {
    return openNexusWorkflow(centralWorkflowId, {
      command: mapped.response || label || config.userTitle || config.title || "",
      source: "user-process-helper",
      workflow: sectionId,
      action: config.action || ""
    });
  }
  closeAskNexus({ silent: true });
  closeUserCaptionPanel();
  goSection(sectionId, { instant: true, openDefaultAction: false, keepAssistant: false, scroll: false });
  renderUserSimpleActiveSection(sectionId);
  const rendered = renderUserProcessScreen(sectionId, config, mapped, label, { speak: false });
  const ensureVisible = () => {
    const activeSection = $(`#${sectionId}`);
    const panel = activeSection?.querySelector(".user-inline-workflow");
    const hasFields = !config.fields?.length || Boolean(panel?.querySelector("[data-workflow-field]"));
    if (!activeSection?.classList.contains("active") || !panel || panel.classList.contains("hidden") || !hasFields) {
      goSection(sectionId, { instant: true, openDefaultAction: false, keepAssistant: false, scroll: false });
      renderUserSimpleActiveSection(sectionId);
      renderUserProcessScreen(sectionId, config, mapped, label, { speak: false });
    }
    const visiblePanel = $(`#${sectionId} .user-inline-workflow:not(.hidden)`);
    const moduleShell = visiblePanel?.closest(".user-simple-module");
    if (moduleShell && visiblePanel) moduleShell.scrollTo({ top: Math.max(0, visiblePanel.offsetTop - 12), behavior: "smooth" });
    visiblePanel?.scrollIntoView({ behavior: "smooth", block: "nearest" });
    const firstField = visiblePanel?.querySelector("[data-workflow-field]");
    firstField?.focus?.({ preventScroll: true });
  };
  requestAnimationFrame(ensureVisible);
  setTimeout(ensureVisible, 120);
  updateUserCaptionPanel(mapped.response || "Process is open. Fill the visible fields, then press Do this now.", { expanded: true });
  return rendered;
}

function openMappedUserWorkflow(mapped, sectionId = currentSectionId()) {
  if (!mapped) return false;
  if (experienceMode === "user" && mapped.command) {
    paintLocalLevelOneSuggestionForSimpleUserIntent(mapped, mapped.command);
    preserveControlledActionPreviewDuringCommandRoute = true;
    queueMicrotask(() => {
      preserveControlledActionPreviewDuringCommandRoute = false;
    });
  }
  if (mapped.directAction === "full-map") {
    return openFullScaleUserMap(mapped.response);
  }
  if (mapped.conversational) {
    setCommandInputs(mapped.command || "");
    openAskNexus();
    void handleVoiceCommand(mapped.command || "");
    return true;
  }
  const config = mapped.config || workflowConfig(mapped.workflow, mapped.action, { dataset: mapped.dataset || {} });
  if (!config) {
    const message = "Nexus could not build that workflow. Choose another action or ask Nexus in your own words.";
    $(`#${sectionId} .user-module-status`) && ($(`#${sectionId} .user-module-status`).textContent = translateText(message));
    toast(message);
    return false;
  }
  try {
    if (experienceMode === "user") {
      const label = mapped.label || simpleUserSections[sectionId]?.buttons?.find(button => button.command === mapped.command)?.label || config.userTitle || config.title || "Selected action";
      if (config.videoPreview) {
        openHealthVideoPreviewWorkflow(config, mapped.response, sectionId);
        return true;
      }
      const opened = forceOpenUserProcessScreen(sectionId, config, mapped, label);
      paintControlledActionPreview();
      paintLevelOneAgentActionSuggestionLabel();
      setTimeout(() => {
        paintControlledActionPreview();
        paintLevelOneAgentActionSuggestionLabel();
      }, 180);
      return opened;
    }
    openWorkflowModal(config);
  } catch (error) {
    const message = `Workflow window could not open: ${error.message || "unknown error"}`;
    console.error(message, error);
    $(`#${sectionId} .user-module-status`) && ($(`#${sectionId} .user-module-status`).textContent = translateText(message));
    toast(message);
    return false;
  }
  if (experienceMode === "user") {
    $(`#${sectionId} .user-inline-workflow`)?.classList.add("hidden");
    $(`#${sectionId} .user-module-status`) && ($(`#${sectionId} .user-module-status`).textContent = translateText("Workflow window opened. Choose Yes or No."));
  }
  setVoiceResponse(mapped.response || "Workflow is ready.", true);
  return true;
}

function isHealthVideoPreviewCommand(command = "") {
  const lower = String(command || "").toLowerCase();
  return lower.includes("open video for provider") || lower.includes("show injury") || lower.includes("video for provider");
}

function openHealthVideoPreviewWorkflow(config = workflowConfig("health", "video", { dataset: {} }), response = "", sectionId = currentSectionId()) {
  if (!config) return false;
  openWorkflowModal(config);
  const status = $(`#${sectionId} .user-module-status`) || $("#healthActionStatus") || $("#simpleActionStatus");
  if (status) status.textContent = translateText("Local camera preview opened. Ask permission before showing private health details, then confirm only when the handoff record is ready.");
  setVoiceResponse(response || config.userSummary || config.summary || "Local camera preview is open. This is a handoff-only demo, not a live provider room.", true);
  return true;
}

function openExplicitHealthVideoPreviewCommand(command = "") {
  if (!isHealthVideoPreviewCommand(command)) return false;
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  goSection("health");
  const config = workflowConfig("health", "video", { dataset: {} });
  return openHealthVideoPreviewWorkflow(config, "I opened Health and prepared the local camera preview and video handoff record. This does not start a live provider visit. Press Open camera when the patient agrees.", "health");
}

async function runExplicitTypedGlobalControlPreflight(command = "", options = {}) {
  const explicitCommand = String(command || "").trim();
  if (!explicitCommand) return false;
  if (localMusicControlIntent(explicitCommand)) {
    pendingAgentClarification = null;
    pendingNexusSpokenCommand = null;
    return handleLocalMusicControlCommand(explicitCommand);
  }
  if (musicAssistantIntent(explicitCommand)) {
    pendingAgentClarification = null;
    pendingNexusSpokenCommand = null;
    return runMusicAssistantCommand(explicitCommand, { turnToken: options.turnToken || null });
  }
  if (isExplicitNexusVoiceOnCommand(explicitCommand) || isNexusVoiceOnCommand(explicitCommand)) {
    pendingAgentClarification = null;
    pendingNexusSpokenCommand = null;
    voiceConversationPaused = false;
    enableNexusVoiceForDemo("Nexus voice is back on. Say Nexus, then tell me what you need.", { skipListeningStart: true });
    return true;
  }
  if (isExplicitNexusVoiceOffCommand(explicitCommand) || isNexusVoiceOffCommand(explicitCommand)) {
    pendingAgentClarification = null;
    pendingNexusSpokenCommand = null;
    disableNexusVoiceForDemo("Demo quiet mode is on. Nexus voice is off until you turn it back on.");
    return true;
  }
  return false;
}

function openDefaultUserSectionAction(sectionId = currentSectionId()) {
  if (experienceMode !== "user" || sectionId === "dashboard") return false;
  const command = simpleUserSections[sectionId]?.buttons?.[0]?.command;
  if (!command) return false;
  const label = simpleUserSections[sectionId]?.buttons?.[0]?.label || "Selected action";
  const status = $(`#${sectionId} .user-module-status`);
  const mapped = simpleUserCommandWorkflow(command);
  if (status) status.textContent = `${translateText(label)} opened. Review the details and choose Yes or No.`;
  if (mapped) {
    return openMappedUserWorkflow(mapped, sectionId);
  }
  setCommandInputs(command);
  openAskNexus();
  void handleVoiceCommand(command);
  return true;
}

function renderGrandmaConfirmation() {
  const panel = $("#grandmaConfirmPanel");
  if (!panel) return;
  if (!pendingGrandmaAction) {
    panel.classList.add("hidden");
    panel.innerHTML = "";
    return;
  }
  panel.classList.remove("hidden");
  panel.innerHTML = `
    <strong>${translateText(`You chose ${pendingGrandmaAction.label}.`)}</strong>
    <span>${translateText("Do you want Nexus to do this now?")}</span>
    <div class="grandma-confirm-actions">
      <button type="button" class="primary" data-grandma-confirm="yes">${translateText("Yes")}</button>
      <button type="button" data-grandma-confirm="no">${translateText("No")}</button>
    </div>
  `;
  panel.scrollIntoView({ behavior: "smooth", block: "center" });
  announce(`You chose ${pendingGrandmaAction.label}. Do you want Nexus to do this now?`);
}

function startGrandmaActionConfirmation(button) {
  const label = button.querySelector("strong")?.textContent || button.textContent.trim() || "this action";
  pendingGrandmaAction = {
    label,
    command: button.dataset.simpleCommand
  };
  renderGrandmaConfirmation();
}

function simpleUserCommandWorkflow(command = "") {
  const lower = String(command || "").toLowerCase();
  const roleId = firstEligibleRole()?.id;
  const productId = firstProduct()?.id;
  const migrantIntent = migrantFriendlyVoiceIntent(command);
  if (migrantIntent) return migrantIntent;
  if (/\b(women|woman|mother|mothers|children|child|youth|girl|girls|family|caregiver|school|student|students)\b/.test(lower) && /\b(learn|learning|lesson|school|study|read|reading|course|tutor|classroom|teach|education)\b/.test(lower)) {
    return { workflow: "women-children-learning", action: "start", response: "Women and children learning is ready.", dataset: {} };
  }
  if (/\b(women|woman|mother|mothers|family|caregiver|children|child|youth|girls|cooperative)\b/.test(lower) && /\b(farm|farmer|agriculture|crop|sell|market|health|learn|school|support|help|clinic)\b/.test(lower)) {
    return { workflow: "women-family", action: "start", response: "Women and family farm support is ready.", dataset: {} };
  }
  if (lower.includes("rural market focus") || lower.includes("focus my country") || lower.includes("country focus")) {
    return { workflow: "cross-platform", action: "remote-country-focus", response: "Country and rural market focus is ready.", dataset: {} };
  }
  if ((lower.includes("sell") || lower.includes("sale") || lower.includes("buyer")) && (lower.includes("track") || lower.includes("delivery") || lower.includes("logistics"))) {
    return { workflow: "cross-platform", action: "crop-sale-simulation", response: "Crop sale, buyer, and delivery tracking is ready.", dataset: { productId } };
  }
  if ((lower.includes("field") || lower.includes("farm") || lower.includes("crop")) && (lower.includes("explain") || lower.includes("drone") || lower.includes("scan") || lower.includes("stress"))) {
    return { workflow: "cross-platform", action: "field-intelligence", response: "Drone and field intelligence is ready.", dataset: { productId } };
  }
  if ((lower.includes("telehealth") || lower.includes("clinic") || lower.includes("patient")) && (lower.includes("walk") || lower.includes("navigate") || lower.includes("support") || lower.includes("safe"))) {
    return { workflow: "cross-platform", action: "telehealth-navigation", response: "Safe telehealth navigation is ready.", dataset: {} };
  }
  if ((lower.includes("learning") || lower.includes("course") || lower.includes("training")) && (lower.includes("income") || lower.includes("work") || lower.includes("job"))) {
    return { workflow: "cross-platform", action: "learning-workforce", response: "Learning to income pathway is ready.", dataset: {} };
  }
  if ((lower.includes("credential") || lower.includes("provider") || lower.includes("engine")) && (lower.includes("live") || lower.includes("connect") || lower.includes("prepare"))) {
    return { workflow: "cross-platform", action: "live-credential-path", response: "Live engine credential path is ready.", dataset: {} };
  }
  const explicitLearningIntent = explicitLearningReadinessIntent(command);
  if (explicitLearningIntent) return { workflow: explicitLearningIntent.workflow, action: explicitLearningIntent.action, response: explicitLearningIntent.response, dataset: explicitLearningIntent.dataset || {} };
  if (lower.includes("start training") || lower.includes("start a course")) return { workflow: "learning", action: "start", response: "Course start is ready.", dataset: {} };
  if (lower.includes("complete my lesson") || lower.includes("finish lesson")) return { workflow: "learning", action: "lesson", response: "Lesson completion is ready.", dataset: {} };
  if (lower.includes("issue my certificate") || lower.includes("certificate")) return { section: "learning", config: learningCertificateWorkflowConfig(), response: "Certificate workflow is ready." };
  if (lower.includes("build captions") || lower.includes("make captions") || lower.includes("open captions") || lower.includes("captions")) {
    return { section: "learning", config: learningAccessibilityWorkflowConfig("caption"), response: "Captions are open. Speak now and Nexus will write the words here while keeping learning support ready." };
  }
  if (lower.includes("show me jobs") || lower.includes("find jobs")) return { workflow: "workforce", action: "build-profile", response: "Job support is ready.", dataset: { roleId } };
  if (lower.includes("apply for")) return { workflow: "workforce", action: "apply-role", response: "Job application is ready.", dataset: { roleId } };
  if (lower.includes("review my workforce gaps") || lower.includes("skills")) return { workflow: "workforce", action: "mentor", response: "Skills review is ready.", dataset: { roleId } };
  if (lower.includes("schedule my shift") || lower.includes("plan shift")) return { workflow: "workforce", action: "shift", response: "Shift planning is ready.", dataset: { roleId } };
  if (lower.includes("telehealth intake") || lower.includes("start intake") || lower.includes("open intake") || lower.includes("begin intake") || lower.includes("create intake") || lower.includes("patient intake")) {
    return { workflow: "health", action: "intake", response: "Telehealth intake is open. I will collect the care request, access needs, language, callback, and safety details. This is not a diagnosis.", dataset: {} };
  }
  if (lower.includes("telehealth access") || lower.includes("talk to provider") || lower.includes("speak to provider")) return { workflow: "health", action: "provider", response: "Provider access is ready.", dataset: {} };
  if (isHealthVideoPreviewCommand(command)) return { workflow: "health", action: "video", response: "Local camera preview and video handoff record are ready.", dataset: {} };
  if (lower.includes("contact the listed telehealth provider") || lower.includes("contact listed telehealth provider") || lower.includes("contact telehealth provider listed")) return { workflow: "health", action: "provider", response: "Listed telehealth provider contact is ready.", dataset: {} };
  if (lower.includes("service menu") || lower.includes("clinic prices")) return { workflow: "health", action: "clinic-service-menu", response: "Mobile clinic service menu is ready.", dataset: {} };
  if (lower.includes("mobile clinic payment") || lower.includes("request payment") || lower.includes("charge patient") || lower.includes("clinic billing")) return { workflow: "health", action: "clinic-payment-request", response: "Mobile clinic payment request is ready.", dataset: {} };
  if (lower.includes("issue receipt") || lower.includes("payment receipt")) return { workflow: "health", action: "clinic-receipt", response: "Mobile clinic receipt is ready.", dataset: {} };
  if (lower.includes("provider payout") || lower.includes("clinic payout") || lower.includes("pay clinic")) return { workflow: "health", action: "clinic-payout", response: "Mobile clinic payout is ready.", dataset: {} };
  if (lower.includes("call provider") || lower.includes("call the provider")) return { workflow: "communications", action: "health-whatsapp", response: "Provider call or WhatsApp handoff is ready.", dataset: {} };
  if (lower.includes("message provider")) return { workflow: "communications", action: "health-chat", response: "Provider message is ready.", dataset: {} };
  if (lower.includes("check health risk") || lower.includes("check region")) return { workflow: "health", action: "safety", response: "Regional health risk review is ready.", dataset: {} };
  if (lower.includes("audio guide") || lower.includes("accessibility")) return { workflow: "health", action: "accessibility", response: "Accessibility support is ready.", dataset: {} };
  if (lower.includes("contact my buyer") || lower.includes("contact buyer")) return { workflow: "trade", action: "buyer-contact", response: "Buyer contact is ready.", dataset: { productId } };
  if (lower.includes("open video for buyer") || lower.includes("show crops") || lower.includes("show crop")) return { workflow: "trade", action: "buyer-video", response: "Buyer crop video is ready.", dataset: { productId } };
  if ((lower.includes("sell my crop") || lower.includes("sell crop")) && (lower.includes("track my sale") || lower.includes("track sale") || lower.includes("delivery"))) return { workflow: "trade", action: "order", response: "Crop sale and delivery tracking is ready.", dataset: { productId } };
  if (lower.includes("crop order") || lower.includes("create order")) return { workflow: "trade", action: "order", response: "Crop order is ready.", dataset: { productId } };
  if (lower.includes("quote shipment") || lower.includes("shipping quote")) return { workflow: "trade", action: "logistics-quote", response: "Shipment quote is ready.", dataset: { productId } };
  if (lower.includes("book shipment") || lower.includes("ship my crop") || lower.includes("book delivery")) return { workflow: "trade", action: "shipping-booking", response: "Shipping booking is ready.", dataset: { productId } };
  if (lower.includes("buyer pickup") || lower.includes("buyer pick up")) return { workflow: "trade", action: "buyer-pickup", response: "Buyer pickup is ready.", dataset: { productId } };
  if (lower.includes("seller delivery") || lower.includes("deliver to buyer")) return { workflow: "trade", action: "seller-delivery", response: "Seller delivery is ready.", dataset: { productId } };
  if (lower.includes("confirm delivery") || lower.includes("delivery proof")) return { workflow: "trade", action: "delivery-confirm", response: "Delivery confirmation is ready.", dataset: { productId } };
  if (lower.includes("settlement") || lower.includes("seller payout") || lower.includes("farmer payout")) return { workflow: "trade", action: "settlement", response: "Settlement workflow is ready.", dataset: { productId } };
  if (lower.includes("buyer checkout") || lower.includes("create checkout") || lower.includes("collect payment") || lower.includes("buyer pay")) return { workflow: "trade", action: "payment-checkout", response: "Buyer checkout is ready.", dataset: { productId } };
  if (lower.includes("track my route") || lower.includes("check route")) return { workflow: "ai", action: "route", response: "Route intelligence is ready.", dataset: {} };
  if (lower.includes("drone scan") || lower.includes("scan farm") || lower.includes("check farm")) return { workflow: "trade", action: "drone", response: "Drone scan is ready.", dataset: { productId } };
  if (isFullScaleMapCommand(command)) return { section: "map", directAction: "full-map", response: isMapTrackingCommand(command) ? "Full global map is open with shipment tracking. You can zoom, drag, check the route, and follow crop or delivery movement." : "Full map is open. You can zoom, drag, check route risk, find facilities, or track shipment movement.", dataset: {} };
  if (lower.includes("nearest health facility") || lower.includes("find facility")) return { workflow: "map", action: "facility-route", response: "Facility route is ready.", dataset: {} };
  if (lower.includes("explain the map")) return { workflow: "map", action: "inspector", response: "Map explanation is ready.", dataset: {} };
  if (lower.includes("help me") || lower.includes("what should i do next") || lower.includes("understand the platform")) return { workflow: "ai", action: "orchestrate", response: "Nexus help is ready.", dataset: {} };
  if (lower.includes("read the current response") || lower.includes("read to me")) return { section: "agent", conversational: true, command: "read the current response", response: "Nexus is ready to read." };
  if (lower.includes("agent plan") || lower.includes("plan mission")) return { workflow: "ai", action: "command", response: "Agent plan support is ready.", dataset: {} };
  return null;
}

async function answerGrandmaActionConfirmation(answer) {
  const action = pendingGrandmaAction;
  pendingGrandmaAction = null;
  renderGrandmaConfirmation();
  if (answer !== "yes" || !action?.command) {
    toast("Canceled");
    announce("Canceled. Choose another button when ready.");
    return;
  }
  setCommandInputs(action.command);
  openAskNexus();
  await handleVoiceCommand(action.command);
}

function renderElevationPanels() {
  const impact = data.impactDashboard || { metrics: [], status: "build-evidence", summary: "" };
  if ($("#impactStatus")) $("#impactStatus").textContent = impact.status || "Pilot-ready";
  if ($("#impactDashboardPanel")) {
    $("#impactDashboardPanel").innerHTML = (impact.metrics || []).map(item => {
      const value = item.format === "money" ? money(item.value || 0) : `${item.value}${item.suffix || ""}`;
      return row(item.label, `${value} - ${item.detail}`);
    }).join("") || row("Impact", "Run workflows to create impact evidence.");
  }
  const timeline = data.missionTimeline || { items: [], stages: [] };
  if ($("#missionTimelineCount")) $("#missionTimelineCount").textContent = `${timeline.total || 0} events`;
  if ($("#missionTimelinePanel")) {
    const stageHtml = (timeline.stages || []).map(stage => `<div><strong>${translateText(stage.title)}</strong><span>${translateText(stage.status)}</span></div>`).join("");
    const itemHtml = (timeline.items || []).slice(0, 8).map(item => `<div><strong>${translateText(item.module)} - ${translateText(item.title)}</strong><span>${translateText(item.detail)}</span><small>${translateText(item.status)}${item.evidence ? ` - ${translateText(item.evidence)}` : ""}</small></div>`).join("");
    $("#missionTimelinePanel").innerHTML = itemHtml || stageHtml || `<div>${translateText("Run a workflow to create the first mission timeline event.")}</div>`;
  }
  if ($("#liveInvestorDemoPanel")) {
    const demo = (data.profile.liveInvestorDemos || [])[0];
    const packet = (data.profile.evidenceExports || [])[0];
    $("#liveInvestorDemoPanel").innerHTML = demo
      ? `<div><strong>${translateText(demo.title)} - ${translateText(demo.status)}</strong><span>${translateText((demo.narratorScript || []).join(" "))}</span><small>${translateText(`Evidence packet: ${demo.evidenceExportId || packet?.id || "ready"}`)}</small></div>`
      : `<div>${translateText("Run live investor mode to create a narrated pilot, AI orchestration, timeline evidence, and export packet.")}</div>`;
  }
  if ($("#pwaPolishPanel")) {
    const nativeReadiness = nativeAppReadinessSummary();
    $("#pwaPolishStatus").textContent = `${nativeReadiness.ready}/${nativeReadiness.total} ready`;
    $("#pwaPolishPanel").innerHTML = nativeReadiness.items.map(item => row(item.title, `${item.ready ? "Ready" : "Needs native app"} - ${item.detail}`)).join("");
  }
}

