function ensureLiveRouteLayer() {
  if (!map) return null;
  if (!layers.liveRoute) layers.liveRoute = L.layerGroup().addTo(map);
  return layers.liveRoute;
}

function drawLiveRouteTracking() {
  if (!window.L || !map || !routeTrackingPoints.length) return;
  const layer = ensureLiveRouteLayer();
  if (!layer) return;
  layer.clearLayers();
  const latest = routeTrackingPoints[routeTrackingPoints.length - 1];
  if (routeTrackingPoints.length > 1) {
    L.polyline(routeTrackingPoints, { color: "#d94c31", weight: 5, opacity: .95, dashArray: "8 6" })
      .addTo(layer)
      .bindTooltip(translateText("Live route trail"));
  }
  L.circleMarker(latest, { radius: 8, color: "#d94c31", fillColor: "#d94c31", fillOpacity: .95, weight: 3 })
    .addTo(layer)
    .bindTooltip(translateText("Live route position"));
  map.setView(latest, Math.max(map.getZoom(), 13));
}

function stopLiveRouteTracking() {
  if (routeTrackingWatchId !== null && navigator.geolocation) {
    navigator.geolocation.clearWatch(routeTrackingWatchId);
  }
  routeTrackingWatchId = null;
  ensureLiveRouteLayer()?.clearLayers();
  setVoiceResponse("Live route tracking is stopped. Your saved route points stay in this session until you refresh.", true);
}

async function startLiveRouteTracking() {
  goSection("map");
  if (!navigator.geolocation) {
    setVoiceResponse("This device does not expose GPS tracking to the browser. I can still run route-risk intelligence from the map and trade route tools.", true);
    return;
  }
  if (routeTrackingWatchId !== null) {
    setVoiceResponse("Live route tracking is already on. I will keep updating the map as the device moves.", true);
    return;
  }
  routeTrackingPoints = [];
  if (!map) renderMap();
  setVoiceResponse("Live route tracking is starting. Please allow location access if your browser asks.", true);
  try {
    await request("/api/workflow/record", {
      method: "POST",
      body: {
        module: "Map",
        action: "route.live_tracking_started",
        detail: "Live route tracking started from a voice command.",
        providerId: "maps"
      }
    });
  } catch {
    // Tracking can still run locally if evidence recording is temporarily unavailable.
  }
  routeTrackingWatchId = navigator.geolocation.watchPosition(position => {
    const point = [position.coords.latitude, position.coords.longitude];
    routeTrackingPoints.push(point);
    routeTrackingPoints = routeTrackingPoints.slice(-120);
    drawLiveRouteTracking();
    const accuracy = Math.round(position.coords.accuracy || 0);
    $("#globalAssistantStatus").textContent = translateText(`Live route tracking active. Latest accuracy: ${accuracy} meters.`);
  }, error => {
    routeTrackingWatchId = null;
    setVoiceResponse(`I could not start live route tracking: ${error.message}. Check browser location permission, then try again.`, true);
  }, {
    enableHighAccuracy: true,
    maximumAge: 5000,
    timeout: 15000
  });
}

function renderMap() {
  if (!window.L || !data) return;
  const country = activeCountry();
  const route = activeRoute();
  if (!map) {
    map = L.map("mapCanvas", leafletMapOptions()).setView([8, 20], 3);
    addRealMapTiles(map);
    layers.routes = L.layerGroup().addTo(map);
    layers.markers = L.layerGroup().addTo(map);
    layers.facilities = L.layerGroup().addTo(map);
    layers.liveRoute = L.layerGroup().addTo(map);
  }
  layers.routes.clearLayers();
  layers.markers.clearLayers();
  layers.facilities.clearLayers();

  data.routes.forEach(item => {
    const active = item.id === route.id;
    drawShipmentRoute(layers.routes, item, {
      order: active ? data.profile.orders?.[data.profile.orders.length - 1] : null,
      active,
      includeCurrentMarker: active,
      muted: !active
    });
  });

  data.countries.forEach(item => {
    L.marker([item.lat, item.lng])
      .addTo(layers.markers)
      .bindPopup(`<strong>${translateText(item.name)}</strong><br>${item.patients.toLocaleString()} ${translateText("patients")}<br>${item.facilities} ${translateText("facilities")}`);
  });

  [[country.lat + .7, country.lng - .8], [country.lat - .5, country.lng + .9], [country.lat + .3, country.lng + .5]].forEach((point, index) => {
    L.circleMarker(point, { radius: 6, color: "#1b8f68", fillColor: "#1b8f68", fillOpacity: .65 }).addTo(layers.facilities).bindTooltip(`${translateText("Facility")} ${index + 1}`);
  });
  map.setView([country.lat, country.lng], country.zoom);
  drawLiveRouteTracking();
  setTimeout(() => safeInvalidateLeafletMap(map), 100);
}

function shipmentTrackingState(route = activeRoute(), order = null) {
  const checkpoints = route?.checkpoints || [];
  const live = order?.liveTracking || {};
  const activeCheckpoint = order?.checkpoint || data?.profile?.activeCheckpoint || checkpoints[0] || "Pickup";
  const checkpointIndex = checkpoints.findIndex(checkpoint => checkpoint === activeCheckpoint);
  const safeIndex = Math.max(0, Math.min(checkpointIndex < 0 ? 0 : checkpointIndex, Math.max(0, checkpoints.length - 1)));
  const completed = checkpoints.length ? safeIndex + 1 : 1;
  const total = Math.max(1, checkpoints.length);
  const progress = Math.round((completed / total) * 100);
  const nextCheckpoint = checkpoints[Math.min(safeIndex + 1, total - 1)] || checkpoints[total - 1] || "Buyer handoff";
  const remainingStops = Math.max(0, total - completed);
  const etaHours = Math.max(2, remainingStops * 5 + 3);
  return {
    activeCheckpoint,
    safeIndex,
    completed,
    total,
    progress,
    nextCheckpoint: live.currentLocation || nextCheckpoint,
    remainingStops,
    eta: live.eta || (remainingStops ? `${etaHours}-${etaHours + 4} hrs` : "Arriving now"),
    status: live.status || order?.stage || data?.profile?.routeStage || "Tracking",
    provider: live.provider || "AgriNexus route tracker",
    source: live.source || "local-route-estimate",
    trackingNumber: live.trackingNumber || order?.trackingNumber || order?.orderNumber || "",
    livePoint: Number.isFinite(Number(live.latitude)) && Number.isFinite(Number(live.longitude)) ? [Number(live.latitude), Number(live.longitude)] : null,
    lastEvent: live.lastEvent || ""
  };
}

function shipmentMarkerIcon(label = "Shipment") {
  return L.divIcon({
    className: "shipment-tracker-marker",
    html: `<span aria-hidden="true"></span><b>${escapeHtml(translateText(label))}</b>`,
    iconSize: [112, 34],
    iconAnchor: [18, 17],
    popupAnchor: [0, -14]
  });
}

function drawShipmentRoute(layer, route = activeRoute(), { order = null, active = true, includeCurrentMarker = true, muted = false } = {}) {
  if (!window.L || !layer || !route?.points?.length) return;
  const state = shipmentTrackingState(route, order);
  const points = route.points || [];
  const currentPoint = state.livePoint || points[Math.min(state.safeIndex, points.length - 1)] || points[0];
  const completedPoints = points.slice(0, Math.min(state.safeIndex + 1, points.length));
  const remainingPoints = points.slice(Math.min(state.safeIndex, points.length - 1));
  const routeColor = active ? "#2563eb" : "#64748b";
  const completedColor = active ? "#1d4ed8" : "#64748b";
  const remainingColor = active ? "#0f766e" : "#94a3b8";
  if (completedPoints.length > 1) {
    L.polyline(completedPoints, {
      color: completedColor,
      weight: active ? 4 : 3,
      opacity: muted ? .42 : .82,
      lineCap: "round",
      lineJoin: "round"
    }).addTo(layer).bindTooltip(translateText("Completed shipment leg"));
  }
  if (remainingPoints.length > 1) {
    L.polyline(remainingPoints, {
      color: remainingColor,
      weight: active ? 4 : 3,
      opacity: muted ? .35 : .72,
      dashArray: active ? "8 8" : "6 8",
      lineCap: "round",
      lineJoin: "round"
    }).addTo(layer).bindTooltip(translateText("Remaining shipment leg"));
  } else if (points.length > 1) {
    L.polyline(points, { color: routeColor, weight: active ? 4 : 3, opacity: muted ? .42 : .78 }).addTo(layer);
  }
  (route.checkpoints || []).forEach((checkpoint, index) => {
    const point = points[Math.min(index, points.length - 1)];
    if (!point) return;
    const isCurrent = index === state.safeIndex;
    const isDone = index < state.safeIndex;
    L.circleMarker(point, {
      radius: isCurrent ? 7 : 5,
      color: isCurrent ? "#111827" : isDone ? completedColor : "#334155",
      fillColor: isCurrent ? "#ffffff" : isDone ? completedColor : "#ffffff",
      fillOpacity: 1,
      weight: isCurrent ? 3 : 2
    }).addTo(layer).bindPopup(`<strong>${translateText(checkpoint)}</strong><br>${translateText(isCurrent ? "Current shipment checkpoint" : isDone ? "Completed checkpoint" : "Next checkpoint")}`);
  });
  if (includeCurrentMarker && currentPoint) {
    L.marker(currentPoint, { icon: shipmentMarkerIcon("Live shipment") })
      .addTo(layer)
      .bindPopup(`<strong>${translateText("Shipment tracking")}</strong><br>${translateText(state.nextCheckpoint || state.activeCheckpoint)}<br>${translateText(`ETA: ${state.eta}`)}<br>${translateText(state.source === "live-provider" ? "Live provider GPS" : "Platform tracking")}`);
  }
}

function addLiveMapStatusControl(targetMap) {
  const state = {
    loaded: 0,
    errors: 0,
    lastLayer: "Operational map"
  };
  const control = L.control({ position: "topright" });
  control.onAdd = () => {
    const div = L.DomUtil.create("div", "live-map-status-control");
    div.innerHTML = `
      <strong>${translateText("Live map")}</strong>
      <span data-live-map-status>${translateText("Loading real map tiles")}</span>
      <small>${translateText("Grid, country lines, scale, and global view active")}</small>
    `;
    L.DomEvent.disableClickPropagation(div);
    return div;
  };
  control.addTo(targetMap);
  const update = () => {
    const label = targetMap.getContainer()?.querySelector("[data-live-map-status]");
    if (!label) return;
    const status = state.loaded
      ? `${state.loaded} ${translateText("real tile(s) loaded")} - ${translateText(state.lastLayer)}`
      : state.errors
        ? `${translateText("Tile provider retrying")} - ${state.errors} ${translateText("error(s)")}`
        : translateText("Loading real map tiles");
    label.textContent = status;
  };
  update();
  return {
    tileLoad(layerName) {
      state.loaded += 1;
      state.lastLayer = layerName || state.lastLayer;
      update();
    },
    tileError(layerName) {
      state.errors += 1;
      state.lastLayer = layerName || state.lastLayer;
      update();
    }
  };
}

function addRealMapTiles(targetMap) {
  if (!targetMap || !window.L) return {};
  if (!targetMap.getPane("countryLabels")) {
    targetMap.createPane("countryLabels");
    targetMap.getPane("countryLabels").style.zIndex = 420;
    targetMap.getPane("countryLabels").style.pointerEvents = "none";
  }
  if (!targetMap.getPane("mapGrid")) {
    targetMap.createPane("mapGrid");
    targetMap.getPane("mapGrid").style.zIndex = 430;
    targetMap.getPane("mapGrid").style.pointerEvents = "none";
  }
  const tileOptions = leafletTileOptions();
  const mapLayers = normalizedMapTileLayers();
  const operationalLayer = L.tileLayer(mapLayers.operational.url, {
    ...tileOptions,
    attribution: mapLayers.operational.attribution
  });
  const osmStandardLayer = L.tileLayer(mapLayers.openStreetMap.url, {
    ...tileOptions,
    attribution: mapLayers.openStreetMap.attribution
  });
  const satelliteLayer = L.tileLayer(mapLayers.satellite.url, {
    ...tileOptions,
    attribution: mapLayers.satellite.attribution
  });
  const labelLayer = L.tileLayer(mapLayers.labels.url, {
    ...tileOptions,
    attribution: mapLayers.labels.attribution,
    pane: "countryLabels",
    opacity: .95
  });
  const humanitarianLayer = L.tileLayer(mapLayers.humanitarian.url, {
    ...tileOptions,
    attribution: mapLayers.humanitarian.attribution
  });
  const gridLayer = createGlobalGridLayer();
  const statusControl = addLiveMapStatusControl(targetMap);
  [
    [operationalLayer, mapLayers.operational.name],
    [satelliteLayer, mapLayers.satellite.name],
    [labelLayer, mapLayers.labels.name],
    [osmStandardLayer, mapLayers.openStreetMap.name],
    [humanitarianLayer, mapLayers.humanitarian.name]
  ].forEach(([layer, layerName]) => {
    layer.on("tileload", () => statusControl.tileLoad(layerName));
    layer.on("tileerror", () => statusControl.tileError(layerName));
  });
  let fallbackAdded = false;
  const activateFallback = () => {
    if (fallbackAdded || targetMap.hasLayer(osmStandardLayer)) return;
    fallbackAdded = true;
    osmStandardLayer.addTo(targetMap);
  };
  operationalLayer.on("tileerror", activateFallback);
  satelliteLayer.on("tileerror", activateFallback);
  operationalLayer.addTo(targetMap);
  labelLayer.addTo(targetMap);
  gridLayer.addTo(targetMap);
  L.control.layers({
    [mapLayers.operational.name]: operationalLayer,
    [mapLayers.satellite.name]: satelliteLayer,
    [mapLayers.openStreetMap.name]: osmStandardLayer,
    [mapLayers.humanitarian.name]: humanitarianLayer
  }, {
    [mapLayers.labels.name]: labelLayer,
    "Latitude/longitude grid": gridLayer
  }, { collapsed: true }).addTo(targetMap);
  L.control.scale({ metric: true, imperial: false }).addTo(targetMap);
  addGlobalMapControl(targetMap);
  return { operationalLayer, satelliteLayer, osmStandardLayer, humanitarianLayer, labelLayer, gridLayer };
}

function normalizedMapTileLayers() {
  const defaults = DEFAULT_MAP_TILE_CONFIG.layers;
  const configured = mapTileConfig?.layers || {};
  return Object.fromEntries(Object.entries(defaults).map(([key, fallback]) => {
    const layer = configured[key] || {};
    const url = typeof layer.url === "string" && layer.url.trim() ? layer.url.trim() : fallback.url;
    const attribution = typeof layer.attribution === "string" && layer.attribution.trim() ? layer.attribution.trim() : fallback.attribution;
    const name = typeof layer.name === "string" && layer.name.trim() ? layer.name.trim() : fallback.name;
    return [key, { ...fallback, ...layer, name, url, attribution }];
  }));
}

async function loadPublicMapConfig() {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 3500);
  try {
    const response = await fetch("/api/config", { credentials: "same-origin", signal: controller.signal });
    if (!response.ok) throw new Error("Map config unavailable");
    const config = await response.json();
    if (config?.map?.engine === "leaflet" && config.map.layers) {
      mapTileConfig = {
        ...DEFAULT_MAP_TILE_CONFIG,
        ...config.map,
        layers: {
          ...DEFAULT_MAP_TILE_CONFIG.layers,
          ...(config.map.layers || {})
        }
      };
    }
    if (config?.assistantRuntimePreview && typeof config.assistantRuntimePreview === "object") {
      nexusAssistantRuntimePreviewConfig = Object.freeze({
        enabled: config.assistantRuntimePreview.enabled === true,
        liveSourceRetrievalEnabled: config.assistantRuntimePreview.liveSourceRetrievalEnabled === true,
        assistantDialogueLivePreviewEnabled: config.assistantRuntimePreview.assistantDialogueLivePreviewEnabled === true,
        standardUserLiveSourcePreviewEnabled: config.assistantRuntimePreview.standardUserLiveSourcePreviewEnabled === true,
        defaultOff: config.assistantRuntimePreview.defaultOff !== false,
        executionAuthority: false
      });
    }
    if (config?.a100SafeAutonomy && typeof config.a100SafeAutonomy === "object") {
      nexusA100SafeAutonomyConfig = Object.freeze({
        enabled: config.a100SafeAutonomy.enabled !== false,
        surface: "standard-user",
        previewOnly: true,
        defaultSafe: config.a100SafeAutonomy.defaultSafe !== false,
        executionAuthority: false,
        noProviderHandoff: true,
        noLocationPermissionRequested: true,
        noBrowserPermissionPrompt: true,
        noExternalActionAuthorized: true,
        highRiskActionsGated: true
      });
    }
  } catch (error) {
    mapTileConfig = DEFAULT_MAP_TILE_CONFIG;
    if (localStorage.getItem("agrinexusMapDebug") === "on") {
      console.warn("Using default map tile configuration", error?.message || error);
    }
  } finally {
    clearTimeout(timeout);
  }
  return mapTileConfig;
}

function isNexusAssistantRuntimePreviewEnabled() {
  return Boolean(
    nexusAssistantRuntimePreviewConfig?.enabled === true
    && nexusAssistantRuntimePreviewConfig?.liveSourceRetrievalEnabled === true
    && nexusAssistantRuntimePreviewConfig?.assistantDialogueLivePreviewEnabled === true
    && nexusAssistantRuntimePreviewConfig?.standardUserLiveSourcePreviewEnabled === true
    && nexusAssistantRuntimePreviewConfig?.executionAuthority === false
  );
}

function assistantRuntimePreviewText(result = {}) {
  const response = result && typeof result === "object" ? result.response || result : {};
  return String(response.answer || response.message || "").trim();
}

function isSafeAssistantRuntimeFollowUpChip(value = "") {
  const text = String(value || "").trim();
  return Boolean(text) && NEXUS_ASSISTANT_BLOCKED_FOLLOW_UP_CHIP_PATTERNS.every(pattern => !pattern.test(text));
}

function defaultAssistantRuntimeFollowUps(response = {}) {
  const provider = String(response.selectedProvider || "").trim();
  const intent = String(response.intent || "").trim();
  if (provider === "job-search" || intent === "job-search") {
    return ["Show entry-level options", "Compare sources", "Make a checklist", "Draft questions I should ask"];
  }
  if (provider === "music-media") {
    return ["Show training options", "Compare sources", "Explain this", "Narrow results"];
  }
  if (provider === "agriculture-context") {
    return ["Explain this", "Make a checklist", "Show training options", "What should I do next?"];
  }
  if (provider === "weather") {
    return ["Explain this", "Make a checklist", "Narrow results", "What should I do next?"];
  }
  return NEXUS_ASSISTANT_SAFE_FOLLOW_UP_CHIPS;
}

function assistantRuntimePreviewSuggestions(result = {}) {
  const response = result && typeof result === "object" ? result.response || result : {};
  const suggestions = Array.isArray(response.safeFollowUps) ? response.safeFollowUps
    : Array.isArray(response.safeNextSteps) ? response.safeNextSteps
      : [];
  return [...suggestions, ...defaultAssistantRuntimeFollowUps(response)]
    .map(item => typeof item === "string" ? item.trim() : "")
    .filter(Boolean)
    .filter(isSafeAssistantRuntimeFollowUpChip)
    .filter((item, index, all) => all.indexOf(item) === index)
    .slice(0, 6);
}

function normalizeAssistantRuntimePreviewCard(response = {}) {
  const safeResponse = response && typeof response === "object" ? response : {};
  const text = assistantRuntimePreviewText(safeResponse) || "Nexus prepared a safe informational preview. No action has been taken.";
  const citations = Array.isArray(safeResponse.citations) ? safeResponse.citations.slice(0, 4) : [];
  const sourceLabels = Array.isArray(safeResponse.sourceLabels) ? safeResponse.sourceLabels.slice(0, 4) : [];
  const providerHealth = safeResponse.providerHealth && typeof safeResponse.providerHealth === "object"
    ? safeResponse.providerHealth
    : {};
  const safeRetryPolicy = providerHealth.safeRetryPolicy && typeof providerHealth.safeRetryPolicy === "object"
    ? providerHealth.safeRetryPolicy
    : {};
  const cachePolicy = providerHealth.cachePolicy && typeof providerHealth.cachePolicy === "object"
    ? providerHealth.cachePolicy
    : {};
  const sourceResultCount = Number(safeResponse.sourceResultCount || 0);
  const reliabilityWarnings = [];
  if (providerHealth.providerTimedOut === true) reliabilityWarnings.push("Provider timed out. Nexus kept this as a safe unavailable preview.");
  if (providerHealth.providerErrorNormalized === true) reliabilityWarnings.push("Provider error was normalized. No fallback action was executed.");
  if (providerHealth.safeUnavailableState === true) reliabilityWarnings.push("Provider/source unavailable. Review the guidance or try again manually.");
  if (providerHealth.staleResultWarning === true || String(safeResponse.freshnessStatus || "").trim() === "stale") reliabilityWarnings.push("Freshness warning: this result may be stale.");
  if (String(safeResponse.confidence || "low").trim().toLowerCase() === "low") reliabilityWarnings.push("Low confidence: compare sources before relying on this answer.");
  if (sourceResultCount === 0) reliabilityWarnings.push("Empty result guidance: no provider source result was returned.");
  if (safeRetryPolicy.userVisibleRetryOnly === true || safeRetryPolicy.automaticRetryAllowed === false) reliabilityWarnings.push("Retry is user-visible only. Nexus will not run hidden auto-retry loops.");
  const agentExperience = safeResponse.standardUserAgentExperience && typeof safeResponse.standardUserAgentExperience === "object"
    ? safeResponse.standardUserAgentExperience
    : null;
  return {
    userPrompt: String(safeResponse.userPrompt || "").trim(),
    answer: text,
    intent: String(safeResponse.intent || "general-question").trim(),
    selectedProvider: String(safeResponse.selectedProvider || "provider unavailable").trim(),
    providerStatus: String(safeResponse.providerStatus || "unknown").trim(),
    sourceLabels: sourceLabels.map(item => String(item || "").trim()).filter(Boolean),
    citations: citations.map(citation => ({
      sourceName: String(citation?.sourceName || "Source unavailable").trim(),
      sourceUrl: String(citation?.sourceUrl || "source-url-unavailable").trim(),
      evidenceStatus: String(citation?.evidenceStatus || "source-unavailable").trim(),
      freshnessStatus: String(citation?.freshnessStatus || "unknown").trim()
    })),
    retrievedAt: String(safeResponse.retrievedAt || "retrieval time unavailable").trim(),
    confidence: String(safeResponse.confidence || "low").trim(),
    freshnessStatus: String(safeResponse.freshnessStatus || "unknown").trim(),
    trustTier: String(safeResponse.trustTier || "unavailable").trim(),
    sourceResultCount,
    providerReliability: {
      providerDisplayName: String(providerHealth.providerDisplayName || safeResponse.selectedProvider || "Provider unavailable").trim(),
      providerStatus: String(providerHealth.providerStatus || safeResponse.providerStatus || "unknown").trim(),
      safeUnavailableState: providerHealth.safeUnavailableState === true,
      providerTimedOut: providerHealth.providerTimedOut === true,
      providerErrorNormalized: providerHealth.providerErrorNormalized === true,
      staleResultWarning: providerHealth.staleResultWarning === true,
      confidence: String(providerHealth.confidence || safeResponse.confidence || "low").trim(),
      freshnessStatus: String(providerHealth.freshnessStatus || safeResponse.freshnessStatus || "unknown").trim(),
      retryAllowed: safeRetryPolicy.retryAllowed === true,
      automaticRetryAllowed: safeRetryPolicy.automaticRetryAllowed === true,
      userVisibleRetryOnly: safeRetryPolicy.userVisibleRetryOnly === true,
      cacheMode: String(cachePolicy.mode || "no-cache").trim(),
      noSecretsCached: providerHealth.noSecretsCached === true || cachePolicy.storesSecrets === false,
      noSensitiveUserDataCached: providerHealth.noSensitiveUserDataCached === true || cachePolicy.storesSensitiveUserData === false,
      noExecutionFallback: providerHealth.noExecutionFallback !== false,
      warnings: reliabilityWarnings.slice(0, 7)
    },
    safeFollowUps: assistantRuntimePreviewSuggestions(safeResponse),
    standardUserAgentExperience: agentExperience && agentExperience.schemaVersion === "nexus.nap6.standardUserAgentExperience.v1" ? {
      answerMode: String(agentExperience.answerMode || "informational").trim(),
      displayMode: String(agentExperience.displayMode || "flag-gated-agent-preview").trim(),
      safeNextSteps: Array.isArray(agentExperience.safeNextSteps) ? agentExperience.safeNextSteps.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
      followUpPrompts: Array.isArray(agentExperience.followUpPrompts) ? agentExperience.followUpPrompts.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
      taskPlanPreview: agentExperience.taskPlanPreview && typeof agentExperience.taskPlanPreview === "object" ? {
        goal: String(agentExperience.taskPlanPreview.goal || "").trim(),
        goalType: String(agentExperience.taskPlanPreview.goalType || "informational").trim(),
        nextBestStep: String(agentExperience.taskPlanPreview.nextBestStep || "").trim(),
        confidence: String(agentExperience.taskPlanPreview.confidence || "low").trim(),
        providerQueryMode: String(agentExperience.taskPlanPreview.providerQueryMode || "read-only").trim(),
        steps: Array.isArray(agentExperience.taskPlanPreview.steps) ? agentExperience.taskPlanPreview.steps.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        neededInformation: Array.isArray(agentExperience.taskPlanPreview.neededInformation) ? agentExperience.taskPlanPreview.neededInformation.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        providerQueries: Array.isArray(agentExperience.taskPlanPreview.providerQueries) ? agentExperience.taskPlanPreview.providerQueries.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        safeUserActions: Array.isArray(agentExperience.taskPlanPreview.safeUserActions) ? agentExperience.taskPlanPreview.safeUserActions.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        blockedActions: Array.isArray(agentExperience.taskPlanPreview.blockedActions) ? agentExperience.taskPlanPreview.blockedActions.slice(0, 8).map(item => String(item || "").trim()).filter(Boolean) : [],
        noExecutionAuthorized: agentExperience.taskPlanPreview.noExecutionAuthorized === true
      } : null,
      preparationPreview: agentExperience.preparationPreview && typeof agentExperience.preparationPreview === "object" ? {
        title: String(agentExperience.preparationPreview.title || "").trim(),
        content: Array.isArray(agentExperience.preparationPreview.content) ? agentExperience.preparationPreview.content.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : []
      } : null,
      sourceReview: agentExperience.sourceReview && typeof agentExperience.sourceReview === "object" ? {
        sourceCount: Number(agentExperience.sourceReview.sourceCount || 0),
        citationSummaries: Array.isArray(agentExperience.sourceReview.citationSummaries) ? agentExperience.sourceReview.citationSummaries.slice(0, 3).map(item => ({
          sourceName: String(item.sourceName || "Source unavailable").trim(),
          evidenceStatus: String(item.evidenceStatus || "source-unavailable").trim(),
          freshnessStatus: String(item.freshnessStatus || "unknown").trim()
        })) : []
      } : null,
      artifactPreviews: Array.isArray(agentExperience.artifactPreviews) ? agentExperience.artifactPreviews.slice(0, 3).map(artifact => ({
        type: String(artifact?.type || "checklist").trim(),
        title: String(artifact?.title || "Safe artifact preview").trim(),
        items: Array.isArray(artifact?.items) ? artifact.items.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        columns: Array.isArray(artifact?.columns) ? artifact.columns.slice(0, 4).map(item => String(item || "").trim()).filter(Boolean) : [],
        rows: Array.isArray(artifact?.rows) ? artifact.rows.slice(0, 4).map(row => Array.isArray(row) ? row.slice(0, 4).map(cell => String(cell || "").trim()).filter(Boolean) : []).filter(row => row.length > 0) : [],
        content: Array.isArray(artifact?.content) ? artifact.content.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
        copyOnly: artifact?.copyOnly === true,
        userMustReview: artifact?.userMustReview === true,
        executionAuthority: artifact?.executionAuthority === true,
        providerHandoffAllowed: artifact?.providerHandoffAllowed === true,
        sendAllowed: artifact?.sendAllowed === true,
        submitAllowed: artifact?.submitAllowed === true,
        bookingAllowed: artifact?.bookingAllowed === true,
        paymentAllowed: artifact?.paymentAllowed === true
      })).filter(artifact => artifact.executionAuthority !== true && artifact.providerHandoffAllowed !== true && artifact.sendAllowed !== true && artifact.submitAllowed !== true && artifact.bookingAllowed !== true && artifact.paymentAllowed !== true) : [],
      standardUserWorkflowCard: agentExperience.standardUserWorkflowCard
        && agentExperience.standardUserWorkflowCard.schemaVersion === "nexus.aut6.standardUserWorkflowCard.v1"
        && agentExperience.standardUserWorkflowCard.noExecutionAuthorized === true
        && agentExperience.standardUserWorkflowCard.noProviderHandoff === true
        && agentExperience.standardUserWorkflowCard.noPermissionPromptAuthorized === true
        && agentExperience.standardUserWorkflowCard.dataAttributes?.["data-read-only"] === "true"
        && agentExperience.standardUserWorkflowCard.dataAttributes?.["data-execution-authority"] === "false"
        && agentExperience.standardUserWorkflowCard.dataAttributes?.["data-provider-handoff"] === "false"
        ? {
          workflowId: String(agentExperience.standardUserWorkflowCard.workflowId || "").trim(),
          workflowType: String(agentExperience.standardUserWorkflowCard.workflowType || "").trim(),
          goal: String(agentExperience.standardUserWorkflowCard.goal || "").trim(),
          status: String(agentExperience.standardUserWorkflowCard.status || "preview-only").trim(),
          currentStep: agentExperience.standardUserWorkflowCard.currentStep && typeof agentExperience.standardUserWorkflowCard.currentStep === "object" ? {
            title: String(agentExperience.standardUserWorkflowCard.currentStep.title || "").trim(),
            description: String(agentExperience.standardUserWorkflowCard.currentStep.description || "").trim(),
            index: Number(agentExperience.standardUserWorkflowCard.currentStep.index || 0)
          } : null,
          steps: Array.isArray(agentExperience.standardUserWorkflowCard.steps) ? agentExperience.standardUserWorkflowCard.steps.slice(0, 7).map(step => ({
            title: String(step?.title || "").trim(),
            description: String(step?.description || "").trim(),
            status: String(step?.status || "pending").trim(),
            readOnly: step?.readOnly === true,
            executionProhibited: step?.executionProhibited === true
          })).filter(step => step.title) : [],
          safeArtifacts: Array.isArray(agentExperience.standardUserWorkflowCard.safeArtifacts) ? agentExperience.standardUserWorkflowCard.safeArtifacts.slice(0, 4).map(artifact => ({
            artifactType: String(artifact?.artifactType || "checklist").trim(),
            title: String(artifact?.title || "Safe artifact").trim(),
            noExecutionAuthorized: artifact?.noExecutionAuthorized === true
          })).filter(artifact => artifact.noExecutionAuthorized === true) : [],
          safeNextSteps: Array.isArray(agentExperience.standardUserWorkflowCard.safeNextSteps) ? agentExperience.standardUserWorkflowCard.safeNextSteps.slice(0, 5).map(item => String(item || "").trim()).filter(Boolean) : [],
          sourceDetails: Array.isArray(agentExperience.standardUserWorkflowCard.sourceDetails) ? agentExperience.standardUserWorkflowCard.sourceDetails.slice(0, 5).map(item => ({
            sourceId: String(item?.sourceId || "read-only-source").trim(),
            mode: String(item?.mode || "read-only").trim()
          })) : [],
          safeControls: Array.isArray(agentExperience.standardUserWorkflowCard.safeControls) ? agentExperience.standardUserWorkflowCard.safeControls.slice(0, 9).map(item => String(item || "").trim()).filter(Boolean) : [],
          blockedControls: Array.isArray(agentExperience.standardUserWorkflowCard.blockedControls) ? agentExperience.standardUserWorkflowCard.blockedControls.slice(0, 10).map(item => String(item || "").trim()).filter(Boolean) : [],
          blockedActionsNote: String(agentExperience.standardUserWorkflowCard.blockedActionsNote || "").trim(),
          safetyNote: String(agentExperience.standardUserWorkflowCard.safetyNote || "Read-only workflow preview. No action has been taken.").trim()
        }
        : null,
      blockedUnsafeActionExplanation: String(agentExperience.blockedUnsafeActionExplanation || "").trim(),
      noExecutionAuthorized: agentExperience.noExecutionAuthorized === true,
      noProviderHandoff: agentExperience.noProviderHandoff === true,
      noPermissionPromptAuthorized: agentExperience.noPermissionPromptAuthorized === true,
      noHiddenActionMetadata: agentExperience.noHiddenActionMetadata === true
    } : null,
    safetyNote: "Read-only preview. No action has been taken."
  };
}

function renderAssistantRuntimePreviewCardMarkup(card = {}) {
  const sourceLabels = Array.isArray(card.sourceLabels) && card.sourceLabels.length
    ? card.sourceLabels.map(label => `<span>${htmlSafe(label)}</span>`).join("")
    : "<span>Source label unavailable</span>";
  const citations = Array.isArray(card.citations) && card.citations.length
    ? card.citations.map(citation => `
      <li>
        <strong>${htmlSafe(citation.sourceName)}</strong>
        <span>${htmlSafe(citation.sourceUrl)}</span>
        <span>Evidence: ${htmlSafe(citation.evidenceStatus)}; Freshness: ${htmlSafe(citation.freshnessStatus)}</span>
      </li>
    `).join("")
    : "<li><strong>Source unavailable</strong><span>No citation details were returned.</span></li>";
  const followUps = Array.isArray(card.safeFollowUps) && card.safeFollowUps.length
    ? card.safeFollowUps.map(item => `<button type="button" data-nexus-assistant-runtime-follow-up="${htmlSafe(item)}">${htmlSafe(item)}</button>`).join("")
    : "<span>Ask a follow-up</span>";
  const localTools = card.standardUserAgentExperience && Array.isArray(card.standardUserAgentExperience.artifactPreviews) && card.standardUserAgentExperience.artifactPreviews.length
    ? `
      <div class="nexus-assistant-runtime-local-tools" aria-label="Safe local assistant tools" data-nexus-assistant-runtime-local-tools="true">
        <button type="button" data-nexus-assistant-runtime-local-tool="copy-preview">Copy preview text</button>
        <button type="button" data-nexus-assistant-runtime-local-tool="clear-context">Clear preview</button>
        <button type="button" data-nexus-assistant-runtime-local-tool="restart-task">Restart task</button>
      </div>
    `
    : "";
  const experience = card.standardUserAgentExperience;
  const reliability = card.providerReliability || {};
  const reliabilityWarnings = Array.isArray(reliability.warnings) && reliability.warnings.length
    ? reliability.warnings.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>Provider health did not report additional warnings.</li>";
  const experienceMarkup = experience
    && experience.noExecutionAuthorized === true
    && experience.noProviderHandoff === true
    && experience.noPermissionPromptAuthorized === true
    && experience.noHiddenActionMetadata === true
    ? renderStandardUserAgentExperienceMarkup(experience)
    : "";
  return `
    <section
      class="nexus-assistant-runtime-preview-card"
      data-nexus-assistant-runtime-preview-card="true"
      data-read-only="true"
      data-execution-authority="false"
      data-provider-handoff="false"
      aria-label="Nexus source-backed read-only preview"
    >
      <div class="nexus-assistant-runtime-preview-head">
        <strong>Source-backed preview</strong>
        <span>${htmlSafe(card.safetyNote || "Read-only preview. No action has been taken.")}</span>
      </div>
      <p>${htmlSafe(card.answer)}</p>
      <div class="nexus-assistant-runtime-preview-meta" aria-label="Preview source labels">${sourceLabels}</div>
      <dl class="nexus-assistant-runtime-preview-facts">
        <div><dt>Intent</dt><dd>${htmlSafe(card.intent || "general-question")}</dd></div>
        <div><dt>Provider</dt><dd>${htmlSafe(card.selectedProvider || "provider unavailable")}</dd></div>
        <div><dt>Status</dt><dd>${htmlSafe(card.providerStatus || "unknown")}</dd></div>
        <div><dt>Retrieved</dt><dd>${htmlSafe(card.retrievedAt)}</dd></div>
        <div><dt>Confidence</dt><dd>${htmlSafe(card.confidence)}</dd></div>
        <div><dt>Freshness</dt><dd>${htmlSafe(card.freshnessStatus)}</dd></div>
        <div><dt>Trust</dt><dd>${htmlSafe(card.trustTier || "unavailable")}</dd></div>
        <div><dt>Sources</dt><dd>${htmlSafe(String(Number.isFinite(card.sourceResultCount) ? card.sourceResultCount : 0))}</dd></div>
      </dl>
      <section class="nexus-assistant-runtime-reliability" data-nexus-assistant-runtime-provider-health="true" data-execution-authority="false" data-provider-handoff="false" aria-label="Provider health and reliability">
        <div>
          <strong>Provider health</strong>
          <span>${htmlSafe(reliability.providerDisplayName || card.selectedProvider || "Provider unavailable")} - ${htmlSafe(reliability.providerStatus || card.providerStatus || "unknown")}</span>
        </div>
        <ul>${reliabilityWarnings}</ul>
        <p>Cache: ${htmlSafe(reliability.cacheMode || "no-cache")}. Secrets cached: ${reliability.noSecretsCached === true ? "no" : "unknown"}. Sensitive data cached: ${reliability.noSensitiveUserDataCached === true ? "no" : "unknown"}. Execution fallback: ${reliability.noExecutionFallback === true ? "disabled" : "unknown"}.</p>
      </section>
      <ul class="nexus-assistant-runtime-preview-citations" aria-label="Preview citation details">${citations}</ul>
      <div class="nexus-assistant-runtime-preview-followups" aria-label="Safe follow-up prompts">${followUps}</div>
      ${localTools}
      ${experienceMarkup}
    </section>
  `;
}

function renderStandardUserWorkflowCardMarkup(card = {}) {
  if (!card || typeof card !== "object") return "";
  const list = items => Array.isArray(items) && items.length
    ? items.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>Review the workflow preview before choosing a manual next step.</li>";
  const steps = Array.isArray(card.steps) && card.steps.length
    ? card.steps.map((step, index) => `
      <li data-workflow-step-index="${htmlSafe(String(index))}" data-read-only="true" data-execution-authority="false" data-provider-handoff="false">
        <strong>${htmlSafe(step.title)}</strong>
        <span>${htmlSafe(step.description || "Read-only step")}</span>
        <em>${htmlSafe(step.status || "pending")}</em>
      </li>
    `).join("")
    : "<li data-read-only=\"true\" data-execution-authority=\"false\" data-provider-handoff=\"false\">No workflow steps are available.</li>";
  const artifacts = Array.isArray(card.safeArtifacts) && card.safeArtifacts.length
    ? card.safeArtifacts.map(artifact => `<li>${htmlSafe(artifact.title)} <span>${htmlSafe(artifact.artifactType)}</span></li>`).join("")
    : "<li>No safe artifacts prepared yet.</li>";
  const sources = Array.isArray(card.sourceDetails) && card.sourceDetails.length
    ? card.sourceDetails.map(source => `<li>${htmlSafe(source.sourceId)} <span>${htmlSafe(source.mode || "read-only")}</span></li>`).join("")
    : "<li>No provider/source query is required yet.</li>";
  const safeControls = Array.isArray(card.safeControls) && card.safeControls.length
    ? card.safeControls.map(control => `<button type="button" disabled aria-disabled="true" data-nexus-aut-workflow-control="${htmlSafe(control)}">${htmlSafe(control)}</button>`).join("")
    : "";
  return `
    <section
      class="nexus-aut-workflow-card"
      data-nexus-aut-workflow-card="true"
      data-read-only="true"
      data-execution-authority="false"
      data-provider-handoff="false"
      aria-label="Nexus controlled workflow preview"
    >
      <div class="nexus-aut-workflow-card-head">
        <strong>Controlled workflow</strong>
        <span>${htmlSafe(card.safetyNote || "Read-only workflow preview. No action has been taken.")}</span>
      </div>
      <dl class="nexus-aut-workflow-card-meta">
        <div><dt>Goal</dt><dd>${htmlSafe(card.goal || "Safe workflow")}</dd></div>
        <div><dt>Type</dt><dd>${htmlSafe(card.workflowType || "general_assistant_plan_workflow")}</dd></div>
        <div><dt>Status</dt><dd>${htmlSafe(card.status || "preview-only")}</dd></div>
        <div><dt>Current step</dt><dd>${htmlSafe(card.currentStep?.title || "Review the plan")}</dd></div>
      </dl>
      <section aria-label="Workflow progress">
        <strong>Progress</strong>
        <ol>${steps}</ol>
      </section>
      <section aria-label="Safe workflow artifacts">
        <strong>Safe artifacts</strong>
        <ul>${artifacts}</ul>
      </section>
      <section aria-label="Read-only source details">
        <strong>Source details</strong>
        <ul>${sources}</ul>
      </section>
      <section aria-label="Safe workflow controls">
        <strong>Safe controls</strong>
        <div class="nexus-aut-workflow-controls">${safeControls}</div>
        <p>Controls are review-only in this phase. They do not call providers, write backend state, request permissions, navigate, or execute actions.</p>
      </section>
      <section aria-label="Safe next steps">
        <strong>Safe next steps</strong>
        <ul>${list(card.safeNextSteps)}</ul>
      </section>
      <section aria-label="Blocked workflow actions">
        <strong>Blocked actions</strong>
        <p>${htmlSafe(card.blockedActionsNote || "Unsafe actions remain blocked.")}</p>
        <ul>${list(card.blockedControls)}</ul>
      </section>
    </section>
  `;
}

function renderStandardUserAgentExperienceMarkup(experience = {}) {
  const list = items => Array.isArray(items) && items.length
    ? items.map(item => `<li>${htmlSafe(item)}</li>`).join("")
    : "<li>Review the answer and ask a safe follow-up.</li>";
  const plan = experience.taskPlanPreview || {};
  const prep = experience.preparationPreview || {};
  const sourceReview = experience.sourceReview || {};
  const sourceItems = Array.isArray(sourceReview.citationSummaries) && sourceReview.citationSummaries.length
    ? sourceReview.citationSummaries.map(item => `<li>${htmlSafe(item.sourceName)} - evidence ${htmlSafe(item.evidenceStatus)}; freshness ${htmlSafe(item.freshnessStatus)}</li>`).join("")
    : "<li>No additional citation summary is available.</li>";
  const blocked = experience.blockedUnsafeActionExplanation
    ? `<p>${htmlSafe(experience.blockedUnsafeActionExplanation)}</p>`
    : "";
  const artifactRows = Array.isArray(experience.artifactPreviews) && experience.artifactPreviews.length
    ? experience.artifactPreviews.map(artifact => {
      const type = String(artifact.type || "checklist");
      const title = htmlSafe(artifact.title || "Safe artifact preview");
      if (type === "comparison" && Array.isArray(artifact.rows) && artifact.rows.length) {
        const columns = Array.isArray(artifact.columns) && artifact.columns.length
          ? artifact.columns
          : ["Option", "What to compare", "Manual review"];
        const header = columns.map(column => `<th scope="col">${htmlSafe(column)}</th>`).join("");
        const rows = artifact.rows.map(row => `<tr>${row.map(cell => `<td>${htmlSafe(cell)}</td>`).join("")}</tr>`).join("");
        return `<article data-nexus-safe-artifact-preview="true" data-artifact-type="comparison" data-execution-authority="false" data-provider-handoff="false"><strong>${title}</strong><table><thead><tr>${header}</tr></thead><tbody>${rows}</tbody></table></article>`;
      }
      const content = type === "draft-text" ? artifact.content : artifact.items;
      return `<article data-nexus-safe-artifact-preview="true" data-artifact-type="${htmlSafe(type)}" data-execution-authority="false" data-provider-handoff="false"><strong>${title}</strong><ul>${list(content)}</ul></article>`;
    }).join("")
    : `<article data-nexus-safe-artifact-preview="true" data-artifact-type="checklist" data-execution-authority="false" data-provider-handoff="false"><strong>Safe artifact preview</strong><ul>${list([])}</ul></article>`;
  const workflowCardMarkup = experience.standardUserWorkflowCard ? renderStandardUserWorkflowCardMarkup(experience.standardUserWorkflowCard) : "";
  return `
    <div class="nexus-assistant-runtime-agent-experience" data-nexus-nap6-agent-experience="true" data-execution-authority="false" data-provider-handoff="false" data-permission-prompt="false">
      <div>
        <strong>Agent preview</strong>
        <span>${htmlSafe(experience.answerMode || "informational")} - ${htmlSafe(experience.displayMode || "flag-gated-agent-preview")}</span>
      </div>
      <section aria-label="Safe next steps">
        <strong>Safe next steps</strong>
        <ul>${list(experience.safeNextSteps)}</ul>
      </section>
      <section aria-label="Task plan preview">
        <strong>Plan preview</strong>
        <p>${htmlSafe(plan.goal || "Goal: safe informational support")} - ${htmlSafe(plan.goalType || "informational")} - ${htmlSafe(plan.confidence || "low")} confidence - ${htmlSafe(plan.providerQueryMode || "read-only")} provider queries</p>
        <p>${htmlSafe(plan.nextBestStep || "Review the source-backed answer before choosing a manual next step.")}</p>
        <ul>${list(plan.steps)}</ul>
      </section>
      <section aria-label="Planner inputs and safe actions">
        <strong>Planner inputs and safe actions</strong>
        <p>Needed information</p>
        <ul>${list(plan.neededInformation)}</ul>
        <p>Read-only provider queries</p>
        <ul>${list(plan.providerQueries)}</ul>
        <p>Safe user actions</p>
        <ul>${list(plan.safeUserActions)}</ul>
        <p>Blocked execution actions</p>
        <ul>${list(plan.blockedActions)}</ul>
      </section>
      <section aria-label="Preparation preview">
        <strong>${htmlSafe(prep.title || "Preparation preview")}</strong>
        <ul>${list(prep.content)}</ul>
      </section>
      <section aria-label="Source review">
        <strong>Source review</strong>
        <ul>${sourceItems}</ul>
      </section>
      <section class="nexus-assistant-runtime-artifacts" aria-label="Safe artifact previews">
        <strong>Safe artifact previews</strong>
        ${artifactRows}
      </section>
      ${workflowCardMarkup}
      <section aria-label="Safe follow-up prompts">
        <strong>Follow-up prompts</strong>
        <ul>${list(experience.followUpPrompts)}</ul>
      </section>
      ${blocked}
      <p>Preview only - no call, message, provider contact, permission request, navigation, payment, booking, dispatch, or submission has been started.</p>
    </div>
  `;
}

function clearAssistantRuntimePreviewCard() {
  assistantRuntimePreviewCard = null;
  $$("[data-nexus-assistant-runtime-preview-card]").forEach(card => card.remove());
}

function renderAssistantRuntimePreviewCard(response = {}) {
  if (!isNexusAssistantRuntimePreviewEnabled()) {
    clearAssistantRuntimePreviewCard();
    return;
  }
  const container = [$("#globalConversationPanel"), $("#jarvisInsightPanel"), $("#globalAssistantBar")]
    .find(panel => panel && getComputedStyle(panel).display !== "none" && panel.getClientRects().length > 0)
    || $("#globalAssistantBar");
  if (!container) return;
  clearAssistantRuntimePreviewCard();
  assistantRuntimePreviewCard = normalizeAssistantRuntimePreviewCard(response);
  container.insertAdjacentHTML("afterbegin", renderAssistantRuntimePreviewCardMarkup(assistantRuntimePreviewCard));
}

async function runStandardUserAssistantRuntimePreview(command = "", options = {}) {
  const prompt = String(command || "").trim();
  if (!prompt || !isNexusAssistantRuntimePreviewEnabled()) return false;
  clearAssistantRuntimePreviewCard();
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  openAskNexus();
  enableHeyAgriNexusMode();
  updateNexusBehaviorLayer("thinking", "Nexus is preparing a source-backed preview. No action will be taken.");
  try {
    const result = await requestWithTimeout("/api/nexus/assistant-runtime-preview", {
      method: "POST",
      body: {
        prompt,
        inputMode: options.source || "typed",
        previewOnly: true
      }
    }, 12000);
    const previewFlags = result.assistantRuntimePreview || {};
    const response = result.response || {};
    if (previewFlags.noExecutionAuthorized !== true || previewFlags.noProviderHandoff !== true || response.noExecutionAuthorized !== true) {
      setVoiceResponse("Nexus kept this request informational. No action was taken.", true, { allowHandoff: false, command: prompt });
      renderLiveVoiceSuggestions(["ask for information only", "cancel"]);
      return true;
    }
    const text = assistantRuntimePreviewText(response) || "Nexus prepared a safe informational preview. No action has been taken.";
    const suggestions = assistantRuntimePreviewSuggestions(response);
    renderLiveVoiceSuggestions(suggestions.length ? suggestions : ["ask a follow-up", "compare sources", "explain simply", "cancel"]);
    updateNexusBehaviorLayer("answering", "Nexus showed a source-backed preview without execution, navigation, or provider handoff.");
    setVoiceResponse(text, true, { allowHandoff: false, command: prompt, source: "standard-user-assistant-runtime-preview" });
    renderAssistantRuntimePreviewCard(response);
    return true;
  } catch (error) {
    clearAssistantRuntimePreviewCard();
    updateNexusBehaviorLayer("ready", "Nexus kept the preview path safe because the source-backed preview was unavailable.");
    setVoiceResponse("I could not load the source-backed preview right now, so I kept this informational and took no action.", true, { allowHandoff: false, command: prompt });
    renderLiveVoiceSuggestions(["try again", "ask a follow-up", "cancel"]);
    return true;
  }
}

function handleAssistantRuntimeFollowUpClick(event) {
  const button = event.target.closest("[data-nexus-assistant-runtime-follow-up]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const followUp = String(button.dataset.nexusAssistantRuntimeFollowUp || button.textContent || "").trim();
  if (!isSafeAssistantRuntimeFollowUpChip(followUp)) {
    setVoiceResponse("Nexus kept that follow-up informational. No action was taken.", true, { allowHandoff: false });
    return true;
  }
  const previous = assistantRuntimePreviewCard?.userPrompt
    || assistantRuntimePreviewCard?.answer
    || "the previous source-backed preview";
  const refinementPrompt = `${followUp}. Use the previous source-backed preview context: ${previous}`;
  runStandardUserAssistantRuntimePreview(refinementPrompt, { source: "safe-follow-up-chip" });
  return true;
}

function assistantRuntimeLocalToolText(card = assistantRuntimePreviewCard) {
  if (!card || typeof card !== "object") return "";
  const lines = [
    `Nexus preview: ${card.answer || "No answer text available."}`,
    `Intent: ${card.intent || "unknown"}`,
    `Provider: ${card.selectedProvider || "provider unavailable"}`,
    `Confidence: ${card.confidence || "unknown"}`,
    `Freshness: ${card.freshnessStatus || "unknown"}`,
    "Safety: read-only preview; no action has been taken."
  ];
  const experience = card.standardUserAgentExperience || {};
  const plan = experience.taskPlanPreview || {};
  if (Array.isArray(plan.steps) && plan.steps.length) {
    lines.push("Plan steps:");
    plan.steps.forEach((step, index) => lines.push(`${index + 1}. ${step}`));
  }
  if (Array.isArray(experience.artifactPreviews) && experience.artifactPreviews.length) {
    lines.push("Safe artifact previews:");
    experience.artifactPreviews.forEach(artifact => {
      lines.push(`- ${artifact.title || artifact.type || "Artifact"}`);
    });
  }
  return lines.join("\n");
}

async function handleAssistantRuntimeLocalToolClick(event) {
  const button = event.target.closest("[data-nexus-assistant-runtime-local-tool]");
  if (!button) return false;
  event.preventDefault();
  event.stopPropagation();
  const tool = String(button.dataset.nexusAssistantRuntimeLocalTool || "").trim();
  if (!assistantRuntimePreviewCard || assistantRuntimePreviewCard.standardUserAgentExperience?.noExecutionAuthorized !== true) {
    setVoiceResponse("Nexus kept the local tool unavailable because there is no safe preview to use.", true, { allowHandoff: false });
    return true;
  }
  if (tool === "copy-preview") {
    const textToCopy = assistantRuntimeLocalToolText();
    if (navigator.clipboard && typeof navigator.clipboard.writeText === "function") {
      await navigator.clipboard.writeText(textToCopy);
      setVoiceResponse("Copied the read-only Nexus preview text. No action was taken.", true, { allowHandoff: false });
    } else {
      setVoiceResponse("Copy is not available in this browser. The preview remains read-only and no action was taken.", true, { allowHandoff: false });
    }
    return true;
  }
  if (tool === "clear-context") {
    clearAssistantRuntimePreviewCard();
    renderLiveVoiceSuggestions(["ask a new question", "find training", "find farm jobs"]);
    setVoiceResponse("Cleared the local preview. No provider, message, call, payment, booking, or location action was started.", true, { allowHandoff: false });
    return true;
  }
  if (tool === "restart-task") {
    const prompt = String(assistantRuntimePreviewCard.userPrompt || "").trim();
    if (!prompt) {
      setVoiceResponse("Nexus needs a previous safe prompt before it can restart this task.", true, { allowHandoff: false });
      return true;
    }
    runStandardUserAssistantRuntimePreview(prompt, { source: "safe-local-tool-restart" });
    return true;
  }
  setVoiceResponse("Nexus ignored that local tool because it is not supported. No action was taken.", true, { allowHandoff: false });
  return true;
}

function leafletMapOptions(options = {}) {
  return {
    zoomControl: true,
    attributionControl: true,
    scrollWheelZoom: true,
    tap: true,
    worldCopyJump: true,
    // SVG is Leaflet's default renderer and avoids noisy canvas teardown errors
    // when demo maps are opened, closed, and recreated during guided flows.
    preferCanvas: false,
    zoomSnap: 1,
    zoomDelta: 1,
    wheelPxPerZoomLevel: MAP_ZOOM_CONFIG.wheelPxPerZoomLevel,
    minZoom: MAP_ZOOM_CONFIG.minZoom,
    maxZoom: MAP_ZOOM_CONFIG.maxZoom,
    ...options
  };
}

function leafletTileOptions(options = {}) {
  return {
    minZoom: MAP_ZOOM_CONFIG.minZoom,
    maxZoom: MAP_ZOOM_CONFIG.maxZoom,
    maxNativeZoom: MAP_ZOOM_CONFIG.maxNativeZoom,
    detectRetina: true,
    updateWhenZooming: true,
    updateWhenIdle: false,
    keepBuffer: 3,
    crossOrigin: true,
    ...options
  };
}

function globalMapBounds() {
  return L.latLngBounds([[-60, -180], [80, 180]]);
}

function mapGridLabel(value, axis) {
  if (value === 0) return "0 deg";
  if (axis === "lat") return `${Math.abs(value)} deg ${value > 0 ? "N" : "S"}`;
  return `${Math.abs(value)} deg ${value > 0 ? "E" : "W"}`;
}

function createGlobalGridLayer() {
  const layer = L.layerGroup();
  const lineStyle = {
    color: "#173240",
    weight: 1,
    opacity: .28,
    interactive: false,
    pane: "mapGrid"
  };
  for (let lat = -60; lat <= 75; lat += 15) {
    L.polyline([[lat, -180], [lat, 180]], lineStyle).addTo(layer);
    L.marker([lat, -176], {
      interactive: false,
      icon: L.divIcon({
        className: "map-grid-label",
        html: mapGridLabel(lat, "lat"),
        iconSize: [58, 18],
        iconAnchor: [0, 9]
      })
    }).addTo(layer);
  }
  for (let lng = -180; lng <= 180; lng += 30) {
    L.polyline([[-60, lng], [80, lng]], lineStyle).addTo(layer);
    L.marker([78, lng], {
      interactive: false,
      icon: L.divIcon({
        className: "map-grid-label map-grid-label-lng",
        html: mapGridLabel(lng, "lng"),
        iconSize: [64, 18],
        iconAnchor: [32, 9]
      })
    }).addTo(layer);
  }
  return layer;
}

function addGlobalMapControl(targetMap) {
  const control = L.control({ position: "topleft" });
  control.onAdd = () => {
    const wrap = L.DomUtil.create("div", "leaflet-bar global-map-control");
    const button = L.DomUtil.create("button", "", wrap);
    button.type = "button";
    button.title = translateText("Zoom to global map");
    button.setAttribute("aria-label", translateText("Zoom to global map"));
    button.textContent = translateText("Global");
    L.DomEvent.disableClickPropagation(wrap);
    L.DomEvent.on(button, "click", event => {
      L.DomEvent.preventDefault(event);
      targetMap.fitBounds(globalMapBounds(), { padding: [22, 22], maxZoom: 2 });
    });
    return wrap;
  };
  control.addTo(targetMap);
}

function startAskNexusAfterLogin() {
  if (voiceDemoQuietMode) {
    disableNexusVoiceForDemo("Demo quiet mode is on. Nexus voice will stay off until you turn it back on.", { silent: true });
    return;
  }
  voiceFirstMode = false;
  voiceAutoRestart = false;
  voiceStopRequested = true;
  localStorage.removeItem("agrinexusVoiceFirst");
  nexusAwaitingCommand = true;
  setVoiceStatus("standby");
  const message = `Welcome ${userFirstName()}. Nexus is ready. Click Talk to Nexus or type a request. I will keep important actions review-only.`;
  recordNexusAutonomousLearning({ type: "login-greeting", command: "Nexus ready after login" });
  if (defaultExperienceMode() !== "user") {
    openAskNexus();
  } else {
    closeAskNexus({ silent: true });
  }
  setVoiceResponse(message, false, { allowVoiceFirst: false });
  updateUserCaptionPanel(message, { expanded: false });
  [80, 360, 900, 1800].forEach(delay => {
    setTimeout(() => {
      if (!voiceDemoQuietMode && !document.hidden && voiceFirstMode && !voiceRecognition && !voiceSpeaking && !voiceStopRequested) {
        startVoiceListening();
      }
    }, delay);
  });
}

function surroundingMapBounds(route = activeRoute(), country = activeCountry()) {
  const points = [
    ...(route?.points || []),
    ...((data?.countries || []).map(item => [item.lat, item.lng])),
    [country.lat + 1.8, country.lng - 2.2],
    [country.lat - 1.6, country.lng + 2.3],
    [country.lat + 1.1, country.lng + 1.8]
  ].filter(point => Array.isArray(point) && Number.isFinite(Number(point[0])) && Number.isFinite(Number(point[1])));
  const bounds = points.length ? L.latLngBounds(points) : L.latLngBounds([[-35, -20], [36, 55]]);
  return bounds.pad(.35);
}

function fitMapToSurroundingRegion(targetMap, route = activeRoute(), country = activeCountry(), maxZoom = 5) {
  const bounds = surroundingMapBounds(route, country);
  if (bounds.isValid?.()) {
    targetMap.fitBounds(bounds, { padding: [34, 34], maxZoom });
  } else {
    targetMap.setView([3.2, 20.5], 3);
  }
}

function addOperationalCountryMarkers(targetMap, markerLayer, country = activeCountry(), { health = false } = {}) {
  const riskColor = risk => {
    const value = String(risk || "").toLowerCase();
    if (value.includes("high")) return "#d94c31";
    if (value.includes("moderate") || value.includes("elevated")) return "#d9a71d";
    return "#1b8f68";
  };
  (data.countries || []).forEach(item => {
    const active = item.id === country.id;
    const color = health ? riskColor(item.risk) : active ? "#d94c31" : "#1b8f68";
    L.circleMarker([item.lat, item.lng], {
      radius: active ? 12 : 8,
      color: active ? "#173240" : color,
      fillColor: color,
      fillOpacity: active ? .9 : .72,
      weight: active ? 4 : 2
    })
      .addTo(markerLayer)
      .bindPopup(`<strong>${translateText(item.name)}</strong><br>${item.facilities} ${translateText("facilities")}<br>${translateText(item.risk || "Monitored")} ${translateText("risk")}<br>${translateText(item.queue || "Operational area")}`);
  });
}

function addNearbyFacilityMarkers(layer, country = activeCountry(), label = "Facility") {
  [[country.lat + .7, country.lng - .8], [country.lat - .5, country.lng + .9], [country.lat + .3, country.lng + .5]].forEach((point, index) => {
    L.circleMarker(point, {
      radius: 7,
      color: "#173240",
      fillColor: "#ffffff",
      fillOpacity: 1,
      weight: 3
    }).addTo(layer).bindPopup(`<strong>${translateText(label)} ${index + 1}</strong><br>${translateText("Nearby support point")}`);
  });
}

