let workflowVideoStream = null;

async function startWorkflowCamera() {
  const video = $("#workflowVideoPreview");
  if (!video || !navigator.mediaDevices?.getUserMedia) {
    setVoiceResponse("This browser cannot open the camera here. The workflow still creates the video handoff record and fallback contact options.", true);
    return;
  }
  try {
    stopWorkflowCamera();
    workflowVideoStream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
    video.srcObject = workflowVideoStream;
    setVoiceResponse("Camera is open. Ask permission before showing private details. Press confirm when the video handoff is ready.", true);
  } catch (error) {
    setVoiceResponse(`Camera could not open: ${error.message || "permission blocked"}. The workflow can still create a video-ready handoff record.`, true);
  }
}

function stopWorkflowCamera() {
  if (workflowVideoStream) {
    workflowVideoStream.getTracks().forEach(track => track.stop());
    workflowVideoStream = null;
  }
  const video = $("#workflowVideoPreview");
  if (video) video.srcObject = null;
}

function openWorkflowModal(config) {
  pendingWorkflow = config;
  document.body.classList.add("workflow-open");
  lastFocusedElement = document.activeElement;
  closeAskNexus({ silent: true });
  $("#workflowModal")?.classList.remove("grandma-workflow");
  $("#workflowModal")?.classList.toggle("user-full-workflow", experienceMode === "user");
  $("#workflowEyebrow").textContent = translateText(config.eyebrow || "Workflow");
  $("#workflowTitle").textContent = translateText((experienceMode === "user" && config.userTitle) || config.title || "Workflow");
  $("#workflowSummary").textContent = translateText((experienceMode === "user" && config.userSummary) || config.summary || "Review this workflow and confirm when ready.");
  $("#workflowComfort").innerHTML = workflowComfortHtml(config);
  stopWorkflowCamera();
  $("#workflowShipmentMap").innerHTML = `${workflowOperatingScreenHtml(config)}${videoSessionPreviewHtml(config)}`;
  $("#workflowSteps").innerHTML = workflowStepHtml(config.steps || []);
  $("#workflowFields").innerHTML = workflowFieldsHtml(config.fields || [], "workflow-fields");
  $("#workflowChecklist").innerHTML = (config.checklist || []).map(item => taskItem(item.title, item.detail, item.status || "ready", item.label || "Ready")).join("");
  $("#workflowOutcome").innerHTML = workflowOutcomeHtml(config);
  $("#workflowNote").value = config.note || "";
  $("#workflowConfirm").textContent = translateText(config.confirmLabel || "Confirm action");
  $("#workflowCancel").textContent = translateText("Cancel");
  $("#workflowVoiceInput").value = "";
  $("#workflowVoicePrompt").textContent = translateText("Voice ready: say yes to confirm, no to cancel, or read to hear this workflow.");
  $("#workflowModal").classList.remove("hidden");
  try {
    renderWorkflowLiveMap(config);
  } catch (error) {
    console.error("Workflow map failed to render", error);
    const mapCanvas = $("#workflowLiveMapCanvas");
    if (mapCanvas) {
      mapCanvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Map could not load in this window. The workflow is still open; refresh map or continue the action safely.")}</div>`;
    }
  }
  $("#workflowStartCamera")?.addEventListener("click", startWorkflowCamera);
  $("#workflowStopCamera")?.addEventListener("click", stopWorkflowCamera);
  $("[data-workflow-focus-field]")?.addEventListener("click", () => {
    const field = $("[data-workflow-field]");
    if (field) field.focus();
  });
  $("#workflowConfirm").focus();
  const instruction = `${translateText((experienceMode === "user" && config.userTitle) || config.title || "Workflow")}. ${translateText((experienceMode === "user" && config.userSummary) || config.summary || "Review this workflow and confirm when ready.")}. Say yes to confirm, no to cancel, or read to hear the workflow.`;
  recordVoiceEvent(`Workflow ready: ${(experienceMode === "user" && config.userTitle) || config.title || "Workflow"}.`, "progress");
  announce(instruction);
  setVoiceResponse(instruction, false, { allowVoiceFirst: true });
}

function workflowFieldValues() {
  const fields = activeWorkflowFieldCandidates();
  return Object.fromEntries(fields.map(field => [field.dataset.workflowField, field.value]));
}

function lessonWorkflowConfig(course, moduleIndex) {
  const localized = translatedCourse(course);
  const enrollment = courseEnrollment(course.id) || {};
  const modules = localized.modules || [];
  const selectedIndex = Math.max(0, Math.min(moduleIndex ?? enrollment.activeModuleIndex ?? 0, Math.max(0, modules.length - 1)));
  return {
    eyebrow: "Learning workflow",
    title: `Complete lesson: ${modules[selectedIndex] || localized.title}`,
    userTitle: "Finish this lesson",
    summary: "Review the lesson context, confirm progress, and add a note before the learning record is updated.",
    userSummary: `Complete ${modules[selectedIndex] || localized.title}. AgriNexus saves progress, learning hours, and the next recommended step.`,
    confirmLabel: "Complete lesson",
    record: "Enrollment progress, learning hours, readiness, and active module state",
    provider: "Learning record updates immediately; certificate provider is used when issuing credentials.",
    guide: "This marks the lesson complete, moves the learner forward, and keeps the course record ready for certificate and workforce use.",
    steps: [
      { title: "Review lesson", detail: modules[selectedIndex] || localized.title },
      { title: "Confirm support", detail: "Captions, audio, large print, or instructor help stay connected." },
      { title: "Save progress", detail: "Press Complete lesson to update the learner record." }
    ],
    path: "/api/learning/lesson",
    body: { courseId: course.id, moduleIndex: selectedIndex },
    success: "Lesson completed",
    userOutcome: "AgriNexus marks the lesson complete and prepares the next learning step.",
    userRecord: "Course progress, readiness, learning hours, accessibility support, and activity history are updated.",
    checklist: [
      { title: localized.title, detail: `${enrollment.progress || 0}% current progress`, status: enrollment.progress ? "live" : "pending", label: "Course" },
      { title: "Selected module", detail: modules[selectedIndex] || "Core lesson", status: "live", label: `Step ${selectedIndex + 1}` },
      { title: "Completion evidence", detail: "Progress, hours, readiness, and activity feed will update.", status: "ready", label: "Record" }
    ]
  };
}

function roleWorkflowConfig(roleId) {
  const role = data.roles.find(item => item.id === roleId) || firstEligibleRole();
  if (!role) return null;
  const gate = roleGate(role);
  const application = (data.profile.applications || []).find(item => item.roleId === role.id);
  const missingCourses = gate.missingCertificates.map(id => data.courses.find(course => course.id === id)?.title || id);
  const blocked = !gate.eligible;
  const userCopy = workforceUserCopy("apply-role", role, blocked);
  return {
    eyebrow: application ? "Application record" : blocked ? "Readiness review" : "Workforce application",
    title: application ? `Application submitted: ${role.title}` : blocked ? `Review gaps: ${role.title}` : `Apply for role: ${role.title}`,
    userTitle: application ? "You already applied" : userCopy.title,
    summary: blocked
      ? "This role is not unlocked yet. Review the exact readiness and certificate gaps before submitting."
      : application
        ? "This job application is already saved. Review the status and continue to interview, mentor, or shift planning."
        : "Confirm role fit, readiness, and provider handoff before submitting the application.",
    userSummary: application ? `${role.title} is already applied with status ${application.status || "submitted"}.` : userCopy.summary,
    confirmLabel: application ? "Review application" : blocked ? "Open learning path" : "Submit application",
    record: blocked ? "No application is submitted; use this review to guide training next steps." : application ? "Existing application, candidate stage, interview path, and activity feed" : "Application, candidate stage, HRIS event, and activity feed",
    provider: blocked ? "Learning and readiness gates determine eligibility." : "Workforce HRIS provider records the application event.",
    guide: userCopy.guide,
    steps: userCopy.steps,
    path: blocked ? null : application ? "/api/workflow/record" : "/api/workforce/apply",
    redirectSection: blocked ? "learning" : null,
    body: application
      ? { module: "Workforce", action: "application.reviewed", section: "workforce", detail: `${role.title} application reviewed from User mode.` }
      : { roleId: role.id },
    success: blocked ? "Review gaps opened" : application ? "Application reviewed" : "Application submitted",
    userOutcome: blocked ? "AgriNexus shows the exact training gap before applying." : application ? "AgriNexus keeps the application visible and prepares the next workforce step." : "AgriNexus submits the job application and prepares the interview path.",
    userRecord: blocked ? "Readiness, certificates, and missing steps stay visible for learning support." : application ? "Submitted application, role, status, interview, mentor, and shift evidence stay connected." : "Application, role, readiness, HR evidence, interview path, and notifications stay connected.",
    checklist: [
      { title: "Readiness gate", detail: `${data.profile.readiness}% current / ${role.minReadiness}% required`, status: gate.missingReadiness ? "blocked" : "ready", label: gate.missingReadiness ? `${gate.missingReadiness}% gap` : "Met" },
      { title: "Certificates", detail: missingCourses.length ? missingCourses.join(", ") : "Required certificates are complete", status: missingCourses.length ? "blocked" : "ready", label: missingCourses.length ? "Gaps" : "Met" },
      { title: "Role terms", detail: `${role.country} - ${role.level} - ${money(role.rate || 0)}/shift`, status: "live", label: "Role" }
    ]
  };
}

function simpleWorkflowConfig({ eyebrow, title, userTitle, summary, userSummary, confirmLabel, path, body, redirectSection, success, record, provider, checklist, fields, guide, steps, routePreview, healthPreview, videoPreview, userOutcome, userRecord }) {
  return { eyebrow, title, userTitle, summary, userSummary, confirmLabel, path, body, redirectSection, success, record, provider, checklist, fields, guide, steps, routePreview, healthPreview, videoPreview, userOutcome, userRecord };
}

function courseSelectOptions() {
  return (data.courses || []).map(course => ({ value: course.id, label: `${translatedCourse(course).title} - ${translatedCourse(course).track}` }));
}

function productSelectOptions() {
  return (data.products || []).map(product => ({ value: product.id, label: `${product.name} - ${money(product.price || 0)} - ${product.country}` }));
}

function routeSelectOptions() {
  return (data.routes || []).map(route => ({ value: route.id, label: `${route.name} - ${route.checkpoints.length} checkpoints` }));
}

