function bindDynamic() {
  $$("[data-persona]").forEach(button => {
    button.onclick = () => {
      selectedPersona = button.dataset.persona || "farmer";
      localStorage.setItem("agrinexusPersona", selectedPersona);
      renderSimpleHome();
      toast(`${button.textContent.trim()} view selected`);
    };
  });
  $$("[data-simple-command], [data-simple-section], [data-simple-pilot], [data-simple-demo], [data-simple-mission], [data-simple-action]").forEach(button => {
    button.onclick = runSimpleAction;
  });
  $$("[data-user-language]").forEach(button => {
    button.onclick = event => {
      event.preventDefault();
      event.stopPropagation();
      mutate("/api/user/language", { language: button.dataset.userLanguage }, platformCopy[button.dataset.userLanguage]?.languageToast || "Platform language updated");
    };
  });
  $$(".course").forEach(button => button.onclick = () => {
    const course = data.courses.find(item => item.id === button.dataset.course);
    if (course) {
      data.profile.activeCourseId = course.id;
      openWorkflowModal(workflowConfig("learning", "start", { dataset: {} }));
    }
  });
  $$("[data-course-action]").forEach(card => card.onclick = event => {
    if (event.target.closest("button")) return;
    const course = data.courses.find(item => item.id === card.dataset.courseAction);
    if (course) {
      data.profile.activeCourseId = course.id;
      openWorkflowModal(workflowConfig("learning", "start", { dataset: {} }));
    }
  });
  $$(".track-card").forEach(card => card.onclick = () => {
    selectedLearningTrack = card.dataset.track;
    render();
    toast(selectedLearningTrack === "All" ? "Showing all tracks" : `${selectedLearningTrack} track selected`);
  });
  $$(".lesson-step").forEach(button => button.onclick = () => {
    const course = data.courses.find(item => item.id === button.dataset.course);
    if (course) openWorkflowModal(lessonWorkflowConfig(course, Number(button.dataset.moduleIndex)));
  });
  $$(".catalog-lesson").forEach(button => button.onclick = event => {
    event.stopPropagation();
    const course = data.courses.find(item => item.id === button.dataset.course);
    const enrollment = course ? courseEnrollment(course.id) : null;
    if (course) openWorkflowModal(lessonWorkflowConfig(course, enrollment?.activeModuleIndex || 0));
  });
  $$(".apply").forEach(button => button.onclick = () => openWorkflowModal(roleWorkflowConfig(button.dataset.role)));
  $$(".role-card").forEach(card => card.onclick = event => {
    if (event.target.closest("button")) return;
    openWorkflowModal(roleWorkflowConfig(card.dataset.roleCard));
  });
  $$(".order").forEach(button => button.onclick = () => openWorkflowModal(workflowConfig("trade", "order", { dataset: { productId: button.dataset.productId } })));
  $$(".product-card").forEach(card => card.onclick = event => {
    if (event.target.closest("button")) return;
    openWorkflowModal(workflowConfig("trade", "order", { dataset: { productId: card.dataset.productCard } }));
  });
  $$(".provider-test").forEach(button => button.onclick = () => openWorkflowModal(workflowConfig("integrations", "test-provider", { dataset: { providerId: button.dataset.provider } })));
  $$(".provider-card").forEach(card => card.onclick = event => {
    if (event.target.closest("button")) return;
    const providerId = card.querySelector("[data-provider]")?.dataset.provider;
    if (providerId) openWorkflowModal(workflowConfig("integrations", "test-provider", { dataset: { providerId } }));
  });
  $$("[data-module-test]").forEach(button => button.onclick = event => {
    event.stopPropagation();
    openWorkflowModal(workflowConfig("integrations", "test-module", { dataset: { module: button.dataset.moduleTest } }));
  });
  $$("[data-provider-workflow]").forEach(button => button.onclick = event => {
    event.stopPropagation();
    openTelehealthProviderWorkflow(button.dataset.providerWorkflow, button.dataset.encounterId);
  });
  $$("[data-workflow]").forEach(element => element.onclick = event => {
    event.stopPropagation();
    runWorkflowAction(element.dataset.workflow, element.dataset.action, element);
  });
  $$("[data-download-receipt]").forEach(button => {
    button.onclick = event => {
      event.preventDefault();
      event.stopPropagation();
      downloadTransactionReceipt(button.dataset.downloadReceipt, button.dataset.receiptId);
    };
  });
  $$(".dashboard-jump").forEach(button => button.onclick = event => {
    event.stopPropagation();
    goSection(button.dataset.jump);
  });
  $$(".dashboard-card").forEach(card => card.onclick = () => goSection(card.dataset.jump));
}

async function mutate(path, body, success) {
  try {
    const previousLanguage = languageCode();
    updateNexusBehaviorLayer("thinking", "Nexus is running the selected workflow.");
    data = await request(path, { method: "POST", body });
    render();
    if (path === "/api/user/language") {
      refreshLanguageEverywhere();
      if (previousLanguage !== languageCode()) refreshVoiceForLanguageChange();
    }
    updateNexusBehaviorLayer("ready", success || "Workflow complete.");
    toast(success);
  } catch (error) {
    updateNexusBehaviorLayer("ready", error.message || "Workflow needs attention.");
    toast(error.message);
  }
}

async function runLiveInvestorDemoMode() {
  const button = $("#liveInvestorDemoBtn");
  if (button) {
    button.disabled = true;
    button.textContent = "Running...";
  }
  try {
    data = await request("/api/demo/investor-live", { method: "POST", body: { scenario: "farmer-market" } });
    render();
    const demo = data.liveInvestorDemoResult?.demo || (data.profile.liveInvestorDemos || [])[0];
    const message = demo?.narratorScript?.join(" ") || "Live investor mode completed with pilot evidence, AI orchestration, and export packet.";
    setVoiceResponse(message, true);
    toast("Live investor mode complete");
  } catch (error) {
    toast(error.message);
  } finally {
    if (button) {
      button.disabled = false;
      button.textContent = "Run live investor mode";
    }
  }
}

async function exportEvidencePacket() {
  try {
    data = await request("/api/evidence/export", { method: "POST", body: { audience: "investor" } });
    render();
    const packet = data.evidenceExportResult;
    if (packet?.content) {
      const blob = new Blob([packet.content], { type: "text/markdown;charset=utf-8" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(blob);
      link.download = `agrinexus-evidence-${new Date().toISOString().slice(0, 10)}.md`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      setTimeout(() => URL.revokeObjectURL(link.href), 1000);
    }
    toast("Evidence packet exported");
  } catch (error) {
    toast(error.message);
  }
}

function transactionReceiptCatalog() {
  const profile = data?.profile || {};
  return [
    ...(profile.walletTransactions || []).map(item => ({
      type: "wallet",
      id: item.id,
      receiptNumber: item.receiptNumber || `AN-WALLET-${String(item.id || "").slice(0, 8)}`,
      module: "AgriTrade",
      title: item.provider || "Wallet transaction",
      status: item.status || "posted",
      amount: item.amount,
      grossAmount: item.grossAmount,
      platformFeeAmount: item.platformFeeAmount,
      sellerNetAmount: item.amount,
      currency: item.currency || "USD",
      createdAt: item.createdAt,
      lines: [
        ["Transaction type", item.type || "credit"],
        ["Order", item.orderId || "Not linked"],
        ["Logistics", item.logisticsId || "Not linked"]
      ]
    })),
    ...(profile.platformTransactionFees || []).map(item => ({
      type: "platform-fee",
      id: item.id,
      receiptNumber: item.feeNumber || `AN-FEE-${String(item.id || "").slice(0, 8)}`,
      module: "AgriTrade",
      title: "AgriNexus transaction fee",
      status: item.status || "captured",
      amount: item.feeAmount,
      grossAmount: item.grossAmount,
      platformFeeAmount: item.feeAmount,
      sellerNetAmount: item.sellerNetAmount,
      currency: item.currency || "USD",
      createdAt: item.createdAt,
      lines: [
        ["Product", item.productName || "Crop transaction"],
        ["Buyer", item.buyerName || "Buyer"],
        ["Seller", item.sellerName || "Seller"],
        ["Fee rate", `${item.feePercent || 0}%`],
        ["Order", item.orderNumber || item.orderId || "Not linked"]
      ]
    })),
    ...(profile.mobileClinicRevenueRecords || []).map(item => ({
      type: "mobile-clinic",
      id: item.id,
      receiptNumber: item.receiptNumber || item.revenueNumber || `MCR-${String(item.id || "").slice(0, 8)}`,
      module: "Healthcare",
      title: item.service || "Mobile clinic transaction",
      status: item.status || "recorded",
      amount: item.amount,
      currency: item.currency || "USD",
      createdAt: item.createdAt,
      lines: [
        ["Provider", item.providerName || "Mobile clinic provider"],
        ["Patient or sponsor", item.patientName || "Patient"],
        ["Payment method", item.paymentMethod || "Not specified"],
        ["Clinical boundary", item.clinicalBoundary || "AgriNexus records payment evidence only."]
      ]
    })),
    ...(profile.paymentReleases || []).map(item => ({
      type: "payment-release",
      id: item.id,
      receiptNumber: item.releaseNumber || `AN-REL-${String(item.id || "").slice(0, 8)}`,
      module: "AgriTrade",
      title: "Payment release",
      status: item.status || "released",
      amount: item.amount,
      currency: item.currency || "USD",
      createdAt: item.createdAt,
      lines: [
        ["Product", item.productName || "Trade product"],
        ["Buyer", item.buyerName || "Buyer"],
        ["Seller", item.sellerName || "Seller"]
      ]
    }))
  ].filter(item => item.id || item.receiptNumber);
}

function receiptRecordByKey(type, id) {
  return transactionReceiptCatalog().find(item => item.type === type && String(item.id || item.receiptNumber) === String(id));
}

function transactionReceiptText(record) {
  const issuedAt = new Date().toISOString();
  const lines = [
    "AGRINEXUS TRANSACTION RECEIPT",
    "================================",
    `Receipt: ${record.receiptNumber}`,
    `Module: ${record.module}`,
    `Transaction: ${record.title}`,
    `Status: ${record.status}`,
    `Issued: ${issuedAt}`,
    `Recorded: ${record.createdAt || "Not recorded"}`,
    "",
    "AMOUNTS",
    "-------",
    `Currency: ${record.currency || "USD"}`,
    `Amount: ${record.currency || "USD"} ${record.amount ?? 0}`
  ];
  if (record.grossAmount !== undefined) lines.push(`Gross amount: ${record.currency || "USD"} ${record.grossAmount}`);
  if (record.platformFeeAmount !== undefined) lines.push(`AgriNexus fee: ${record.currency || "USD"} ${record.platformFeeAmount}`);
  if (record.sellerNetAmount !== undefined) lines.push(`Seller net payout: ${record.currency || "USD"} ${record.sellerNetAmount}`);
  lines.push("", "DETAILS", "-------");
  (record.lines || []).forEach(([label, value]) => lines.push(`${label}: ${value || "Not specified"}`));
  lines.push(
    "",
    "NOTICE",
    "------",
    "This receipt is generated from AgriNexus workflow records. Live payment settlement depends on the connected payment provider, bank, mobile money, or marketplace processor.",
    "",
    `Generated by AgriNexus ${AGRINEXUS_BUILD_VERSION}`
  );
  return lines.join("\n");
}

function downloadTextFile(filename, content) {
  const blob = new Blob([content], { type: "text/plain;charset=utf-8" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(link.href), 1000);
}

function downloadTransactionReceipt(type, id) {
  const record = receiptRecordByKey(type, id);
  if (!record) {
    toast("Receipt record not found");
    return;
  }
  const filename = `${record.receiptNumber || "agrinexus-receipt"}.txt`.replace(/[^a-z0-9._-]/gi, "-");
  downloadTextFile(filename, transactionReceiptText(record));
  toast("Receipt downloaded");
}

function receiptButton(type, id) {
  if (!id) return "";
  return `<button type="button" data-download-receipt="${escapeHtml(type)}" data-receipt-id="${escapeHtml(String(id))}">${translateText("Download receipt")}</button>`;
}

