let activeGenesisVoiceCorrelationId = "";

function createGenesisVoiceCorrelationId() {
  if (window.crypto?.randomUUID) return `gv-${window.crypto.randomUUID()}`;
  return `gv-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 12)}`;
}

function genesisVoiceDebugEnabled() {
  try {
    return new URLSearchParams(window.location.search).get("voiceDebug") === "1";
  } catch {
    return false;
  }
}

function recordGenesisSpokenResponsePipelineEvent(stage, details = {}) {
  const safe = {
    correlationId: String(details.correlationId || activeGenesisVoiceCorrelationId || "").slice(0, 96),
    buildVersion: AGRINEXUS_BUILD_VERSION,
    voiceRuntimeVersion: NEXUS_GENESIS_VOICE_RUNTIME_VERSION,
    stage,
    success: details.success !== false,
    route: String(details.route || "").slice(0, 120),
    intent: String(details.intent || "").slice(0, 120),
    httpStatus: Number.isFinite(Number(details.httpStatus)) ? Number(details.httpStatus) : null,
    responseFieldSelected: String(details.responseFieldSelected || "").slice(0, 80),
    responseLength: Number.isFinite(Number(details.responseLength)) ? Number(details.responseLength) : 0,
    sanitizedLength: Number.isFinite(Number(details.sanitizedLength)) ? Number(details.sanitizedLength) : 0,
    ttsProvider: String(details.ttsProvider || "").slice(0, 80),
    audioByteLength: Number.isFinite(Number(details.audioByteLength)) ? Number(details.audioByteLength) : 0,
    playbackStarted: details.playbackStarted === true,
    elapsedTimeMs: Number.isFinite(Number(details.elapsedTimeMs)) ? Number(details.elapsedTimeMs) : null,
    errorCategory: String(details.errorCategory || "").slice(0, 100),
    sourceFunction: String(details.sourceFunction || "").slice(0, 120)
  };
  try {
    const trace = Array.isArray(window.__nexusGenesisSpokenResponseTrace)
      ? window.__nexusGenesisSpokenResponseTrace
      : [];
    trace.push({ ...safe, createdAt: new Date().toISOString() });
    window.__nexusGenesisSpokenResponseTrace = trace.slice(-160);
  } catch {
    // Diagnostics must never interrupt voice.
  }
  recordNexusAudioPipelineEvent(stage, safe);
  if (genesisVoiceDebugEnabled()) {
    console.info(`[NexusVoiceTrace] ${stage}`, safe);
  }
  return safe;
}

function extractGenesisSpeakableResponse(payload = {}, correlationId = "") {
  recordGenesisSpokenResponsePipelineEvent("speakable-extraction-started", {
    correlationId,
    route: "/api/agent/command",
    sourceFunction: "extractGenesisSpeakableResponse"
  });
  const contract = payload?.nexusResponse || payload?.genesisResponse || null;
  if (!contract || contract.ok !== true || typeof contract.response !== "string") {
    recordGenesisSpokenResponsePipelineEvent("speakable-extraction-empty", {
      correlationId,
      route: "/api/agent/command",
      success: false,
      errorCategory: "missing-normalized-genesis-response",
      sourceFunction: "extractGenesisSpeakableResponse"
    });
    throw new Error("Nexus response contract was missing speakable content.");
  }
  const response = authoritativeNexusFinalAnswer(contract, payload?.commandResult || {}, payload?.result || {});
  if (!response) {
    recordGenesisSpokenResponsePipelineEvent("speakable-extraction-empty", {
      correlationId: contract.correlationId || correlationId,
      route: contract.route || "/api/agent/command",
      intent: contract.intent || "",
      success: false,
      responseFieldSelected: contract.diagnostics?.responseFieldSelected || "response",
      sourceFunction: "extractGenesisSpeakableResponse"
    });
    throw new Error("Nexus response contract was empty after extraction.");
  }
  recordGenesisSpokenResponsePipelineEvent("speakable-extraction-succeeded", {
    correlationId: contract.correlationId || correlationId,
    route: contract.route || "/api/agent/command",
    intent: contract.intent || "",
    responseFieldSelected: contract.diagnostics?.responseFieldSelected || "response",
    responseLength: contract.diagnostics?.responseLength || response.length,
    sanitizedLength: response.length,
    sourceFunction: "extractGenesisSpeakableResponse"
  });
  return {
    ...contract,
    response
  };
}

function isNexusInternalStatusOnlyResponse(value = "") {
  const compact = String(value || "").replace(/\s+/g, " ").trim().toLowerCase();
  if (!compact) return true;
  if (/^(prepared|prepared locally|completed local|completed locally|completed_local|prepared_local|routed|blocked|confirmation required|confirmation_required|execution blocked|queued|pending)$/i.test(compact)) return true;
  if (/^(prepared|completed|routed|blocked|queued|pending)[_ -]?(local|locally|only)?$/i.test(compact)) return true;
  if (/^status[: ]/.test(compact)) return true;
  return false;
}

function authoritativeNexusFinalAnswer(...candidates) {
  const flattened = candidates.flatMap(candidate => {
    if (!candidate || typeof candidate !== "object") return [candidate];
    return [
      candidate.response,
      candidate.answer,
      candidate.finalAnswer,
      candidate.spokenResponse,
      candidate.displayResponse,
      candidate.userVisibleStatus,
      candidate.conversationalResponse,
      candidate.summary,
      candidate.message
    ];
  });
  const normalized = flattened
    .map(value => String(value || "").replace(/\s+/g, " ").trim())
    .filter(Boolean);
  const natural = normalized.find(value => !isNexusInternalStatusOnlyResponse(value));
  return natural || normalized[0] || "";
}

function setVoiceResponse(message, speak = false, options = {}) {
  if (options.turnToken && !isCurrentNexusVoiceTurn(options.turnToken)) return;
  if (speak || options.forceHandoff) clearAgentProgressTimers();
  const allowVoiceFirst = options.allowVoiceFirst !== false;
  if (voiceDemoQuietMode && !options.allowDemoQuietSpeech) {
    speak = false;
    options = { ...options, allowVoiceFirst: false };
  }
  const token = ++voiceTranslationToken;
  const interruptToken = voiceInterruptToken;
  const rawResponseMessage = speak || options.forceHandoff ? composeJarvisResponse(message, options) : message;
  let responseMessage = nexusHumanResponsePolicy(rawResponseMessage, { ...options, speak, command: options.command || agentPerformanceState.lastCommand || conversationModeState.lastQuestion || "" });
  responseMessage = repeatSafeVoiceResponse(responseMessage, { ...options, speak });
  const compactResponse = String(responseMessage || "").replace(/\s+/g, " ").trim();
  const now = Date.now();
  const duplicateSpeech = Boolean(speak && compactResponse && compactResponse === String(lastVoiceResponse || "").replace(/\s+/g, " ").trim() && now - lastVoiceResponseAt < 8000);
  if (speak || (voiceFirstMode && allowVoiceFirst)) {
    const spokenPreview = sanitizeNexusSpokenResponseText(compactResponse);
    recordGenesisSpokenResponsePipelineEvent(spokenPreview ? "speech-sanitization-succeeded" : "speech-sanitization-empty", {
      correlationId: options.correlationId || activeGenesisVoiceCorrelationId || "",
      intent: options.genesisResponse?.intent || "",
      success: Boolean(spokenPreview),
      responseLength: compactResponse.length,
      sanitizedLength: spokenPreview.length,
      sourceFunction: "setVoiceResponse"
    });
  }
  setNexusGenesisTrustChainState(compactResponse ? "response_ready" : "response_failed", {
    response: compactResponse,
    visibleFeedback: compactResponse || "I heard you, but I was not able to prepare a response. Please try again.",
    failureRecovery: compactResponse ? "" : "Ask the user to try again or type the request.",
    reason: options.source || "set-voice-response"
  });
  nexusGenesisConversationSupervisor?.observeResponse?.(compactResponse, {
    source: options.source || "set-voice-response",
    command: options.command || agentPerformanceState.lastCommand || conversationModeState.lastQuestion || ""
  });
  updateNexusBehaviorLayer(speak ? "speaking" : "ready", responseMessage);
  if (!options.skipPresenceUpdate) {
    const inferredPresence = inferNexusPresenceStateFromMessage(responseMessage, options);
    setNexusPresenceState(inferredPresence, {
      lastUserInput: options.command || nexusPresenceState.lastUserInput || agentPerformanceState.lastCommand || conversationModeState.lastQuestion || "",
      lastResponse: responseMessage,
      nextQuestion: options.handoffText || (inferredPresence === NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP ? nexusPresenceStateLabel(NEXUS_PRESENCE_STATES.AWAITING_FOLLOWUP) : "Ask Nexus what you need next."),
      activeMission: nexusActiveWorkflowState?.agenticMission?.title || nexusAgenticCommandMissions[0]?.title || nexusPresenceState.activeMission || ""
    });
  }
  syncNexusPresenceSurfaces(nexusOsVoiceRuntimeState.mode || "standby", {
    source: "voice-response-caption",
    captionText: responseMessage,
    assistantSpeaking: nexusOsVoiceRuntimeState.assistantSpeaking === true
  });
  lastVoiceResponse = responseMessage;
  lastVoiceResponseAt = now;
  recordNexusAudioPipelineEvent("agent-command-response", {
    status: "ok",
    responseLength: compactResponse.length
  });
  nexusGenesisVoiceDebugLog("response-received", {
    responseLength: compactResponse.length,
    speak: Boolean(speak || (voiceFirstMode && allowVoiceFirst))
  });
  rememberNexusAnswerContext(responseMessage, options);
  rememberConversationTurn(agentPerformanceState.lastCommand || conversationModeState.lastQuestion || "", responseMessage);
  recordNexusOsConversationTurn("assistant", responseMessage, { source: options.source || "set-voice-response", state: nexusCoreRuntimeState.current });
  const transcript = $("#voiceTranscript");
  if (transcript) transcript.textContent = responseMessage;
  const summary = $("#jarvisSummary");
  if (summary) summary.textContent = responseMessage;
  const globalStatus = $("#globalAssistantStatus");
  if (globalStatus) globalStatus.textContent = responseMessage;
  updateUserCaptionPanel(responseMessage);
  announce(responseMessage);
  if (experienceMode !== "user" || responseMessage.length < 90) toast(responseMessage);
  if (languageCode() !== "en" && !options.alreadyTranslated) {
    request("/api/translate", {
      method: "POST",
      body: { text: responseMessage, sourceLanguage: "en", targetLanguage: languageCode(), context: "voice-response" }
    }).then(result => {
      if (token !== voiceTranslationToken || interruptToken !== voiceInterruptToken || (options.turnToken && !isCurrentNexusVoiceTurn(options.turnToken))) return;
      const translated = result.translationResult?.translatedText || responseMessage;
      lastVoiceResponse = translated;
      if (transcript) transcript.textContent = translated;
      if (summary) summary.textContent = translated;
      if (globalStatus) globalStatus.textContent = translated;
      updateUserCaptionPanel(translated);
      syncNexusPresenceSurfaces(nexusOsVoiceRuntimeState.mode || "standby", {
        source: "translated-voice-response-caption",
        captionText: translated,
        assistantSpeaking: nexusOsVoiceRuntimeState.assistantSpeaking === true
      });
      announce(translated);
      if (interruptToken === voiceInterruptToken && !duplicateSpeech && (speak || (voiceFirstMode && allowVoiceFirst))) scheduleNexusSpeech(translated, options);
    }).catch(() => {
      if (interruptToken === voiceInterruptToken && !duplicateSpeech && (!options.turnToken || isCurrentNexusVoiceTurn(options.turnToken)) && (speak || (voiceFirstMode && allowVoiceFirst))) scheduleNexusSpeech(responseMessage, options);
    });
    return;
  }
  if (interruptToken === voiceInterruptToken && !duplicateSpeech && (speak || (voiceFirstMode && allowVoiceFirst))) scheduleNexusSpeech(responseMessage, options);
}

function userFirstName() {
  return userDisplayName().split(/\s+/)[0] || "there";
}

function friendlyRoleLabel(role = data?.user?.role) {
  const value = String(role || "").toLowerCase();
  if (value.includes("standard") || value === "user") return "User";
  if (value.includes("admin")) return "Admin";
  if (value.includes("investor")) return "Investor";
  return String(role || "User");
}

function userHeaderName() {
  const name = userDisplayName();
  return name === "there" ? friendlyRoleLabel(data?.user?.role) : name;
}

function userDisplayName() {
  const guestName = String(localStorage.getItem("agrinexusGuestDisplayName") || "").trim();
  if (guestName) return guestName;
  const name = String(data?.user?.name || "").trim();
  const role = String(data?.user?.role || "").trim();
  const roleLike = new Set([
    "standard user",
    "admin",
    "platform admin",
    "investor",
    "investor viewer",
    "user"
  ]);
  if (name && !roleLike.has(name.toLowerCase()) && name.toLowerCase() !== role.toLowerCase()) return name;
  const emailName = String(data?.user?.email || "").split("@")[0].replace(/[._-]+/g, " ").trim();
  if (emailName && !roleLike.has(emailName.toLowerCase())) return emailName;
  return "there";
}

function welcomeSignedInUser() {
  if (!data?.user) return;
  const userKey = data.user.email || data.user.id || data.user.name || "current-user";
  const welcomeKey = `agrinexusWelcome:${userKey}`;
  if (sessionStorage.getItem(welcomeKey)) return;
  sessionStorage.setItem(welcomeKey, "shown");
  const behavior = nexusBehaviorMode();
  const message = `${behavior.greeting} ${behavior.prompt}`;
  setVoiceResponse(message, false, { allowVoiceFirst: false });
}

async function createGovernmentBriefing() {
  const status = $("#agentActionStatus");
  if (status) status.textContent = "Creating government-ready briefing from current platform evidence...";
  try {
    data = await request("/api/agent/briefing", { method: "POST", body: { purpose: "government presentation" } });
    render();
    goSection("agent", { instant: true });
    const briefing = data.briefingResult || (data.profile.agentBriefings || [])[0];
    const message = briefing?.plainLanguageSummary || "Government briefing created.";
    if ($("#agentActionStatus")) $("#agentActionStatus").textContent = message;
    setVoiceResponse(message);
    toast("Government briefing created");
  } catch (error) {
    if (status) status.textContent = error.message;
    toast(error.message);
  }
}

function toggleVoiceFirstMode() {
  voiceFirstMode = !voiceFirstMode;
  if (voiceFirstMode) {
    voiceDemoQuietMode = false;
    voiceConversationPaused = false;
  }
  voiceAutoRestart = voiceFirstMode;
  localStorage.removeItem("agrinexusVoiceFirst");
  localStorage.setItem("agrinexusDemoQuiet", voiceDemoQuietMode ? "on" : "off");
  ["#voiceFirstBtn", "#globalVoiceFirstBtn"].forEach(selector => {
    const button = $(selector);
    if (!button) return;
    button.classList.toggle("primary", voiceFirstMode);
    button.setAttribute("aria-pressed", String(voiceFirstMode));
  });
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  setVoiceResponse(voiceFirstMode ? "Hey AgriNexus mode is on. You can also call me Nexus. Say Nexus, then tell me what you need. I will speak back and keep listening when the browser allows it." : "Hey AgriNexus mode is off.", voiceFirstMode);
  if (voiceFirstMode) startVoiceListening();
}

function disableNexusVoiceForDemo(message = "Demo quiet mode is on. Nexus voice is off until you turn it back on.", options = {}) {
  voiceDemoQuietMode = true;
  voiceConversationPaused = false;
  voiceFirstMode = false;
  voiceAutoRestart = false;
  voiceStopRequested = true;
  voiceResumeAfterSpeech = false;
  localStorage.removeItem("agrinexusVoiceFirst");
  localStorage.setItem("agrinexusDemoQuiet", "on");
  clearAgentProgressTimers();
  if (voiceRecognition) {
    try {
      voiceRecognition.stop();
    } catch (error) {
      // Recognition may already be stopped.
    }
    voiceRecognition = null;
  }
  stopVoicePlayback({ hard: true });
  setVoiceStatus("standby");
  updateNexusBehaviorLayer("ready", message);
  ["#voiceFirstBtn", "#globalVoiceFirstBtn"].forEach(selector => {
    const button = $(selector);
    if (!button) return;
    button.classList.remove("primary");
    button.setAttribute("aria-pressed", "false");
  });
  refreshMicSupport();
  lastVoiceResponse = translateText(message);
  ["#globalAssistantStatus", "#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
    const element = $(selector);
    if (element) element.textContent = lastVoiceResponse;
  });
  updateUserCaptionPanel(lastVoiceResponse, { expanded: true });
  if (!options.silent) toast(message);
}

function enableNexusVoiceForDemo(message = "Nexus voice is back on. Say Nexus, then tell me what you need.", options = {}) {
  voiceDemoQuietMode = false;
  voiceConversationPaused = false;
  voiceFirstMode = true;
  voiceAutoRestart = true;
  voiceStopRequested = false;
  localStorage.removeItem("agrinexusVoiceFirst");
  localStorage.setItem("agrinexusDemoQuiet", "off");
  refreshMicSupport();
  setVoiceStatus("voice-first");
  setVoiceResponse(message, true);
  if (options.skipListeningStart) {
    const translated = translateText(message);
    lastVoiceResponse = translated;
    ["#globalAssistantStatus", "#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
      const element = $(selector);
      if (element) element.textContent = lastVoiceResponse;
    });
    updateUserCaptionPanel(lastVoiceResponse, { expanded: true });
    renderTypedGlobalVoiceControlConfirmation(message);
  }
  if (!options.skipListeningStart) startVoiceListening();
}

function preferredOpenAiTtsVoice() {
  const profileVersion = String(localStorage.getItem("agrinexusVoiceProfileVersion") || "");
  const stored = String(localStorage.getItem("agrinexusOpenAiTtsVoice") || "").trim().toLowerCase();
  if (profileVersion !== NEXUS_TTS_PROFILE_VERSION && (!stored || stored === "coral" || stored === "onyx")) {
    localStorage.setItem("agrinexusOpenAiTtsVoice", OPENAI_TTS_VOICE_FALLBACK);
    localStorage.setItem("agrinexusVoiceProfileVersion", NEXUS_TTS_PROFILE_VERSION);
    return OPENAI_TTS_VOICE_FALLBACK;
  }
  if (profileVersion !== NEXUS_TTS_PROFILE_VERSION) {
    localStorage.setItem("agrinexusVoiceProfileVersion", NEXUS_TTS_PROFILE_VERSION);
  }
  if (OPENAI_TTS_VOICE_CHOICES.has(stored)) return stored;
  localStorage.setItem("agrinexusOpenAiTtsVoice", OPENAI_TTS_VOICE_FALLBACK);
  return OPENAI_TTS_VOICE_FALLBACK;
}

function browserVoiceStorageKey(locale) {
  return `agrinexusBrowserVoice:${String(locale || "en-US").toLowerCase()}`;
}

function normalizeNexusVoiceLocale(locale = voiceLocale()) {
  const requested = String(locale || voiceLocale() || "en-US").trim();
  return requested || "en-US";
}

function voiceMatchesLocale(voice, locale) {
  const exact = String(locale || "").toLowerCase();
  const language = exact.split("-")[0];
  const voiceLang = String(voice?.lang || "").toLowerCase();
  return voiceLang === exact || Boolean(language && voiceLang.startsWith(`${language}-`));
}

function nexusRegionalVoiceMatchType(voice, locale) {
  const exact = String(locale || "").toLowerCase();
  const language = exact.split("-")[0];
  const voiceLang = String(voice?.lang || "").toLowerCase();
  if (voiceLang && voiceLang === exact) return "exact-locale-browser-voice";
  if (language && voiceLang.startsWith(`${language}-`)) return "language-family-browser-voice";
  return "browser-default-voice";
}

function scoreNexusRegionalVoiceCandidate(voice, locale, savedName = "") {
  const name = String(voice?.name || "").toLowerCase();
  const matchType = nexusRegionalVoiceMatchType(voice, locale);
  const score = [
    matchType === "exact-locale-browser-voice" ? 50 : 0,
    matchType === "language-family-browser-voice" ? 28 : 0,
    savedName && voice?.name === savedName ? 18 : 0,
    voice?.localService ? 8 : 0,
    /\b(neural|natural|online|enhanced|premium|google|microsoft|zira|susan|samantha|joanna|ava|aria|guy|jenny|sonia)\b/.test(name) ? 6 : 0,
    /\b(default|compact|legacy)\b/.test(name) ? -6 : 0
  ].reduce((sum, value) => sum + value, 0);
  return { voice, score, matchType };
}

function resolveNexusRegionalVoice(locale = voiceLocale(), options = {}) {
  const requestedLocale = normalizeNexusVoiceLocale(locale);
  const language = requestedLocale.split("-")[0].toLowerCase();
  const synthesisAvailable = Boolean(typeof window !== "undefined" && window.speechSynthesis && window.SpeechSynthesisUtterance);
  const voices = synthesisAvailable ? (window.speechSynthesis.getVoices?.() || []) : [];
  const storageKey = browserVoiceStorageKey(requestedLocale);
  const savedName = String(localStorage.getItem(storageKey) || "").trim();
  const localeMatches = voices.filter(voice => voiceMatchesLocale(voice, requestedLocale));
  const saved = localeMatches.find(voice => savedName && voice.name === savedName);
  const candidates = localeMatches
    .map(voice => scoreNexusRegionalVoiceCandidate(voice, requestedLocale, savedName))
    .sort((a, b) => b.score - a.score || String(a.voice.name || "").localeCompare(String(b.voice.name || "")));
  const fallbackCandidates = candidates.length
    ? candidates
    : voices
      .map(voice => scoreNexusRegionalVoiceCandidate(voice, requestedLocale, savedName))
      .sort((a, b) => b.score - a.score || String(a.voice.name || "").localeCompare(String(b.voice.name || "")));
  const selectedEntry = saved
    ? scoreNexusRegionalVoiceCandidate(saved, requestedLocale, savedName)
    : fallbackCandidates[0] || null;
  const selectedVoice = selectedEntry?.voice || null;
  const fallbackMatchType = selectedEntry?.matchType || (selectedVoice ? "browser-default-voice" : "caption-and-typed-fallback");
  const fallbackReason = selectedVoice
    ? (selectedEntry.matchType === "exact-locale-browser-voice"
      ? "Exact locale browser voice is available."
      : selectedEntry.matchType === "language-family-browser-voice"
        ? "Exact regional voice is unavailable; using the closest available language voice."
        : "Regional voice is unavailable; using the browser default voice with captions.")
    : synthesisAvailable
      ? "No browser voice list is available yet; captions and typed fallback remain available."
      : "Speech synthesis is unsupported; captions and typed fallback remain available.";
  const resolution = {
    schemaVersion: NEXUS_REGIONAL_VOICE_RESOLUTION_CONTRACT.schemaVersion,
    resolver: NEXUS_REGIONAL_VOICE_RESOLUTION_CONTRACT.resolver,
    requestedLocale,
    requestedLanguage: voiceLanguageNames[language] || voiceLanguageName(),
    selectedVoiceName: selectedVoice?.name || "",
    selectedVoiceLang: selectedVoice?.lang || "",
    selectedVoiceLocalService: Boolean(selectedVoice?.localService),
    matchType: fallbackMatchType,
    providerSuppliedRegionalVoice: fallbackMatchType === "exact-locale-browser-voice",
    fallbackReason,
    noFakeAccent: true,
    noRegionalAccentClaimWithoutProvider: true,
    captionsRemainAvailable: true,
    textFallbackAvailable: true,
    voiceCount: voices.length
  };
  if (selectedVoice?.name && options.persist !== false) localStorage.setItem(storageKey, selectedVoice.name);
  return { ...resolution, voice: selectedVoice };
}

function nexusRegionalVoiceSummary(locale = voiceLocale()) {
  const resolved = resolveNexusRegionalVoice(locale, { persist: false });
  const { voice, ...summary } = resolved;
  return summary;
}

function chooseSpeechVoice(locale) {
  if (!("speechSynthesis" in window)) return null;
  const resolved = resolveNexusRegionalVoice(locale);
  return resolved.voice || null;
}

function installStableSpeechVoicePreference() {
  if (!("speechSynthesis" in window)) return;
  chooseSpeechVoice(voiceLocale());
  const previous = window.speechSynthesis.onvoiceschanged;
  window.speechSynthesis.onvoiceschanged = event => {
    if (typeof previous === "function") previous.call(window.speechSynthesis, event);
    chooseSpeechVoice(voiceLocale());
  };
}

const NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT = Object.freeze({
  schemaVersion: "nexus-voice-preferences-accessibility.v1",
  controllerName: "NexusVoicePreferenceManager",
  runtimeOwner: "nexus-os-canonical-voice",
  storageKey: "nexusPresenceVoicePreferences",
  pendingConsentKey: "nexusVoicePreferencePendingConsent",
  preferenceFields: Object.freeze([
    "language",
    "locale",
    "voiceName",
    "speechRatePreset",
    "speechVolume",
    "speechEnabled",
    "captionsEnabled",
    "answerLength",
    "formality",
    "deliveryMode"
  ]),
  commands: Object.freeze([
    "speak more slowly",
    "speak faster",
    "use a different English voice",
    "stop speaking and show text only",
    "enable captions",
    "prefer concise responses",
    "prefer more explanation",
    "prefer formal delivery",
    "prefer conversational delivery",
    "reset voice settings",
    "forget voice preferences"
  ]),
  safeguards: Object.freeze({
    consentRequiredForPersistentMemory: true,
    temporaryPreferencesAllowed: true,
    reviewPreferencesRequired: true,
    resetSupported: true,
    forgetSupported: true,
    crossTenantIsolation: "local-user-browser-scope",
    noSensitiveAttributeInference: true,
    textFallbackAlwaysAvailable: true,
    unavailableVoiceFallsBackHonestly: true,
    noWorkflowExecutionAuthority: true
  })
});

function defaultNexusVoicePreferences() {
  return {
    schemaVersion: NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.schemaVersion,
    language: languageCode(),
    locale: voiceLocale(),
    voiceName: "",
    speechRatePreset: localStorage.getItem("agrinexusSlowSpeech") === "on" ? "slow" : "standard",
    speechVolume: Number(localStorage.getItem("nexusPresenceSpeechVolume") || 1),
    speechEnabled: localStorage.getItem("agrinexusDemoQuiet") !== "on",
    captionsEnabled: localStorage.getItem("nexusPresenceCaptionsEnabled") !== "off",
    answerLength: localStorage.getItem("agrinexusShortAnswers") === "on" ? "concise" : "balanced",
    formality: localStorage.getItem("nexusPresenceFormality") || "conversational",
    deliveryMode: localStorage.getItem("nexusPresenceDeliveryMode") || "STANDARD",
    memoryStatus: "temporary-until-approved",
    updatedAt: new Date().toISOString()
  };
}

function getNexusVoicePreferences() {
  try {
    const saved = JSON.parse(localStorage.getItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.storageKey) || "null");
    return { ...defaultNexusVoicePreferences(), ...(saved || {}), memoryStatus: saved ? "saved-with-user-approval" : "temporary-until-approved" };
  } catch {
    return defaultNexusVoicePreferences();
  }
}

function applyNexusVoicePreferences(preferences = {}) {
  const merged = { ...getNexusVoicePreferences(), ...preferences, updatedAt: new Date().toISOString() };
  localStorage.setItem("agrinexusSlowSpeech", merged.speechRatePreset === "slow" ? "on" : "off");
  localStorage.setItem("agrinexusShortAnswers", merged.answerLength === "concise" ? "on" : "off");
  localStorage.setItem("agrinexusDemoQuiet", merged.speechEnabled === false ? "on" : "off");
  localStorage.setItem("nexusPresenceCaptionsEnabled", merged.captionsEnabled === false ? "off" : "on");
  localStorage.setItem("nexusPresenceSpeechVolume", String(Math.max(0, Math.min(1, Number(merged.speechVolume) || 1))));
  localStorage.setItem("nexusPresenceFormality", merged.formality || "conversational");
  localStorage.setItem("nexusPresenceDeliveryMode", merged.deliveryMode || "STANDARD");
  voiceDemoQuietMode = merged.speechEnabled === false;
  if (merged.speechEnabled === false) nexusOsConversationMuted = true;
  if (preferences.speechEnabled === true) nexusOsConversationMuted = false;
  updateNexusOsVoiceRuntimeState({
    mode: merged.speechEnabled === false ? "muted" : "standby",
    voicePreferenceController: NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.controllerName,
    captionsEnabled: merged.captionsEnabled !== false,
    speechRatePreset: merged.speechRatePreset,
    speechVolume: merged.speechVolume,
    captionText: nexusVoicePreferencesSummary(merged)
  }, "voice-preferences-applied");
  return merged;
}

function rememberNexusVoicePreferences(preferences = {}) {
  const merged = { ...getNexusVoicePreferences(), ...preferences, memoryStatus: "saved-with-user-approval", updatedAt: new Date().toISOString() };
  localStorage.setItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.storageKey, JSON.stringify(merged));
  localStorage.removeItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.pendingConsentKey);
  nexusVoicePreferencePendingConsent = null;
  return applyNexusVoicePreferences(merged);
}

function setTemporaryNexusVoicePreference(preferences = {}, label = "voice preference") {
  const applied = applyNexusVoicePreferences(preferences);
  nexusVoicePreferencePendingConsent = {
    preferences,
    label,
    createdAt: new Date().toISOString(),
    consentQuestion: `Would you like me to remember that ${label}?`
  };
  localStorage.setItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.pendingConsentKey, JSON.stringify(nexusVoicePreferencePendingConsent));
  return applied;
}

function forgetNexusVoicePreferences() {
  localStorage.removeItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.storageKey);
  localStorage.removeItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.pendingConsentKey);
  localStorage.removeItem("agrinexusSlowSpeech");
  localStorage.removeItem("agrinexusShortAnswers");
  localStorage.removeItem("nexusPresenceCaptionsEnabled");
  localStorage.removeItem("nexusPresenceSpeechVolume");
  localStorage.removeItem("nexusPresenceFormality");
  localStorage.removeItem("nexusPresenceDeliveryMode");
  nexusVoicePreferencePendingConsent = null;
  return applyNexusVoicePreferences({ ...defaultNexusVoicePreferences(), speechEnabled: true, captionsEnabled: true });
}

function nexusVoicePreferencesSummary(preferences = getNexusVoicePreferences()) {
  const captions = preferences.captionsEnabled === false ? "captions off" : "captions on";
  const speech = preferences.speechEnabled === false ? "text only" : "speech available";
  const saved = preferences.memoryStatus === "saved-with-user-approval" ? "saved" : "temporary";
  return `Voice preferences: ${speech}, ${captions}, ${preferences.speechRatePreset || "standard"} pace, ${preferences.answerLength || "balanced"} answers, ${preferences.formality || "conversational"} delivery, ${saved}.`;
}

function rotateNexusAvailableVoice(locale = voiceLocale()) {
  if (typeof window === "undefined" || !window.speechSynthesis) return { ok: false, reason: "speech-synthesis-unavailable" };
  const voices = window.speechSynthesis.getVoices?.() || [];
  const requestedLocale = normalizeNexusVoiceLocale(locale);
  const matches = voices.filter(voice => voiceMatchesLocale(voice, requestedLocale));
  const candidates = matches.length ? matches : voices;
  if (!candidates.length) return { ok: false, reason: "no-browser-voices-available" };
  const storageKey = browserVoiceStorageKey(requestedLocale);
  const currentName = localStorage.getItem(storageKey) || "";
  const currentIndex = Math.max(0, candidates.findIndex(voice => voice.name === currentName));
  const selected = candidates[(currentIndex + 1) % candidates.length];
  localStorage.setItem(storageKey, selected.name);
  setTemporaryNexusVoicePreference({ voiceName: selected.name, locale: selected.lang || requestedLocale }, "voice choice");
  return { ok: true, voiceName: selected.name, voiceLang: selected.lang || requestedLocale, providerSuppliedRegionalVoice: nexusRegionalVoiceMatchType(selected, requestedLocale) === "exact-locale-browser-voice" };
}

function handleNexusVoicePreferenceMemoryConsent(command = "") {
  const text = normalizeToolText(command);
  if (!nexusVoicePreferencePendingConsent) return false;
  if (/\b(yes|remember|save|keep|store)\b/.test(text)) {
    const remembered = rememberNexusVoicePreferences(nexusVoicePreferencePendingConsent.preferences || {});
    setVoiceResponse(`Saved. ${nexusVoicePreferencesSummary(remembered)}`, false, { allowVoiceFirst: false, source: "voice-preference-consent" });
    return true;
  }
  if (/\b(no|do not|don't|decline|temporary only)\b/.test(text)) {
    localStorage.removeItem(NEXUS_VOICE_PREFERENCES_ACCESSIBILITY_CONTRACT.pendingConsentKey);
    nexusVoicePreferencePendingConsent = null;
    setVoiceResponse("Okay. I will keep that preference for this browser session only.", false, { allowVoiceFirst: false, source: "voice-preference-consent" });
    return true;
  }
  return false;
}

function handleNexusVoicePreferenceCommand(command = "", options = {}) {
  const text = normalizeToolText(command);
  if (!text) return false;
  if (handleNexusVoicePreferenceMemoryConsent(command)) return true;
  let applied = null;
  let message = "";
  let label = "";
  if (/\b(review|show|what are)\b.*\b(voice|speech|caption|accessibility).*preferences?\b/.test(text)) {
    setVoiceResponse(nexusVoicePreferencesSummary(), false, { allowVoiceFirst: false, source: "voice-preference-review" });
    return true;
  }
  if (/\b(forget|delete|clear)\b.*\b(voice|speech|caption|accessibility).*preferences?\b/.test(text)) {
    applied = forgetNexusVoicePreferences();
    setVoiceResponse(`Voice preferences cleared. ${nexusVoicePreferencesSummary(applied)}`, false, { allowVoiceFirst: false, source: "voice-preference-forget" });
    renderUserWorkspace?.();
    return true;
  }
  if (/\b(reset)\b.*\b(voice|speech|caption|accessibility|settings)\b/.test(text)) {
    applied = forgetNexusVoicePreferences();
    setVoiceResponse(`Voice settings reset. ${nexusVoicePreferencesSummary(applied)}`, false, { allowVoiceFirst: false, source: "voice-preference-reset" });
    renderUserWorkspace?.();
    return true;
  }
  if (/\b(use|choose|select|different|another|change)\b.*\bvoice\b/.test(text)) {
    const rotated = rotateNexusAvailableVoice(voiceLocale());
    message = rotated.ok
      ? `I selected another available browser voice for ${voiceLanguageName()}. ${rotated.providerSuppliedRegionalVoice ? "It matches the requested locale." : "If an exact regional voice is unavailable, I will use the closest honest fallback."}`
      : "I could not find another browser voice on this device. Captions and typed responses remain available.";
    label = "voice choice";
  } else if (/\b(speak|talk|read)\b.*\b(slower|slowly|slow)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ speechRatePreset: "slow" }, "slower speech pace");
    message = `I will speak more slowly. ${nexusVoicePreferencesSummary(applied)}`;
    label = "slower speech pace";
  } else if (/\b(speak|talk|read)\b.*\b(faster|quickly|fast)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ speechRatePreset: "fast" }, "faster speech pace");
    message = `I will speak a little faster while keeping clarity. ${nexusVoicePreferencesSummary(applied)}`;
    label = "faster speech pace";
  } else if (/\b(stop speaking|text only|show text only|disable speech|turn off speech)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ speechEnabled: false, captionsEnabled: true }, "text-only speech setting");
    stopVoicePlayback({ hard: true, reason: "voice-preference-text-only" });
    message = "Speech is off. I will show text and captions only.";
    label = "text-only speech setting";
  } else if (/\b(enable|turn on|show)\b.*\b(captions|caption)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ captionsEnabled: true }, "caption preference");
    message = "Captions are on. I will keep text visible with voice responses.";
    label = "caption preference";
  } else if (/\b(disable|turn off|hide)\b.*\b(captions|caption)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ captionsEnabled: false }, "caption preference");
    message = "Captions are off for now. Text responses remain available in the conversation.";
    label = "caption preference";
  } else if (/\b(concise|short|brief)\b.*\b(response|answer|reply|mode|answers?)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ answerLength: "concise" }, "concise response preference");
    message = "I will keep responses more concise.";
    label = "concise response preference";
  } else if (/\b(more explanation|explain more|detailed|more detail|longer)\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ answerLength: "detailed" }, "more explanation preference");
    message = "I will give more explanation when it helps.";
    label = "more explanation preference";
  } else if (/\b(formal|professional)\b.*\b(delivery|tone|style|voice)?\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ formality: "formal", deliveryMode: "FOCUS" }, "formal delivery preference");
    message = "I will use a more formal delivery.";
    label = "formal delivery preference";
  } else if (/\b(conversational|friendly|natural)\b.*\b(delivery|tone|style|voice)?\b/.test(text)) {
    applied = setTemporaryNexusVoicePreference({ formality: "conversational", deliveryMode: "STANDARD" }, "conversational delivery preference");
    message = "I will use a more conversational delivery.";
    label = "conversational delivery preference";
  } else if (/\b(volume up|louder|increase volume)\b/.test(text)) {
    const current = getNexusVoicePreferences();
    applied = setTemporaryNexusVoicePreference({ speechVolume: Math.min(1, Number(current.speechVolume || 1) + 0.15) }, "speech volume preference");
    message = `Speech volume is set to ${Math.round(applied.speechVolume * 100)} percent.`;
    label = "speech volume preference";
  } else if (/\b(volume down|quieter|reduce volume|lower volume)\b/.test(text)) {
    const current = getNexusVoicePreferences();
    applied = setTemporaryNexusVoicePreference({ speechVolume: Math.max(0.2, Number(current.speechVolume || 1) - 0.15) }, "speech volume preference");
    message = `Speech volume is set to ${Math.round(applied.speechVolume * 100)} percent.`;
    label = "speech volume preference";
  } else {
    return false;
  }
  if (!applied) applied = getNexusVoicePreferences();
  const consentQuestion = `Would you like me to remember that ${label || "voice preference"}?`;
  setVoiceResponse(`${message} ${consentQuestion}`, false, { allowVoiceFirst: false, source: options.source || "voice-preference-command" });
  renderUserWorkspace?.();
  return true;
}

function browserSpeechFallbackEnabled() {
  return localStorage.getItem(BROWSER_SPEECH_FALLBACK_STORAGE_KEY) === "on";
}

function genesisVoiceBrowserSpeechRecoveryEnabled() {
  return Boolean(nexusGenesisVoiceSessionActive);
}

function nexusListeningReadyMessage() {
  return voiceFirstMode
    ? "Nexus is listening now. Ask your next question."
    : "Nexus is ready. Ask your next question.";
}

function streamingVoiceEnabled() {
  return Boolean(voiceStreamingMode && voiceFirstMode && !voiceDemoQuietMode);
}

function persistNexusVoiceSession() {
  localStorage.setItem("agrinexusVoiceSession", JSON.stringify({
    ...nexusVoiceSession,
    queuedSpeechText: undefined
  }));
}

function updateNexusVoiceSession(patch = {}, reason = "") {
  nexusVoiceSession = {
    ...nexusVoiceSession,
    ...patch,
    reason,
    updatedAt: new Date().toISOString()
  };
  persistNexusVoiceSession();
  updateNativeVoiceBridgeState(nexusVoiceSession.state || "session", {
    reason,
    userSpeaking: nexusVoiceSession.userSpeaking,
    assistantSpeaking: nexusVoiceSession.assistantSpeaking,
    activeTurnToken: nexusVoiceSession.activeTurnToken,
    lastPartial: nexusVoiceSession.lastPartial,
    lastFinal: nexusVoiceSession.lastFinal
  });
  return nexusVoiceSession;
}

function persistNexusOsVoiceRuntimeState() {
  localStorage.setItem("nexusOsVoiceRuntimeState", JSON.stringify({
    ...nexusOsVoiceRuntimeState,
    speechConfidence: typeof nexusOsVoiceRuntimeState.speechConfidence === "number" ? nexusOsVoiceRuntimeState.speechConfidence : null
  }));
}

const NEXUS_PRESENCE_SYNCHRONIZATION_CONTRACT = Object.freeze({
  schemaVersion: "nexus-presence-synchronization.v1",
  controllerName: "NexusPresenceSynchronizationController",
  runtimeOwner: "nexus-os-canonical-voice",
  synchronizedSurfaces: Object.freeze([
    "nexus-core-orb",
    "voice-caption",
    "voice-runtime-status",
    "mission-lifecycle-status",
    "screen-reader-announcement"
  ]),
  stateMap: Object.freeze({
    starting: "wake",
    listening: "listening",
    "speech-detected": "hearing",
    "partial-transcript": "hearing",
    "final-transcript": "processing",
    thinking: "reasoning",
    processing: "processing",
    reasoning: "reasoning",
    speaking: "speaking",
    awaiting_confirmation: "confirmation",
    confirmation: "confirmation",
    preparing: "preparing",
    executing: "executing",
    verifying: "verifying",
    completed: "completed",
    completed_local: "completed",
    muted: "idle",
    standby: "idle",
    "typed-fallback": "waiting",
    stopped: "idle",
    "permission-denied": "blocked",
    "microphone-unavailable": "blocked",
    "recognition-timeout": "waiting",
    failed: "error",
    error: "error"
  }),
  safeguards: Object.freeze({
    speakingStartsOnlyOnPlaybackStart: true,
    speakingEndsOnPlaybackEndOrFailure: true,
    captionUsesExactUserFacingResponse: true,
    executionAnimationIndependentOfSpeechPlayback: true,
    completionRequiresHonestCompletionSignal: true,
    reducedMotionUsesStatusText: true,
    screenReaderAnnouncementRequired: true,
    noFakeExecutionClaim: true,
    noFakeCompletionClaim: true
  })
});

function normalizeNexusPresenceSyncMode(mode = "standby") {
  const key = String(mode || "standby").replace(/-/g, "_").toLowerCase();
  const dashed = key.replace(/_/g, "-");
  return NEXUS_PRESENCE_SYNCHRONIZATION_CONTRACT.stateMap[key]
    || NEXUS_PRESENCE_SYNCHRONIZATION_CONTRACT.stateMap[dashed]
    || normalizeNexusCoreState(key);
}

function nexusPresenceSynchronizationState(extra = {}) {
  const rawMode = extra.mode || nexusOsVoiceRuntimeState.mode || "standby";
  const coreState = normalizeNexusPresenceSyncMode(rawMode);
  const captionText = String(extra.captionText || nexusOsVoiceRuntimeState.captionText || lastVoiceResponse || "").trim();
  return {
    schemaVersion: NEXUS_PRESENCE_SYNCHRONIZATION_CONTRACT.schemaVersion,
    controllerName: NEXUS_PRESENCE_SYNCHRONIZATION_CONTRACT.controllerName,
    mode: rawMode,
    coreState,
    captionText,
    missionState: currentNexusOsMission?.()?.currentState || "return_home",
    assistantSpeaking: Boolean(extra.assistantSpeaking ?? nexusOsVoiceRuntimeState.assistantSpeaking),
    userSpeaking: Boolean(extra.userSpeaking ?? nexusOsVoiceRuntimeState.userSpeaking),
    reducedMotionSafe: true,
    screenReaderAnnouncement: nexusCoreStateAccessibleLabel(coreState),
    noExecutionAuthority: true,
    updatedAt: new Date().toISOString()
  };
}

function syncNexusPresenceSurfaces(mode = "standby", details = {}) {
  if (typeof document === "undefined") return nexusPresenceSynchronizationState({ ...details, mode });
  const state = nexusPresenceSynchronizationState({ ...details, mode });
  setNexusCoreState(state.coreState, {
    source: details.source || "presence-synchronization",
    statusText: details.statusText || state.screenReaderAnnouncement
  });
  document.body?.setAttribute?.("data-nexus-presence-sync-state", state.coreState);
  document.body?.setAttribute?.("data-nexus-presence-speaking", String(state.assistantSpeaking));
  document.querySelectorAll("[data-nexus-os-core-orb]").forEach(orb => {
    orb.dataset.nexusPresenceSyncState = state.coreState;
    orb.dataset.nexusPresenceSpeechActive = String(state.assistantSpeaking);
  });
  document.querySelectorAll("[data-nexus-os-voice-runtime-status]").forEach(surface => {
    surface.dataset.nexusPresenceSyncState = state.coreState;
    surface.dataset.nexusPresenceSpeaking = String(state.assistantSpeaking);
  });
  document.querySelectorAll("[data-nexus-os-mission-lifecycle-status]").forEach(surface => {
    surface.dataset.nexusPresenceSyncState = state.coreState;
    surface.dataset.nexusPresenceMissionState = state.missionState;
  });
  document.querySelectorAll("[data-nexus-presence-caption-sync]").forEach(caption => {
    caption.textContent = state.captionText || details.fallbackCaption || nexusOsVoiceRuntimeSummary();
  });
  document.querySelectorAll("[data-nexus-presence-status-announcement]").forEach(status => {
    status.textContent = `${state.screenReaderAnnouncement} ${state.captionText || ""}`.trim();
  });
  return state;
}

function updateNexusOsVoiceRuntimeState(patch = {}, reason = "voice-runtime-update") {
  const profile = typeof browserVoiceRuntimeProfile === "function" ? browserVoiceRuntimeProfile() : {};
  const incomingPermissionState = patch.permissionState !== undefined
    ? patch.permissionState
    : nexusOsVoiceRuntimeState.permissionState || "unknown";
  const permissionState = normalizeNexusMicrophonePermissionState(incomingPermissionState);
  nexusOsVoiceRuntimeState = {
    ...nexusOsVoiceRuntimeState,
    ...patch,
    permissionState,
    permissionDisplayText: patch.permissionDisplayText || nexusMicrophonePermissionDisplayText(permissionState),
    schemaVersion: "nexus-os-voice-runtime.v1",
    runtimeOwner: "nexus-os-canonical-voice",
    language: languageCode(),
    locale: voiceLocale(),
    recognitionSupported: Boolean(profile.supported || realtimeVoiceSupported?.()),
    synthesisSupported: Boolean(window.speechSynthesis && window.SpeechSynthesisUtterance),
    voiceFirst: voiceFirstMode,
    muted: nexusOsConversationMuted || voiceDemoQuietMode,
    privacy: "Voice starts from an explicit button, wake phrase, or user action. Nexus does not run always-on listening without consent.",
    reason,
    updatedAt: new Date().toISOString()
  };
  persistNexusOsVoiceRuntimeState();
  const surface = document.querySelector("[data-nexus-os-voice-runtime-status]");
  if (surface) surface.textContent = nexusOsVoiceRuntimeSummary();
  document.body?.setAttribute?.("data-nexus-os-voice-state", nexusOsVoiceRuntimeState.mode || "standby");
  syncNexusPresenceSurfaces(nexusOsVoiceRuntimeState.mode || "standby", {
    ...patch,
    reason,
    source: patch.source || "voice-runtime",
    captionText: patch.captionText || patch.lastFinal || patch.lastPartial || patch.lastSpokenPreview || nexusOsVoiceRuntimeState.captionText || ""
  });
  return nexusOsVoiceRuntimeState;
}

function nexusOsVoiceRuntimeSummary() {
  const state = nexusOsVoiceRuntimeState || {};
  const confidence = typeof state.speechConfidence === "number"
    ? ` Confidence ${Math.round(state.speechConfidence * 100)}%.`
    : "";
  const support = state.recognitionSupported
    ? "Speech recognition available."
    : "Typed fallback available.";
  return `${state.mode || "standby"} in ${voiceLanguageName()} (${voiceLocale()}). ${support}${confidence}`;
}

function renderNexusOsVoiceRuntimeStatus() {
  updateNexusOsVoiceRuntimeState({ mode: nexusOsVoiceRuntimeState.mode || "standby" }, "render-status");
  const voiceState = typeof nexusVoiceTroubleshootingState === "function"
    ? nexusVoiceTroubleshootingState()
    : { listeningState: nexusOsVoiceRuntimeState.mode || "standby", outputState: "Speech output available", typedFallback: "Workflow forms available after Nexus opens them" };
  return `
    <div class="nexus-os-voice-runtime-status" data-nexus-os-voice-runtime-status="true">
      <span>${escapeHtml(translateText("Voice"))}</span>
      <strong>${escapeHtml(translateText(voiceState.listeningState || nexusOsVoiceRuntimeState.mode || "standby"))}</strong>
      <small>${escapeHtml(translateText(`${voiceState.outputState || "Speech output available"}. ${voiceState.typedFallback || "Workflow forms available after Nexus opens them"}. ${nexusOsVoiceRuntimeSummary()}`))}</small>
      <em>${escapeHtml(translateText("Push-to-talk. No always-on listening without explicit consent."))}</em>
      <small class="sr-only" aria-live="polite" data-nexus-presence-status-announcement="true">${escapeHtml(translateText(nexusCoreStateAccessibleLabel(nexusCoreRuntimeState.current)))}</small>
      <small class="nexus-presence-caption-sync" data-nexus-presence-caption-sync="true">${escapeHtml(lastVoiceResponse || nexusOsVoiceRuntimeSummary())}</small>
    </div>
  `;
}

function persistNexusOsMissionLifecycleState() {
  localStorage.setItem("nexusOsMissionLifecycleState", JSON.stringify(nexusOsMissionLifecycleState));
}

function nexusOsMissionNow() {
  return new Date().toISOString();
}

function nexusOsMissionId() {
  if (typeof crypto !== "undefined" && crypto.randomUUID) return `nexus-mission-${crypto.randomUUID()}`;
  return `nexus-mission-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function inferNexusOsMissionDomain(goal = "") {
  const text = String(goal || "").toLowerCase();
  if (/\b(diabetes|blood pressure|hypertension|obesity|rpm|rtm|chronic|health|telehealth|doctor|clinic|pharmacy|medicine|provider|patient)\b/.test(text)) return "healthcare";
  if (/\b(crop|farm|farmer|agriculture|soil|irrigation|pest|disease|harvest|maize|tomato|field)\b/.test(text)) return "agriculture";
  if (/\b(job|workforce|training|learning|literacy|course|employer|worker|skill)\b/.test(text)) return "workforce-learning";
  if (/\b(buyer|seller|marketplace|agritrade|sell|trade|vendor|price)\b/.test(text)) return "marketplace";
  if (/\b(map|route|location|field visit|mobile clinic|transport|logistics)\b/.test(text)) return "maps-logistics";
  if (/\b(message|sms|whatsapp|telegram|email|call|phone)\b/.test(text)) return "communications";
  return "general-assistant";
}

function inferNexusOsMissionIntent(goal = "") {
  const text = String(goal || "").toLowerCase();
  if (/\b(record|track|log|capture|enter)\b/.test(text)) return "collect-information";
  if (/\b(prepare|draft|build|create|summary|report|packet|script)\b/.test(text)) return "prepare-output";
  if (/\b(open|show|go to|launch|start)\b/.test(text)) return "open-workflow";
  if (/\b(find|research|source|search|learn|explain)\b/.test(text)) return "source-backed-guidance";
  if (/\b(send|call|book|pay|buy|dispatch|share|submit|schedule)\b/.test(text)) return "sensitive-action-review";
  return "guided-support";
}

function nexusOsMissionSafetyClassification(goal = "") {
  const text = String(goal || "").toLowerCase();
  if (/\b(emergency|911|ambulance|dispatch|diagnose|prescribe|refill|pay|payment|buy|checkout|send|sms|whatsapp|telegram|email|call|share my location|use my camera|book|schedule|submit)\b/.test(text)) return "elevated-review-required";
  if (/\b(health|patient|pharmacy|provider|clinic|medicine|location|route|buyer|seller)\b/.test(text)) return "medium-risk-review-required";
  return "low-risk-local-guidance";
}

function nexusOsMissionMissingInformation(goal = "", domain = "general-assistant") {
  const text = String(goal || "").toLowerCase();
  const missing = [];
  if (domain === "healthcare" && !/\b(diabetes|blood pressure|hypertension|obesity|rpm|rtm|pharmacy|telehealth|clinic|provider)\b/.test(text)) missing.push("health topic");
  if (domain === "agriculture" && !/\b(crop|field|soil|irrigation|pest|disease|rain|market|farm)\b/.test(text)) missing.push("crop or farm context");
  if (domain === "maps-logistics" && !/\b(from|to|route|field|clinic|destination|origin|stockton|sacramento)\b/.test(text)) missing.push("origin and destination");
  if (domain === "communications" && !/\b(recipient|buyer|seller|provider|doctor|pharmacy|owner|team|john|mary)\b/.test(text)) missing.push("recipient");
  if (domain === "marketplace" && !/\b(product|crop|buyer|seller|quantity|price|maize|tomato)\b/.test(text)) missing.push("product or trade detail");
  return missing;
}

function nexusOsMissionProviderRequirement(domain, safetyClassification) {
  if (safetyClassification === "elevated-review-required") return "provider-or-action-connector-required-before-execution";
  if (["healthcare", "marketplace", "maps-logistics", "communications"].includes(domain)) return "verified-source-or-provider-needed-for-live-action";
  return "not-required-for-local-guidance";
}

function nexusOsMissionExecutionAvailability(safetyClassification) {
  if (safetyClassification === "elevated-review-required") return "blocked-until-consent-final-gate-provider-and-audit";
  if (safetyClassification === "medium-risk-review-required") return "preparation-only-until-reviewed";
  return "local-guidance-available";
}

function createNexusOsMissionRecord(goal = "", metadata = {}) {
  const now = nexusOsMissionNow();
  const domain = metadata.domain || inferNexusOsMissionDomain(goal);
  const intent = metadata.intent || inferNexusOsMissionIntent(goal);
  const safetyClassification = nexusOsMissionSafetyClassification(goal);
  const missingInformation = nexusOsMissionMissingInformation(goal, domain);
  return {
    missionId: nexusOsMissionId(),
    userGoal: goal || "Nexus guided mission",
    interpretedGoal: metadata.interpretedGoal || `${intent} in ${domain}`,
    domain,
    intent,
    currentState: "listen",
    currentStep: "Listen to the user's goal",
    completedSteps: [],
    missingInformation,
    collectedInformation: {},
    requiredConsent: safetyClassification !== "low-risk-local-guidance",
    providerRequirement: nexusOsMissionProviderRequirement(domain, safetyClassification),
    executionAvailability: nexusOsMissionExecutionAvailability(safetyClassification),
    safetyClassification,
    currentOutcome: "Mission started. Nexus has not executed any external action.",
    receiptReferences: [],
    createdAt: now,
    updatedAt: now,
    pauseState: "active",
    failureReason: "",
    retryEligibility: true,
    source: metadata.source || "nexus-os-mission-runtime"
  };
}

function currentNexusOsMission() {
  return nexusOsMissionLifecycleState.activeMission || null;
}

function startNexusOsMission(goal = "", metadata = {}) {
  const mission = createNexusOsMissionRecord(goal, metadata);
  nexusOsMissionLifecycleState.activeMission = mission;
  nexusOsMissionLifecycleState.updatedAt = mission.updatedAt;
  persistNexusOsMissionLifecycleState();
  return mission;
}

function canTransitionNexusOsMission(fromState, toState) {
  return Boolean((NEXUS_OS_MISSION_TRANSITIONS[fromState] || []).includes(toState));
}

function transitionNexusOsMission(toState, details = {}) {
  const mission = currentNexusOsMission();
  if (!mission) return null;
  const fromState = mission.currentState || "listen";
  if (!canTransitionNexusOsMission(fromState, toState)) {
    mission.failureReason = `Invalid transition blocked: ${fromState} to ${toState}`;
    mission.retryEligibility = true;
    mission.updatedAt = nexusOsMissionNow();
    persistNexusOsMissionLifecycleState();
    return mission;
  }
  mission.completedSteps = Array.from(new Set([...(mission.completedSteps || []), fromState]));
  mission.currentState = toState;
  mission.currentStep = details.currentStep || nexusOsMissionStepLabel(toState);
  mission.currentOutcome = details.currentOutcome || nexusOsMissionOutcomeForState(toState, mission);
  mission.pauseState = toState === "paused" ? "paused" : toState === "cancelled" ? "cancelled" : "active";
  if (toState === "failed") mission.failureReason = details.failureReason || mission.failureReason || "Mission failed safely.";
  if (toState === "complete") mission.completedSteps = Array.from(new Set([...(mission.completedSteps || []), "complete"]));
  if (toState === "return_home") {
    mission.completedSteps = Array.from(new Set([...(mission.completedSteps || []), "return_home"]));
    nexusOsMissionLifecycleState.missionHistory = [mission, ...(nexusOsMissionLifecycleState.missionHistory || [])].slice(0, 12);
    nexusOsMissionLifecycleState.activeMission = null;
  }
  mission.updatedAt = nexusOsMissionNow();
  nexusOsMissionLifecycleState.updatedAt = mission.updatedAt;
  persistNexusOsMissionLifecycleState();
  return mission;
}

function nexusOsMissionStepLabel(state = "listen") {
  return ({
    listen: "Listen to the user's goal",
    understand: "Interpret the goal",
    clarify: "Ask only for missing information",
    plan: "Build a safe plan",
    collect: "Collect required details",
    prepare: "Prepare the local output",
    confirm: "Request explicit confirmation where required",
    execute: "Execute only if configured and approved",
    verify: "Verify the result",
    record: "Record receipt and audit trail",
    learn: "Learn approved context",
    complete: "Complete the mission",
    return_home: "Return to Nexus Home",
    paused: "Paused by user",
    cancelled: "Cancelled before execution",
    failed: "Failed safely",
    retry: "Retry eligible mission"
  })[state] || "Mission step";
}

function nexusOsMissionOutcomeForState(state, mission = {}) {
  if (state === "confirm") return "Confirmation is required before any high-risk or provider action can proceed.";
  if (state === "execute") return mission.executionAvailability === "local-guidance-available" ? "Local safe action may run." : "External execution remains blocked until provider, consent, final gate, and audit are ready.";
  if (state === "complete") return "Mission completed with an outcome state. No unsupported external action was claimed.";
  if (state === "return_home") return "Mission returned to the calm Nexus Home state.";
  if (state === "cancelled") return "Mission cancelled before execution.";
  if (state === "failed") return "Mission failed safely and did not produce a success claim.";
  return `${nexusOsMissionStepLabel(state)}.`;
}

function advanceNexusOsMissionForCommand(command = "", metadata = {}) {
  const goal = String(command || "").trim();
  if (!goal) return currentNexusOsMission();
  const lower = goal.toLowerCase();
  let mission = currentNexusOsMission();
  if (/\b(pause mission|pause this mission|hold mission)\b/.test(lower)) return transitionNexusOsMission("paused", { currentOutcome: "Mission paused. Current step is retained." });
  if (/\b(resume mission|continue mission|keep going)\b/.test(lower) && mission?.currentState === "paused") return transitionNexusOsMission(mission.completedSteps?.at?.(-1) || "listen", { currentOutcome: "Mission resumed from the retained step." });
  if (/\b(cancel mission|stop mission|end mission)\b/.test(lower)) return transitionNexusOsMission("cancelled", { currentOutcome: "Mission cancelled before execution." });
  if (/\b(retry mission|try again)\b/.test(lower) && mission?.currentState === "failed") return transitionNexusOsMission("retry", { currentOutcome: "Mission is retry eligible and ready to restart." });
  if (/\b(complete mission|finish mission)\b/.test(lower)) return transitionNexusOsMission("complete", { currentOutcome: "Mission completed with a clear outcome state." });
  if (/\b(return home|back to nexus home|go home)\b/.test(lower)) return transitionNexusOsMission("return_home", { currentOutcome: "Returned to Nexus Home." });
  if (!mission || NEXUS_OS_MISSION_TERMINAL_STATES.includes(mission.currentState)) mission = startNexusOsMission(goal, metadata);
  if (mission.currentState === "listen") mission = transitionNexusOsMission("understand", { currentOutcome: "Nexus interpreted the user goal." }) || mission;
  if (mission.currentState === "understand") {
    mission = transitionNexusOsMission(mission.missingInformation?.length ? "clarify" : "plan", {
      currentOutcome: mission.missingInformation?.length ? "Nexus identified missing information." : "Nexus can plan with the available information."
    }) || mission;
  }
  if (mission.currentState === "clarify" && !mission.missingInformation?.length) mission = transitionNexusOsMission("plan") || mission;
  if (mission.currentState === "plan") {
    mission = transitionNexusOsMission(mission.safetyClassification === "elevated-review-required" ? "confirm" : "prepare") || mission;
  }
  return mission;
}

function renderNexusOsMissionLifecycleStatus() {
  const mission = currentNexusOsMission();
  const history = nexusOsMissionLifecycleState.missionHistory || [];
  const label = mission ? mission.currentState : "return_home";
  const title = mission ? mission.interpretedGoal : "Nexus Home";
  const outcome = mission ? mission.currentOutcome : "No active mission. Nexus is ready for the next goal.";
  return `
    <div class="nexus-os-mission-lifecycle-status" data-nexus-os-mission-lifecycle-status="true" data-current-state="${escapeHtml(label)}" data-execution-availability="${escapeHtml(mission?.executionAvailability || "no-active-execution")}">
      <div>
        <span>${escapeHtml(translateText("Mission"))}</span>
        <strong>${escapeHtml(translateText(title))}</strong>
        <small>${escapeHtml(translateText(outcome))}</small>
      </div>
      <div class="nexus-os-mission-lifecycle-steps" aria-label="${escapeHtml(translateText("Mission lifecycle"))}">
        ${NEXUS_OS_MISSION_LIFECYCLE_STATES.map(state => `<span class="${mission?.currentState === state ? "active" : mission?.completedSteps?.includes(state) ? "done" : ""}">${escapeHtml(translateText(state.replace("_", " ")))}</span>`).join("")}
      </div>
      <div class="nexus-os-mission-lifecycle-actions">
        <button type="button" data-nexus-os-mission-action="pause">${escapeHtml(translateText("Pause"))}</button>
        <button type="button" data-nexus-os-mission-action="resume">${escapeHtml(translateText("Resume"))}</button>
        <button type="button" data-nexus-os-mission-action="cancel">${escapeHtml(translateText("Cancel"))}</button>
        <button type="button" data-nexus-os-mission-action="complete">${escapeHtml(translateText("Complete"))}</button>
        <button type="button" data-nexus-os-mission-action="return-home">${escapeHtml(translateText("Return home"))}</button>
      </div>
      <small>${escapeHtml(translateText(`${history.length} previous mission(s) retained locally. Form completion alone does not complete a mission.`))}</small>
    </div>
  `;
}

async function handleNexusOsMissionLifecycleAction(action = "") {
  const normalized = String(action || "").toLowerCase();
  if (!currentNexusOsMission() && normalized !== "return-home") startNexusOsMission(agentPerformanceState.lastCommand || "Nexus guided mission", { source: "mission-action" });
  if (normalized === "pause") transitionNexusOsMission("paused", { currentOutcome: "Mission paused. Current step is retained." });
  if (normalized === "resume") {
    const mission = currentNexusOsMission();
    const retained = mission?.completedSteps?.at?.(-1) || "listen";
    transitionNexusOsMission(retained, { currentOutcome: "Mission resumed from the retained step." });
  }
  if (normalized === "cancel") transitionNexusOsMission("cancelled", { currentOutcome: "Mission cancelled before execution." });
  if (normalized === "complete") transitionNexusOsMission("complete", { currentOutcome: "Mission completed with an outcome state." });
  if (normalized === "return-home") {
    transitionNexusOsMission("return_home", { currentOutcome: "Returned to Nexus Home." });
    nexusGenesisExperienceActivated = false;
    nexusTrueExperienceSessionStarted = false;
    nexusTrueExperienceHomeResetEpoch = Date.now();
    nexusActiveWorkflowState = { id: "", command: "", source: "return-home", workflow: "", action: "", openedAt: 0 };
    nexusIntentDrivenWorkflowLastRoute = null;
    nexusAgenticCommandMissions = [];
  }
  renderUserWorkspace();
  updateNexusGenesisExperienceDom();
  if (normalized === "return-home") resetNexusGenesisHomeViewport();
  return true;
}

async function handleNexusOsVoiceControlAction(action = "toggle-listening", options = {}) {
  const normalized = String(action || "toggle-listening").toLowerCase();
  const source = options.source || "nexus-os-voice-control";
  if (normalized === "enable-voice") {
    if (nexusVoicePermissionDeniedThisSession || nexusOsVoiceRuntimeState.permissionState === "denied") {
      const response = "Microphone permission is blocked right now. Change microphone permission in your browser, then reload or allow microphone access again.";
      recordNexusOsConversationTurn("assistant", response, { source });
      showNexusVoiceFallbackMessage(response, { source: "voice-permission-denied-session", mode: "voice-unavailable", trustChainState: "permission_denied" });
      renderUserWorkspace();
      return true;
    }
    await startVoiceListening({ source: "explicit-enable-voice" });
    return true;
  }
  if (normalized === "toggle-hands-free") {
    const nextEnabled = !voiceFirstMode;
    voiceFirstMode = nextEnabled;
    voiceAutoRestart = nextEnabled;
    voiceStopRequested = false;
    try {
      localStorage.removeItem("agrinexusVoiceFirst");
    } catch {}
    const response = nextEnabled
      ? "Hands-free Nexus is on while this page is open. Say Nexus, Hello Nexus, or Hey Nexus when the browser is listening."
      : "Hands-free Nexus is off. Use the microphone permission control to resume voice when ready.";
    updateNexusOsVoiceRuntimeState({
      mode: nextEnabled ? "voice-first" : "standby",
      listeningState: nextEnabled ? "wake-phrase-ready" : "idle",
      hearingState: "idle"
    }, source);
    recordNexusOsConversationTurn("assistant", response, { source });
    setVoiceResponse(response, false, { allowVoiceFirst: false, source });
    renderUserWorkspace();
    if (nextEnabled) await startVoiceListening({ source: "explicit-hands-free-toggle" });
    return true;
  }
  if (normalized === "stop-listening") {
    voiceStopRequested = true;
    voiceAutoRestart = false;
    voiceFirstMode = false;
    try {
      localStorage.removeItem("agrinexusVoiceFirst");
    } catch {}
    try {
      if (voiceRecognition && typeof voiceRecognition.stop === "function") voiceRecognition.stop();
    } catch {}
    voiceRecognition = null;
    updateNexusOsVoiceRuntimeState({ mode: "standby", listeningState: "stopped", hearingState: "idle", assistantSpeaking: false }, source);
    const response = "Stopped listening. Use the microphone permission control or say start listening when voice is available.";
    recordNexusOsConversationTurn("assistant", response, { source });
    setVoiceResponse(response, false, { allowVoiceFirst: false, source });
    renderUserWorkspace();
    return true;
  }
  if (normalized === "stop-speaking") {
    stopVoicePlayback({ hard: true, reason: source });
    updateNexusOsVoiceRuntimeState({ mode: "standby", listeningState: "idle", hearingState: "idle" }, source);
    setVoiceResponse("Stopped speaking. Voice remains available when microphone permission is active.", false, { allowVoiceFirst: false, source });
    return true;
  }
  if (normalized === "repeat-response") {
    updateNexusOsVoiceRuntimeState({ mode: "speaking", listeningState: "idle" }, source);
    speakVoiceResponse(options.text || lastVoiceResponse || "Nexus is ready.");
    return true;
  }
  if (normalized === "mute") {
    nexusOsConversationMuted = true;
    disableNexusVoiceForDemo("Nexus voice is muted. Text responses remain available.", { silent: true });
    updateNexusOsVoiceRuntimeState({ mode: "muted", listeningState: "idle" }, source);
    recordNexusOsConversationTurn("assistant", "Nexus voice is muted. Captions and read-only transcript remain available.", { source });
    renderUserWorkspace();
    return true;
  }
  if (normalized === "unmute") {
    nexusOsConversationMuted = false;
    voiceDemoQuietMode = false;
    localStorage.setItem("agrinexusDemoQuiet", "off");
    saveNexusOsConversationTurns();
    updateNexusOsVoiceRuntimeState({ mode: "standby", listeningState: "idle" }, source);
    recordNexusOsConversationTurn("assistant", "Nexus voice is unmuted. Use voice when microphone permission is active.", { source });
    renderUserWorkspace();
    return true;
  }
  if (normalized === "typed-fallback") {
    if (nexusTrueExperienceHasActiveWorkflow()) {
      openAskNexus();
      $("#nexusCommandCenterInput")?.focus?.();
      updateNexusOsVoiceRuntimeState({ mode: "workflow-structured-entry", listeningState: "workflow-entry" }, source);
    } else {
      const response = "General typed commands are not available on Genesis home. Voice is the front door; structured typing appears only inside an active workflow.";
      recordNexusOsConversationTurn("assistant", response, { source });
      setVoiceResponse(response, false, { allowVoiceFirst: false, source });
      updateNexusOsVoiceRuntimeState({ mode: "standby", listeningState: "audio-only-home" }, source);
      renderUserWorkspace();
    }
    return true;
  }
  if (normalized === "voice-help") {
    const response = "Voice help is available. Use the microphone permission control when your browser supports speech recognition. Structured fields appear only after Nexus opens a workflow.";
    updateUserCaptionPanel(response);
    recordNexusOsConversationTurn("assistant", response, { source });
    setVoiceResponse(response, false, { allowVoiceFirst: false, source });
    updateNexusOsVoiceRuntimeState({ mode: "voice-help", listeningState: "audio-only-home" }, source);
    renderUserWorkspace();
    return true;
  }
  await startVoiceListening({ source });
  return true;
}

function userIsActivelySpeaking() {
  return Boolean(nexusVoiceSession.userSpeaking || (voiceLastPartialAt && Date.now() - voiceLastPartialAt < NEXUS_USER_SPEAKING_HOLD_MS));
}

function cancelQueuedNexusSpeech(reason = "newer voice turn") {
  clearTimeout(queuedVoiceSpeechTimer);
  queuedVoiceSpeechTimer = null;
  queuedVoiceSpeechPayload = null;
  updateNexusVoiceSession({ queuedSpeechAt: 0 }, reason);
}

function markNexusUserSpeech(text = "", source = "voice") {
  const phrase = normalizeVoicePartial(text);
  updateNexusOsVoiceRuntimeState({
    mode: "hearing",
    listeningState: "active",
    hearingState: "interim",
    lastPartial: phrase || nexusOsVoiceRuntimeState.lastPartial || ""
  }, source);
  updateNexusVoiceSession({
    state: "user-speaking",
    userSpeaking: true,
    assistantSpeaking: false,
    lastPartial: phrase || nexusVoiceSession.lastPartial,
    lastUserSpeechAt: Date.now()
  }, source);
  if (phrase && voiceSpeaking && shouldBargeInFromPartial(phrase)) {
    cancelQueuedNexusSpeech("human-barge-in");
    stopVoicePlayback({ hard: true, reason: "human-barge-in" });
  }
}

function markNexusUserSpeechFinal(text = "", turnToken = null) {
  const phrase = normalizeVoicePartial(text);
  cancelQueuedNexusSpeech("final-user-command");
  updateNexusOsVoiceRuntimeState({
    mode: "thinking",
    listeningState: "final",
    hearingState: "final",
    lastFinal: phrase,
    lastPartial: "",
    captionText: phrase
  }, "final-user-command");
  updateNexusVoiceSession({
    state: "thinking",
    userSpeaking: false,
    assistantSpeaking: false,
    activeTurnToken: turnToken || nexusVoiceTurnToken,
    lastFinal: phrase,
    lastPartial: "",
    lastUserSpeechAt: Date.now()
  }, "final-user-command");
}

function shouldDeferNexusSpeech(options = {}) {
  if (options.immediate || options.source === "stop" || voiceDemoQuietMode) return false;
  return streamingVoiceEnabled() && userIsActivelySpeaking();
}

function scheduleNexusSpeech(text = "", options = {}) {
  const compact = normalizeVoicePartial(text);
  if (!compact) return;
  if (options.turnToken && !isCurrentNexusVoiceTurn(options.turnToken)) return;
  if (shouldDeferNexusSpeech(options)) {
    queuedVoiceSpeechPayload = { text: compact, options: { ...options, immediate: true } };
    nexusVoiceSession.queuedSpeechText = compact;
    updateNexusVoiceSession({
      state: "speech-queued",
      queuedSpeechAt: Date.now(),
      assistantSpeaking: false
    }, "waiting-for-user-to-finish");
    clearTimeout(queuedVoiceSpeechTimer);
    queuedVoiceSpeechTimer = setTimeout(() => {
      const payload = queuedVoiceSpeechPayload;
      queuedVoiceSpeechPayload = null;
      queuedVoiceSpeechTimer = null;
      if (!payload || userIsActivelySpeaking()) {
        if (payload) scheduleNexusSpeech(payload.text, payload.options);
        return;
      }
      speakVoiceResponse(payload.text);
    }, NEXUS_SPEECH_GATE_DELAY_MS);
    return;
  }
  cancelQueuedNexusSpeech("speaking-now");
  updateNexusVoiceSession({
    state: "assistant-speaking",
    userSpeaking: false,
    assistantSpeaking: true,
    lastAssistantSpeechAt: Date.now()
  }, options.source || "assistant-response");
  speakVoiceResponse(compact);
}

function setStreamingVoiceEnabled(enabled = true, reason = "") {
  voiceStreamingMode = Boolean(enabled);
  localStorage.setItem("agrinexusStreamingVoice", voiceStreamingMode ? "on" : "off");
  updateNativeVoiceBridgeState(voiceStreamingMode ? "streaming-ready" : "streaming-off", { reason });
  refreshMicSupport();
}

function normalizeVoicePartial(text = "") {
  return String(text || "")
    .replace(/\s+/g, " ")
    .trim();
}

function nativeVoiceBridge() {
  return window.AgriNexusNativeVoice
    || window.NexusNativeVoice
    || window.ReactNativeWebView
    || window.webkit?.messageHandlers?.agrinexusVoice
    || null;
}

function postNativeVoiceMessage(bridge, payload) {
  try {
    if (typeof bridge?.onNexusVoiceState === "function") {
      bridge.onNexusVoiceState(payload);
      return true;
    }
    if (typeof bridge?.onVoiceState === "function") {
      bridge.onVoiceState(payload);
      return true;
    }
    if (typeof bridge?.postMessage === "function") {
      bridge.postMessage(JSON.stringify(payload));
      return true;
    }
    if (typeof bridge?.postMessage === "object" && typeof bridge.postMessage?.postMessage === "function") {
      bridge.postMessage.postMessage(JSON.stringify(payload));
      return true;
    }
  } catch (error) {
    console.warn("Native voice bridge update failed", error);
  }
  return false;
}

function updateNativeVoiceBridgeState(state, payload = {}) {
  const bridge = nativeVoiceBridge();
  nativeVoiceBridgeReady = Boolean(bridge);
  const session = {
    id: nativeVoiceSession?.id || `voice-${Date.now()}`,
    state,
    build: AGRINEXUS_BUILD_VERSION,
    streaming: streamingVoiceEnabled(),
    voiceFirst: voiceFirstMode,
    locale: voiceLocale(),
    language: languageCode(),
    updatedAt: new Date().toISOString(),
    ...payload
  };
  nativeVoiceSession = session;
  localStorage.setItem("agrinexusNativeVoiceSession", JSON.stringify(session));
  if (bridge) postNativeVoiceMessage(bridge, { type: "agrinexus.voice.state", ...session });
  return session;
}

function registerNativeVoiceSession(reason = "web-voice-session") {
  nativeVoiceSession = {
    id: `voice-${Date.now()}`,
    build: AGRINEXUS_BUILD_VERSION,
    state: "ready",
    reason,
    streaming: streamingVoiceEnabled(),
    voiceFirst: voiceFirstMode,
    locale: voiceLocale(),
    language: languageCode(),
    updatedAt: new Date().toISOString()
  };
  localStorage.setItem("agrinexusNativeVoiceSession", JSON.stringify(nativeVoiceSession));
  updateNativeVoiceBridgeState("ready", { reason });
  return nativeVoiceSession;
}

function nativeVoiceReadinessSummary() {
  const bridge = nativeVoiceBridge();
  const mode = streamingVoiceEnabled() ? "streaming web voice is on" : "streaming web voice is off";
  const native = bridge ? "native bridge is detected" : "native bridge hooks are ready for the mobile app shell";
  return `${mode}; ${native}; locale ${voiceLocale()}.`;
}

function shouldBargeInFromPartial(text = "") {
  const partial = normalizeVoicePartial(text);
  if (partial.length < VOICE_PARTIAL_BARGE_IN_MIN_CHARS) return false;
  if (isLikelyNexusSelfEcho(partial)) return false;
  const lower = normalizeToolText(partial);
  if (isGlobalStopCommand(lower)) return true;
  if (answerChoiceFromSpeech(partial)) return true;
  if (/\b(nexus|agrinexus|doctor|medicine|clinic|work|job|course|learn|crop|sell|buyer|map|route|stop|yes|no)\b/.test(lower)) return true;
  return partial.split(/\s+/).filter(Boolean).length >= 4;
}

function updateStreamingVoicePartial(text = "", options = {}) {
  const partial = normalizeVoicePartial(text);
  if (!partial) return;
  voiceInterimTranscript = partial;
  voiceLastPartialAt = Date.now();
  if (!voiceInterimStartedAt) voiceInterimStartedAt = voiceLastPartialAt;
  const message = `Hearing: ${partial}`;
  ["#globalVoiceOutputStatus", "#voiceTranscript", "#jarvisSummary"].forEach(selector => {
    const element = $(selector);
    if (element) element.textContent = translateText(message);
  });
  updateNativeVoiceBridgeState("partial", { transcript: partial, source: options.source || "web-speech" });
  updateNexusOsVoiceRuntimeState({
    mode: "hearing",
    listeningState: "active",
    hearingState: "interim",
    lastPartial: partial
  }, options.source || "interim-speech");
  markNexusUserSpeech(partial, options.source || "interim-speech");
}

function clearStreamingVoicePartial() {
  voiceInterimTranscript = "";
  voiceInterimStartedAt = 0;
  voiceLastPartialAt = 0;
  updateNexusOsVoiceRuntimeState({
    hearingState: "idle",
    lastPartial: ""
  }, "partial-cleared");
  updateNexusVoiceSession({ userSpeaking: false, lastPartial: "" }, "partial-cleared");
}

function resumeVoiceListeningAfterSpeech(playbackToken, interruptToken) {
  if (playbackToken !== voicePlaybackToken || interruptToken !== voiceInterruptToken) return;
  recordGenesisSpokenResponsePipelineEvent("listening-resume-started", {
    correlationId: activeGenesisVoiceCorrelationId || "",
    success: true,
    sourceFunction: "resumeVoiceListeningAfterSpeech"
  });
  voiceSpeaking = false;
  if (nexusGenesisVoiceSessionActive && isNexusGenesisHomeActive()) {
    voiceFirstMode = true;
    voiceStopRequested = false;
  }
  voiceAutoRestart = voiceFirstMode || (nexusGenesisVoiceSessionActive && isNexusGenesisHomeActive());
  updateNexusVoiceSession({
    state: voiceFirstMode ? "listening-ready" : "standby",
    assistantSpeaking: false,
    userSpeaking: false
  }, "speech-finished");
  updateNativeVoiceBridgeState(voiceFirstMode ? "listening-ready" : "standby", { reason: "speech-finished" });
  const message = nexusListeningReadyMessage();
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translateText(message);
  updateNexusBehaviorLayer(voiceFirstMode ? "listening" : "ready", message);
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  refreshMicSupport();
  const shouldResume = voiceFirstMode || voiceResumeAfterSpeech || (nexusGenesisVoiceSessionActive && isNexusGenesisHomeActive());
  if (shouldResume && !voiceRecognition && !voiceStopRequested && !document.hidden) {
    voiceResumeAfterSpeech = false;
    clearTimeout(nexusGenesisVoiceRestartTimer);
    nexusGenesisVoiceRestartTimer = setTimeout(() => {
      nexusGenesisVoiceRestartTimer = null;
      if (!voiceRecognition && !voiceSpeaking && !voiceStopRequested && (voiceFirstMode || nexusGenesisVoiceSessionActive)) {
        recordNexusAudioPipelineEvent("recognition-restart-requested", { source: "speech-finished" });
        nexusGenesisVoiceDebugLog("recognition-restarted", { source: "speech-finished" });
        startVoiceListening({ source: "genesis-speech-finished-restart" });
      }
    }, VOICE_RESTART_DELAY_MS);
  }
  recordGenesisSpokenResponsePipelineEvent("listening-resumed", {
    correlationId: activeGenesisVoiceCorrelationId || "",
    success: true,
    sourceFunction: "resumeVoiceListeningAfterSpeech"
  });
}

function stopVoicePlayback(options = {}) {
  voicePlaybackToken += 1;
  if (options.hard) {
    voiceInterruptToken += 1;
    voiceTranslationToken += 1;
    lastSpokenText = "";
    lastSpokenAt = 0;
  }
  if (activeVoiceRequestController) {
    try {
      activeVoiceRequestController.abort();
    } catch (error) {
      // The request may already have finished.
    }
    activeVoiceRequestController = null;
  }
  if (activeVoiceAudio) {
    activeVoiceAudio.pause();
    activeVoiceAudio.onended = null;
    activeVoiceAudio.onerror = null;
    activeVoiceAudio.src = "";
    activeVoiceAudio.load?.();
    activeVoiceAudio = null;
  }
  if ("speechSynthesis" in window) window.speechSynthesis.cancel();
  voiceSpeaking = false;
  voiceAutoRestart = voiceFirstMode;
  updateNexusOsVoiceRuntimeState({
    mode: options.hard ? "interrupted" : "speech-stopped",
    hearingState: "idle",
    assistantSpeaking: false
  }, options.reason || "voice-playback-stop");
  updateNexusVoiceSession({
    state: options.hard ? "interrupted" : "speech-stopped",
    assistantSpeaking: false
  }, options.reason || "voice-playback-stop");
  updateNativeVoiceBridgeState(options.hard ? "interrupted" : "speech-stopped", { reason: options.reason || "voice-playback-stop" });
}

function voiceResponseSignature(text = "") {
  return normalizeToolText(text).split(/\s+/).filter(Boolean).slice(0, 18).join(" ");
}

function stripStandaloneVoiceAcknowledgement(text = "") {
  return String(text || "")
    .replace(/^\s*(got it|yes|okay|ok|sure|absolutely|i hear you)\s*[.!]\s+(?=\S)/i, "")
    .replace(/\s+/g, " ")
    .trim();
}

function sanitizeNexusSpokenResponseText(value = "") {
  return String(value || "")
    .replace(/```[\s\S]*?```/g, " code block omitted from spoken response. ")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, "$1")
    .replace(/https?:\/\/\S+/g, " source link available in text ")
    .replace(/\b[A-Z0-9_]*(?:API[_-]?KEY|SECRET|TOKEN|AUTHORIZATION|BEARER)\s*[:=]\s*\S+/gi, match => `${match.split(/[:=]/)[0]} redacted`)
    .replace(/\b(api[_-]?key|secret|token|authorization|bearer)\s*[:=]\s*\S+/gi, "$1 redacted")
    .replace(/[*#>|~]+/g, " ")
    .replace(/\bsk-[A-Za-z0-9_-]{12,}\b/g, "redacted credential")
    .replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, "email address")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 3600);
}

const NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT = Object.freeze({
  schemaVersion: "nexus-speech-synthesis-controller.v1",
  controllerName: "NexusSpeechSynthesisController",
  canonicalRuntimeOwner: "nexus-os-canonical-voice",
  supportedAdapters: Object.freeze(["openai-tts", "browser-speech-synthesis", "typed-caption-fallback"]),
  browserAdapter: "NexusBrowserSpeechSynthesisAdapter",
  serverAdapter: "NexusServerTtsAdapter",
  defaultOptions: Object.freeze({
    rate: 0.92,
    pitch: 0.9,
    volume: 1
  }),
  safeguards: Object.freeze({
    featureDetected: true,
    userGestureRequiredForAudibleSpeech: true,
    captionsFallbackRequired: true,
    noAutoplayClaim: true,
    noProviderClaimWithoutAvailability: true,
    noVoiceCloning: true,
    noCharacterImitation: true,
    noWorkflowExecutionAuthority: true
  })
});

function nexusSpeechSynthesisControllerState() {
  const synthesisSupported = typeof window !== "undefined" && "speechSynthesis" in window && typeof window.SpeechSynthesisUtterance === "function";
  const capability = typeof nexusVoiceCapabilitySummary === "function" ? nexusVoiceCapabilitySummary() : {};
  const regionalVoice = typeof nexusRegionalVoiceSummary === "function" ? nexusRegionalVoiceSummary() : {};
  return {
    schemaVersion: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.schemaVersion,
    controllerName: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
    runtimeOwner: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.canonicalRuntimeOwner,
    synthesisSupported,
    browserFallbackEnabled: typeof browserSpeechFallbackEnabled === "function" ? browserSpeechFallbackEnabled() : false,
    captionsFallbackRequired: true,
    selectedLocale: typeof voiceLocale === "function" ? voiceLocale() : "en-US",
    selectedVoiceName: regionalVoice.voiceName || "",
    selectedVoiceMatch: regionalVoice.matchType || "not-evaluated",
    readyProviderIds: capability.readyProviderIds || [],
    noWorkflowExecutionAuthority: true,
    noProviderClaimWithoutAvailability: true
  };
}

function createNexusSpeechSynthesisUtterance(text = "", options = {}) {
  const compact = String(text || "").replace(/\s+/g, " ").trim();
  if (!compact) return { ok: false, reason: "empty-text", utterance: null, controllerState: nexusSpeechSynthesisControllerState() };
  if (typeof window === "undefined" || !("speechSynthesis" in window) || typeof window.SpeechSynthesisUtterance !== "function") {
    return { ok: false, reason: "browser-speech-synthesis-unavailable", utterance: null, controllerState: nexusSpeechSynthesisControllerState() };
  }
  const utterance = new SpeechSynthesisUtterance(compact);
  const locale = options.locale || (typeof voiceLocale === "function" ? voiceLocale() : "en-US");
  const voice = options.voice || (typeof chooseSpeechVoice === "function" ? chooseSpeechVoice(locale) : null);
  if (voice) utterance.voice = voice;
  if (options.locale) {
    utterance.lang = locale;
  } else if (typeof voiceLocale === "function") {
    utterance.lang = voiceLocale();
  } else {
    utterance.lang = locale;
  }
  if (Number.isFinite(options.rate)) {
    utterance.rate = options.rate;
  } else if (typeof speechRateForLanguage === "function") {
    utterance.rate = speechRateForLanguage();
  } else {
    utterance.rate = NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.defaultOptions.rate;
  }
  if (Number.isFinite(options.pitch)) {
    utterance.pitch = options.pitch;
  } else if (typeof speechPitchForLanguage === "function") {
    utterance.pitch = speechPitchForLanguage();
  } else {
    utterance.pitch = NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.defaultOptions.pitch;
  }
  const preferredVolume = getNexusVoicePreferences?.().speechVolume;
  utterance.volume = Number.isFinite(options.volume)
    ? options.volume
    : Number.isFinite(Number(preferredVolume))
      ? Math.max(0, Math.min(1, Number(preferredVolume)))
      : NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.defaultOptions.volume;
  return {
    ok: true,
    reason: "browser-speech-synthesis-ready",
    utterance,
    controllerState: {
      ...nexusSpeechSynthesisControllerState(),
      selectedLocale: locale,
      selectedVoiceName: voice?.name || "",
      rate: utterance.rate,
      pitch: utterance.pitch,
      volume: utterance.volume
    }
  };
}

function runNexusSpeechSynthesisController(text = "", options = {}) {
  const prepared = createNexusSpeechSynthesisUtterance(text, options);
  const compact = String(text || "").replace(/\s+/g, " ").trim();
  if (!prepared.ok) {
    recordNexusAudioPipelineEvent("speech-synthesis-unavailable", {
      reason: prepared.reason,
      synthesisRequested: false
    });
    updateNexusOsVoiceRuntimeState({
      mode: "caption-fallback",
      assistantSpeaking: false,
      speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
      speechSynthesisReason: prepared.reason,
      captionText: compact
    }, options.reason || "speech-synthesis-fallback");
    return prepared;
  }
  try {
    recordNexusAudioPipelineEvent("speech-synthesis-request", {
      synthesisRequested: true,
      selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default",
      locale: prepared.controllerState.selectedLocale
    });
    nexusGenesisVoiceDebugLog("synthesis-requested", {
      selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default",
      locale: prepared.controllerState.selectedLocale,
      textLength: compact.length
    });
    window.speechSynthesis.cancel();
    prepared.utterance.onstart = event => {
      recordNexusAudioPipelineEvent("speech-synthesis-onstart", { synthesisRequested: true });
      nexusGenesisVoiceDebugLog("synthesis-started", {
        selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default",
        locale: prepared.controllerState.selectedLocale
      });
      updateNexusOsVoiceRuntimeState({
        mode: "speaking",
        assistantSpeaking: true,
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechSynthesisProvider: "browser-speech-synthesis",
        speechSynthesisReason: "browser-speech-onstart",
        selectedSpeechVoice: prepared.controllerState.selectedVoiceName || "browser-default",
        selectedSpeechLocale: prepared.controllerState.selectedLocale,
        speechRate: prepared.controllerState.rate,
        speechPitch: prepared.controllerState.pitch,
        speechVolume: prepared.controllerState.volume,
        speechStartEventReceived: true,
        captionText: compact
      }, options.reason || "speech-synthesis-onstart");
      setNexusGenesisTrustChainState("speaking", {
        response: compact,
        visibleFeedback: compact,
        reason: "speech-synthesis-onstart"
      });
      options.onStart?.(event);
    };
    prepared.utterance.onboundary = event => {
      updateNexusOsVoiceRuntimeState({
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechBoundaryEventReceived: true,
        speechBoundaryCharIndex: event?.charIndex ?? null,
        captionText: compact
      }, options.reason || "speech-synthesis-boundary");
      options.onBoundary?.(event);
    };
    prepared.utterance.onpause = event => {
      updateNexusOsVoiceRuntimeState({
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechSynthesisReason: "browser-speech-paused",
        captionText: compact
      }, options.reason || "speech-synthesis-paused");
      options.onPause?.(event);
    };
    prepared.utterance.onresume = event => {
      updateNexusOsVoiceRuntimeState({
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechSynthesisReason: "browser-speech-resumed",
        captionText: compact
      }, options.reason || "speech-synthesis-resumed");
      options.onResume?.(event);
    };
    prepared.utterance.onend = event => {
      recordNexusAudioPipelineEvent("speech-synthesis-onend", { synthesisRequested: true });
      nexusGenesisVoiceDebugLog("synthesis-completed", {
        selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default",
        locale: prepared.controllerState.selectedLocale
      });
      updateNexusOsVoiceRuntimeState({
        mode: "standby",
        assistantSpeaking: false,
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechSynthesisReason: "browser-speech-finished",
        speechEndEventReceived: true,
        captionText: compact
      }, options.reason || "speech-synthesis-finished");
      setNexusGenesisTrustChainState("waiting", {
        response: compact,
        visibleFeedback: "Nexus is ready for your next request.",
        reason: "speech-synthesis-finished"
      });
      nexusGenesisConversationSupervisor?.speechOutputEnded?.("browser-speech-finished");
      options.onEnd?.(event);
    };
    prepared.utterance.onerror = event => {
      recordNexusAudioPipelineEvent("speech-synthesis-error", {
        error: event?.error || "unknown",
        synthesisRequested: true
      });
      nexusGenesisVoiceDebugLog("synthesis-error", { error: event?.error || "unknown" });
      updateNexusOsVoiceRuntimeState({
        mode: "caption-fallback",
        assistantSpeaking: false,
        speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
        speechSynthesisReason: "browser-speech-error",
        speechErrorCode: event?.error || "unknown",
        captionText: compact
      }, options.reason || "speech-synthesis-error");
      setNexusGenesisTrustChainState("synthesis_failed", {
        response: compact,
        visibleFeedback: "I heard you, but I am unable to speak right now. I will continue in text.",
        failureRecovery: "Continue in visible text and allow retry by user gesture.",
        reason: "speech-synthesis-error"
      });
      options.onError?.(event);
    };
    updateNexusOsVoiceRuntimeState({
      mode: "speech-preparing",
      assistantSpeaking: false,
      speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
      speechSynthesisProvider: "browser-speech-synthesis",
      speechSynthesisReason: prepared.reason,
      selectedSpeechVoice: prepared.controllerState.selectedVoiceName || "browser-default",
      selectedSpeechLocale: prepared.controllerState.selectedLocale,
      speechRate: prepared.controllerState.rate,
      speechPitch: prepared.controllerState.pitch,
      speechVolume: prepared.controllerState.volume,
      captionText: compact
    }, options.reason || "speech-synthesis-preparing");
    setNexusGenesisTrustChainState("speech_preparing", {
      response: compact,
      visibleFeedback: compact,
      reason: "speech-synthesis-preparing"
    });
    window.speechSynthesis.speak(prepared.utterance);
    nexusGenesisVoiceDebugLog("synthesis-speak-called", {
      selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default",
      locale: prepared.controllerState.selectedLocale
    });
    setTimeout(() => {
      const startStillUnconfirmed = nexusOsVoiceRuntimeState.speechSynthesisReason === prepared.reason
        && nexusOsVoiceRuntimeState.captionText === compact;
      if (!startStillUnconfirmed) return;
      recordNexusAudioPipelineEvent("speech-synthesis-start-unconfirmed", {
        synthesisRequested: true,
        selectedVoice: prepared.controllerState.selectedVoiceName || "browser-default"
      });
      updateNexusOsVoiceRuntimeState({
        mode: "caption-fallback",
        assistantSpeaking: false,
        speechSynthesisReason: "browser-speech-start-unconfirmed",
        captionText: compact
      }, options.reason || "speech-synthesis-start-unconfirmed");
    }, 2500);
    return { ...prepared, requested: true, started: false };
  } catch (error) {
    recordNexusAudioPipelineEvent("speech-synthesis-start-failed", {
      error: error.message || "speech synthesis failed",
      synthesisRequested: true
    });
    updateNexusOsVoiceRuntimeState({
      mode: "caption-fallback",
      assistantSpeaking: false,
      speechSynthesisController: NEXUS_SPEECH_SYNTHESIS_CONTROLLER_CONTRACT.controllerName,
      speechSynthesisReason: "browser-speech-start-failed",
      captionText: compact
    }, options.reason || "speech-synthesis-start-failed");
    setNexusGenesisTrustChainState("synthesis_failed", {
      response: compact,
      visibleFeedback: "I heard you, but I am unable to speak right now. I will continue in text.",
      failureRecovery: "Continue in visible text and allow retry by user gesture.",
      reason: "speech-synthesis-start-failed"
    });
    options.onError?.(error);
    return { ok: false, reason: "browser-speech-start-failed", error: error.message || String(error), controllerState: nexusSpeechSynthesisControllerState() };
  }
}

function isGuidedHealthVoiceResponse(text = "", options = {}) {
  const value = normalizeToolText(`${options.command || ""} ${text || ""}`);
  const healthNeed = /\b(doctor|nurse|provider|clinic|hospital|medicine|medication|pharmacy|dawa|health|care|patient|sick|injury|baby|child|grandma)\b/.test(value);
  const guided = /\b(not a diagnosis|first tell me|where you are|village|city|landmark|medicine concern|provider handoff|mobile clinic|pharmacy support)\b/.test(value);
  return healthNeed && guided;
}

function conciseVoiceResponse(message = "", options = {}) {
  const text = stripStandaloneVoiceAcknowledgement(message);
  if (!text || options.allowLongResponse || options.longForm) return text;
  const shouldShorten = options.speak || voiceFirstMode || experienceMode === "user" || localStorage.getItem("agrinexusShortAnswers") === "on";
  if (!shouldShorten) return text;
  const sentences = text.match(/[^.!?]+[.!?]+/g) || [];
  const healthGuidance = isGuidedHealthVoiceResponse(text, options);
  const sentenceLimit = healthGuidance ? 4 : experienceMode === "user" || localStorage.getItem("agrinexusShortAnswers") === "on" ? 1 : 2;
  const sentenceText = sentences.length ? sentences.slice(0, sentenceLimit).join(" ").trim() : text;
  const words = sentenceText.split(/\s+/).filter(Boolean);
  const maxWords = healthGuidance ? 88 : experienceMode === "user" ? 26 : 42;
  if (words.length <= maxWords) return sentenceText;
  return `${words.slice(0, maxWords).join(" ")}.`;
}

function repeatSafeVoiceResponse(message = "", options = {}) {
  const compact = conciseVoiceResponse(message, options);
  const signature = voiceResponseSignature(compact);
  const now = Date.now();
  if (options.speak && signature && signature === lastVoiceResponseSignature && now - lastVoiceResponseAt < 45000) {
    lastVoiceResponseRepeatCount += 1;
  } else {
    lastVoiceResponseRepeatCount = 0;
  }
  lastVoiceResponseSignature = signature;
  if (lastVoiceResponseRepeatCount >= 1 && options.speak) {
    return "I hear you. I will stop repeating. Say it again slowly, or say one word: health, medicine, crop, work, learning, map, or stop.";
  }
  return compact;
}

function isLikelyNexusSelfEcho(command = "") {
  const heard = normalizeToolText(command);
  const spoken = normalizeToolText(lastVoiceResponse);
  if (!heard || !spoken || heard.length < 18) return false;
  if (spoken.includes(heard) || heard.includes(spoken.slice(0, Math.min(80, spoken.length)))) return true;
  const heardTokens = new Set(heard.split(/\s+/).filter(token => token.length > 3));
  const spokenTokens = new Set(spoken.split(/\s+/).filter(token => token.length > 3));
  if (heardTokens.size < 4 || spokenTokens.size < 4) return false;
  const overlap = [...heardTokens].filter(token => spokenTokens.has(token)).length;
  return overlap / Math.max(heardTokens.size, 1) >= 0.68;
}

function abortActiveAgentCommand() {
  if (!activeAgentCommandController) return;
  try {
    activeAgentCommandController.abort();
  } catch (error) {
    // Request may already be settled.
  }
  activeAgentCommandController = null;
}

function beginNexusVoiceTurn(command = "") {
  nexusVoiceTurnToken += 1;
  cancelQueuedNexusSpeech("new-voice-turn");
  stopVoicePlayback({ hard: true });
  abortActiveAgentCommand();
  clearAgentProgressTimers();
  voiceStopRequested = false;
  voiceAutoRestart = voiceFirstMode;
  updateNexusVoiceSession({
    state: "thinking",
    userSpeaking: false,
    assistantSpeaking: false,
    activeTurnToken: nexusVoiceTurnToken,
    lastFinal: normalizeVoicePartial(command)
  }, "begin-voice-turn");
  updateNexusBehaviorLayer("thinking", command ? `Nexus is listening to the newest request: ${command}` : "Nexus is listening to the newest request.");
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translateText("Nexus heard the new request.");
  return nexusVoiceTurnToken;
}

function isCurrentNexusVoiceTurn(turnToken) {
  return !turnToken || turnToken === nexusVoiceTurnToken;
}

function ignoreStaleNexusTurn(turnToken, label = "stale response") {
  if (isCurrentNexusVoiceTurn(turnToken)) return false;
  clearAgentProgressTimers();
  updateNexusBehaviorLayer("listening", `Nexus ignored a ${label} because you already asked something newer.`);
  return true;
}

function interruptNexusSpeech(reason = "I stopped speaking and I am ready for the next instruction.") {
  cancelQueuedNexusSpeech("manual-interrupt");
  stopVoicePlayback({ hard: true });
  resetNexusForNextPrompt(reason);
}

function speakVoiceResponse(textOverride) {
  if (voiceDemoQuietMode) {
    stopVoicePlayback({ hard: true });
    updateNexusOsVoiceRuntimeState({ mode: "muted", assistantSpeaking: false }, "speech-muted");
    return;
  }
  const text = textOverride || lastVoiceResponse;
  const correlationId = activeGenesisVoiceCorrelationId || createGenesisVoiceCorrelationId();
  activeGenesisVoiceCorrelationId = correlationId;
  const compact = sanitizeNexusSpokenResponseText(text);
  if (!compact) {
    recordGenesisSpokenResponsePipelineEvent("speech-sanitization-empty", {
      correlationId,
      success: false,
      sourceFunction: "speakVoiceResponse"
    });
    updateNexusOsVoiceRuntimeState({ mode: "caption-fallback", assistantSpeaking: false }, "speech-empty-after-sanitization");
    return;
  }
  recordGenesisSpokenResponsePipelineEvent("speech-sanitization-succeeded", {
    correlationId,
    success: true,
    responseLength: String(text || "").length,
    sanitizedLength: compact.length,
    sourceFunction: "speakVoiceResponse"
  });
  const interruptToken = voiceInterruptToken;
  const now = Date.now();
  if (compact && compact === lastSpokenText && now - lastSpokenAt < 3500) return;
  lastSpokenText = compact;
  lastSpokenAt = now;
  stopVoicePlayback();
  const genesisActive = nexusGenesisVoiceSessionActive && isNexusGenesisHomeActive();
  const keepListeningForAnswer = genesisActive || shouldKeepListeningDuringSpeech(compact);
  const keepStreamingOpen = streamingVoiceEnabled();
  if (voiceRecognition && !keepListeningForAnswer && !keepStreamingOpen) {
    const activeRecognition = voiceRecognition;
    voiceRecognition = null;
    voiceAutoRestart = false;
    try {
      activeRecognition.stop();
    } catch (error) {
      // Recognition may already be stopped.
    }
  }
  const playbackToken = ++voicePlaybackToken;
  voiceSpeaking = true;
  voiceAutoRestart = keepListeningForAnswer || keepStreamingOpen || false;
  updateNexusOsVoiceRuntimeState({
    mode: "speech-preparing",
    listeningState: voiceAutoRestart ? "active" : "idle",
    hearingState: "idle",
    assistantSpeaking: false,
    lastSpokenPreview: compact.slice(0, 180),
    spokenTextSanitized: true,
    spokenTextLength: compact.length,
    captionText: compact
  }, "speech-playback-preparing");
  setNexusGenesisTrustChainState("speech_preparing", {
    response: compact,
    visibleFeedback: compact,
    reason: "speech-playback-preparing"
  });
  updateNexusVoiceSession({
    state: "speech-preparing",
    assistantSpeaking: false,
    userSpeaking: false,
    queuedSpeechAt: Date.now()
  }, "speech-playback-preparing");
  updateNativeVoiceBridgeState("speech-preparing", { text: compact.slice(0, 180), keepListening: voiceAutoRestart });
  const updateVoiceOutputStatus = message => {
    const localStatus = $("#voicePlaybackStatus");
    const globalStatus = $("#globalVoiceOutputStatus");
    if (localStatus) localStatus.textContent = message;
    if (globalStatus) globalStatus.textContent = message;
  };
  const finishSpeaking = () => {
    if (playbackToken !== voicePlaybackToken || interruptToken !== voiceInterruptToken) return;
    activeVoiceAudio = null;
    recordGenesisSpokenResponsePipelineEvent("audio-play-completed", {
      correlationId,
      success: true,
      playbackStarted: Boolean(finishSpeaking.playbackStarted),
      sourceFunction: "speakVoiceResponse.finishSpeaking"
    });
    nexusGenesisConversationSupervisor?.speechOutputEnded?.("audio-play-completed");
    resumeVoiceListeningAfterSpeech(playbackToken, interruptToken);
  };
  finishSpeaking.playbackStarted = false;
  const browserSpeak = reason => {
    const genesisRecoveryEnabled = genesisVoiceBrowserSpeechRecoveryEnabled();
    const optInBrowserFallbackEnabled = browserSpeechFallbackEnabled();
    if (!optInBrowserFallbackEnabled && !genesisRecoveryEnabled) {
      const fallbackMessage = "I heard you, but I am unable to speak right now. I will continue in text.";
      updateVoiceOutputStatus(`${fallbackMessage} ${reason} Browser speech fallback is off by default.`);
      updateUserCaptionPanel(fallbackMessage, { expanded: true });
      setNexusGenesisTrustChainState("synthesis_unavailable", {
        response: compact,
        visibleFeedback: fallbackMessage,
        failureRecovery: "Visible text remains available.",
        reason: "browser-speech-fallback-disabled"
      });
      toast("OpenAI voice unavailable. Browser voice fallback is off.");
      finishSpeaking();
      return;
    }
    recordGenesisSpokenResponsePipelineEvent("browser-speech-fallback-started", {
      correlationId,
      success: true,
      ttsProvider: "browser-speech-synthesis",
      sourceFunction: "speakVoiceResponse.browserSpeak"
    });
    const speechResult = runNexusSpeechSynthesisController(compact, {
      reason: genesisRecoveryEnabled ? "genesis-browser-speech-recovery" : "browser-speech-fallback",
      onStart: event => {
        finishSpeaking.playbackStarted = true;
        recordGenesisSpokenResponsePipelineEvent("audio-play-started", {
          correlationId,
          success: true,
          ttsProvider: "browser-speech-synthesis",
          playbackStarted: true,
          sourceFunction: "runNexusSpeechSynthesisController.onStart"
        });
      },
      onEnd: event => {
        recordGenesisSpokenResponsePipelineEvent("browser-speech-fallback-completed", {
          correlationId,
          success: true,
          ttsProvider: "browser-speech-synthesis",
          playbackStarted: true,
          sourceFunction: "runNexusSpeechSynthesisController.onEnd"
        });
        finishSpeaking(event);
      },
      onError: event => {
        recordGenesisSpokenResponsePipelineEvent("browser-speech-fallback-completed", {
          correlationId,
          success: false,
          ttsProvider: "browser-speech-synthesis",
          errorCategory: event?.error || "browser-speech-error",
          sourceFunction: "runNexusSpeechSynthesisController.onError"
        });
        finishSpeaking(event);
      }
    });
    if (speechResult.ok && (speechResult.requested || speechResult.started)) {
      const optInRecoveryLabel = "Using opt-in browser speech fallback. NexusSpeechSynthesisController is managing playback.";
      const recoveryLabel = genesisRecoveryEnabled
        ? "Using browser-native speech synthesis for the Genesis voice session because OpenAI voice audio is unavailable."
        : optInRecoveryLabel;
      updateVoiceOutputStatus(`${reason} ${recoveryLabel} Speech state will change to speaking after the browser start event.`);
    } else {
      updateVoiceOutputStatus(`${reason} Browser speech fallback could not start: ${speechResult.reason}.`);
      finishSpeaking();
    }
  };
  updateVoiceOutputStatus("Requesting OpenAI voice audio...");
  recordGenesisSpokenResponsePipelineEvent("tts-request-started", {
    correlationId,
    route: "/api/voice/speak",
    success: true,
    ttsProvider: "openai",
    sanitizedLength: compact.length,
    sourceFunction: "speakVoiceResponse"
  });
  activeVoiceRequestController = new AbortController();
  request("/api/voice/speak", { method: "POST", signal: activeVoiceRequestController.signal, body: { correlationId, text: compact, language: languageCode(), locale: voiceLocale(), rate: speechRateForLanguage(), pitch: speechPitchForLanguage(), forceOpenAi: true, voice: preferredOpenAiTtsVoice() } })
    .then(result => {
      if (playbackToken !== voicePlaybackToken || interruptToken !== voiceInterruptToken) return;
      activeVoiceRequestController = null;
      const audioDataUrl = result.voiceResult?.audioDataUrl;
      recordGenesisSpokenResponsePipelineEvent("tts-response-received", {
        correlationId,
        route: "/api/voice/speak",
        success: true,
        httpStatus: 200,
        ttsProvider: result.voiceResult?.provider || "unknown",
        audioByteLength: String(audioDataUrl || "").length,
        errorCategory: result.voiceResult?.error ? result.voiceResult?.diagnostics?.errorType || "provider_error" : "",
        sourceFunction: "speakVoiceResponse"
      });
      if (result.voiceResult?.error) {
        const diagnostics = result.voiceResult?.diagnostics || {};
        const errorType = diagnostics.errorType || "provider_error";
        const statusCategory = diagnostics.httpStatusCategory || "unknown";
        const attempted = diagnostics.requestAttempted ? "request attempted" : "request not attempted";
        updateVoiceOutputStatus(`OpenAI voice error: ${result.voiceResult.error}. Provider diagnostic: ${errorType}, ${statusCategory}, ${attempted}.`);
        toast("OpenAI voice error. Check Render logs for /api/voice/speak.");
        browserSpeak(`OpenAI voice error: ${result.voiceResult.error}`);
        return;
      }
      if (audioDataUrl) {
        const audio = new Audio(audioDataUrl);
        activeVoiceAudio = audio;
        const voice = result.voiceResult?.voice || "OpenAI";
        const model = result.voiceResult?.model || "speech";
        const spokenLength = Number(result.voiceResult?.spokenTextLength || compact.length);
        updateVoiceOutputStatus(`Using OpenAI voice: ${voice} (${model}). Spoken output prepared safely (${spokenLength} characters).`);
        audio.onplay = () => {
          if (playbackToken !== voicePlaybackToken || interruptToken !== voiceInterruptToken) return;
          finishSpeaking.playbackStarted = true;
          recordGenesisSpokenResponsePipelineEvent("audio-play-started", {
            correlationId,
            success: true,
            ttsProvider: "openai-tts",
            audioByteLength: String(audioDataUrl || "").length,
            playbackStarted: true,
            sourceFunction: "HTMLAudioElement.onplay"
          });
          updateNexusOsVoiceRuntimeState({
            mode: "speaking",
            assistantSpeaking: true,
            speechSynthesisProvider: "openai-tts",
            speechStartEventReceived: true,
            spokenTextSanitized: true,
            spokenTextLength: spokenLength,
            speechResponseFormat: result.voiceResult?.responseFormat || "mp3",
            captionText: compact
          }, "openai-audio-onplay");
          setNexusGenesisTrustChainState("speaking", {
            response: compact,
            visibleFeedback: compact,
            reason: "openai-audio-onplay"
          });
          updateNexusVoiceSession({
            state: "assistant-speaking",
            assistantSpeaking: true,
            userSpeaking: false,
            lastAssistantSpeechAt: Date.now()
          }, "openai-audio-onplay");
          updateNativeVoiceBridgeState("speaking", { text: compact.slice(0, 180), keepListening: voiceAutoRestart });
        };
        audio.onended = finishSpeaking;
        audio.onerror = finishSpeaking;
        recordGenesisSpokenResponsePipelineEvent("audio-play-requested", {
          correlationId,
          success: true,
          ttsProvider: "openai-tts",
          audioByteLength: String(audioDataUrl || "").length,
          sourceFunction: "HTMLAudioElement.play"
        });
        audio.play().catch(() => {
          recordGenesisSpokenResponsePipelineEvent("audio-play-rejected", {
            correlationId,
            success: false,
            ttsProvider: "openai-tts",
            audioByteLength: String(audioDataUrl || "").length,
            errorCategory: "browser-play-rejected",
            sourceFunction: "HTMLAudioElement.play"
          });
          browserSpeak("OpenAI audio was created, but the browser blocked playback.");
        });
        return;
      }
      recordGenesisSpokenResponsePipelineEvent("tts-response-invalid", {
        correlationId,
        route: "/api/voice/speak",
        success: false,
        ttsProvider: result.voiceResult?.provider || "unknown",
        errorCategory: "missing-audio-data-url",
        sourceFunction: "speakVoiceResponse"
      });
      browserSpeak(`OpenAI voice returned no audio. Provider: ${result.voiceResult?.provider || "unknown"}.`);
    })
    .catch(error => {
      if (playbackToken !== voicePlaybackToken || interruptToken !== voiceInterruptToken) return;
      activeVoiceRequestController = null;
      if (error.name === "AbortError") {
        updateVoiceOutputStatus("Voice playback interrupted.");
        return;
      }
      recordGenesisSpokenResponsePipelineEvent("tts-response-invalid", {
        correlationId,
        route: "/api/voice/speak",
        success: false,
        ttsProvider: "openai",
        errorCategory: /sign in required/i.test(error.message || "") ? "session-expired" : "tts-request-failed",
        sourceFunction: "speakVoiceResponse.catch"
      });
      if (/sign in required/i.test(error.message || "")) {
        updateVoiceOutputStatus("Your session expired after redeploy. Sign in again, then press Read response.");
        toast("Please sign in again to use OpenAI voice.");
        finishSpeaking();
        return;
      }
      updateVoiceOutputStatus(`OpenAI voice unavailable: ${error.message || "speech request failed"}. Browser speech fallback is off by default.`);
      toast("OpenAI voice unavailable. Check Render environment values.");
      browserSpeak(`OpenAI voice unavailable: ${error.message || "speech request failed"}.`);
    });
}

function setVoiceStatus(status) {
  updateNexusOsVoiceRuntimeState({
    mode: status || "standby",
    listeningState: status === "listening" || status === "voice-first" ? "active" : "idle",
    microphoneUnavailable: status === "unavailable"
  }, "set-voice-status");
  const statusEl = $("#voiceStatus");
  if (statusEl) statusEl.textContent = status;
  const globalStatus = $("#globalAssistantStatus");
  if (globalStatus) globalStatus.textContent = status === "paused"
    ? "Nexus is paused. Say Nexus or press the mic to continue."
    : status === "listening"
      ? "Listening now. Speak your request."
      : lastVoiceResponse || status;
  const jarvisMode = $("#jarvisMode");
  if (jarvisMode) jarvisMode.textContent = status;
  const panel = $(".voice-command");
  if (panel) panel.classList.toggle("voice-listening", status === "listening");
  const bar = $("#globalAssistantBar");
  if (bar) bar.classList.toggle("voice-listening", status === "listening");
  updateNexusBehaviorLayer(status);
}

function showNexusVoiceFallbackMessage(message = "Voice is not available in this browser. You can keep using typed Ask Nexus.", options = {}) {
  const compact = String(message || "").replace(/\s+/g, " ").trim();
  if (!compact) return;
  const source = options.source || "browser-voice-fallback";
  lastVoiceResponse = compact;
  lastVoiceResponseAt = Date.now();
  updateNexusOsVoiceRuntimeState({
    mode: options.mode || "typed-fallback",
    listeningState: "typed",
    hearingState: "idle",
    assistantSpeaking: false,
    captionText: compact
  }, source);
  setNexusGenesisTrustChainState(options.trustChainState || "recognition_unavailable", {
    visibleFeedback: compact,
    failureRecovery: "Keep typed Ask Nexus available.",
    reason: source
  });
  setNexusPresenceState(NEXUS_PRESENCE_STATES.WAITING, {
    lastResponse: compact,
    nextQuestion: "Type your request in Ask Nexus.",
    activeMission: nexusPresenceState.activeMission
  });
  recordNexusOsConversationTurn("assistant", compact, { source, state: nexusCoreRuntimeState.current });
  updateUserCaptionPanel(compact, { expanded: true });
  syncNexusPresenceSurfaces(options.mode || "typed-fallback", {
    source,
    captionText: compact,
    assistantSpeaking: false
  });
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translateText(compact);
  const assistantStatus = $("#globalAssistantStatus");
  if (assistantStatus) assistantStatus.textContent = translateText(compact);
  updateNexusOsUnifiedConversationDom();
}

function realtimeVoiceSupported() {
  const secureEnough = window.isSecureContext || ["localhost", "127.0.0.1"].includes(location.hostname);
  return Boolean(window.RTCPeerConnection && navigator.mediaDevices?.getUserMedia && secureEnough);
}

function realtimeMicrophoneUiAvailable() {
  const secureEnough = window.isSecureContext || ["localhost", "127.0.0.1"].includes(location.hostname);
  return Boolean(navigator.mediaDevices?.getUserMedia && secureEnough);
}

function realtimeVoiceEnabled() {
  const status = realtimeVoiceStatusCache?.realtimeVoice;
  return Boolean(status?.runtime === "realtime" && status?.realtimeEnabled !== false);
}

function realtimeVoiceActive() {
  return Boolean(realtimeVoiceSession?.active && realtimeMicrophoneProofIsLive(realtimeVoiceSession?.sdkController));
}

function genesisVoiceConversationActive() {
  return Boolean(realtimeVoiceActive());
}

function openAiRealtimeSelectedByPolicy() {
  const runtimeStatus = realtimeVoiceStatusCache?.realtimeVoice?.runtime;
  const policy = nexusGenesisVoiceRuntimePolicyCache?.voiceRuntime || {};
  return runtimeStatus === "realtime"
    || policy.serverSelectedRuntime === "realtime"
    || policy.selectedRuntime === "realtime"
    || policy.activeRuntime === "realtime";
}

function shouldBypassLegacyPlannerForRealtimeFallback() {
  return Boolean(openAiRealtimeSelectedByPolicy() || realtimeVoiceStarting || realtimeVoiceSession?.handoffPending);
}

function realtimeVoiceStatusMessage() {
  if (!realtimeMicrophoneUiAvailable()) return "Enable microphone from a secure HTTPS, localhost, or 127.0.0.1 page to talk with Nexus.";
  if (!realtimeVoiceSupported()) return "Realtime voice needs WebRTC support. The microphone control remains available so Nexus can show the exact startup issue.";
  const status = realtimeVoiceStatusCache?.realtimeVoice;
  if (status?.ready) return "Nexus realtime voice is ready.";
  if (status?.runtime === "legacy") return "Nexus legacy voice runtime is selected by server configuration.";
  if (status?.runtime === "disabled") return "Nexus voice is temporarily unavailable.";
  if (status && !status.configured) return status.note || "OpenAI Realtime voice needs OPENAI_API_KEY in hosting.";
  return "Nexus realtime voice can start when selected and configured by the server.";
}

function elevenLabsVoiceSupported() {
  return false;
}

function elevenLabsVoiceEnabled() {
  return false;
}

function elevenLabsVoiceActive() {
  return Boolean(elevenLabsVoiceSession?.active);
}

async function loadNexusGenesisVoiceRuntimePolicy(options = {}) {
  if (!options.force && nexusGenesisVoiceRuntimePolicyCache && Date.now() - (nexusGenesisVoiceRuntimePolicyCache.checkedAt || 0) < 60000) {
    return nexusGenesisVoiceRuntimePolicyCache;
  }
  try {
    const response = await fetch("/api/voice/runtime/status", {
      method: "GET",
      credentials: "same-origin",
      cache: "no-store",
      headers: { Accept: "application/json" }
    });
    const payload = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(payload.error || `Voice runtime policy failed: ${response.status}`);
    nexusGenesisVoiceRuntimePolicyCache = { ...payload, checkedAt: Date.now() };
  } catch {
    nexusGenesisVoiceRuntimePolicyCache = {
      voiceRuntime: {
        activeRuntime: "realtime",
        selectedRuntime: "realtime",
        candidateRuntime: "",
        candidateEnabled: false,
        candidateAllowed: false,
        automaticRollback: false,
        legacyBrowserVoiceActiveForNormalUsers: false,
        noSecretValues: true
      },
      checkedAt: Date.now()
    };
  }
  return nexusGenesisVoiceRuntimePolicyCache;
}

function initializeNexusGenesisVoiceRuntimeManager(policyPayload = {}) {
  if (nexusGenesisVoiceRuntimeManager) return nexusGenesisVoiceRuntimeManager;
  const factory = window.NexusGenesisVoiceRuntimeManagerFactory;
  if (!factory?.createNexusVoiceRuntimeManager) return null;
  const policy = policyPayload.voiceRuntime || {};
  const lock = factory.createVoiceOwnershipLock();
  const sessionContext = factory.createSessionContext();
  const realtimeAdapter = factory.RealtimeVoiceAdapter({
    lock,
    sessionContext,
    startSession: () => startRealtimeVoiceSession({ managedRuntime: true }),
    stopSession: reason => stopRealtimeVoiceSession(reason || "manager-realtime-stop"),
    startListening: () => Boolean(realtimeVoiceActive() && realtimeMicrophoneProofIsLive(realtimeVoiceSession?.sdkController)),
    stopListening: () => realtimeVoiceSession?.sdkController?.mute?.(true),
    recover: () => startRealtimeVoiceSession({ managedRuntime: true, recovery: true }),
    interrupt: () => realtimeVoiceSession?.sdkController?.interrupt?.(),
    updateLanguage: language => realtimeVoiceSession?.sdkController?.sendMessage?.(`Continue in language ${language}.`),
    releaseOwnership: reason => stopRealtimeVoiceSession(reason || "manager-realtime-release")
  });
  nexusGenesisVoiceRuntimeManager = factory.createNexusVoiceRuntimeManager({
    lock,
    sessionContext,
    legacyAdapter: null,
    elevenLabsAdapter: null,
    realtimeAdapter,
    activeRuntime: "realtime",
    candidateRuntime: "",
    candidateEnabled: false,
    candidateAllowed: false,
    automaticRollback: false
  });
  nexusGenesisConversationSupervisor = factory.createGenesisConversationSupervisor({
    runtimeManager: nexusGenesisVoiceRuntimeManager,
    sessionContext,
    language: languageCode(),
    voice: "openai-realtime-webrtc",
    isTransportActive: () => Boolean(realtimeVoiceActive())
  });
  window.NexusGenesisVoiceRuntimeManager = nexusGenesisVoiceRuntimeManager;
  window.NexusGenesisConversationSupervisor = nexusGenesisConversationSupervisor;
  return nexusGenesisVoiceRuntimeManager;
}

async function nexusGenesisElevenLabsCandidateAllowed() {
  const policyPayload = await loadNexusGenesisVoiceRuntimePolicy({ force: true });
  const manager = initializeNexusGenesisVoiceRuntimeManager(policyPayload);
  const policy = policyPayload.voiceRuntime || {};
  nexusGenesisVoiceDebugLog("voice-runtime-policy-resolved", {
    activeRuntime: "realtime",
    selectedRuntime: "realtime",
    candidateRuntime: "",
    candidateEnabled: false,
    candidateAllowed: false,
    automaticRollback: false,
    managerAvailable: Boolean(manager),
    noSecretValues: true
  });
  return false;
}

function elevenLabsVoiceStatusMessage() {
  if (!elevenLabsVoiceSupported()) return "ElevenLabs voice needs HTTPS, WebRTC, and microphone permission.";
  const status = elevenLabsVoiceStatusCache?.elevenLabsVoice;
  if (status?.ready) return "Nexus ElevenLabs Agents voice is ready.";
  if (status && !status.configured) return status.note || `ElevenLabs Agents needs ${status.missingEnv?.join(", ") || "provider configuration"} in hosting.`;
  if (status?.runtime && status.runtime !== "elevenlabs") return status.note || "ElevenLabs Agents is not selected.";
  return "Nexus ElevenLabs Agents voice can start when configured by the server.";
}

async function loadElevenLabsVoiceStatus(options = {}) {
  if (!options.force && elevenLabsVoiceStatusCache && Date.now() - (elevenLabsVoiceStatusCache.checkedAt || 0) < 60000) {
    return elevenLabsVoiceStatusCache;
  }
  const response = await fetch("/api/voice/elevenlabs/status", {
    method: "GET",
    credentials: "same-origin",
    headers: { Accept: "application/json" }
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error || `ElevenLabs voice status failed: ${response.status}`);
  elevenLabsVoiceStatusCache = { ...payload, checkedAt: Date.now() };
  return elevenLabsVoiceStatusCache;
}

async function loadElevenLabsConversationSdk() {
  throw new Error("ElevenLabs SDK loading has been removed from Genesis production.");
}

function normalizeElevenLabsSdkErrorEvent(message, context = {}) {
  const raw = context && typeof context === "object" ? context : {};
  const candidate = raw.error || raw.event || raw.detail || raw.message || message || {};
  const errorType = String(candidate?.error_type || candidate?.type || candidate?.code || raw.error_type || "sdk-error");
  const errorMessage = String(candidate?.message || candidate?.error || message || raw.message || "ElevenLabs SDK session error.");
  return {
    errorType: errorType.slice(0, 80),
    message: errorMessage.slice(0, 180),
    malformed: !candidate || typeof candidate !== "object" || !("error_type" in candidate)
  };
}

function nexusElevenLabsSafeToolResult(result = {}) {
  const safe = {
    ok: Boolean(result.ok),
    response: String(result.response || result.message || "Nexus completed the local tool step."),
    capability: String(result.capability || ""),
    blockedReason: String(result.blockedReason || ""),
    executionAttempted: Boolean(result.executionAttempted),
    confirmationRequired: Boolean(result.confirmationRequired),
    receipt: result.receipt ? {
      id: String(result.receipt.id || ""),
      status: String(result.receipt.status || "")
    } : null
  };
  return JSON.stringify(safe);
}

async function runElevenLabsClientTool(toolName = "nexus_capability_router", parameters = {}, toolCallId = "") {
  try {
    const response = await fetch("/api/voice/runtime/tool", {
      method: "POST",
      credentials: "same-origin",
      cache: "no-store",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: JSON.stringify({
        name: toolName,
        callId: toolCallId,
        correlationId: `el-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
        arguments: {
          ...parameters,
          command: parameters.command || parameters.query || parameters.text || ""
        },
        language: languageCode()
      })
    });
    const result = await response.json().catch(() => ({
      ok: false,
      response: "I could not complete that Nexus tool request.",
      blockedReason: "client-parse-failed"
    }));
    return nexusElevenLabsSafeToolResult(result);
  } catch {
    return nexusElevenLabsSafeToolResult({
      ok: false,
      response: "I could not reach the Nexus tool layer right now.",
      blockedReason: "provider-unavailable",
      executionAttempted: false
    });
  }
}

function nexusElevenLabsClientTools() {
  const names = [
    "nexus_general_capability",
    "nexus_weather",
    "nexus_maps_route",
    "nexus_agriculture",
    "nexus_health_preparation",
    "nexus_workforce_learning",
    "nexus_marketplace_logistics",
    "nexus_communications",
    "nexus_workflow",
    "nexus_receipts",
    "nexus_provider_readiness",
    "nexus_capability_router"
  ];
  return names.reduce((tools, toolName) => {
    tools[toolName] = async parameters => runElevenLabsClientTool(toolName, parameters || {});
    return tools;
  }, {});
}

function handleElevenLabsSdkMessage(message = {}) {
  const source = String(message.source || message.role || "");
  const text = String(message.message || message.text || "");
  const safeSource = source || "unknown";
  nexusGenesisVoiceDebugLog("elevenlabs-sdk-message", {
    source: safeSource,
    messageLength: text.length,
    conversationId: elevenLabsVoiceSession?.conversationId || ""
  });
  if (!text) return;
  if (safeSource === "user" || safeSource === "human") {
    updateStreamingVoicePartial(text, { source: "elevenlabs-sdk-user-transcript" });
    recordNexusOsConversationTurn("user", text, { source: "elevenlabs-sdk-final-transcript" });
    nexusGenesisVoiceDebugLog("final-transcript-received", { source: "elevenlabs-sdk", transcriptLength: text.length });
    return;
  }
  recordNexusOsConversationTurn("assistant", text, { source: "elevenlabs-sdk-agent-response" });
  updateUserCaptionPanel(text, { expanded: true });
  setNexusGenesisTrustChainState("response_ready", {
    response: text,
    visibleFeedback: text,
    reason: "elevenlabs-sdk-agent-response"
  });
}

function stopElevenLabsVoiceSession(reason = "ElevenLabs voice stopped.") {
  if (!elevenLabsVoiceSession) return;
  const session = elevenLabsVoiceSession;
  elevenLabsVoiceSession = null;
  try {
    session.conversation?.endSession?.();
  } catch {}
  elevenLabsVoiceStarting = false;
  setVoiceStatus("standby");
  updateNexusBehaviorLayer("standby", reason);
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translateText(reason);
  refreshMicSupport();
}

async function startElevenLabsVoiceSession(options = {}) {
  return false;
  if (!elevenLabsVoiceSupported()) return false;
  if (elevenLabsVoiceActive()) return true;
  if (elevenLabsVoiceStarting) return true;
  elevenLabsVoiceStarting = true;
  try {
    const candidateAllowed = await nexusGenesisElevenLabsCandidateAllowed();
    if (!candidateAllowed) return false;
    const statusPayload = await loadElevenLabsVoiceStatus({ force: true });
    const status = statusPayload?.elevenLabsVoice || {};
    if (status.runtime !== "elevenlabs") return false;
    if (!status.ready) throw new Error(status.note || "ElevenLabs Agents voice is not configured.");
    if (realtimeVoiceActive()) stopRealtimeVoiceSession("OpenAI Realtime disabled for ElevenLabs acceptance.");
    if (voiceRecognition) {
      try {
        voiceRecognition.stop();
      } catch {}
      voiceRecognition = null;
    }
    stopVoicePlayback();
    stopNexusAudioFallbackRecorder("elevenlabs-selected");
    stopNexusVoicePermissionStream("elevenlabs-selected");
    const sdk = await loadElevenLabsConversationSdk();
    const sessionCorrelationId = `el-session-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
    nexusGenesisVoiceDebugLog("elevenlabs-session-request-started", {
      correlationId: sessionCorrelationId,
      credentialsMode: "same-origin",
      language: languageCode()
    });
    const sessionResponse = await fetch(`/api/voice/elevenlabs/session?language=${encodeURIComponent(languageCode())}`, {
      method: "POST",
      credentials: "same-origin",
      cache: "no-store",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: JSON.stringify({ language: languageCode(), correlationId: sessionCorrelationId })
    });
    const sessionPayload = await sessionResponse.json().catch(() => ({}));
    nexusGenesisVoiceDebugLog(sessionResponse.ok ? "authorization-request-succeeded" : "authorization-request-failed", {
      correlationId: sessionCorrelationId,
      httpStatus: sessionResponse.status,
      authMechanism: sessionPayload.authMechanism || "",
      providerAttempted: sessionPayload.providerAttempted === true,
      artifactType: sessionPayload.conversationToken ? "conversationToken" : sessionPayload.signedUrl ? "signedUrl" : "",
      errorCategory: sessionPayload.category || ""
    });
    if (!sessionResponse.ok || (!sessionPayload.conversationToken && !sessionPayload.signedUrl)) {
      throw new Error(sessionPayload.error || `ElevenLabs session failed: ${sessionResponse.status}`);
    }
    const connectionType = sessionPayload.conversationToken ? "webrtc" : "websocket";
    elevenLabsVoiceSession = {
      active: true,
      runtime: "elevenlabs",
      provider: "elevenlabs",
      conversation: null,
      connectionType,
      startedAt: Date.now(),
      conversationId: sessionPayload.conversationId || "",
      runtimeVersion: sessionPayload.runtimeVersion || NEXUS_GENESIS_ELEVENLABS_RUNTIME_VERSION
    };
    nexusGenesisVoiceDebugLog("elevenlabs-sdk-session-authorized", {
      connectionType,
      authArtifact: sessionPayload.conversationToken ? "conversationToken" : "signedUrl",
      conversationId: sessionPayload.conversationId || ""
    });
    const sdkOptions = {
      connectionType,
      clientTools: nexusElevenLabsClientTools(),
      overrides: {
        agent: {
          prompt: {
            prompt: "You are Nexus Genesis, the live voice companion inside AgriNexus. Keep ordinary conversation conversational. Use Nexus tools only for real platform workflows, and never claim execution without verified evidence."
          },
          firstMessage: "Nexus is listening."
        }
      },
      dynamicVariables: {
        language: languageCode(),
        product: "Nexus Genesis | AgriNexus"
      },
      onConnect: info => {
        const activeSession = elevenLabsVoiceSession;
        if (!activeSession) return;
        elevenLabsVoiceStarting = false;
        voiceStopRequested = false;
        activeSession.conversationId = info?.conversationId || activeSession.conversationId || "";
        setVoiceStatus("listening");
        updateNexusVoiceSession({
          state: "elevenlabs-listening",
          userSpeaking: false,
          assistantSpeaking: false
        }, "elevenlabs-sdk-connected");
        updateNativeVoiceBridgeState("elevenlabs-listening", { provider: "elevenlabs-agents-sdk", locale: voiceLocale() });
        setNexusGenesisTrustChainState("listening", {
          visibleFeedback: "Nexus is listening.",
          reason: "elevenlabs-sdk-connected"
        });
        const outputStatus = $("#globalVoiceOutputStatus");
        if (outputStatus) outputStatus.textContent = translateText("Nexus is listening.");
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-connected", {
          connectionType: activeSession.connectionType,
          conversationId: activeSession.conversationId
        });
        refreshMicSupport();
      },
      onDisconnect: details => {
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-disconnected", {
          reason: String(details?.reason || details?.code || "closed")
        });
        if (elevenLabsVoiceSession) {
          stopElevenLabsVoiceSession("ElevenLabs voice session closed.");
          if (options.managedRuntime && nexusGenesisVoiceRuntimeManager?.policy?.automaticRollback !== false) {
            void nexusGenesisVoiceRuntimeManager.rollbackToLegacy("candidate-disconnect", { announce: true });
          }
        }
      },
      onMessage: handleElevenLabsSdkMessage,
      onError: (message, context) => {
        const normalizedError = normalizeElevenLabsSdkErrorEvent(message, context);
        setNexusGenesisTrustChainState("recognition_failed", {
          visibleFeedback: "The ElevenLabs voice session had a connection problem.",
          failureRecovery: "Reload Genesis after ElevenLabs provider credentials are available.",
          reason: "elevenlabs-sdk-error"
        });
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-error", {
          reason: normalizedError.message,
          errorType: normalizedError.errorType,
          malformedProviderEvent: normalizedError.malformed
        });
        if (options.managedRuntime && nexusGenesisVoiceRuntimeManager?.policy?.automaticRollback !== false) {
          void nexusGenesisVoiceRuntimeManager.rollbackToLegacy(normalizedError.malformed ? "malformed-provider-error" : normalizedError.errorType, { announce: true });
        }
      },
      onUnhandledClientToolCall: toolCall => {
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-unhandled-tool", {
          toolName: String(toolCall?.tool_name || toolCall?.name || "unknown").slice(0, 80)
        });
      },
      onAgentToolRequest: toolRequest => {
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-agent-tool-request", {
          toolName: String(toolRequest?.tool_name || toolRequest?.name || "unknown").slice(0, 80)
        });
      },
      onModeChange: mode => {
        const nextMode = String(mode?.mode || mode || "");
        if (nextMode === "speaking") {
          updateNexusVoiceSession({ state: "elevenlabs-speaking", assistantSpeaking: true, userSpeaking: false }, "elevenlabs-sdk-speaking");
          setNexusGenesisTrustChainState("speaking", {
            visibleFeedback: "Nexus is speaking.",
            reason: "elevenlabs-sdk-speaking"
          });
        } else if (nextMode === "listening") {
          updateNexusVoiceSession({ state: "elevenlabs-listening", assistantSpeaking: false, lastAssistantSpeechAt: Date.now() }, "elevenlabs-sdk-listening");
          setNexusGenesisTrustChainState("listening", {
            visibleFeedback: "Nexus is listening.",
            reason: "elevenlabs-sdk-listening"
          });
        }
      },
      onStatusChange: statusChange => {
        const statusValue = String(statusChange?.status || statusChange || "");
        nexusGenesisVoiceDebugLog("elevenlabs-sdk-status", { status: statusValue });
      },
      onVadScore: payload => {
        const score = Number(payload?.vadScore ?? payload ?? 0);
        if (score > 0.65) {
          updateNexusVoiceSession({ state: "elevenlabs-user-speaking", userSpeaking: true, assistantSpeaking: false }, "elevenlabs-sdk-vad");
          setNexusGenesisTrustChainState("hearing", {
            visibleFeedback: "Nexus hears speech.",
            reason: "elevenlabs-sdk-vad"
          });
        }
      },
      onInterruption: () => {
        updateNexusVoiceSession({ state: "elevenlabs-listening", assistantSpeaking: false }, "elevenlabs-sdk-interruption");
        setNexusGenesisTrustChainState("listening", {
          visibleFeedback: "Nexus is listening.",
          reason: "elevenlabs-sdk-interruption"
        });
      }
    };
    if (sessionPayload.conversationToken) sdkOptions.conversationToken = sessionPayload.conversationToken;
    else sdkOptions.signedUrl = sessionPayload.signedUrl;
    nexusGenesisVoiceDebugLog("SDK-session-started", {
      correlationId: sessionPayload.correlationId || sessionCorrelationId,
      connectionType,
      conversationId: sessionPayload.conversationId || "",
      authArtifact: sessionPayload.conversationToken ? "conversationToken" : "signedUrl"
    });
    const conversation = await sdk.Conversation.startSession(sdkOptions);
    if (elevenLabsVoiceSession) elevenLabsVoiceSession.conversation = conversation;
    return true;
  } catch (error) {
    elevenLabsVoiceStarting = false;
    stopElevenLabsVoiceSession("ElevenLabs voice did not start.");
    const status = elevenLabsVoiceStatusCache?.elevenLabsVoice || {};
    const missing = Array.isArray(status.missingEnv) && status.missingEnv.length ? ` Missing: ${status.missingEnv.join(", ")}.` : "";
    const message = `${status.note || "Nexus ElevenLabs Agents voice is not available yet."}${missing}`;
    const outputStatus = $("#globalVoiceOutputStatus");
    if (outputStatus) outputStatus.textContent = translateText(message);
    updateNexusBehaviorLayer("blocked", message);
    setNexusGenesisTrustChainState("recognition_failed", {
      visibleFeedback: "Nexus voice is not configured yet.",
      failureRecovery: message,
      reason: "elevenlabs-start-failed"
    });
    nexusGenesisVoiceDebugLog("elevenlabs-session-failed", {
      reason: error.message || "elevenlabs-start-failed"
    });
    return false;
  }
}

function realtimeControllerSnapshot(extra = {}) {
  const session = realtimeVoiceSession || {};
  const proof = normalizeRealtimeMicrophoneProof(session.sdkController || null);
  const track = proof.track || session.stream?.getAudioTracks?.()[0] || null;
  return {
    sessionId: session.sessionId || "",
    turnId: session.turnId || "",
    controllerState: session.controllerState || "closed",
    runtime: session.runtime || "realtime",
    active: Boolean(session.active && proof.hasLiveTrack),
    handoffPending: Boolean(session.handoffPending),
    transport: session.transport || "",
    model: session.model || "",
    peerConnectionState: session.peerConnection?.connectionState || "",
    iceConnectionState: session.peerConnection?.iceConnectionState || "",
    signalingState: session.peerConnection?.signalingState || "",
    dataChannelState: session.dataChannel?.readyState || "",
    microphoneTrackState: proof.trackState || track?.readyState || "none",
    microphoneTrackEnabled: proof.trackEnabled || (track ? Boolean(track.enabled) : false),
    microphoneTrackMuted: proof.trackMuted || (track ? Boolean(track.muted) : false),
    liveMicrophoneTrack: Boolean(proof.hasLiveTrack),
    inboundAudioState: session.inboundAudioState || "none",
    lastModelEvent: session.lastModelEvent || "",
    lastToolEvent: session.lastToolEvent || "",
    fallbackState: session.fallbackState || "",
    activeResponseId: session.activeResponseId || "",
    responseInProgress: Boolean(session.responseInProgress),
    elapsedMs: session.startedAt ? Date.now() - session.startedAt : 0,
    ...extra
  };
}

function nexusRealtimeClientRuntimeStatus(extra = {}) {
  const snapshot = realtimeControllerSnapshot(extra);
  const connected = Boolean(realtimeVoiceSession?.active && snapshot.liveMicrophoneTrack);
  return {
    schemaVersion: "nexus.realtime.clientStatus.v1",
    activeRuntime: connected ? "realtime" : "unconfirmed",
    runtimeSelectedByServer: realtimeVoiceStatusCache?.realtimeVoice?.runtime || nexusGenesisVoiceRuntimePolicyCache?.voiceRuntime?.serverSelectedRuntime || nexusGenesisVoiceRuntimePolicyCache?.voiceRuntime?.selectedRuntime || "",
    connectionState: connected ? "connected" : snapshot.controllerState || "closed",
    transport: snapshot.transport || "agents-sdk-webrtc",
    model: snapshot.model || realtimeVoiceStatusCache?.realtimeVoice?.model || "",
    microphoneTrackState: snapshot.microphoneTrackState,
    liveMicrophoneTrack: snapshot.liveMicrophoneTrack,
    inboundAudioState: snapshot.inboundAudioState,
    lastModelEvent: snapshot.lastModelEvent,
    lastToolEvent: snapshot.lastToolEvent,
    fallbackState: snapshot.fallbackState || (connected ? "inactive" : "legacy-listener-or-backend-responses"),
    soleInputOwner: connected ? !voiceRecognition : false,
    noSecretValues: true
  };
}

window.NexusGenesisRealtimeClientStatus = nexusRealtimeClientRuntimeStatus;

function normalizeRealtimeMicrophoneProof(controller = null) {
  const proof = typeof controller?.getMicrophoneProof === "function"
    ? controller.getMicrophoneProof()
    : null;
  const stream = controller?.mediaStream || realtimeVoiceSession?.stream || null;
  const track = proof?.microphoneTrack || controller?.microphoneTrack || stream?.getAudioTracks?.()[0] || null;
  const streamActive = proof?.streamActive ?? Boolean(stream?.active);
  const trackState = String(proof?.trackState || track?.readyState || "none");
  const trackEnabled = proof?.trackEnabled ?? (track ? track.enabled !== false : false);
  const trackMuted = proof?.trackMuted ?? (track ? Boolean(track.muted) : false);
  const trackCount = Number(proof?.trackCount ?? stream?.getAudioTracks?.().length ?? 0);
  return {
    stream,
    track,
    streamActive: Boolean(streamActive),
    trackCount,
    trackState,
    trackEnabled: Boolean(trackEnabled),
    trackMuted: Boolean(trackMuted),
    hasLiveTrack: Boolean(track && trackEnabled && trackState === "live")
  };
}

function nexusVoiceLifecycleSafeSessionFingerprint() {
  const sessionId = realtimeVoiceSession?.conversationIdentity || nexusRealtimeConversationIdentity || realtimeVoiceSession?.sessionId || nexusOsVoiceRuntimeState?.sessionId || "";
  if (!sessionId) return "none";
  return `session-${String(sessionId).slice(0, 8)}-${String(sessionId).length}`;
}

function nexusVoiceLifecycleMicrophoneOwnerCount() {
  const owners = [];
  if (realtimeVoiceSession?.active) owners.push("openai-realtime-session");
  else if (nexusPermanentMicrophoneOwner && nexusPermanentMicrophoneOwner !== "none") owners.push(nexusPermanentMicrophoneOwner);
  if (voiceRecognition) owners.push("legacy-recognition");
  if (nexusVoiceAudioFallbackRecorder) owners.push("mediarecorder-fallback");
  return new Set(owners).size;
}

function nexusVoiceLifecycleSnapshot(extra = {}) {
  const proof = normalizeRealtimeMicrophoneProof();
  const permanentProof = verifyNexusPermanentMicrophoneStream?.(nexusPermanentMicrophoneStream) || {};
  const activeTrack = proof.track || permanentProof.track || null;
  const audioContextState = realtimeVoiceSession?.audioContext?.state || window.nexusRealtimeAudioContext?.state || "not-retained";
  return {
    schemaVersion: "nexus.genesis.voiceLifecycle.v1",
    sequence: nexusVoiceLifecycleSequence,
    at: new Date().toISOString(),
    turnNumber: Number(realtimeVoiceSession?.turnIndex || 0),
    managerState: realtimeVoiceSession?.controllerState || nexusOsVoiceRuntimeState?.listeningState || "idle",
    realtimeConnectionState: realtimeVoiceSession?.connectionState || realtimeVoiceSession?.peerConnection?.connectionState || (realtimeVoiceSession?.active ? "connected" : "not-connected"),
    sessionFingerprint: nexusVoiceLifecycleSafeSessionFingerprint(),
    microphoneReadyState: activeTrack?.readyState || permanentProof.trackState || proof.trackState || "none",
    microphoneEnabled: activeTrack ? activeTrack.enabled !== false : Boolean(permanentProof.trackEnabled || proof.trackEnabled),
    microphoneMuted: activeTrack ? Boolean(activeTrack.muted) : Boolean(permanentProof.trackMuted || proof.trackMuted),
    microphoneOwnerCount: nexusVoiceLifecycleMicrophoneOwnerCount(),
    streamTrackCount: Number(proof.trackCount || permanentProof.trackCount || 0),
    streamActive: Boolean(proof.streamActive || permanentProof.streamActive),
    audioContextState,
    audioContextCount: window.nexusRealtimeAudioContext ? 1 : 0,
    peerConnectionState: realtimeVoiceSession?.peerConnection?.connectionState || "closed",
    dataChannelState: realtimeVoiceSession?.dataChannel?.readyState || "closed",
    inputActivityDetected: /speech|audio|input/i.test(String(extra.eventName || extra.eventType || realtimeVoiceSession?.lastModelEvent || "")),
    speechDetectionState: realtimeVoiceSession?.controllerState === "user-speaking" ? "speech-detected" : realtimeVoiceSession?.active ? "armed" : "not-armed",
    responsePlaybackState: realtimeVoiceSession?.responseInProgress ? "active" : nexusOsVoiceRuntimeState?.assistantSpeaking ? "speaking" : "idle",
    listeningResumed: realtimeVoiceSession?.controllerState === "listening" || nexusOsVoiceRuntimeState?.listeningState === "active",
    recoveryAttempt: Boolean(realtimeVoiceSession?.reconnectAttempted || /recover|reconnect/i.test(String(extra.eventName || extra.eventType || ""))),
    sanitizedErrorName: String(extra.errorType || extra.errorName || "").replace(/sk-[A-Za-z0-9_-]+|ek_[A-Za-z0-9_-]+/g, "[redacted]").slice(0, 80),
    ...extra
  };
}

function recordNexusVoiceLifecycleEvent(eventName = "lifecycle-event", details = {}) {
  nexusVoiceLifecycleSequence += 1;
  const safeDetails = Object.fromEntries(Object.entries(details || {}).filter(([key, value]) => {
    if (/transcript|prompt|response|token|secret|credential|sdp|url|audio/i.test(key)) return false;
    return value === null || value === undefined || ["string", "number", "boolean"].includes(typeof value);
  }));
  const event = nexusVoiceLifecycleSnapshot({
    eventName: String(eventName || "lifecycle-event").slice(0, 120),
    ...safeDetails
  });
  nexusVoiceLifecycleEvents.push(event);
  while (nexusVoiceLifecycleEvents.length > NEXUS_VOICE_LIFECYCLE_EVENT_LIMIT) {
    nexusVoiceLifecycleEvents.shift();
  }
  return event;
}

function assertNexusVoiceLifecycleInvariant(label = "voice-lifecycle") {
  const snapshot = recordNexusVoiceLifecycleEvent(`assert:${label}`, { assertion: true });
  const failures = [];
  const active = Boolean(realtimeVoiceSession?.active);
  if (active && snapshot.microphoneReadyState !== "live") failures.push("microphone-track-not-live");
  if (active && snapshot.microphoneEnabled !== true) failures.push("microphone-track-not-enabled");
  if (active && snapshot.microphoneMuted === true) failures.push("microphone-track-muted");
  if (active && snapshot.microphoneOwnerCount !== 1) failures.push("microphone-owner-count-not-one");
  if (active && !snapshot.sessionFingerprint.startsWith("session-")) failures.push("missing-session-fingerprint");
  if (active && !["listening", "user-speaking", "processing", "responding", "reconnecting", "connected"].some(state => String(snapshot.managerState || snapshot.realtimeConnectionState).includes(state))) {
    failures.push("manager-state-not-active");
  }
  snapshot.ok = failures.length === 0;
  snapshot.failures = failures;
  window.NexusGenesisVoiceLifecycleLastInvariant = snapshot;
  return snapshot;
}

function nexusVoiceLifecycleDiagnostics() {
  return {
    schemaVersion: "nexus.genesis.voiceLifecycleDiagnostics.v1",
    build: AGRINEXUS_BUILD_VERSION,
    pwaCache: AGRINEXUS_PWA_CACHE_VERSION,
    selectedRuntime: "openai-realtime",
    microphoneOwner: nexusPermanentMicrophoneOwner || "none",
    currentInvariant: assertNexusVoiceLifecycleInvariant("diagnostic-snapshot"),
    events: nexusVoiceLifecycleEvents.slice(),
    eventCount: nexusVoiceLifecycleEvents.length,
    noSecretValues: true
  };
}

window.NexusGenesisVoiceLifecycleDiagnostics = nexusVoiceLifecycleDiagnostics;

function realtimeMicrophoneProofIsLive(controller = null) {
  return normalizeRealtimeMicrophoneProof(controller).hasLiveTrack;
}

function safeRealtimeStartupMessage(error) {
  const raw = String(error?.message || error || "OpenAI Realtime startup failed.").slice(0, 260);
  return raw
    .replace(/sk-[A-Za-z0-9_-]+/g, "[redacted-openai-key]")
    .replace(/ek_[A-Za-z0-9_-]+/g, "[redacted-client-secret]")
    .replace(/Bearer\s+[A-Za-z0-9._-]+/gi, "Bearer [redacted]");
}

function updateRealtimeControllerState(state, eventType, extra = {}) {
  if (!NEXUS_REALTIME_CONTROLLER_STATES.includes(state)) return;
  if (realtimeVoiceSession) realtimeVoiceSession.controllerState = state;
  const snapshot = realtimeControllerSnapshot({
    eventType,
    state,
    ...extra
  });
  window.NexusGenesisRealtimeLastClientStatus = nexusRealtimeClientRuntimeStatus(snapshot);
  recordNexusVoiceLifecycleEvent(eventType, { state, ...extra });
  nexusGenesisVoiceDebugLog(eventType, snapshot);
}

function nextRealtimeTurnId() {
  if (!realtimeVoiceSession) return "";
  realtimeVoiceSession.turnIndex = Number(realtimeVoiceSession.turnIndex || 0) + 1;
  realtimeVoiceSession.turnId = `${realtimeVoiceSession.sessionId || "rt"}-turn-${String(realtimeVoiceSession.turnIndex).padStart(2, "0")}`;
  return realtimeVoiceSession.turnId;
}

function markRealtimeResponseStarted(payload = {}, sourceEvent = "response-created") {
  if (!realtimeVoiceSession) return;
  const responseId = payload.response?.id || payload.response_id || payload.item_id || realtimeVoiceSession.activeResponseId || `${realtimeVoiceSession.turnId || "turn"}-response`;
  realtimeVoiceSession.activeResponseId = responseId;
  realtimeVoiceSession.responseInProgress = true;
  realtimeVoiceSession.cancelInProgress = false;
  updateRealtimeControllerState("responding", sourceEvent, { activeResponseId: responseId });
}

function markRealtimeResponseCompleted(sourceEvent = "response-completed") {
  if (!realtimeVoiceSession) return;
  realtimeVoiceSession.responseInProgress = false;
  realtimeVoiceSession.activeResponseId = "";
  realtimeVoiceSession.cancelInProgress = false;
  updateRealtimeControllerState("listening", sourceEvent, { readyForNextInput: true });
  updateRealtimeControllerState("listening", "turn-ready-for-next-input", { readyForNextInput: true });
  assertNexusVoiceLifecycleInvariant("listening-resumed-after-response");
}

// Barge-in must key off authoritative playback state as well as response
// bookkeeping. Agents transport can deliver microphone VAD while audio is
// already playing, before response.created/activeResponseId reaches the UI.
function cancelActiveRealtimeResponse(reason = "user-barge-in") {
  const session = realtimeVoiceSession;
  if (!session) return false;
  const playbackActive = Boolean(session.responseInProgress || session.activeResponseId
    || nexusOsVoiceRuntimeState?.assistantSpeaking
    || session.inboundAudioState === "audio-started"
    || session.inboundAudioState === "model-audio-event");
  if (!playbackActive) return false;
  session.cancelInProgress = true;
  updateRealtimeControllerState("interrupted", "response-cancel-requested", {
    guard: "active-playback-or-response", reason
  });
  try {
    if (session.dataChannel?.readyState === "open") {
      session.dataChannel.send(JSON.stringify({ type: "response.cancel" }));
    }
  } catch {}
  try {
    session.sdkController?.interrupt?.();
  } catch {}
  return true;
}

function scheduleRealtimeRecovery(reason = "connection-state") {
  const session = realtimeVoiceSession;
  if (!session?.active || session.reconnectAttempted) return;
  session.reconnectAttempted = true;
  updateRealtimeControllerState("reconnecting", "bounded-recovery-scheduled", { reason });
  window.setTimeout(() => {
    if (realtimeVoiceSession !== session) return;
    const state = session.peerConnection?.connectionState || "";
    if (state !== "failed" && state !== "disconnected") return;
    const preservedPermanentStream = nexusPermanentMicrophoneStream && session.stream === nexusPermanentMicrophoneStream
      ? nexusPermanentMicrophoneStream
      : null;
    stopRealtimeVoiceSession("Realtime voice connection recovered by restarting the failed session.");
    startRealtimeVoiceSession({
      source: "bounded-realtime-recovery",
      preverifiedMicrophoneStream: preservedPermanentStream,
      conversationIdentity: session.conversationIdentity || nexusRealtimeConversationIdentity,
      turnIndex: Number(session.turnIndex || 0),
      recovery: true
    });
  }, 1200);
}

async function loadRealtimeVoiceStatus(options = {}) {
  if (!options.force && realtimeVoiceStatusCache && Date.now() - (realtimeVoiceStatusCache.checkedAt || 0) < 60000) {
    return realtimeVoiceStatusCache;
  }
  const response = await fetch("/api/voice/realtime/status", {
    method: "GET",
    credentials: "same-origin",
    headers: { Accept: "application/json" }
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error || `Realtime voice status failed: ${response.status}`);
  realtimeVoiceStatusCache = { ...payload, checkedAt: Date.now() };
  return realtimeVoiceStatusCache;
}

function handleRealtimeVoiceEvent(event) {
  let payload = null;
  try {
    payload = typeof event === "string" ? JSON.parse(event) : JSON.parse(event?.data || "{}");
  } catch {
    return;
  }
  const type = String(payload.type || "");
  // Keep raw Realtime transport on the same browser acceptance event path as
  // the Agents adapter. This is the actual WebRTC/data-channel path used by
  // the live provider and must remain observable for interruption evidence.
  if (typeof window.__NEXUS_VOICE_ACCEPTANCE_EVENT_SINK__ === "function") {
    window.__NEXUS_VOICE_ACCEPTANCE_EVENT_SINK__({
      eventName: "transport_event",
      type,
      text: String(payload.acceptanceText || payload.output || payload.transcript || "").slice(0, 1200),
      status: String(payload.status || "").slice(0, 80),
      toolName: String(payload.toolName || "").slice(0, 120),
      turnCount: Number(payload.turnCount || 0)
    });
  }
  const delta = payload.delta || payload.transcript || payload.text || "";
  nexusGenesisVoiceDebugLog("realtime-event", {
    type,
    itemId: payload.item_id || payload.item?.id || "",
    callId: payload.call_id || payload.item?.call_id || ""
  });
  if (type.includes("transcript") && delta) {
    updateStreamingVoicePartial(delta, { source: "openai-realtime" });
  }
  if (type === "session.created" || type === "session.updated") {
    updateNexusBehaviorLayer("realtime-ready", "Nexus is ready.");
    updateRealtimeControllerState("listening", "session-configured", { realtimeEventType: type });
  }
  if (type === "response.created") {
    markRealtimeResponseStarted(payload, "response-created");
  }
  if (type === "response.audio.delta" || type === "response.output_audio.delta") {
    if (!realtimeVoiceSession?.responseInProgress) {
      markRealtimeResponseStarted(payload, "response-audio-started");
    } else {
      updateRealtimeControllerState("responding", "response-audio-started", { realtimeEventType: type });
    }
    updateNexusVoiceSession({ state: "realtime-speaking", assistantSpeaking: true }, "openai-realtime-audio-delta");
  }
  if (type === "response.done" || type === "response.audio.done") {
    updateNexusVoiceSession({
      state: "realtime-listening",
      assistantSpeaking: false,
      userSpeaking: false,
      lastAssistantSpeechAt: Date.now()
    }, "openai-realtime-response-done");
    markRealtimeResponseCompleted(type === "response.done" ? "response-completed" : "output-audio-finished");
  }
  if (type === "input_audio_buffer.speech_started") {
    const turnId = nextRealtimeTurnId();
    markNexusUserSpeech("Realtime voice detected speech.", "openai-realtime");
    const isSecondTurn = Number(realtimeVoiceSession?.turnIndex || 0) >= 2;
    updateRealtimeControllerState("user-speaking", isSecondTurn ? "second-user-speech-detected" : "user-speech-started", { turnId });
    if (!cancelActiveRealtimeResponse("raw-realtime-speech-started")) {
      updateRealtimeControllerState("user-speaking", "response-cancel-skipped", { guard: "no-active-playback-to-cancel" });
    }
  }
  if (type === "input_audio_buffer.speech_stopped") {
    updateNexusVoiceSession({ userSpeaking: false }, "openai-realtime-speech-stopped");
    updateRealtimeControllerState("processing", "user-speech-stopped");
  }
  if (type === "input_audio_buffer.committed") {
    updateRealtimeControllerState("processing", "input-audio-committed");
  }
  if (type === "response.cancelled" || type === "response.canceled") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.responseInProgress = false;
      realtimeVoiceSession.activeResponseId = "";
      realtimeVoiceSession.cancelInProgress = false;
    }
    updateRealtimeControllerState("listening", "response-cancel-cleared", { readyForNextInput: true });
  }
  if (type === "error") {
    const errorType = payload.error?.type || payload.error?.code || "realtime-error";
    if (/cancel/i.test(errorType) && realtimeVoiceSession) {
      realtimeVoiceSession.cancelInProgress = false;
      if (!realtimeVoiceSession.responseInProgress) realtimeVoiceSession.activeResponseId = "";
    }
    updateRealtimeControllerState("listening", "realtime-error", { errorType });
  }
  if (type === "response.function_call_arguments.delta") {
    const callId = payload.call_id || payload.item_id || payload.output_index || "pending";
    realtimeToolArgumentBuffers.set(callId, `${realtimeToolArgumentBuffers.get(callId) || ""}${payload.delta || ""}`);
  }
  if (type === "response.function_call_arguments.done") {
    const callId = payload.call_id || payload.item_id || payload.output_index || "pending";
    const argsText = payload.arguments || realtimeToolArgumentBuffers.get(callId) || "{}";
    realtimeToolArgumentBuffers.delete(callId);
    dispatchRealtimeToolCall({
      callId,
      name: payload.name || payload.tool_name || "nexus_capability_router",
      argumentsText: argsText
    });
  }
  if (type === "response.output_item.done" && payload.item?.type === "function_call") {
    dispatchRealtimeToolCall({
      callId: payload.item.call_id || payload.item.id,
      name: payload.item.name || "nexus_capability_router",
      argumentsText: payload.item.arguments || "{}"
    });
  }
}

function sendRealtimeDataChannelEvent(event) {
  const channel = realtimeVoiceSession?.dataChannel;
  if (!channel || channel.readyState !== "open") {
    updateRealtimeControllerState("blocked", "data-channel-send-blocked", {
      eventType: event?.type || "",
      guard: "data-channel-not-open"
    });
    return false;
  }
  if (event?.type === "response.create") {
    const turnIndex = Number(realtimeVoiceSession?.turnIndex || 0);
    updateRealtimeControllerState("processing", turnIndex >= 2 ? "second-response-requested" : "response-requested", {
      guard: "data-channel-open"
    });
  }
  if (event?.type === "input_audio_buffer.commit") {
    updateRealtimeControllerState("processing", "input-audio-committed", { guard: "manual-commit" });
  }
  channel.send(JSON.stringify(event));
  return true;
}

async function dispatchRealtimeToolCall(call = {}) {
  if (!realtimeVoiceSession?.active) return;
  updateRealtimeControllerState("processing", "realtime-tool-dispatch-started", {
    toolName: call.name || "nexus_capability_router",
    callId: call.callId || ""
  });
  let args = {};
  try {
    args = JSON.parse(call.argumentsText || "{}");
  } catch {
    args = { command: String(call.argumentsText || "") };
  }
  const correlationId = `rt-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  nexusGenesisVoiceDebugLog("realtime-tool-call-requested", {
    name: call.name,
    callId: call.callId || "",
    correlationId
  });
  try {
    const response = await fetch("/api/voice/realtime/tool", {
      method: "POST",
      credentials: "same-origin",
      cache: "no-store",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: JSON.stringify({
        name: call.name || "nexus_capability_router",
        callId: call.callId,
        correlationId,
        arguments: args,
        language: languageCode()
      })
    });
    const result = await response.json().catch(() => ({
      ok: false,
      status: "failed-truthfully",
      response: "I could not complete that Nexus tool request.",
      blockedReason: "client-parse-failed"
    }));
    const genesisAction = result.genesisAction || result.metadata?.genesisAction || result.action || null;
    if (genesisAction?.type === "genesis.workspace.open") {
      await dispatchGenesisWorkspaceActionVerified(genesisAction, result);
    }
    const toolPayload = JSON.stringify(result);
    sendRealtimeDataChannelEvent({
      type: "conversation.item.create",
      item: {
        type: "function_call_output",
        call_id: call.callId,
        output: toolPayload
      }
    });
    sendRealtimeDataChannelEvent({
      type: "response.create",
      response: {
        instructions: "Briefly explain the Nexus tool result in natural spoken language. Do not read JSON, metadata, or internal route names aloud."
      }
    });
    nexusGenesisVoiceDebugLog("realtime-tool-call-completed", {
      name: call.name,
      status: result.status || "",
      correlationId
    });
  } catch (error) {
    const failed = {
      ok: false,
      correlationId,
      capability: "conversation",
      status: "failed-truthfully",
      response: "I could not reach the Nexus tool layer right now.",
      providerAttempted: false,
      providerSucceeded: false,
      executionAttempted: false,
      executionVerified: false,
      missingInformation: [],
      blockedReason: "provider-unavailable"
    };
    sendRealtimeDataChannelEvent({
      type: "conversation.item.create",
      item: {
        type: "function_call_output",
        call_id: call.callId,
        output: JSON.stringify(failed)
      }
    });
    sendRealtimeDataChannelEvent({
      type: "response.create",
      response: {
        instructions: "Tell the user the Nexus tool layer is temporarily unavailable, then ask what they want to try next."
      }
    });
  }
}

function stopRealtimeVoiceSession(reason = "Realtime voice stopped.") {
  if (!realtimeVoiceSession) return;
  updateRealtimeControllerState("closed", "controller-cleanup-entered", { reason });
  const explicitShutdown = /explicit-stop|user-stop|signed-out|logout|pagehide|beforeunload|left-genesis|security|shutdown|application-shutdown/i.test(reason);
  const permanentStreamActive = nexusPermanentMicrophoneStream && realtimeVoiceSession.stream === nexusPermanentMicrophoneStream;
  try {
    realtimeVoiceSession.sdkController?.close?.(reason, {
      stopMicrophone: explicitShutdown,
      preverifiedMicrophone: Boolean(permanentStreamActive)
    });
  } catch (error) {
    // SDK session may already be closed.
  }
  try {
    realtimeVoiceSession.sdkSession?.close?.();
  } catch (error) {
    // SDK session may already be closed.
  }
  try {
    realtimeVoiceSession.dataChannel?.close?.();
  } catch (error) {
    // Already closed.
  }
  try {
    realtimeVoiceSession.peerConnection?.close?.();
  } catch (error) {
    // Already closed.
  }
  if (explicitShutdown || !permanentStreamActive) {
    try {
      realtimeVoiceSession.stream?.getTracks?.().forEach(track => track.stop());
    } catch (error) {
      // Stream may already be gone.
    }
    // The permanent browser microphone is owned by the lifecycle manager, not
    // only by the realtime session. Explicit shutdown must release that stream
    // as well; otherwise browser acceptance leaves a live track behind.
    try {
      if (typeof stopNexusVoicePermissionStream === "function") stopNexusVoicePermissionStream(reason);
    } catch (error) {
      // Permission stream may already be closed.
    }
  } else {
    recordNexusVoiceLifecycleEvent("realtime-session-cleanup-preserved-permanent-microphone", {
      reason,
      microphoneOwner: nexusPermanentMicrophoneOwner
    });
  }
  try {
    realtimeVoiceSession.remoteAudio?.pause?.();
    realtimeVoiceSession.remoteAudio.srcObject = null;
  } catch (error) {
    // Audio node may already be detached.
  }
  realtimeVoiceSession = null;
  realtimeToolArgumentBuffers.clear();
  realtimeVoiceStarting = false;
  setVoiceStatus("standby");
  updateNexusBehaviorLayer("standby", reason);
  const outputStatus = $("#globalVoiceOutputStatus");
  if (outputStatus) outputStatus.textContent = translateText(reason);
  refreshMicSupport();
}

let nexusOpenAiRealtimeAgentModulePromise = null;

function loadNexusOpenAiRealtimeAgentModule() {
  if (!nexusOpenAiRealtimeAgentModulePromise) {
    nexusOpenAiRealtimeAgentModulePromise = import(`/vendor/nexus-openai-realtime-agent.bundle.mjs?v=${encodeURIComponent(AGRINEXUS_BUILD_VERSION)}&module=nexus-esm-mime-1`);
  }
  return nexusOpenAiRealtimeAgentModulePromise;
}

async function requestNexusOpenAiRealtimeSession(status = {}) {
  const response = await fetch(`/api/voice/realtime/session?language=${encodeURIComponent(languageCode())}`, {
    method: "POST",
    credentials: "same-origin",
    cache: "no-store",
    headers: { "Content-Type": "application/json", Accept: "application/json" },
    body: JSON.stringify({
      language: languageCode(),
      model: status.model || "",
      transport: "agents-sdk-webrtc"
    })
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error || `OpenAI Realtime session failed: ${response.status}`);
  if (!String(payload.clientSecret || "").startsWith("ek_")) throw new Error("OpenAI Realtime session did not return a browser client secret.");
  return payload;
}

async function callNexusOpenAiRealtimeTool(toolName, args = {}) {
  const command = String(args.command || args.query || "").trim();
  const correlationId = `rt-sdk-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  nexusGenesisVoiceDebugLog("openai-agents-tool-call-requested", {
    toolName,
    correlationId,
    commandLength: command.length
  });
  const response = await fetch("/api/voice/realtime/tool", {
    method: "POST",
    credentials: "same-origin",
    cache: "no-store",
    headers: { "Content-Type": "application/json", Accept: "application/json" },
    body: JSON.stringify({
      name: toolName || "nexus_general_conversation",
      correlationId,
      arguments: {
        ...args,
        command,
        language: args.language || languageCode()
      },
      language: args.language || languageCode()
    })
  });
  const result = await response.json().catch(() => ({
    ok: false,
    status: "failed-truthfully",
    response: "I could not parse the Nexus tool result.",
    blockedReason: "client-parse-failed",
    category: "tool-response-parse"
  }));
  const genesisAction = result.genesisAction || result.metadata?.genesisAction || null;
  if (genesisAction) {
    await dispatchGenesisWorkspaceActionVerified(genesisAction, result);
  }
  nexusGenesisVoiceDebugLog("openai-agents-tool-http-result", {
    toolName,
    correlationId,
    requestUrl: "/api/voice/realtime/tool",
    httpStatus: response.status,
    ok: Boolean(response.ok),
    category: result.category || result.blockedReason || "",
    status: result.status || "",
    providerAttempted: Boolean(result.providerAttempted || result.provider?.attempted),
    executionAttempted: Boolean(result.executionAttempted || result.execution?.attempted)
  });
  nexusGenesisVoiceDebugLog("openai-agents-tool-call-completed", {
    toolName,
    correlationId,
    status: result.status || "",
    providerAttempted: Boolean(result.providerAttempted || result.provider?.attempted),
    executionAttempted: Boolean(result.executionAttempted || result.execution?.attempted)
  });
  return result;
}

function handleOpenAiAgentsRealtimeEvent(eventName, payload = {}) {
  const eventType = String(payload.type || "");
  if (typeof window.__NEXUS_VOICE_ACCEPTANCE_EVENT_SINK__ === "function") {
    window.__NEXUS_VOICE_ACCEPTANCE_EVENT_SINK__({
      eventName: String(eventName || "").slice(0, 80),
      type: eventType.slice(0, 120),
      text: String(payload.acceptanceText || payload.output || "").slice(0, 1200),
      status: String(payload.status || "").slice(0, 80),
      toolName: String(payload.toolName || "").slice(0, 120),
      turnCount: Number(payload.turnCount || 0)
    });
  }
  nexusGenesisVoiceDebugLog(`openai-agents-${eventName}`, {
    type: eventType,
    status: payload.status || "",
    toolName: payload.toolName || ""
  });
  if (eventName === "connection_change") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.connectionState = payload.status || "";
      realtimeVoiceSession.lastModelEvent = `connection:${payload.status || ""}`;
    }
    updateRealtimeControllerState(payload.status === "connected" ? "connecting" : "authorizing", "openai-agents-connection-change", {
      connectionState: payload.status || ""
    });
  }
  if (eventName === "media_stream_requested") {
    updateRealtimeControllerState("connecting", "openai-agents-media-stream-requested", {
      audioRequested: payload.audioRequested !== false
    });
  }
  if (eventName === "media_stream_acquired") {
    updateRealtimeControllerState("connecting", "openai-agents-media-stream-acquired", {
      streamActive: Boolean(payload.streamActive),
      trackCount: payload.trackCount || 0,
      trackState: payload.trackState || "none",
      trackEnabled: Boolean(payload.trackEnabled),
      hasLiveTrack: Boolean(payload.hasLiveTrack)
    });
  }
  if (eventName === "microphone_track_live") {
    updateRealtimeControllerState("connecting", "openai-agents-live-microphone-track-verified", {
      streamActive: Boolean(payload.streamActive),
      trackCount: payload.trackCount || 0,
      trackState: payload.trackState || "none",
      trackEnabled: Boolean(payload.trackEnabled),
      trackMuted: Boolean(payload.trackMuted)
    });
  }
  if (eventName === "media_stream_failed") {
    updateRealtimeControllerState("failed", "openai-agents-media-stream-failed", {
      errorType: payload.type || "media-stream-failed"
    });
  }
  if (eventName === "microphone_track_ended") {
    updateRealtimeControllerState("reconnecting", "openai-agents-microphone-track-ended", {
      trackState: payload.trackState || "ended"
    });
    scheduleRealtimeRecovery("openai-agents-microphone-track-ended");
  }
  if (eventName === "transport_event") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.lastModelEvent = eventType || realtimeVoiceSession.lastModelEvent || "";
      if (/audio|response|conversation|session|input_audio/i.test(eventType)) {
        realtimeVoiceSession.inboundAudioState = /response\.audio|output_audio|audio_start/i.test(eventType)
          ? "model-audio-event"
          : /input_audio/i.test(eventType)
            ? "input-audio-event"
            : realtimeVoiceSession.inboundAudioState || "event-channel-active";
      }
    }
    if (eventType === "input_audio_buffer.speech_started") {
      const turnId = nextRealtimeTurnId();
      markNexusUserSpeech("Realtime voice detected speech.", "openai-agents-realtime");
      updateRealtimeControllerState("user-speaking", Number(realtimeVoiceSession?.turnIndex || 0) >= 2 ? "second-user-speech-detected" : "user-speech-started", { turnId });
      if (!cancelActiveRealtimeResponse("agents-realtime-speech-started")) {
        updateRealtimeControllerState("user-speaking", "response-cancel-skipped", { guard: "no-active-playback-to-cancel" });
      }
    }
    if (eventType === "input_audio_buffer.speech_stopped") {
      updateNexusVoiceSession({ userSpeaking: false }, "openai-agents-realtime-speech-stopped");
      updateRealtimeControllerState("processing", "user-speech-stopped");
    }
    if (eventType === "input_audio_buffer.speech_stopped" || eventType === "input_audio_buffer.committed") {
      updateRealtimeControllerState("processing", eventType === "input_audio_buffer.committed" ? "input-audio-committed" : "user-speech-stopped");
    }
    if (eventType === "response.done") {
      markRealtimeResponseCompleted("response-completed");
    }
  }
  if (eventName === "audio_start") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.inboundAudioState = "audio-started";
      realtimeVoiceSession.lastModelEvent = "audio_start";
    }
    markRealtimeResponseStarted({}, "openai-agents-audio-started");
    updateNexusVoiceSession({ state: "realtime-speaking", assistantSpeaking: true, userSpeaking: false }, "openai-agents-realtime-audio-start");
  }
  if (eventName === "audio_stopped") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.inboundAudioState = "audio-stopped";
      realtimeVoiceSession.lastModelEvent = "audio_stopped";
    }
    updateNexusVoiceSession({ state: "realtime-listening", assistantSpeaking: false, userSpeaking: false, lastAssistantSpeechAt: Date.now() }, "openai-agents-realtime-audio-stopped");
    markRealtimeResponseCompleted("output-audio-finished");
  }
  if (eventName === "audio_interrupted") {
    if (realtimeVoiceSession) {
      realtimeVoiceSession.responseInProgress = false;
      realtimeVoiceSession.activeResponseId = "";
      realtimeVoiceSession.cancelInProgress = false;
      realtimeVoiceSession.inboundAudioState = "audio-interrupted";
    }
    try { realtimeVoiceSession?.sdkController?.interrupt?.(); } catch {}
    updateNexusVoiceSession({ state: "realtime-listening", assistantSpeaking: false }, "openai-agents-realtime-interruption");
    updateRealtimeControllerState("interrupted", "openai-agents-interruption", { interrupted: true });
    updateRealtimeControllerState("listening", "interruption-ready-for-next-input", { readyForNextInput: true });
  }
  if (eventName === "agent_tool_start") {
    if (realtimeVoiceSession) realtimeVoiceSession.lastToolEvent = `start:${payload.toolName || ""}`;
    updateRealtimeControllerState("processing", "openai-agents-tool-dispatch-started", { toolName: payload.toolName || "" });
  }
  if (eventName === "agent_tool_end") {
    if (realtimeVoiceSession) realtimeVoiceSession.lastToolEvent = `end:${payload.toolName || ""}`;
    updateRealtimeControllerState("responding", "openai-agents-tool-dispatch-completed", { toolName: payload.toolName || "" });
  }
  if (eventName === "agent_end") {
    if (realtimeVoiceSession) realtimeVoiceSession.lastModelEvent = "agent_end";
    updateRealtimeControllerState("listening", "openai-agents-agent-response-completed", { readyForNextInput: true });
  }
  if (eventName === "error") {
    updateRealtimeControllerState("reconnecting", "openai-agents-sdk-error", { errorType: payload.type || "sdk-error" });
    scheduleRealtimeRecovery(payload.type || "openai-agents-sdk-error");
  }
}

async function startOpenAiAgentsRealtimeVoiceSession(status = {}, options = {}) {
  const sessionId = `rt-sdk-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  if (!nexusRealtimeConversationIdentity) {
    nexusRealtimeConversationIdentity = `rt-conversation-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  }
  const conversationIdentity = options.conversationIdentity || nexusRealtimeConversationIdentity;
  nexusRealtimeConversationIdentity = conversationIdentity;
  nexusGenesisVoiceDebugLog("runtime-selected", { runtime: "realtime", transport: "agents-sdk-webrtc", sessionId });
  const legacyRecognitionAtStart = voiceRecognition;
  const legacyListenerWasActive = Boolean(voiceRecognition || nexusOsVoiceStartInFlight || nexusVoicePermissionStream);
  const priorVoiceStopRequested = voiceStopRequested;
  realtimeVoiceSession = {
    active: false,
    handoffPending: true,
    runtime: "realtime",
    transport: "agents-sdk-webrtc",
    startedAt: Date.now(),
    controllerState: "authorizing",
    sessionId,
    conversationIdentity,
    turnIndex: Number(options.turnIndex || 0),
    turnId: "",
    responseInProgress: false,
    activeResponseId: "",
    cancelInProgress: false,
    reconnectAttempted: false,
    model: status.model,
    voice: status.voice,
    runtimeVersion: status.runtimeVersion || NEXUS_GENESIS_REALTIME_RUNTIME_VERSION,
    fallbackState: "legacy-listener-preserved"
  };
  updateRealtimeControllerState("authorizing", "openai-agents-session-requested", {
    model: status.model || "",
    voice: status.voice || "",
    legacyListenerPreserved: legacyListenerWasActive
  });
  recordNexusAudioPipelineEvent("openai-realtime-session-request", {
    model: status.model || "",
    voice: status.voice || "",
    legacyListenerPreserved: legacyListenerWasActive
  });
  nexusGenesisVoiceDebugLog("openai-realtime-session-request", {
    model: status.model || "",
    voice: status.voice || "",
    legacyListenerPreserved: legacyListenerWasActive
  });
  let controller = null;
  try {
    const [module, sessionPayload] = await Promise.all([
      loadNexusOpenAiRealtimeAgentModule(),
      requestNexusOpenAiRealtimeSession(status)
    ]);
    updateRealtimeControllerState("connecting", "openai-agents-client-secret-issued", {
      model: sessionPayload.model || "",
      voice: sessionPayload.voice || "",
      expiresAt: sessionPayload.expiresAt || null,
      noPermanentKeyInBrowser: true,
      legacyListenerPreserved: legacyListenerWasActive
    });
    recordNexusAudioPipelineEvent("openai-realtime-client-secret-issued", {
      model: sessionPayload.model || "",
      voice: sessionPayload.voice || "",
      noPermanentKeyInBrowser: true
    });
    controller = await module.startNexusOpenAiRealtimeGenesisSession({
      clientSecret: sessionPayload.clientSecret,
      model: sessionPayload.model || status.model || "gpt-realtime-2",
      voice: sessionPayload.voice || status.voice || "marin",
      instructions: sessionPayload.clientConfig?.instructions || "",
      clientConfig: sessionPayload.clientConfig || {},
      preverifiedMicrophoneStream: options.preverifiedMicrophoneStream || null,
      language: () => languageCode(),
      lastUserCommand: () => nexusOsVoiceRuntimeState.lastFinal || "",
      callNexusTool: callNexusOpenAiRealtimeTool,
      onToolResult: (toolName, result) => {
        updateRealtimeControllerState("responding", "openai-agents-tool-result-returned", {
          toolName,
          status: result?.status || "",
          providerAttempted: Boolean(result?.providerAttempted || result?.provider?.attempted),
          executionAttempted: Boolean(result?.executionAttempted || result?.execution?.attempted)
        });
      },
      onEvent: handleOpenAiAgentsRealtimeEvent
    });
    const micProof = normalizeRealtimeMicrophoneProof(controller);
    if (!micProof.hasLiveTrack) {
      throw new Error(`OpenAI Realtime did not acquire a live microphone track (${micProof.trackState}).`);
    }
    if (!realtimeVoiceSession || realtimeVoiceSession.sessionId !== sessionId) {
      controller.close?.("stale-openai-agents-session");
      return false;
    }
    recordNexusAudioPipelineEvent("openai-realtime-connected", {
      model: sessionPayload.model || status.model || "",
      voice: sessionPayload.voice || status.voice || "",
      realtimeConnected: true
    });
    recordNexusAudioPipelineEvent("openai-realtime-microphone-proof", {
      microphoneTrackState: micProof.trackState,
      microphoneTrackEnabled: micProof.trackEnabled,
      microphoneTrackMuted: micProof.trackMuted,
      realtimeConnected: true
    });
    nexusGenesisVoiceDebugLog("openai-realtime-connected", {
      model: sessionPayload.model || status.model || "",
      voice: sessionPayload.voice || status.voice || "",
      realtimeConnected: true
    });
    nexusGenesisVoiceDebugLog("openai-realtime-microphone-proof", {
      microphoneTrackState: micProof.trackState,
      microphoneTrackEnabled: micProof.trackEnabled,
      microphoneTrackMuted: micProof.trackMuted
    });
    realtimeVoiceSession.sdkController = controller;
    realtimeVoiceSession.sdkSession = controller.session;
    realtimeVoiceSession.stream = controller.mediaStream;
    realtimeVoiceSession.microphoneTrack = controller.microphoneTrack || micProof.track;
    realtimeVoiceSession.microphoneProof = {
      streamActive: micProof.streamActive,
      trackCount: micProof.trackCount,
      trackState: micProof.trackState,
      trackEnabled: micProof.trackEnabled,
      trackMuted: micProof.trackMuted,
      hasLiveTrack: micProof.hasLiveTrack
    };
    realtimeVoiceSession.model = sessionPayload.model || status.model;
    realtimeVoiceSession.voice = sessionPayload.voice || status.voice;
    realtimeVoiceSession.active = true;
    realtimeVoiceSession.handoffPending = false;
    realtimeVoiceSession.fallbackState = "inactive-realtime-owns-microphone";
    stopVoicePlayback();
    voiceStopRequested = true;
    if (voiceRecognition) {
      try {
        voiceRecognition.stop();
      } catch {
        // Legacy recognition may already be stopped.
      }
      if (voiceRecognition === legacyRecognitionAtStart || legacyRecognitionAtStart) voiceRecognition = null;
    }
    stopNexusAudioFallbackRecorder("openai-agents-realtime-verified");
    if (!options.preverifiedMicrophoneStream || nexusVoicePermissionStream !== options.preverifiedMicrophoneStream) {
      stopNexusVoicePermissionStream("openai-agents-realtime-verified");
    }
    realtimeVoiceStarting = false;
    voiceStopRequested = false;
    nexusOsVoiceStartInFlight = false;
    setVoiceStatus("listening");
    updateNexusBehaviorLayer("realtime-listening", "Nexus is listening.");
    const outputStatus = $("#globalVoiceOutputStatus");
    if (outputStatus) outputStatus.textContent = translateText("Nexus is listening.");
    updateNexusVoiceSession({
      state: "realtime-listening",
      userSpeaking: false,
      assistantSpeaking: false,
      microphoneUnavailable: false,
      permissionState: "granted"
    }, "openai-agents-realtime-started");
    updateNativeVoiceBridgeState("realtime-listening", { provider: "openai-agents-realtime", locale: voiceLocale() });
    updateRealtimeControllerState("listening", "openai-agents-sdk-session-started", {
      model: realtimeVoiceSession.model || "",
      voice: realtimeVoiceSession.voice || "",
      runtimeVersion: realtimeVoiceSession.runtimeVersion || NEXUS_GENESIS_REALTIME_RUNTIME_VERSION,
      microphoneTrackState: micProof.trackState,
      microphoneTrackEnabled: micProof.trackEnabled
    });
    setNexusPermanentMicrophoneState("connected", "Nexus Realtime voice is connected and listening.");
    refreshMicSupport();
    return true;
  } catch (error) {
    const message = safeRealtimeStartupMessage(error);
    try {
      controller?.close?.("openai-agents-realtime-startup-failed");
    } catch {
      // Startup controller may not have completed construction.
    }
    realtimeVoiceSession = null;
    realtimeVoiceStarting = false;
    voiceStopRequested = priorVoiceStopRequested;
    updateRealtimeControllerState("failed", "openai-agents-startup-failed", {
      reason: message,
      legacyListenerPreserved: Boolean(voiceRecognition || nexusVoicePermissionStream)
    });
    const outputStatus = $("#globalVoiceOutputStatus");
    const fallbackMessage = `OpenAI Realtime voice did not start: ${message}. Nexus voice connection unavailable — retry.`;
    if (outputStatus) outputStatus.textContent = translateText(fallbackMessage);
    setNexusPermanentMicrophoneState("unavailable", "Nexus voice connection unavailable — retry. The microphone and orb remain available.");
    updateNexusBehaviorLayer("fallback", fallbackMessage);
    refreshMicSupport();
    return false;
  }
}

async function startRealtimeVoiceSession(options = {}) {
  if (!realtimeVoiceSupported()) return false;
  if (realtimeVoiceActive()) return true;
  if (realtimeVoiceStarting) return true;
  realtimeVoiceStarting = true;
  try {
    const sessionId = `rt-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
    nexusGenesisVoiceDebugLog("runtime-selected", { runtime: "realtime", sessionId });
    const statusPayload = await loadRealtimeVoiceStatus({ force: true });
    const status = statusPayload?.realtimeVoice || {};
    if (status.runtime === "disabled") throw new Error(status.note || "Nexus voice is disabled.");
    if (status.runtime !== "realtime") return false;
    if (!status.ready) throw new Error(status.note || "OpenAI Realtime voice is not configured.");
    if (status.transport === "agents-sdk-webrtc" || status.endpoint === "/api/voice/realtime/session") {
      return await startOpenAiAgentsRealtimeVoiceSession(status, options);
    }
    throw new Error("OpenAI Realtime direct SDP startup is disabled; the Agents SDK WebRTC session is the only active Nexus Realtime path.");
  } catch (error) {
    realtimeVoiceStarting = false;
    stopRealtimeVoiceSession("Realtime voice did not start.");
    const message = `Nexus Realtime voice is temporarily unavailable: ${error.message || "connection failed"}`;
    const outputStatus = $("#globalVoiceOutputStatus");
    if (outputStatus) outputStatus.textContent = translateText(message);
    setNexusPermanentMicrophoneState("unavailable", "Nexus voice connection unavailable — retry. The microphone control remains visible.");
    updateNexusBehaviorLayer("fallback", message);
    nexusGenesisVoiceDebugLog("session-failed", {
      runtime: "realtime",
      fallback: "blocked",
      reason: error.message || "realtime-start-failed"
    });
    return false;
  }
}

function browserVoiceRuntimeProfile() {
  const userAgent = navigator.userAgent || "";
  const isEdge = /\bEdg\//i.test(userAgent);
  const isOpera = /\bOPR\//i.test(userAgent) || /\bOpera\b/i.test(userAgent);
  const isChrome = /\bChrome\//i.test(userAgent) && !isEdge && !isOpera;
  const isChromeIos = /\bCriOS\//i.test(userAgent);
  const isChromium = (isChrome || isChromeIos || isEdge || /\bChromium\//i.test(userAgent)) && !isOpera;
  const isSafari = /\bSafari\//i.test(userAgent) && !isChromium;
  const recognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  const secureEnough = window.isSecureContext || ["localhost", "127.0.0.1"].includes(location.hostname);
  const browserName = isChrome || isChromeIos
    ? "Chrome"
    : isEdge
      ? "Microsoft Edge"
      : isSafari
        ? "Safari"
        : "this browser";
  return {
    browserName,
    isChrome: isChrome || isChromeIos,
    isChromium,
    isSafari,
    recognitionName: window.SpeechRecognition ? "SpeechRecognition" : window.webkitSpeechRecognition ? "webkitSpeechRecognition" : "none",
    supported: Boolean(recognition),
    secureEnough,
    bestForWebVoice: Boolean(isChromium && recognition && secureEnough)
  };
}

function chromeVoiceRuntimeReady() {
  const profile = browserVoiceRuntimeProfile();
  return profile.isChrome && profile.supported && profile.secureEnough;
}

function chromeVoiceStatusMessage() {
  const profile = browserVoiceRuntimeProfile();
  const languageName = voiceLanguageName();
  const locale = voiceLocale();
  const streamingStatus = streamingVoiceEnabled() ? " Streaming mode is on." : "";
  if (realtimeVoiceSupported()) return `${realtimeVoiceStatusMessage()} Keep this tab open while Nexus listens through OpenAI Realtime.`;
  if (!profile.supported) return `${profile.browserName} does not expose browser speech recognition here. Open the app in desktop Chrome, then use Ask AgriNexus typed commands until microphone support is available.`;
  if (!profile.secureEnough) return `${profile.browserName} needs HTTPS, localhost, or 127.0.0.1 before microphone voice can start. Open the hosted Render URL or your local server URL, then allow the microphone.`;
  if (profile.isChrome) return `Chrome voice ready for ${languageName} (${locale}). Click Mic, choose Allow for microphone, and keep this tab open while testing.${streamingStatus}`;
  return `${profile.browserName} voice ready for ${languageName} (${locale}). Chrome is the recommended browser for the most reliable Ask Nexus voice testing.${streamingStatus}`;
}

function applyChromeVoiceRuntimeDefaults(recognition) {
  if (!recognition) return recognition;
  recognition.lang = voiceLocale();
  recognition.interimResults = streamingVoiceEnabled() || chromeVoiceRuntimeReady();
  recognition.continuous = voiceFirstMode || streamingVoiceEnabled() || chromeVoiceRuntimeReady();
  recognition.maxAlternatives = chromeVoiceRuntimeReady() ? 5 : streamingVoiceEnabled() ? 5 : 3;
  return recognition;
}

const NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT = Object.freeze({
  schemaVersion: "nexus-listening-wake-runtime.v1",
  controllerName: "NexusSpeechRecognitionController",
  canonicalRuntimeOwner: "nexus-os-canonical-voice",
  supportedInputModes: Object.freeze(["press-to-talk", "wake-phrase-gated", "typed-fallback"]),
  wakePhrases: Object.freeze(["Nexus", "Hello Nexus", "Hey Nexus", "Hey AgriNexus"]),
  stateModel: Object.freeze(["idle", "starting", "listening", "speech-detected", "partial-transcript", "final-transcript", "stopping", "typed-fallback", "permission-denied", "microphone-unavailable", "recognition-timeout", "failed"]),
  safeguards: Object.freeze({
    requiresUserGestureForBrowserMic: true,
    noAlwaysOnListeningClaim: true,
    noHiddenMicrophoneStart: true,
    noHeardClaimOnFailure: true,
    duplicateSessionPrevention: true,
    typedFallbackRequired: true,
    transcriptCorrectionSupported: true,
    languageSwitchSupported: true,
    noWorkflowExecutionAuthority: true
  })
});

function nexusListeningWakeControllerState(extra = {}) {
  const profile = typeof browserVoiceRuntimeProfile === "function" ? browserVoiceRuntimeProfile() : {};
  return {
    schemaVersion: NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT.schemaVersion,
    controllerName: NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT.controllerName,
    runtimeOwner: NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT.canonicalRuntimeOwner,
    recognitionSupported: Boolean(profile.supported || realtimeVoiceSupported?.()),
    browserName: profile.browserName || "this browser",
    recognitionName: profile.recognitionName || "none",
    secureEnough: Boolean(profile.secureEnough),
    inputMode: voiceRecognition ? "press-to-talk" : "typed-fallback",
    wakePhrases: [...NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT.wakePhrases],
    listeningState: nexusOsVoiceRuntimeState.listeningState || "idle",
    hearingState: nexusOsVoiceRuntimeState.hearingState || "idle",
    permissionState: nexusOsVoiceRuntimeState.permissionState || "unknown",
    lastPartial: nexusOsVoiceRuntimeState.lastPartial || "",
    lastFinal: nexusOsVoiceRuntimeState.lastFinal || "",
    language: languageCode(),
    locale: voiceLocale(),
    noAlwaysOnListeningClaim: true,
    noHiddenMicrophoneStart: true,
    noWorkflowExecutionAuthority: true,
    ...extra
  };
}

function createNexusRecognitionConfig(options = {}) {
  return {
    lang: options.locale || voiceLocale(),
    interimResults: Boolean(streamingVoiceEnabled() || chromeVoiceRuntimeReady()),
    continuous: Boolean(voiceFirstMode || streamingVoiceEnabled() || chromeVoiceRuntimeReady()),
    maxAlternatives: chromeVoiceRuntimeReady() ? 5 : streamingVoiceEnabled() ? 5 : 3,
    inputMode: options.inputMode || "press-to-talk",
    wakePhraseRequiredForBackground: true,
    typedFallbackAvailable: true
  };
}

function markNexusListeningControllerEvent(eventName = "idle", details = {}) {
  const safeEvent = String(eventName || "idle");
  const partial = normalizeVoicePartial(details.partialTranscript || details.lastPartial || "");
  const finalTranscript = normalizeVoicePartial(details.finalTranscript || details.lastFinal || "");
  const patch = {
    speechRecognitionController: NEXUS_LISTENING_WAKE_CONTROLLER_CONTRACT.controllerName,
    listeningControllerEvent: safeEvent,
    listeningControllerState: safeEvent,
    inputMode: details.inputMode || (voiceRecognition ? "press-to-talk" : "typed-fallback"),
    lastPartial: partial || nexusOsVoiceRuntimeState.lastPartial || "",
    lastFinal: finalTranscript || nexusOsVoiceRuntimeState.lastFinal || "",
    transcriptCorrectionAvailable: true,
    noAlwaysOnListeningClaim: true,
    noHiddenMicrophoneStart: true,
    noWorkflowExecutionAuthority: true
  };
  if (details.permissionState) patch.permissionState = details.permissionState;
  if (details.confidence !== undefined) patch.speechConfidence = details.confidence;
  if (details.microphoneUnavailable !== undefined) patch.microphoneUnavailable = Boolean(details.microphoneUnavailable);
  return updateNexusOsVoiceRuntimeState(patch, `listening-controller:${safeEvent}`);
}

function normalizeNexusWakeTranscript(command = "") {
  const raw = String(command || "").trim();
  const normalized = normalizedWakeText(raw);
  return {
    raw,
    normalized,
    wakeOnly: isWakePhraseOnly(raw),
    greetingOnly: isNexusGreetingOnly(raw),
    greetingPrefix: isNexusGreetingPrefix(raw),
    cleanedCommand: cleanWakeCommand(raw),
    wakeMatched: isWakePhraseOnly(raw) || isNexusGreetingOnly(raw) || isNexusGreetingPrefix(raw),
    noHeardClaimOnFailure: true
  };
}

async function chromeMicrophonePermissionState() {
  if (!navigator.permissions?.query) return "unknown";
  try {
    const result = await navigator.permissions.query({ name: "microphone" });
    return result?.state || "unknown";
  } catch (error) {
    return "unknown";
  }
}

async function maybeStartGenesisRecognitionAfterGrantedPermission(source = "genesis-home-render") {
  if (typeof window === "undefined" || typeof document === "undefined") return false;
  const homeVisible = isNexusGenesisHomeActive() || Boolean(document.querySelector("[data-nexus-genesis-audio-gate='true']"));
  if (!homeVisible) return false;
  nexusGenesisVoiceSessionActive = true;
  voiceFirstMode = true;
  voiceAutoRestart = true;
  voiceStopRequested = false;
  const profile = browserVoiceRuntimeProfile();
  nexusGenesisVoiceDebugLog("controller-initialized", {
    source,
    secureContext: profile.secureEnough,
    recognitionSupported: Boolean(profile.supported || realtimeVoiceSupported?.())
  });
  nexusGenesisVoiceDebugLog("automatic-start-entered", { source, secureContext: profile.secureEnough });
  const recognitionAvailable = Boolean(realtimeVoiceSupported?.() || window.SpeechRecognition || window.webkitSpeechRecognition);
  const skipReason = !profile.secureEnough
    ? "secure-context-required"
    : !recognitionAvailable
      ? "recognition-unsupported"
      : voiceRecognition
        ? "recognition-already-constructed"
        : nexusOsVoiceStartInFlight || nexusGenesisPermissionGrantedAutoStartInFlight
          ? "recognition-start-in-flight"
          : voiceStopRequested
            ? "explicit-stop-requested"
            : voiceConversationPaused
              ? "conversation-paused"
              : voiceSpeaking
                ? "assistant-speaking"
                : voiceDemoQuietMode
                  ? "voice-muted"
                  : nexusVoicePermissionDeniedThisSession
                    ? "permission-denied-this-session"
                    : "";
  recordNexusAudioPipelineEvent("genesis-auto-start-check", {
    source,
    supported: profile.supported,
    secureEnough: profile.secureEnough,
    skipReason: skipReason || "permission-check-required"
  });
  if (skipReason) {
    nexusGenesisVoiceDebugLog("startup-guard", {
      source,
      skipReason,
      secureContext: profile.secureEnough
    });
    return false;
  }
  const now = Date.now();
  if (now - nexusGenesisPermissionGrantedAutoStartLastAttemptAt < 1200) {
    recordNexusAudioPipelineEvent("genesis-auto-start-skipped", {
      source,
      skipReason: "throttled"
    });
    nexusGenesisVoiceDebugLog("startup-guard", {
      source,
      skipReason: "throttled",
      secureContext: profile.secureEnough
    });
    return false;
  }
  nexusGenesisPermissionGrantedAutoStartInFlight = true;
  nexusGenesisPermissionGrantedAutoStartLastAttemptAt = now;
  try {
    const permission = normalizeNexusMicrophonePermissionState(await chromeMicrophonePermissionState());
    const runtimePermission = normalizeNexusMicrophonePermissionState(nexusOsVoiceRuntimeState.permissionState || "unknown");
    const canAttemptStart = nexusMicrophonePermissionCanAttemptStart(permission) || runtimePermission === "browser-managed";
    nexusGenesisVoiceDebugLog("permission-state-resolved", {
      permissionState: permission,
      runtimePermissionState: runtimePermission,
      canAttemptStart
    });
    if (permission === "denied" || runtimePermission === "denied") {
      nexusVoicePermissionDeniedThisSession = true;
      updateNexusOsVoiceRuntimeState({ permissionState: "denied", listeningState: "blocked" }, "genesis-auto-start-permission-denied");
      recordNexusAudioPipelineEvent("genesis-auto-start-skipped", {
        source,
        permissionState: "denied",
        skipReason: "permission-denied"
      });
      return false;
    }
    if (!canAttemptStart) {
      recordNexusAudioPipelineEvent("genesis-auto-start-skipped", {
        source,
        permissionState: permission,
        runtimePermissionState: runtimePermission,
        skipReason: "permission-not-authorized"
      });
      return false;
    }
    updateNexusOsVoiceRuntimeState({
      permissionState: permission,
      recognitionSupported: true,
      voiceRuntimeVersion: NEXUS_GENESIS_VOICE_RUNTIME_VERSION
    }, "genesis-auto-start-permission-granted");
    recordNexusAudioPipelineEvent("genesis-auto-start-triggered", {
      source,
      permissionState: permission,
      runtimePermissionState: runtimePermission,
      authorizationProof: permission === "granted" ? "permissions-api-granted-get-user-media-required" : "get-user-media-required"
    });
    await startVoiceListening({ source: "genesis-home-permission-granted-auto-start" });
    return true;
  } finally {
    nexusGenesisPermissionGrantedAutoStartInFlight = false;
  }
}

function nexusVoiceAudioDebugEnabled() {
  return /(?:[?&])nexusVoiceDebug(?:=1|=true|&|$)/i.test(window.location.search || "")
    || localStorage.getItem("nexusVoiceDebug") === "on";
}

function maskNexusTranscriptForDiagnostics(value = "") {
  const compact = String(value || "").replace(/\s+/g, " ").trim();
  if (!compact) return "";
  return compact.length > 80 ? `${compact.slice(0, 77)}...` : compact;
}

function recordNexusAudioPipelineEvent(stage, details = {}) {
  const safeDetails = { ...details };
  delete safeDetails.audioBase64;
  delete safeDetails.rawAudio;
  if (safeDetails.transcript) safeDetails.transcript = maskNexusTranscriptForDiagnostics(safeDetails.transcript);
  if (safeDetails.finalTranscript) safeDetails.finalTranscript = maskNexusTranscriptForDiagnostics(safeDetails.finalTranscript);
  if (safeDetails.partialTranscript) safeDetails.partialTranscript = maskNexusTranscriptForDiagnostics(safeDetails.partialTranscript);
  const event = {
    stage,
    at: new Date().toISOString(),
    ...safeDetails
  };
  nexusVoiceAudioPipelineEvents.push(event);
  while (nexusVoiceAudioPipelineEvents.length > NEXUS_AUDIO_PIPELINE_EVENT_LIMIT) {
    nexusVoiceAudioPipelineEvents.shift();
  }
  const stageStatePatch = {
    "media-stream-request": { microphonePermissionRequested: true },
    "media-stream-granted": { microphoneTrackState: "live", microphoneStreamActive: true, permissionState: "granted", permissionDisplayText: "granted" },
    "media-stream-stopped": { microphoneStreamActive: false, microphoneTrackState: "stopped" },
    "openai-realtime-session-request": { realtimeSessionRequested: true, realtimeConnected: false, mode: "authorizing" },
    "openai-realtime-client-secret-issued": { realtimeClientSecretIssued: true, noPermanentKeyInBrowser: true, mode: "connecting" },
    "openai-realtime-connected": { realtimeConnected: true, mode: "realtime-listening", listeningState: "active" },
    "openai-realtime-microphone-proof": { realtimeConnected: true, microphoneTrackState: safeDetails.microphoneTrackState || "live", microphoneStreamActive: true, listeningState: "active" },
    "recognition-constructing": { recognitionConstructed: true, recognitionStartRequested: false, recognitionOnStartReceived: false },
    "recognition-handlers-registered": { recognitionHandlersRegistered: true },
    "recognition-start-call": { recognitionStartRequested: true, recognitionOnStartReceived: false },
    "recognition-onstart": { recognitionOnStartReceived: true, listeningState: "active", hearingState: "waiting", mode: "listening" },
    "recognition-audiostart": { recognitionAudioStartReceived: true, hearingState: "audio-started" },
    "recognition-soundstart": { recognitionSoundStartReceived: true, hearingState: "sound-detected" },
    "recognition-speechstart": { recognitionSpeechStartReceived: true, hearingState: "speech-detected" },
    "recognition-result-event": { recognitionResultReceived: true },
    "recognition-final-transcript": { recognitionFinalTranscriptReceived: true, listeningState: "processing", mode: "processing" },
    "recognition-error": { listeningState: "error", mode: "recognition-interrupted" },
    "recognition-start-exception": { listeningState: "failed", mode: "recognition-interrupted" },
    "agent-command-request": { commandRequestStarted: true, commandSubmitted: true, mode: "processing" },
    "agent-command-response": { commandResponseReceived: true, commandResponseStatus: safeDetails.status || "ok", responseTextAvailable: true },
    "agent-command-error": { commandResponseStatus: "error", lastRuntimeError: safeDetails.error || "agent-command-error" },
    "speech-synthesis-request": { utteranceRequested: true, utteranceOnStartReceived: false },
    "speech-synthesis-onstart": { utteranceOnStartReceived: true, assistantSpeaking: true, mode: "speaking" },
    "speech-synthesis-onend": { utteranceOnEndReceived: true, assistantSpeaking: false },
    "speech-synthesis-error": { utteranceError: safeDetails.error || "speech-synthesis-error", assistantSpeaking: false, mode: "caption-fallback" },
    "speech-synthesis-start-unconfirmed": { utteranceError: "speech-start-unconfirmed", assistantSpeaking: false, mode: "caption-fallback" },
    "speech-synthesis-start-failed": { utteranceError: safeDetails.error || "speech-start-failed", assistantSpeaking: false, mode: "caption-fallback" }
  }[stage] || {};
  try {
    updateNexusOsVoiceRuntimeState({
      ...stageStatePatch,
      audioPipelineStage: stage,
      audioPipelineLastEventAt: event.at,
      audioPipelineEventCount: nexusVoiceAudioPipelineEvents.length,
      commandSubmitted: Boolean(safeDetails.commandSubmitted),
      synthesisRequested: Boolean(safeDetails.synthesisRequested)
    }, "audio-pipeline");
  } catch {}
  if (nexusVoiceAudioDebugEnabled() || nexusGenesisVoiceDebugEnabled()) {
    console.info("[Nexus voice pipeline]", event);
  }
  return event;
}

function nexusVoiceAudioPipelineSnapshot() {
  return {
    events: nexusVoiceAudioPipelineEvents.slice(),
    listening: Boolean(voiceRecognition),
    speaking: Boolean(voiceSpeaking),
    fallbackRecording: Boolean(nexusVoiceAudioFallbackRecorder),
    lastSubmittedSignature: nexusVoiceLastSubmittedSignature,
    lastSubmittedAt: nexusVoiceLastSubmittedAt,
    lastFinalTranscriptAt: nexusVoiceLastFinalTranscriptAt
  };
}

window.nexusVoiceAudioPipeline = {
  snapshot: nexusVoiceAudioPipelineSnapshot,
  events: () => nexusVoiceAudioPipelineEvents.slice(),
  enableDebug: () => localStorage.setItem("nexusVoiceDebug", "on"),
  disableDebug: () => localStorage.removeItem("nexusVoiceDebug")
};

function stopNexusVoicePermissionStream(reason = "stopped") {
  if (!nexusVoicePermissionStream) return;
  const isPermanentStream = nexusPermanentMicrophoneStream && nexusVoicePermissionStream === nexusPermanentMicrophoneStream;
  const canStopPermanent = /explicit-stop|user-stop|signed-out|logout|pagehide|beforeunload|left-genesis|security|new-request/i.test(reason);
  if (isPermanentStream && !canStopPermanent) {
    recordNexusAudioPipelineEvent("permanent-microphone-stop-skipped", { reason, owner: nexusPermanentMicrophoneOwner });
    return;
  }
  try {
    nexusVoicePermissionStream.getTracks().forEach(track => track.stop());
  } catch {}
  if (isPermanentStream) {
    nexusPermanentMicrophoneStream = null;
    nexusPermanentMicrophoneOwner = "none";
  }
  nexusVoicePermissionStream = null;
  recordNexusAudioPipelineEvent("media-stream-stopped", { reason });
}

function stopNexusGenesisVoiceController(reason = "controller-stopped") {
  nexusGenesisVoiceSessionActive = false;
  voiceAutoRestart = false;
  voiceStopRequested = true;
  if (nexusGenesisRecognitionStartTimeout) {
    clearTimeout(nexusGenesisRecognitionStartTimeout);
    nexusGenesisRecognitionStartTimeout = null;
  }
  if (nexusGenesisVoiceRestartTimer) {
    clearTimeout(nexusGenesisVoiceRestartTimer);
    nexusGenesisVoiceRestartTimer = null;
  }
  try {
    if (voiceRecognition) voiceRecognition.stop();
  } catch {}
  voiceRecognition = null;
  stopNexusAudioFallbackRecorder(reason);
  stopNexusVoicePermissionStream(reason);
  recordNexusAudioPipelineEvent("genesis-controller-stopped", { reason });
  nexusGenesisVoiceDebugLog("controller-stopped", { reason });
  updateNexusOsVoiceRuntimeState({
    mode: "standby",
    listeningState: "stopped",
    hearingState: "idle",
    assistantSpeaking: false
  }, reason);
}

if (typeof window !== "undefined") {
  window.addEventListener("pagehide", () => stopNexusGenesisVoiceController("pagehide"), { passive: true });
  window.addEventListener("beforeunload", () => stopNexusGenesisVoiceController("beforeunload"), { passive: true });
}

function stopNexusAudioFallbackRecorder(reason = "stopped") {
  if (nexusVoiceAudioFallbackTimer) {
    clearTimeout(nexusVoiceAudioFallbackTimer);
    nexusVoiceAudioFallbackTimer = null;
  }
  const recorder = nexusVoiceAudioFallbackRecorder;
  nexusVoiceAudioFallbackRecorder = null;
  if (!recorder) return;
  try {
    if (recorder.state === "recording") recorder.stop();
  } catch {}
  recordNexusAudioPipelineEvent("audio-fallback-recorder-stopped", { reason });
}

function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = String(reader.result || "");
      resolve(result.includes(",") ? result.split(",").pop() : result);
    };
    reader.onerror = () => reject(reader.error || new Error("Audio read failed."));
    reader.readAsDataURL(blob);
  });
}

async function submitNexusAudioFallbackForTranscription(blob, options = {}) {
  if (!blob?.size) {
    recordNexusAudioPipelineEvent("audio-fallback-empty", { source: options.source || "mediarecorder" });
    return;
  }
  try {
    recordNexusAudioPipelineEvent("audio-fallback-submit", {
      source: options.source || "mediarecorder",
      bytes: blob.size,
      mimeType: blob.type || "audio/webm"
    });
    const audioBase64 = await blobToBase64(blob);
    const payload = await request("/api/voice/transcribe", {
      method: "POST",
      body: {
        audioBase64,
        mimeType: blob.type || "audio/webm",
        filename: "nexus-browser-voice.webm",
        language: languageCode(),
        locale: voiceLocale(),
        source: "browser-mediarecorder-fallback"
      }
    });
    const transcript = normalizeVoicePartial(payload?.transcript || payload?.text || "");
    recordNexusAudioPipelineEvent(transcript ? "audio-fallback-transcript" : "audio-fallback-no-transcript", {
      transcript,
      provider: payload?.provider || payload?.source || "server"
    });
    if (transcript) scheduleFinalVoiceCommand(transcript, { source: "audio-fallback", confidence: null, delay: 0 });
    else if (!voiceRecognition) {
      showNexusVoiceFallbackMessage("Microphone permission is available, but Nexus did not receive usable speech. Try speaking closer to the microphone or use a supported Chrome voice session.", {
        source: "audio-fallback-no-transcript",
        mode: "voice-only",
        trustChainState: "recognition_failed"
      });
    }
  } catch (error) {
    recordNexusAudioPipelineEvent("audio-fallback-transcription-error", {
      error: error.message || "audio fallback transcription failed"
    });
  }
}

function startNexusAudioFallbackRecorder(stream, options = {}) {
  if (!stream || !window.MediaRecorder) {
    recordNexusAudioPipelineEvent("audio-fallback-unavailable", {
      reason: stream ? "mediarecorder-unavailable" : "no-stream"
    });
    return;
  }
  stopNexusAudioFallbackRecorder("restart");
  nexusVoiceAudioFallbackChunks = [];
  try {
    const mimeType = MediaRecorder.isTypeSupported?.("audio/webm;codecs=opus")
      ? "audio/webm;codecs=opus"
      : "audio/webm";
    const recorder = new MediaRecorder(stream, { mimeType });
    nexusVoiceAudioFallbackRecorder = recorder;
    recorder.ondataavailable = event => {
      if (event.data?.size) nexusVoiceAudioFallbackChunks.push(event.data);
    };
    recorder.onerror = event => {
      recordNexusAudioPipelineEvent("audio-fallback-recorder-error", {
        error: event.error?.message || "mediarecorder-error"
      });
    };
    recorder.onstop = () => {
      const chunks = nexusVoiceAudioFallbackChunks.slice();
      nexusVoiceAudioFallbackChunks = [];
      const recentWebSpeechFinal = nexusVoiceLastFinalTranscriptAt && Date.now() - nexusVoiceLastFinalTranscriptAt < 2500;
      if (recentWebSpeechFinal || voiceStopRequested) {
        recordNexusAudioPipelineEvent("audio-fallback-discarded", {
          reason: recentWebSpeechFinal ? "web-speech-final" : "explicit-stop"
        });
        return;
      }
      submitNexusAudioFallbackForTranscription(new Blob(chunks, { type: recorder.mimeType || "audio/webm" }), options);
    };
    recorder.start();
    recordNexusAudioPipelineEvent("audio-fallback-recorder-started", { mimeType: recorder.mimeType || mimeType });
    nexusVoiceAudioFallbackTimer = setTimeout(() => {
      nexusVoiceAudioFallbackTimer = null;
      stopNexusAudioFallbackRecorder("timeout");
    }, NEXUS_AUDIO_FALLBACK_RECORDING_MS);
  } catch (error) {
    recordNexusAudioPipelineEvent("audio-fallback-start-error", {
      error: error.message || "MediaRecorder failed"
    });
  }
}

async function acquireNexusMicrophoneStreamForVoice(source = "nexus-os-voice-runtime") {
  if (!navigator.mediaDevices?.getUserMedia) {
    recordNexusAudioPipelineEvent("media-stream-unavailable", { reason: "getUserMedia-unavailable" });
    nexusGenesisVoiceDebugLog("mediaDevices-unavailable", { source });
    return null;
  }
  stopNexusVoicePermissionStream("new-request");
  try {
    recordNexusAudioPipelineEvent("media-stream-request", { source });
    nexusGenesisVoiceDebugLog("getUserMedia-requested", { source });
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }
    });
    const tracks = typeof stream.getAudioTracks === "function" ? stream.getAudioTracks() : [];
    const liveTrack = tracks.find(track => track && track.enabled !== false && track.readyState === "live");
    if (!liveTrack) {
      try {
        tracks.forEach(track => track.stop?.());
      } catch {}
      recordNexusAudioPipelineEvent("media-stream-no-live-track", {
        trackCount: tracks.length,
        trackStates: tracks.map(track => track?.readyState || "unknown").join(",")
      });
      nexusGenesisVoiceDebugLog("live-audio-track-missing", { source, trackCount: tracks.length });
      throw Object.assign(new Error("no-live-audio-track"), { name: "NoLiveAudioTrackError" });
    }
    nexusVoicePermissionStream = stream;
    recordNexusAudioPipelineEvent("media-stream-granted", {
      trackCount: tracks.length,
      liveTrackVerified: true,
      trackState: liveTrack.readyState,
      trackEnabled: liveTrack.enabled !== false
    });
    nexusGenesisVoiceDebugLog("stream-acquired", {
      source,
      trackCount: tracks.length
    });
    nexusGenesisVoiceDebugLog("live-audio-track-verified", {
      source,
      trackCount: tracks.length,
      trackState: liveTrack.readyState,
      trackEnabled: liveTrack.enabled !== false
    });
    return stream;
  } catch (error) {
    recordNexusAudioPipelineEvent("media-stream-denied", {
      error: error.name || error.message || "getUserMedia failed"
    });
    nexusGenesisVoiceDebugLog("getUserMedia-failed", {
      source,
      exceptionName: error.name || "Error",
      exceptionMessage: error.message || "getUserMedia failed"
    });
    throw error;
  }
}

function nexusPermanentMicrophoneElements() {
  return {
    dock: document.querySelector("#nexusPermanentMicrophoneDock"),
    button: document.querySelector("[data-nexus-permanent-microphone-control='true']") || document.querySelector("#nexusPermanentMicrophoneBtn"),
    status: document.querySelector("#nexusPermanentMicrophoneStatus")
  };
}

function setNexusPermanentMicrophoneState(state = "ready", message = "Microphone ready to enable.") {
  if (typeof document === "undefined") return;
  const { dock, button, status } = nexusPermanentMicrophoneElements();
  if (dock) {
    dock.hidden = false;
    dock.removeAttribute("aria-hidden");
  }
  if (button) {
    button.hidden = false;
    button.disabled = false;
    button.dataset.nexusPermanentMicrophoneState = state;
    if (state === "blocked") button.textContent = "Microphone blocked — view instructions";
    else if (state === "connected") button.textContent = "Microphone connected";
    else if (state === "unavailable") button.textContent = "Nexus voice connection unavailable — retry";
    else if (state === "requesting") button.textContent = "Requesting microphone...";
    else button.textContent = "Enable microphone";
  }
  if (status) {
    status.hidden = false;
    status.textContent = translateText(message);
  }
}

function verifyNexusPermanentMicrophoneStream(stream) {
  const tracks = typeof stream?.getAudioTracks === "function" ? stream.getAudioTracks() : [];
  const liveTrack = tracks.find(track => track && track.readyState === "live" && track.enabled !== false) || null;
  const trackMuted = liveTrack ? Boolean(liveTrack.muted) : false;
  return {
    ok: Boolean(stream && tracks.length === 1 && liveTrack && !trackMuted),
    stream,
    track: liveTrack,
    trackCount: tracks.length,
    trackState: liveTrack?.readyState || tracks[0]?.readyState || "none",
    trackEnabled: liveTrack ? liveTrack.enabled !== false : false,
    trackMuted,
    streamActive: Boolean(stream?.active)
  };
}

async function acquirePermanentGenesisMicrophoneFromClick(source = "permanent-html-microphone-button") {
  if (!navigator.mediaDevices?.getUserMedia) {
    setNexusPermanentMicrophoneState("unavailable", "This browser page cannot request microphone access. Use HTTPS and a browser with microphone support.");
    throw new Error("getUserMedia unavailable");
  }
  setNexusPermanentMicrophoneState("requesting", "Requesting microphone permission...");
  recordNexusAudioPipelineEvent("permanent-microphone-click", { source });
  nexusGenesisVoiceDebugLog("permanent-microphone-click", { source });
  try {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const proof = verifyNexusPermanentMicrophoneStream(stream);
    if (!proof.ok) {
      try {
        stream?.getTracks?.().forEach(track => track.stop?.());
      } catch {}
      setNexusPermanentMicrophoneState("unavailable", "Microphone opened without exactly one live enabled audio track. Check browser or device settings, then retry.");
      throw new Error("invalid-live-audio-track");
    }
    nexusPermanentMicrophoneStream = stream;
    nexusVoicePermissionStream = stream;
    nexusPermanentMicrophoneOwner = "browser-verified-genesis-voice-runtime-manager";
    nexusVoicePermissionDeniedThisSession = false;
    recordNexusAudioPipelineEvent("permanent-microphone-live-track", {
      source,
      trackCount: proof.trackCount,
      trackState: proof.trackState,
      trackEnabled: proof.trackEnabled,
      trackMuted: proof.trackMuted,
      owner: nexusPermanentMicrophoneOwner
    });
    nexusGenesisVoiceDebugLog("permanent-microphone-live-track", {
      source,
      trackCount: proof.trackCount,
      trackState: proof.trackState,
      trackEnabled: proof.trackEnabled,
      trackMuted: proof.trackMuted,
      owner: nexusPermanentMicrophoneOwner
    });
    updateNexusOsVoiceRuntimeState({
      mode: "microphone-ready",
      listeningState: "microphone-ready",
      hearingState: "idle",
      permissionState: "granted",
      permissionDisplayText: "granted",
      microphoneStreamActive: true,
      microphoneTrackState: "live",
      runtimeOwner: nexusPermanentMicrophoneOwner
    }, source);
    assertNexusVoiceLifecycleInvariant("successful-stream-acquisition");
    setNexusPermanentMicrophoneState("connected", "Microphone is live. Connecting Nexus Realtime voice...");
    return { stream, proof };
  } catch (error) {
    const denied = /notallowed|permission|denied/i.test(`${error.name || ""} ${error.message || ""}`);
    nexusVoicePermissionDeniedThisSession = denied;
    setNexusPermanentMicrophoneState(
      denied ? "blocked" : "unavailable",
      denied
        ? "Microphone permission is blocked. Open browser site settings, allow microphone for this site, then reload and retry."
        : `Nexus could not open the microphone: ${error.message || "device unavailable"}.`
    );
    updateNexusOsVoiceRuntimeState({
      mode: denied ? "microphone-blocked" : "microphone-unavailable",
      listeningState: "blocked",
      hearingState: "idle",
      permissionState: denied ? "denied" : "unknown",
      microphoneUnavailable: true,
      lastError: error.message || "microphone-start-failed"
    }, source);
    throw error;
  }
}

async function handleNexusPermanentMicrophoneClick(event) {
  event?.preventDefault?.();
  event?.stopPropagation?.();
  event?.stopImmediatePropagation?.();
  recordNexusVoiceLifecycleEvent("permanent-microphone-user-click", {
    managerState: realtimeVoiceSession?.controllerState || "pre-acquisition",
    microphoneOwner: nexusPermanentMicrophoneOwner
  });
  try {
    const { stream } = await acquirePermanentGenesisMicrophoneFromClick("permanent-html-microphone-button");
    const result = await startVoiceListening({
      source: "permanent-html-microphone-button",
      preverifiedMicrophoneStream: stream
    });
    if (!result?.ok && result !== true) {
      setNexusPermanentMicrophoneState("unavailable", "Nexus voice connection unavailable — retry. The microphone control remains available.");
    } else {
      assertNexusVoiceLifecycleInvariant("realtime-start-after-permanent-click");
    }
  } catch {
    // The visible status region already explains the exact browser recovery path.
  }
}

function bindNexusPermanentMicrophoneControl() {
  if (typeof document === "undefined" || nexusPermanentMicrophoneClickBound) return;
  const { button } = nexusPermanentMicrophoneElements();
  if (!button) return;
  nexusPermanentMicrophoneClickBound = true;
  button.hidden = false;
  button.disabled = false;
  button.addEventListener("click", handleNexusPermanentMicrophoneClick, true);
  setNexusPermanentMicrophoneState("ready", "Microphone ready to enable.");
}

async function refreshChromeVoicePermissionHint() {
  const profile = browserVoiceRuntimeProfile();
  if (!profile.isChrome) return;
  const status = $("#globalMicStatus");
  if (!status || voiceRecognition || voiceDemoQuietMode || voiceConversationPaused) return;
  if (!voiceFirstMode && !genesisVoiceConversationActive()) return;
  const permissionState = normalizeNexusMicrophonePermissionState(await chromeMicrophonePermissionState());
  if (permissionState === "denied") {
    status.classList.add("blocked");
    status.textContent = "Chrome blocked the microphone. Click the tune or lock icon near the address bar, set Microphone to Allow, then reload the page.";
  } else if (permissionState === "granted") {
    status.classList.add("ready");
    status.textContent = chromeVoiceStatusMessage();
  }
}

function refreshMicSupport() {
  const profile = browserVoiceRuntimeProfile();
  const realtimeCapable = realtimeVoiceSupported();
  const realtimeMicAvailable = realtimeMicrophoneUiAvailable();
  const realtimeReady = realtimeVoiceEnabled() && realtimeCapable;
  const elevenLabsReady = elevenLabsVoiceEnabled() && elevenLabsVoiceSupported();
  const ready = (profile.supported || elevenLabsReady || realtimeMicAvailable) && profile.secureEnough;
  const languageName = voiceLanguageName();
  const locale = voiceLocale();
  const status = $("#globalMicStatus");
  const streamingStatus = streamingVoiceEnabled() ? " Streaming mode is on." : "";
  if (status) {
    status.classList.toggle("ready", ready);
    status.classList.toggle("blocked", !ready);
    status.textContent = voiceConversationPaused
      ? "Nexus is paused. Background conversation is ignored. Say Nexus, listen to continue."
      : voiceDemoQuietMode
      ? "Demo quiet mode is on. Nexus voice and auto-listening are off."
      : elevenLabsVoiceActive()
      ? `Nexus ElevenLabs Agents voice is live in ${voiceLanguageName()} (${voiceLocale()}). Workflow fields appear only after Nexus opens a workflow.`
      : realtimeVoiceActive()
      ? `Nexus Realtime voice is live in ${voiceLanguageName()} (${voiceLocale()}). Workflow fields appear only after Nexus opens a workflow.`
      : ready
      ? profile.isChrome
        ? chromeVoiceStatusMessage()
        : realtimeMicAvailable
          ? `${profile.browserName} microphone control is available for OpenAI Realtime in ${languageName} (${locale}). Click Start listening, then allow browser access.${streamingStatus}`
          : `${profile.browserName} microphone ready for ${languageName} (${locale}). Click Mic, then allow browser access.${streamingStatus}`
      : profile.secureEnough
        ? `${languageName} microphone access is not available in ${profile.browserName}. Use a browser with WebRTC microphone support.`
        : `${profile.browserName} needs HTTPS, localhost, or 127.0.0.1 before microphone voice can start. Open the secure hosted URL for voice.`;
  }
  ["#globalListenBtn", "#voiceListenBtn", "#jarvisListenBtn", "#workflowListenBtn"].forEach(selector => {
    const button = $(selector);
    if (!button) return;
    button.disabled = !ready;
    button.title = ready
      ? realtimeCapable
        ? "Enable microphone for OpenAI Realtime Nexus Genesis voice"
        : profile.isChrome ? "Use Chrome microphone with Ask AgriNexus" : "Use your microphone to ask AgriNexus"
      : "Enable microphone from a secure browser page";
    if (!ready) {
      if (selector === "#globalListenBtn") button.textContent = "Enable microphone";
      if (selector === "#voiceListenBtn") button.textContent = "Enable microphone";
      if (selector === "#jarvisListenBtn") button.textContent = "Enable mic";
      return;
    }
    if (voiceDemoQuietMode) {
      if (selector === "#globalListenBtn") button.textContent = "Voice off";
      if (selector === "#voiceListenBtn") button.textContent = "Voice off";
      if (selector === "#jarvisListenBtn") button.textContent = "Voice off";
      button.title = "Demo quiet mode is on. Type 'turn voice on' to re-enable voice.";
      return;
    }
    if (voiceConversationPaused) {
      if (selector === "#globalListenBtn") button.textContent = "Nexus paused";
      if (selector === "#voiceListenBtn") button.textContent = "Nexus paused";
      if (selector === "#jarvisListenBtn") button.textContent = "Paused";
      button.title = "Nexus is ignoring background conversation. Press to listen again.";
      return;
    }
    if (selector === "#globalListenBtn") button.textContent = voiceRecognition || genesisVoiceConversationActive() ? "Stop listening" : "Mic: Start listening";
    if (selector === "#voiceListenBtn") button.textContent = voiceRecognition || genesisVoiceConversationActive() ? "Stop listening" : "Mic: Start listening";
    if (selector === "#jarvisListenBtn") button.textContent = voiceRecognition || genesisVoiceConversationActive() ? "Stop" : "Listen";
  });
  const voiceFirstButton = $("#globalVoiceFirstBtn");
  if (voiceFirstButton) {
    voiceFirstButton.classList.toggle("primary", voiceFirstMode);
    voiceFirstButton.setAttribute("aria-pressed", String(voiceFirstMode));
    voiceFirstButton.textContent = voiceConversationPaused ? "Nexus: Paused" : voiceDemoQuietMode ? "Nexus voice: Off" : voiceFirstMode ? "Hey AgriNexus: On" : "Hey AgriNexus: Off";
  }
  refreshChromeVoicePermissionHint();
}

function normalizedWakeText(command) {
  return String(command || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[.,!?;:"'()[\]{}]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function isWakePhraseOnly(command) {
  const normalized = normalizedWakeText(command);
  if (!normalized) return false;
  if (/^(?:\u0645\u0631\u062d\u0628\u0627|\u064a\u0627)?\s*(?:\u0646\u0643\u0633\u0633|\u0627\u063a\u0631\u064a\u0646\u064a\u0643\u0633\u0633)$/.test(normalized)) return true;
  const wakePhrases = [
    "hey agrinexus", "agri nexus", "agrinexus", "hey nexus", "nexus", "hey agri", "agri",
    "hola agrinexus", "hola nexus", "buenos dias nexus", "buenas tardes nexus", "buenas noches nexus",
    "ola agrinexus", "ola nexus", "oi nexus", "bom dia nexus", "boa tarde nexus", "boa noite nexus",
    "bonjour agrinexus", "salut agrinexus", "bonjour nexus",
    "habari agrinexus", "hujambo agrinexus", "habari nexus",
    "مرحبا اغرينكسوس", "يا اغرينكسوس", "اغرينكسوس", "نيكسس"
  ];
  return wakePhrases.includes(normalized);
}

function isNexusGreetingOnly(command) {
  const normalized = normalizedWakeText(command);
  if (!normalized) return false;
  return [
    "hello", "hi", "good morning", "goodmorning", "good afternoon", "goodafternoon", "good evening", "goodevening",
    "hello nexus", "hi nexus", "hello agrinexus", "hi agrinexus",
    "good morning nexus", "goodmorning nexus", "good afternoon nexus", "goodafternoon nexus", "good evening nexus", "goodevening nexus",
    "hola", "buenos dias", "buenas tardes", "buenas noches",
    "hola nexus", "hola agrinexus", "buenos dias nexus", "buenas tardes nexus", "buenas noches nexus",
    "ola", "oi", "bom dia", "boa tarde", "boa noite",
    "ola nexus", "ola agrinexus", "oi nexus", "bom dia nexus", "boa tarde nexus", "boa noite nexus",
    "bonjour", "salut", "habari", "hujambo",
    "bonjour nexus", "salut nexus", "bonjour agrinexus", "habari nexus", "hujambo nexus"
  ].includes(normalized)
    || /^(?:\u0645\u0631\u062d\u0628\u0627|\u0627\u0647\u0644\u0627|\u0635\u0628\u0627\u062d \u0627\u0644\u062e\u064a\u0631|\u0645\u0633\u0627\u0621 \u0627\u0644\u062e\u064a\u0631)(?:\s+(?:\u0646\u0643\u0633\u0633|\u0627\u063a\u0631\u064a\u0646\u064a\u0643\u0633\u0633|nexus|agrinexus))?$/.test(normalized);
}

function isNexusGreetingPrefix(command) {
  const normalized = normalizedWakeText(command);
  if (!normalized) return false;
  return /^(hello|hi|good morning|good afternoon|good evening)\s+(nexus|agrinexus|agri nexus|agri)\b/.test(normalized)
    || /^(hola|buenos dias|buenas tardes|buenas noches|ola|oi|bom dia|boa tarde|boa noite|bonjour|salut|habari|hujambo)\s+(nexus|agrinexus|agri nexus|agri)\b/.test(normalized)
    || /^(?:\u0645\u0631\u062d\u0628\u0627|\u0627\u0647\u0644\u0627|\u0635\u0628\u0627\u062d \u0627\u0644\u062e\u064a\u0631|\u0645\u0633\u0627\u0621 \u0627\u0644\u062e\u064a\u0631)\s+(?:\u0646\u0643\u0633\u0633|\u0627\u063a\u0631\u064a\u0646\u064a\u0643\u0633\u0633|nexus|agrinexus)\b/.test(normalized);
}

