      wake: `Ndiyo ${name}?`,
      heard: `Nimesikia: ${values.command || ""}. Ninafanya sasa.`,
      confirmed: `Imethibitishwa. Ninafanya sasa: ${values.command || ""}.`,
      canceled: "Imeghairiwa. Niambie Nexus ifanye nini.",
