const SAFE_MAP_CAPABILITY_PROMPTS = Object.freeze([
  "what map features are available",
  "can you show routes",
  "is location enabled",
  "show satellite imagery",
  "help me plan a route"
]);

function safeMapCapabilityIntent(command = "") {
  const text = normalizeToolText(command);
  if (!/\b(map|maps|route|routes|routing|location|satellite|imagery|tiles|layers|navigation|navigate)\b/.test(text)) return null;
  const asksCapability = /\b(what|which|available|features|can you|show routes|show route|layers|status|ready|enabled|configured|provider|providers)\b/.test(text);
  const asksLocation = /\b(location|gps|where am i|my position|enabled)\b/.test(text);
  const asksSatellite = /\b(satellite|imagery|image layer|aerial)\b/.test(text);
  const asksRoutePlan = /\b(plan a route|help me plan a route|route plan|directions|navigation|navigate|routing)\b/.test(text);
  const opensMap = /\b(open|show|display|bring up|launch)\b.*\b(map|maps)\b/.test(text);
  if (!asksCapability && !asksLocation && !asksSatellite && !asksRoutePlan && !opensMap) return null;
  const model = mapProviderReadinessModel();
  const layerSummary = model.layerNames.join(", ");
  if (asksRoutePlan) {
    const routePreview = safeRoutePlanningPreviewModel(command);
    const routeFields = routePreview.reviewFields.map(field => `${field.label}: ${field.value}`).join("; ");
    return {
      action: "route-preview",
      openMap: true,
      response: `I prepared a review-only route planning preview for ${routePreview.routeName}. ${routeFields}. I will not call navigation, request live location, open external maps, or hand off to a routing provider. Current layers are ${layerSummary}. ${model.routingLabel}.`
    };
  }
  if (asksLocation) {
    return {
      action: "location-readiness",
      openMap: true,
      response: `${model.locationLabel}. Nexus will not request browser location automatically. Saved country, route, checkpoint, facility, and shipment context can be shown now; live location needs an explicit user action and permission.`
    };
  }
  if (asksSatellite) {
    return {
      action: "satellite-readiness",
      openMap: true,
      response: `Satellite imagery is available as a Leaflet layer when network tiles load. Use the map layer control to choose ${model.layerNames.find(name => /satellite/i.test(name)) || "Satellite imagery"}. This is a visual preview, not drone dispatch or external navigation.`
    };
  }
  if (asksCapability) {
    return {
      action: "capability-readiness",
      openMap: true,
      response: `Map features available now: public tile layers, saved routes, checkpoints, facilities, shipment context, scale, global view, and safe map readiness. ${model.tileConfigLabel}. ${model.routingLabel}. ${model.offlineLabel}. ${model.vectorLabel}.`
    };
  }
  if (opensMap) {
    return {
      action: "open-map",
      openMap: true,
      response: "Map is open in preview mode. You can zoom, drag, view public layers, inspect saved routes, see facilities, and check readiness. Nexus will not request live location or call routing providers from this prompt."
    };
  }
  return null;
}

function openSafeMapCapabilityPreview(intent) {
  if (!intent) return false;
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  if (intent.openMap) {
    closeAskNexus({ silent: true });
    goSection("map", { instant: true, openDefaultAction: false, keepAssistant: false });
    if (experienceMode === "user") renderUserSimpleActiveSection("map");
    setTimeout(() => {
      renderMap();
      renderUserRealMap();
      safeInvalidateLeafletMap(map);
      safeInvalidateLeafletMap(userMap);
      const target = intent.action === "route-preview" ? $("#userRoutePlanningPreview") : $("#userMapProviderReadiness");
      target?.scrollIntoView?.({ behavior: "smooth", block: "start" });
    }, 120);
  } else {
    openAskNexus();
  }
  renderLiveVoiceSuggestions(["what map features are available", "is location enabled", "show satellite imagery", "help me plan a route"]);
  recordVoiceEvent(`Map readiness preview: ${intent.action}`, "done");
  updateNexusBehaviorLayer("answering", "Nexus showed safe map provider readiness without requesting location or calling routing providers.");
  setVoiceResponse(intent.response, true, { allowHandoff: false, command: intent.action, source: "safe-map-provider-readiness" });
  return true;
}

function a100SafeAutonomyIntent(command = "") {
  if (!isA100SafeAutonomyEnabled() || experienceMode !== "user") return null;
  const text = normalizeA100RuntimeCommand(command);
  if (!text) return null;
  const followUp = a100SafeFollowUpIntent(command);
  if (followUp) return followUp;
  const highRisk = a100HighRiskActionGates().find(item => item.pattern.test(text));
  if (highRisk) {
    return {
      action: "high-risk-gated",
      section: "dashboard",
      response: `${highRisk.label}: This requires review first. ${highRisk.reason} Nexus can prepare a checklist or questions for review, but it will not diagnose, change medicine, call, send, pay, buy, contact providers, turn on location, use camera or microphone, dispatch help, connect devices, transmit health data, or change records.`,
      taskPlan: buildNexusAutonomousTaskPlan(command, { category: "general" }),
      report: a100ChronicCareReport("safety", command),
      healthPrivacyComplianceGuardrails: a100HealthPrivacyComplianceGuardrails(command),
      suggestions: ["what can Nexus do", "prepare a review checklist", "what providers are connected", "what should I do next"]
    };
  }
  const chronicMatched = [
    { id: "navigator", pattern: /\b(chronic care navigator|chronic illness support|chronic care support|family care checklist|condition support summary)\b|\bhelp me prepare for a clinic visit\b/ },
    { id: "diabetes", pattern: /\b(diabetes|diabetic|blood sugar|glucose|a1c)\b.*\b(help|support|manage|high|low|question|prepare|review|visit|education|mean|means|track|enter|reading|summarize)\b|\bi have diabetes\b|\bhelp with diabetes\b|\bmy blood sugar is high\b|\bwhat is a1c\b|\bmy glucose is low\b|\benter a glucose reading\b/ },
    { id: "hypertension", pattern: /\b(blood pressure|hypertension|bp)\b.*\b(help|support|high|question|prepare|review|visit|measure|measurement|technique|track|sodium|salt|activity|adherence)\b|\bhelp me with blood pressure\b|\bmy blood pressure is high\b|\bhow should i measure bp\b/ },
    { id: "asthma", pattern: /\b(asthma|breathing condition|respiratory|chronic respiratory|inhaler)\b.*\b(help|support|prepare|clinic|visit|question|track|warning|manage)\b|\bmy mother has asthma\b|\bi have asthma and want to prepare for my clinic visit\b/ },
    { id: "heart-risk", pattern: /\b(heart disease|heart risk|cardiovascular|chest pain history)\b.*\b(help|support|prepare|question|risk|review|clinic)\b|\bhelp with heart disease risk\b/ },
    { id: "kidney-risk", pattern: /\b(kidney disease|kidney risk|kidney screening|kidney labs|renal)\b.*\b(help|support|prepare|question|risk|review|clinic|lab)\b|\bhelp with kidney disease risk\b/ },
    { id: "maternal-risk", pattern: /\b(pregnancy|pregnant|maternal|antenatal|midwife)\b.*\b(hypertension|diabetes|danger|risk|support|prepare|clinic|warning)\b|\bpregnancy danger signs\b|\bhypertension during pregnancy\b/ },
    { id: "medication-reminder", pattern: /\b(remind|reminder|remember|forget|forgets|forgot|adherence|refill|follow-up|appointment)\b.*\b(medicine|medication|meds|pill|clinic|blood pressure check|blood sugar check|lab|chw visit)\b|\bremind me to take my medicine\b|\bmy father has high blood pressure and forgets his medicine\b/ },
    { id: "wellness", pattern: /\b(obesity|weight|wellness|lose weight|nutrition|diet|activity|physical activity|sleep|stress|barrier|progress)\b.*\b(help|support|safe|safely|question|prepare|review|goal|track)\b|\bhelp me lose weight safely\b|\bhelp with obesity\b|\btrack my weight safely\b|\bhelp with nutrition goals\b|\bactivity goal\b|\bsleep and stress support\b|\bprogress barriers\b/ },
    { id: "rpm", pattern: /\b(what is rpm|what is rtm|rpm|rtm|remote patient monitoring|remote therapeutic monitoring|device connected|monitoring readiness)\b/ },
    { id: "telehealth", pattern: /\b(prepare|prep|plan|summarize|summary)\b.*\b(telehealth|visit|care team|doctor|nurse|coach|clinician|chw|community health worker)\b|\bprepare for my telehealth visit\b|\bsummarize this for my care team\b/ },
    { id: "chw", pattern: /\b(chw|community health worker|health worker)\b.*\b(support|intake|checklist|education|script|referral|follow-up|handoff|summary)\b|\bcommunity health worker support\b|\bprepare chw intake checklist\b|\bprepare referral guidance\b|\bprepare follow-up notes\b/ },
    { id: "report", pattern: /\b(prepare|show|build|create|summarize)\b.*\b(physician report|doctor report|care team report|clinical report|clinical summary|provider report|nurse|community health worker)\b|\bprepare a physician report\b|\bshow physician report\b|\bsummarize for my doctor\b|\bprepare care team report\b|\bcreate a clinical summary\b|\bsummarize this for the nurse\b|\bsummarize this for the community health worker\b|\bwhat data supports this\b|\bwhat is missing\b|\bwhat should the doctor review\b/ }
  ].find(item => item.pattern.test(text));
  if (chronicMatched) {
    const chronicCategoryMap = {
      diabetes: "diabetes",
      hypertension: "hypertension",
      asthma: "asthma",
      "heart-risk": "heart-risk",
      "kidney-risk": "kidney-risk",
      "maternal-risk": "maternal-risk",
      "medication-reminder": "medication-reminder",
      wellness: "wellness",
      chw: "chw",
      navigator: "navigator",
      telehealth: "care-team-summary",
      report: "care-team-summary",
      rpm: "care-team-summary"
    };
    const category = chronicCategoryMap[chronicMatched.id] || "navigator";
    const reportKind = chronicMatched.id === "report" ? (/care team/.test(text) ? "care-team-summary" : "general") : chronicMatched.id;
    const titleMap = {
      diabetes: "Diabetes Support",
      hypertension: "Blood Pressure Support",
      asthma: "Asthma / Breathing Support",
      "heart-risk": "Heart Disease Risk Support",
      "kidney-risk": "Kidney Risk Support",
      "maternal-risk": "Maternal Chronic Risk Support",
      "medication-reminder": "Medication Reminder Plan",
      wellness: "Weight & Wellness",
      rpm: "RPM/RTM Readiness",
      telehealth: /summarize|summary|care team/.test(text) ? "Care Team Summary" : "Prepare Telehealth Visit",
      chw: "CHW Support",
      navigator: "Chronic Care Navigator",
      report: /care team/.test(text) ? "Care Team Report" : "Physician Report"
    };
    const responseMap = {
      diabetes: "I can help prepare diabetes questions for a telehealth visit in review-only mode, including blood sugar concerns, A1c education, high/low glucose warning questions, food/activity context, and what to collect for review. Nexus does not diagnose, change insulin or medicine, connect devices, send data, or replace a clinician.",
      hypertension: "I can help prepare blood pressure questions and warning-sign education in review-only mode, including home BP reading context, measurement technique questions, sodium/activity education, and medication-adherence discussion prep. Nexus does not diagnose, change medicine, dispatch help, connect devices, send data, or replace urgent professional care.",
      asthma: "I can help prepare asthma or chronic respiratory clinic questions in review-only mode, including symptom and trigger notes, inhaler-technique questions, warning signs, and low-bandwidth visit prep. Nexus does not diagnose, change inhalers or medicine, dispatch help, call providers, connect devices, or transmit data.",
      "heart-risk": "I can help prepare heart disease risk questions, warning-sign education, medication-adherence discussion points, and clinic follow-up notes. Nexus does not diagnose heart disease, interpret urgent symptoms as final advice, change medicine, call providers, or dispatch help.",
      "kidney-risk": "I can help prepare kidney disease risk questions, screening and lab-follow-up notes, diabetes/BP context, and medication-safety questions for clinician or pharmacist review. Nexus does not diagnose kidney disease, give final lab interpretation, change medicine, or update records.",
      "maternal-risk": "I can help prepare maternal chronic risk questions for antenatal clinic, nurse, midwife, CHW, or physician review, and route pregnancy danger signs to urgent professional care guidance. Nexus does not diagnose pregnancy complications, change medicine, call providers, or dispatch help.",
      "medication-reminder": "I can help prepare a medication and appointment reminder plan from an existing prescription or clinic instructions, including refill dates, BP/glucose checks, labs, and CHW visits. Nexus will not change medicine, auto-notify, order pharmacy items, buy medicine, mutate calendars, message providers, or call anyone.",
      wellness: "I can help prepare supportive weight and wellness questions safely for a provider, coach, nurse, or community health worker, including nutrition goals, physical activity, sleep, stress, self-reported barriers, and RTM behavior signal notes. Nexus gives general education only with no shame/blame language and will not prescribe a diet, medicine, supplement, product, purchase, or paid plan.",
      rpm: "RPM means remote patient monitoring, and RTM means remote therapeutic monitoring. Nexus can explain readiness and prepare questions, but no device is connected, no readings are transmitted, and provider review is required.",
      telehealth: "I can prepare a review-only telehealth visit checklist or care team summary. Nothing is sent, stored as a medical record, or handed off to a provider from this card.",
      chw: "I can help prepare CHW intake checklist notes, low-literacy explanation prompts, patient education scripts, referral guidance questions, follow-up preparation, and a clinician handoff summary. Nexus does not diagnose, change medicines, submit referrals, send messages, call providers, connect devices, or update records.",
      navigator: "I can help you prepare, understand, track, and navigate chronic care with education, reminders, clinic questions, tracking checklists, red-flag guidance, and community health worker support. I do not replace a doctor, nurse, pharmacist, CHW, or emergency service, and I will not diagnose, prescribe, book care, call, message, buy medicine, request location, connect devices, transmit data, or store sensitive health data persistently.",
      report: "I prepared a session-only physician/care-team report for review. It shows data inputs, missing data, source labels, review level, and safety boundaries, but it is not a diagnosis or treatment plan."
    };
    return {
      action: `low-risk-chronic-${chronicMatched.id}`,
      section: "dashboard",
      title: titleMap[chronicMatched.id],
      response: responseMap[chronicMatched.id],
      preparation: a100ReviewOnlyPreparation(category),
      taskPlan: buildNexusAutonomousTaskPlan(command, { category }),
      providerReadiness: a100ChronicCareReadinessCards(),
      healthPrivacyComplianceGuardrails: a100HealthPrivacyComplianceGuardrails(command),
      guidance: a100ChronicCareGuidanceCard(chronicMatched.id),
      report: a100ChronicCareReport(reportKind, command),
      suggestions: ["help with diabetes", "help me with blood pressure", "help me lose weight safely", "what is RPM", "prepare for my telehealth visit"]
    };
  }
  const capabilities = a100StandardUserCapabilities();
  const matched = [
    { id: "next", pattern: /\b(what can you do|how can you help|what can nexus do|what do you do|help me$|what should i do next)\b/ },
    { id: "agriculture", pattern: /\b(agriculture|crop|farm|farmer|field|pest|soil|harvest)\b.*\b(help|support|what|explain|next|guide|issue|problem)\b|\bhelp me with agriculture\b|\bi have a crop issue\b|\bcrop issue\b/ },
    { id: "learning", pattern: /\b(find|show|start|help|open)\b.*\b(training|course|learning|lesson|certificate|agriculture training)\b/ },
    { id: "workforce", pattern: /\b(show|find|help|open|prepare)\b.*\b(job|jobs|workforce|work|role|interview|farm jobs)\b/ },
    { id: "marketplace", pattern: /\b(browse|open|show|compare|view)\b.*\b(agritrade|agri trade|marketplace|market|buyer|seller)\b/ },
    { id: "map", pattern: /\b(help me plan a route|plan a route|route planning|map readiness|is location enabled|show satellite|open map)\b/ },
    { id: "providers", pattern: /\b(provider|providers|connected|connection|readiness|what providers are connected)\b/ },
    { id: "task", pattern: /\b(prepare|draft|checklist|questions|safe task|message draft)\b/ }
  ].find(item => item.pattern.test(text));
  if (!matched) return null;
  const capability = capabilities.find(item => item.id === matched.id) || capabilities[0];
  const preparationCategory = capability.id === "map" ? "route" : capability.id === "task" ? "general" : capability.id;
  const responseMap = {
    agriculture: "I can help with agriculture in safe preview mode: crop symptoms, pest questions, soil or weather context, buyer prep, and field-support next steps. I will not scan fields, contact buyers, or create records from this prompt.",
    learning: "I can help find agriculture training, explain lessons, prepare captions, and review certificate readiness. I will not issue a certificate or change records from this prompt.",
    workforce: "I can help review farm jobs, skills, readiness gaps, interview preparation, and next steps. I will not submit an application, message an employer, or schedule a shift from this prompt.",
    marketplace: "I can help browse AgriTrade, compare products, prices, buyers, and seller questions. I will not buy, sell, message, or process payment.",
    map: "I can open map readiness and route planning previews. I will not request live location, open external navigation, or call routing providers.",
    providers: "Provider readiness is review-only: Nexus can show connected, not connected, preview-only, and review-required states without testing or handing off to providers.",
    task: "I can prepare a safe draft, checklist, or questions for review. Sending, calling, submitting, buying, paying, or provider handoff stays gated.",
    next: "Nexus can help with agriculture, training, jobs, marketplace browsing, map readiness, provider readiness, safe task preparation, and next-step guidance. High-risk actions stay gated."
  };
  return {
    action: `low-risk-${capability.id}`,
    section: capability.section,
    title: capability.label,
    response: responseMap[capability.id] || responseMap.next,
    preparation: /\b(prepare|draft|checklist|questions|plan|setup guidance)\b/.test(text) ? a100ReviewOnlyPreparation(preparationCategory) : null,
    taskPlan: buildNexusAutonomousTaskPlan(command, { category: preparationCategory }),
    providerReadiness: capability.id === "providers" ? a100ProviderReadinessCards() : null,
    providerAccountApiAccess: capability.id === "providers" ? a100ProviderAccountApiAccessPanel() : null,
    productionProviderReadiness: capability.id === "providers" ? a100ProductionProviderReadinessPanel() : null,
    routePreview: capability.id === "map" ? a100RoutePlanningPreview() : null,
    guidance: capability.id === "agriculture" ? a100AgricultureHelpCard() : capability.id === "learning" ? a100TrainingLearningCard() : capability.id === "workforce" ? a100WorkforceJobsCard() : capability.id === "marketplace" ? a100MarketplaceBrowsingCard() : null,
    suggestions: ["help me with agriculture", "find agriculture training", "show me farm jobs", "browse AgriTrade", "help me plan a route", "what providers are connected"].slice(0, 5)
  };
}

function openA100SafeAutonomyPreview(intent) {
  if (!intent) return false;
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  const section = intent.section || "dashboard";
  if (section === "dashboard" || section === "agent") {
    goSection("dashboard", { instant: true, openDefaultAction: false, keepAssistant: false });
    if (experienceMode === "user") renderUserWorkspace();
    renderA100SafeAutonomyCard(intent);
    setTimeout(() => $("#a100SafeAutonomySurface")?.scrollIntoView?.({ behavior: "smooth", block: "start" }), 80);
  } else {
    goSection(section, { instant: true, openDefaultAction: false, keepAssistant: false });
    if (experienceMode === "user") renderUserSimpleActiveSection(section);
  }
  renderLiveVoiceSuggestions(intent.suggestions || ["what can Nexus do", "what should I do next"]);
  recordVoiceEvent(`A100 safe autonomy preview: ${intent.action}`, "done");
  updateNexusBehaviorLayer("answering", "Nexus showed A100 safe autonomy guidance without execution or provider handoff.");
  rememberA100SafeFollowUpContext(intent);
  setVoiceResponse(intent.response, true, { allowHandoff: false, command: intent.action, source: "a100-standard-user-safe-autonomy" });
  return true;
}

function openFullScaleUserMap(response = "Full map is open. You can zoom, drag, check route risk, find facilities, or track shipment movement.", options = {}) {
  const actionLead = "";
  if (!options.keepCountryOverride) voiceMapCountryOverride = null;
  closeAskNexus({ silent: true });
  $("#workflowModal")?.classList.add("hidden");
  closeUserCaptionPanel();
  document.body.classList.add("user-map-full-open");
  goSection("map", { instant: true, openDefaultAction: false, keepAssistant: false });
  if (experienceMode === "user") {
    renderUserSimpleActiveSection("map");
    $(`#map .user-inline-workflow`)?.classList.add("hidden");
  }
  renderLiveVoiceSuggestions(["what map features are available", "show satellite imagery", "is location enabled", "help me plan a route"]);
  setTimeout(() => {
    renderMap();
    renderUserRealMap();
    safeInvalidateLeafletMap(map);
    safeInvalidateLeafletMap(userMap);
    const target = $("#userMapCanvas") || $("#mapCanvas") || $("#map");
    target?.scrollIntoView?.({ behavior: "smooth", block: "start" });
  }, 120);
  recordVoiceEvent("Opened the full map view from voice.", "done");
  updateNexusBehaviorLayer("ready", "Nexus opened the full map view and is ready for route or facility commands.");
  setVoiceResponse(`${actionLead}${response}`.trim(), true);
  return true;
}

function openCountryMapFromVoice(country, response = "") {
  if (!country) return openFullScaleUserMap(response || "Full map is open. You can zoom, drag, find facilities, check routes, and track shipments.");
  const seededCountry = (data?.countries || []).find(item => item.id === country.id || normalizeSpeechForIntent(item.name) === normalizeSpeechForIntent(country.name));
  voiceMapCountryOverride = { ...(seededCountry || country) };
  if (seededCountry?.id && data?.profile) {
    data.profile.activeCountryId = seededCountry.id;
    const selector = $("#countrySelect");
    if (selector && [...selector.options].some(option => option.value === seededCountry.id)) selector.value = seededCountry.id;
  }
  const spoken = response || `I opened the map for ${voiceMapCountryOverride.name}. You can zoom, drag, inspect nearby regions, and add clinic, pharmacy, crop, route, or shipment tracking.`;
  const opened = openFullScaleUserMap(spoken, { keepCountryOverride: true });
  setTimeout(() => {
    if (!userMap || !voiceMapCountryOverride) return;
    userMap.setView([Number(voiceMapCountryOverride.lat), Number(voiceMapCountryOverride.lng)], 6);
    userMapLayers.markers?.clearLayers?.();
    userMapLayers.facilities?.clearLayers?.();
    addOperationalCountryMarkers(userMap, userMapLayers.markers, voiceMapCountryOverride);
    addNearbyFacilityMarkers(userMapLayers.facilities, voiceMapCountryOverride, "Support point");
    safeInvalidateLeafletMap(userMap);
  }, 220);
  return opened;
}

function countryFromAgentMapMetadata(metadata = {}) {
  const targetText = [metadata.countryName, metadata.countryId].filter(Boolean).join(" ");
  const matched = africanMapCountryTarget(targetText);
  if (matched) return matched;
  if (metadata.countryName && Number.isFinite(Number(metadata.lat)) && Number.isFinite(Number(metadata.lng))) {
    return {
      id: normalizeSpeechForIntent(metadata.countryId || metadata.countryName).replace(/\s+/g, "-"),
      name: metadata.countryName,
      lat: Number(metadata.lat),
      lng: Number(metadata.lng)
    };
  }
  return null;
}

function openNexusHome(response = "Home is open. What do you need next?") {
  const actionLead = "";
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  pendingWorkflow = null;
  clearLevelOneAgentActionSuggestionLabel();
  document.body.classList.remove("user-map-full-open");
  closeAskNexus({ silent: true });
  $("#workflowModal")?.classList.add("hidden");
  closeUserCaptionPanel();
  goSection("dashboard", { instant: true, scroll: false, openDefaultAction: false, keepAssistant: false });
  if (experienceMode === "user") renderUserWorkspace();
  renderLiveVoiceSuggestions(["I need medicine", "help me sell my crop", "start a course", "open the map"]);
  recordVoiceEvent("Returned to home from voice.", "done");
  updateNexusBehaviorLayer("ready", "Nexus returned to the home screen and is ready for the next request.");
  setVoiceResponse(`${actionLead}${response}`.trim(), true, { allowHandoff: false });
  return true;
}

function isHealthFacilityMapCommand(command = "", result = {}) {
  const lower = normalizeToolText(command);
  const response = normalizeToolText(result?.response || "");
  const metadataSection = result?.metadata?.redirectSection || "";
  const facilityWords = /\b(clinic|clinics|hospital|health facility|health facilities|pharmacy|pharmacies|medicine|doctor|provider)\b/;
  const mapWords = /\b(show|find|nearest|nearby|closest|near me|where|map|location|route)\b/;
  return (facilityWords.test(lower) && mapWords.test(lower))
    || metadataSection === "map"
    || /\bclinic or pharmacy support on the map|show clinic and pharmacy|closest facility route\b/.test(response);
}

function openHealthFacilityMapNow(response = "I opened the full map for clinic and pharmacy support. Share your village, city, or location, and I will guide the closest facility route.") {
  const defaultMapResponse = "I opened the clinic and pharmacy map. Share your village, city, or nearest landmark, and I will guide the closest clinic, mobile clinic, or pharmacy route.";
  const rawSpoken = response || defaultMapResponse;
  const spoken = /\bmap\b/i.test(rawSpoken) && /\bpharmacy|clinic and pharmacy|clinic or pharmacy\b/i.test(rawSpoken) ? rawSpoken : defaultMapResponse;
  const opened = openFullScaleUserMap(spoken);
  renderLiveVoiceSuggestions(["use my location", "show clinics", "show pharmacy", "call provider", "start intake"]);
  updateNexusBehaviorLayer("ready", "Nexus opened the full health facility map first, with clinic and pharmacy support ready.");
  setActiveAgentJourney("map", "facility-route", spoken);
  return opened;
}

function hideVoiceWorkflowCards() {
  $$(".user-inline-workflow").forEach(panel => {
    panel.classList.add("hidden");
    panel.innerHTML = "";
  });
  $("#workflowModal")?.classList.add("hidden");
}

function startGuidedHealthIntakeSession(kind = "intake", startedBy = "") {
  const seedByKind = {
    doctor: {
      answers: { careNeed: "Doctor or provider support requested." },
      index: 1
    },
    clinic: {
      answers: { careNeed: "Clinic or mobile clinic support requested." },
      index: 1
    },
    mobile: {
      answers: { careNeed: "Mobile clinic support requested." },
      index: 1
    },
    caption: {
      answers: { careNeed: "Telehealth caption relay requested.", accessNeeds: "Caption relay" },
      index: 2
    },
    medicine: {
      answers: {},
      index: 0
    },
    intake: {
      answers: {},
      index: 0
    }
  };
  const seed = seedByKind[kind] || seedByKind.intake;
  saveConversationIntake({
    type: "health",
    mode: conversationPlatformMode(),
    language: languageCode(),
    startedBy,
    guidedKind: kind,
    answers: { ...seed.answers },
    index: seed.index,
    startedAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  });
}

function startGuidedHealthVoiceResponse(kind = "intake", response = "", options = {}) {
  const actionByKind = {
    intake: "intake",
    medicine: "pharmacy",
    clinic: "nearest-clinic",
    doctor: "provider",
    mobile: "mobile-clinic",
    caption: "caption"
  };
  const action = actionByKind[kind] || "intake";
  const spokenResponse = response || "I can help with health support. I am not a doctor and this is not a diagnosis. First, tell me where you are and what happened.";
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  pendingWorkflow = null;
  startGuidedHealthIntakeSession(kind, spokenResponse);
  clearNexusAnswerContext();
  clearAgentProgressTimers();
  hideVoiceWorkflowCards();
  if (canOpenSection("health")) {
    goSection("health", { instant: true, openDefaultAction: false, keepAssistant: true, scroll: false });
    if (experienceMode === "user") renderUserSimpleActiveSection("health");
  }
  recordNexusAutonomousLearning({
    type: "guided-health-voice",
    workflow: "health",
    action,
    kind,
    command: spokenResponse,
    guidedOnly: true
  });
  setActiveAgentJourney("health", action, spokenResponse);
  renderLiveVoiceSuggestions(options.suggestions || ["where are you", "what happened", "find clinic", "medicine", "call provider"]);
  updateNexusBehaviorLayer("listening", options.status || "Nexus is guiding health support by voice without opening a menu card.");
  updateUserCaptionPanel(spokenResponse, { expanded: true });
  setVoiceResponse(spokenResponse, true, { allowHandoff: false, source: "guided-health" });
  return true;
}

function startGuidedServiceIntake(type = "", response = "", options = {}) {
  const plan = conversationIntakePlans()[type];
  if (!plan) return false;
  const seed = options.seed || {};
  const index = Number.isInteger(seed.index) ? seed.index : 0;
  const answers = { ...(seed.answers || {}) };
  const nextQuestion = plan.fields?.[index]?.question || "Tell me the next detail.";
  const spokenResponse = response || `I can help with ${plan.label}. I will ask one question at a time. ${nextQuestion}`;
  saveConversationIntake({
    type,
    mode: conversationPlatformMode(),
    language: languageCode(),
    startedBy: spokenResponse,
    guidedKind: options.kind || type,
    answers,
    index,
    startedAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  });
  pendingAgentClarification = null;
  pendingNexusSpokenCommand = null;
  pendingWorkflow = null;
  clearNexusAnswerContext();
  clearAgentProgressTimers();
  hideVoiceWorkflowCards();
  if (canOpenSection(plan.section)) {
    goSection(plan.section, { instant: true, openDefaultAction: false, keepAssistant: true, scroll: false });
    if (experienceMode === "user") renderUserSimpleActiveSection(plan.section);
  }
  recordNexusAutonomousLearning({
    type: "guided-service-intake",
    intakeType: type,
    command: spokenResponse,
    mode: conversationPlatformMode()
  });
  setActiveAgentJourney(plan.workflow, plan.action, spokenResponse);
  renderLiveVoiceSuggestions(options.suggestions || ["answer in your own words", "repeat the question", "Nexus stop"]);
  updateNexusBehaviorLayer("listening", options.status || `Nexus started guided ${plan.label} and is waiting for the next detail.`);
  updateUserCaptionPanel(spokenResponse, { expanded: true });
  setVoiceResponse(spokenResponse, true, { allowHandoff: false, source: "guided-service" });
  return true;
}

